window.HADITH_CACHE["ahmad_8"] = {"4001":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنِ الزُّهْرِيِّ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي أَنَّ أَرْوَاحَ الشُّهَدَاءِ فِي طَائِرٍ خُضْرٍ تَعْلُقُ مِنْ ثَمَرِ الْجَنَّةِ وَقُرِئَ عَلَى سُفْيَانَ نَسَمَةٌ تَعْلُقُ فِي ثَمَرَةٍ أَوْ شَجَرِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Az Zuhri] dari [Ibnu Ka'b bin Malik] dari [ayahnya] yang ia sampai kepada Nabi shallallahu 'alaihi wasallam, yakni bahwa arwah para syuhada' berada dalam burung hijau yang menggantung pohon yang berbuah di dalam surga.\" Dan telah dibacakan di hadapan Sufyan, \"jiwanya bergantungan pada pohon yang berbuah, atau pohon di surga.\""},"4002":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ بِثَلَاثِ أَصَابِعَ وَلَا يَمْسَحُ يَدَهُ حَتَّى يَلْعَقَهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, Telah menceritakan kepada kami [Hisyam bin Urwah] dari [Abdurrahman bin Sa'd] dari [Ibnu Ka'b bin Malik] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam makan dengan menggunakan tiga jari, dan tidak mengusap tangannya sehingga beliau menjilatinya.\""},"4003":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ هِشَامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ كَعْبِ بْنِ مَالِكٍ أَوْ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ أَخْبَرَاهُ عَنْ أَبِيهِ كَعْبٍ أَنَّهُ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ بِثَلَاثِ أَصَابِعَ فَإِذَا فَرَغَ لَعِقَهَا","id":"Telah menceritakan kepada kami [Ibnu Numair] dari [Hisyam] dari [Abdurrahman bin Sa'ad] bahwa [Abdurrahman bin Ka'b bin Malik] atau [Abdullah bin Ka'b bin Malik] telah mengabarkan dari ayahnya [Ka'b] bahwa dia menceritakan kepada mereka, bahwa Rasulullah shallallahu 'alaihi wasallam makan dengan menggunakan tiga jari, jika selesai maka beliau menjilatinya.\""},"4004":{"ar":"حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْدَمُ مِنْ سَفَرٍ إِلَّا فِي الضُّحَى فَيَبْدَأُ بِالْمَسْجِدِ فَيُصَلِّي فِيهِ رَكْعَتَيْنِ وَيَقْعُدُ فِيهِ","id":"Telah menceritakan kepada kami [Abu Usamah] berkata, Telah mengabarkan kepada kami [Ibnu Juraij] dari [Az Zuhri] dari [Abdurrahman bin Ka'b] dari [ayahnya] dia berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam datang dari bepergian melainkan di waktu dluha, kemudian beliau memulainya dengan memasuki masjid dan shalat dua rakaat lalu duduk di dalamnya.\""},"4005":{"ar":"حَدَّثَنَا يَزِيدُ وَأَبُو النَّضْرِ قَالَا أَنَا الْمَسْعُودِيُّ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَالْخَامَةِ مِنْ الزَّرْعِ تُفَيِّئُهَا الرِّيَاحُ تَصْرَعُهَا مَرَّةً وَتَعْدِلُهَا أُخْرَى حَتَّى يَأْتِيَهُ أَجَلُهُ وَمَثَلُ الْكَافِرِ مَثَلُ الْأَرْزَةِ الْمُجْذِيَةِ عَلَى أَصْلِهَا لَا يُقِلُّهَا شَيْءٌ حَتَّى يَكُونَ انْجِعَافُهَا مَرَّةً","id":"Telah menceritakan kepada kami [Yazid] dan [Abu Nadlr] keduanya berkata, aku [Al Mas'udi] dari [Sa'd bin Ibrahim] dari [Ibnu Ka'b bin Malik] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan seorang mukmin seperti"},"4006":{"ar":"حَدَّثَنَا سُرَيْجٌ وَأَبُو جَعْفَرٍ الْمَدَائِنِيُّ قَالَا حَدَّثَنَا عَبَّادٌ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ مُلَازِمٌ رَجُلًا فَقَالَ مَا هَذَا قَالَ يَا رَسُولَ اللَّهِ غَرِيمٌ لِي وَأَشَارَ بِيَدِهِ أَنْ يَأْخُذَ النِّصْفَ قُلْتُ يَا رَسُولَ اللَّهِ نَعَمْ قَالَ فَأَخَذَ الشَّطْرَ وَتَرَكَ الشَّطْرَ","id":"Telah menceritakan kepada kami [Suraij] dan [Abu Ja'far Al Mada`ini] keduanya berkata, Telah menceritakan kepada kami ['Abbad] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Abdullah bin Ka'b bin Malik] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melewatinya saat sedang berselisih dengan seorang laki-laki. Beliau lalu bertanya: \"Apa ini?\" dia menjawab, \"Wahai Rasulullah, orang ini berhutang kepadaku.\" -Kemudian beliau berisyarat dengan tangannya agar ia mengambil setengahnya- Aku lalu berkata, \"Baik ya Rasulullah, \" kemudian dia mengambil setengah dan meninggalkan yang setengah lagi.\""},"4007":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّهُ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَنْزَلَ فِي الشِّعْرِ مَا أَنْزَلَ فَقَالَ إِنَّ الْمُؤْمِنَ يُجَاهِدُ بِسَيْفِهِ وَلِسَانِهِ وَالَّذِي نَفْسِي بِيَدِهِ لَكَأَنَّ مَا تَرْمُونَهُمْ بِهِ نَضْحُ النَّبْلِ","id":"Telah menceritakan kepada kami ['Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abdurrahman bin Ka'b bin Malik] dari [ayahnya] bahwa dia berkata kepada Nabi shallallahu 'alaihi wasallam, \"Sesungguhnya Allah Azza wa Jalla telah menurunkan di dalam bait-bait syair sesuatu yang telah Dia turunkan, maka beliau bersabda: \"Sesungguhnya seorang mukmin berjihad dengan pedang dan lisannya, demi Dzat yang jiwaku berada dalam genggaman-Nya, sesungguhnya apa yang kalian lemparkan kepada mereka seakan-akan anak panah yang meluncur.\""},"4008":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ مَعْمَرٍ وَيُونُسَ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سُرَّ اسْتَنَارَ وَجْهُهُ حَتَّى كَأَنَّ وَجْهَهُ شِقَّةُ قَمَرٍ وَكُنَّا نَعْرِفُ ذَلِكَ فِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Ibnu Mubarak] dari [Ma'mar] dan [Yunus] dari [Az Zuhri] dari ['Abdurrahman bin 'Abdullah bin Ka'b bin Malik] dari [Ka'b] dia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam dalam keadaan senang, maka wajahnya akan bersinar, hingga seakan-akan wajahnya seperti belahan bulan, dan kami dulu mengetahui hal itu padanya.\""},"4009":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّهُتَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَانَ لَهُ عَلَيْهِ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا حَتَّى كَشَفَ سِجْفَ حُجْرَتِهِ فَنَادَى يَا كَعْبُ بْنَ مَالِكٍ فَقَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَأَشَارَ إِلَيْهِ أَنْ ضَعْ مِنْ دَيْنِكَ الشَّطْرَ قَالَ قَدْ فَعَلْتُ يَا رَسُولَ اللَّهِ قَالَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] berkata, telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari ['Abdullah bin Ka'b bin Malik] bahwa [ayahnya] telah mengabarkan kepadanya, bahwa pada masa Rasulullah shallallahu 'alaihi wasallam dia pernah minta pembayaran hutang kepada Ibnu Abu Hadrad di dalam masjid, suara keduanya sangat keras hingga terdengar oleh Rasulullah shallallahu 'alaihi wasallam yang saat itu berada di rumahnya, lalu beliau menemui keduanya seraya menyingkap kain penutup kamarnya sambil menyeru: \"Wahai Ka'b bin Malik!\" Ka'b menjawab, \"Wahai Rasulullah, aku penuhi panggilanmu.\" Kemudian beliau berisyarat 'Hendaknya kamu bebaskan setengah dari piutangmu'. Ka'b lantas menjawab, \"Aku telah melaksanakannya wahai Rasulullah, ' beliau bersabda: \"Sekarang bangun dan putuskanlah hutangmu.\""},"4010":{"ar":"حَدَّثَنَا إِسْحَاقُ يَعْنِي ابْنَ الطَّبَاعِ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنِ الزُّهْرِيِّ عَنِ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يُسَافِرَ لَمْ يُسَافِرْ إِلَّا يَوْمَ الْخَمِيسِ","id":"Telah menceritakan kepada kami [Ishaq] -yakni Ibnu Thaba'- berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Az Zuhri] dari [Ibnu Ka'b bin Malik] dari [ayahnya], bahwa jika Rasulullah shallallahu 'alaihi wasallam hendak bepergian, beliau tidak berangkat kecuali hari kamis.\""},"4011":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجَارُ أَحَقُّ بِصَقَبِهِ أَوْ سَقَبِهِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari ['Amru bin Syarid] dari [Abu Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga itu lebih berhak karena kedekatannya.\""},"4012":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مَالِكٍ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْلَفَ مِنْ رَجُلٍ بَكْرًا فَأَتَتْهُ إِبِلٌ مِنْ إِبِلِ الصَّدَقَةِ فَقَالَ أَعْطُوهُ فَقَالُوا لَا نَجِدُ لَهُ إِلَّا رَبَاعِيًا خِيَارًا قَالَ أَعْطُوهُ فَإِنَّ خِيَارَ النَّاسِ أَحْسَنُهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Malik] dia berkata, telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Rafi'], bahwa Nabi shallallahu 'alaihi wasallam meminjam seekor unta muda dari seseorang, kemudian beliau mendapat unta dari unta sedekah (zakat), maka beliau pun berkata: \"Berikanlah kepadanya.\" Para sahabat pun bertanya, \"Kami tidak mendapatkan kecuali unta bagus dan telah berumur tujuh tahun.\" Baliau pun bersabda: \"Berikanlah padanya karena sebaik-baik manusia adalah yang terbaik dalam pelunasan.\""},"4013":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ أَخْبَرَنَا شَرِيكٌ وَأَبُو النَّضْرِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِي رَافِعٍ قَالَلَمَّا وَلَدَتْ فَاطِمَةُ حَسَنًا قَالَتْ أَلَا أَعُقُّ عَنْ ابْنِي بِدَمٍ قَالَ لَا وَلَكِنْ احْلِقِي رَأْسَهُ وَتَصَدَّقِي بِوَزْنِ شَعْرِهِ مِنْ فِضَّةٍ عَلَى الْمَسَاكِينِ وَالْأَوْفَاضِ وَكَانَ الْأَوْفَاضُ نَاسًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجِينَ فِي الْمَسْجِدِ أَوْ فِي الصُّفَّةِ وَقَالَ أَبُو النَّضْرِ مِنْ الْوَرِقِ عَلَى الْأَوْفَاضِ يَعْنِي أَهْلَ الصُّفَّةِ أَوْ عَلَى الْمَسَاكِينِ فَفَعَلْتُ ذَلِكَ قَالَتْ فَلَمَّا وَلَدْتُ حُسَيْنًا فَعَلْتُ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Ibnu Numair] berkata, telah mengabarkan kepada kami [Syarik] dan [Abu Nadlr] berkata, telah menceritakan kepada kami [Syarik] dari ['Abdullah bin Muhammad bin 'Aqil] dari ['Ali bin Husain] dari [Abu Rafi'] dia berkata, \"Ketika Fatimah melahirkan Hasan, Fatimah berkata, \"Tidakkah aku mengakikahi anakku dengan menyembelih seekor hewan?\" belaiu menjawab: \"Jangan, namun cukurlah rambutnya dan bersedekahlah sebesar timbangan rambutnya dengan perak kepada orang-orang miskin dan aufadl, yaitu para sahabat Rasulullah shallallahu 'alaihi wasallam, yang sedang membutuhkan di dalam masjid, atau di pelataran masjid.\" Abu Nadlr menyebutkan, \"Dari perak kepada aufadl, yaitu ahli shuffah, atau kepada orang-orang miskin.\" Fatimah berkata, \"Ketika aku melahirkan Husain aku melakukan hal yang sama.\""},"4014":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مُخَوَّلِ بْنِ رَاشِدٍ عَنْ رَجُلٍ عَنْ أَبِي رَافِعٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ الرَّجُلُ وَشَعْرُهُ مَعْقُوصٌ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Mukhawwal bin Rasyid] dari [seorang laki-laki] dari [Abu Rafi'] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang yang sedang shalat sedangkan rambutnya digelung.\""},"4015":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ الْحَسَنَ بْنَ عَلِيِّ بْنِ أَبِي رَافِعٍ حَدَّثَهُ عَنْ أَبِي رَافِعٍ أَنَّهُ قَالَكُنْتُ فِي بَعْثٍ مَرَّةً فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَأْتِنِي بِمَيْمُونَةَ فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنِّي فِي الْبَعْثِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَسْتَ تُحِبُّ مَا أُحِبُّ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ اذْهَبْ فَأْتِنِي بِهَا فَذَهَبْتُ فَجِئْتُهُ بِهَا","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku ['Amru] bahwa [Bukair] telah menceritakan kepadanya bahwa [Hasan bin 'Ali bin Abu Rafi'] telah menceritakan kepadanya dari [Abu Rafi'] bahwa dia berkata, \"Suatu ketika aku dalam sebuah pasukan, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Pergi dan bawalah Maimunah kepadaku, \" aku lalu berkata, \"Wahai Nabi Allah, sesungguhnya aku masih dalam sebuah pasukan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah kamu suka seperti yang aku suka?\" aku menjawab, \"Ya, wahai Rasulullah, \" beliau lalu bersabda: \"Pergi dan bawalah dia kepadaku, \" lalu aku pergi dan membawanya kepada beliau.\""},"4016":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ عَمَّتِهِ عَنْ أَبِي رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي لَيْلَةٍ فَاغْتَسَلَ عِنْدَ كُلِّ امْرَأَةٍ مِنْهُنَّ غُسْلًا فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اغْتَسَلْتَ غُسْلًا وَاحِدًا فَقَالَ هَذَا أَطْهَرُ وَأَطْيَبُ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Hammad bin Salamah] dari ['Abdurrahman] dari [bibinya] dari [Abu Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam menggilir isteri-isteri baliau pada satu malam, lalu beliau mandi setiap selesai dari seorang di antara mereka, aku berkata, \"Wahai Rasulullah, andai saja tuan mandi dengan sekali mandi?\" Beliau menjawab: \"Hal ini lebih suci dan lebih baik.\""},"4017":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذَّنَ فِي أُذُنِ الْحَسَنِ يَوْمَ وَلَدَتْهُ بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari ['Ashim bin 'Ubaidullah] dari ['Abdullah bin Abu Rafi'] dari [ayahnya] dia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam adzan untuk shalat di telinganya Hasan sewaktu dia dilahirkan.\""},"4018":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ يَعْنِي الرَّازِيَّ عَنْ شُرَحْبِيلَ عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأُهْدِيَتْ لَهُ شَاةٌ فَجَعَلَهَا فِي الْقِدْرِ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا هَذَا يَا أَبَا رَافِعٍ فَقَالَ شَاةٌ أُهْدِيَتْ لَنَا يَا رَسُولَ اللَّهِ فَطَبَخْتُهَا فِي الْقِدْرِ فَقَالَ نَاوِلْنِي الذِّرَاعَ يَا أَبَا رَافِعٍ فَنَاوَلْتُهُ الذِّرَاعَ ثُمَّ قَالَ نَاوِلْنِي الذِّرَاعَ الْآخَرَ فَنَاوَلْتُهُ الذِّرَاعَ الْآخَرَ ثُمَّ قَالَ نَاوِلْنِي الذِّرَاعَ الْآخَرَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّمَا لِلشَّاةِ ذِرَاعَانِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّكَ لَوْ سَكَتَّ لَنَاوَلْتَنِي ذِرَاعًا فَذِرَاعًا مَا سَكَتَّ ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ فَاهُ وَغَسَلَ أَطْرَافَ أَصَابِعِهِ ثُمَّ قَامَ فَصَلَّى ثُمَّ عَادَ إِلَيْهِمْ فَوَجَدَ عِنْدَهُمْ لَحْمًا بَارِدًا فَأَكَلَ ثُمَّ دَخَلَ الْمَسْجِدَ فَصَلَّى وَلَمْ يَمَسَّ مَاءً","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] berkata, telah menceritakan kepada kami [Abu Ja'far] -yakni Ar Razi- dari [Syurahbil] dari [Abu Rafi'] bekas budak Rasulullah shallallahu 'alaihi wasallam, dia mengatakan bahwa pernah dihadiahkan kepadanya daging kambing, lalu dia memasaknya dalam periuk, ketika Rasulullah shallallahu 'alaihi wasallam masuk beliau pun bertanya: \"Apa ini ya Abu Rafi'?\" dia menjawab, \"Wahai Rasulullah, ini daging kambing yang dihadiahkan kepada kita, lalu aku memasaknya di periuk, \" beliau pun bersabda: \"Berikan aku pahanya wahai Abu Rafi'?\" maka aku pun memberikan daging paha kepada beliau, lalu beliau bersabda: \"Berikan aku paha yang lainnya.\" Lalu aku memberikan daging paha yang satunya, lalu beliau bersabda lagi: \"Berikan kepadaku paha yang lainnya.\" Abu rafi' lalu menjawab, \"Wahai Rasulullah, sesungguhnya kambing hanya mempunyai dua paha saja, \" kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh, jika saja kamu diam, maka kamu akan dapat memberiku paha kambing demi paha kambing.\" Kemudian beliau minta diambilkan air, beliau berkumur-kumur dan mencuci ujung jemarinya, setelah itu beliau berdiri shalat. Kemudian beliau kembali kepada mereka dan mendapatkan daging yang dingin, lalu beliau makan dan kembali ke masjid tanpa menyentuh air sama sekali.\""},"4019":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَ فَسَأَلْتُ عَلِيَّ بْنَ الْحُسَيْنِ فَحَدَّثَنِي عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ الْحَسَنَ بْنَ عَلِيٍّ لَمَّا وُلِدَ أَرَادَتْ أُمُّهُ فَاطِمَةُ أَنْ تَعُقَّ عَنْهُ بِكَبْشَيْنِ فَقَالَ لَا تَعُقِّي عَنْهُ وَلَكِنْ احْلِقِي شَعْرَ رَأْسِهِ ثُمَّ تَصَدَّقِي بِوَزْنِهِ مِنْ الْوَرِقِ فِي سَبِيلِ اللَّهِ ثُمَّ وُلِدَ حُسَيْنٌ بَعْدَ ذَلِكَ فَصَنَعَتْ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Zakaria bin 'Adi] berkata, telah mengabarkan kepadaku ['Ubaidullah] -yakni Ibnu 'Amru- dari ['Abdullah bin Muhammad bin 'Aqil] dia berkata; aku bertanya kepada ['Ali bin Husain] kemudian dia menceritakan kepadaku dari [Abu Rafi'] bekas budak Rasulullah shallallahu 'alaihi wasallam, bahwa waktu Hasan bin 'Ali dilahirkan, maka ibunya, Fatimah hendak mengakikahinya dengan dua ekor domba, maka beliau bersabda: \"Tidak usah kamu mengakikahinya, tetapi cukurlah rambutnya, kemudian bersedekahlah dengan perak di jalan Allah seberat rambut tersebut.\" Setelah Husain lahir maka Fatimah pun mengerjakan seperti itu.\""},"4020":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا الْفُضَيْلُ يَعْنِي ابْنَ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَحْيَى عَنْ أَبِي أَسْمَاءَ مَوْلَى بَنِي جَعْفَرٍ عَنْ أَبِي رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَلِيِّ بْنِ أَبِي طَالِبٍ إِنَّهُ سَيَكُونُ بَيْنَكَ وَبَيْنَ عَائِشَةَ أَمْرٌ قَالَ أَنَا يَا رَسُولَ اللَّهِ قَالَ نَعَمْ قَالَ أَنَا قَالَ نَعَمْ قَالَ فَأَنَا أَشْقَاهُمْ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنْ إِذَا كَانَ ذَلِكَ فَارْدُدْهَا إِلَى مَأْمَنِهَا","id":"Telah menceritakan kepada kami [Husain bin Muhammad] dia berkata, telah menceritakan kepada kami [Al Fudlail] -yakni Ibnu Sulaiman- dia berkata, telah menceritakan kepada kami [Muhammad bin Abu Yahya] dari [Abu Asma'] bekas budak Bani Ja'far, dari [Abu Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada 'Ali bin Abu Thalib: \"Antara kamu dengan 'Aisyah akan terjadi sesuatu, \" 'Ali berkata, \"Aku ya Rasulullah?\" Beliau menjawab: \"Ya.\" Ali berkata lagi, \"Aku!\" Beliau menjawab: \"Ya.\" Ali berkata, \"Akankah aku menyakiti mereka ya Rasulullah?\" Beliau bersabda: \"Jangan, jika itu terjadi maka kembalikanlah ke tempat tinggalnya.\""},"4021":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِى ابْنَ زَيْدٍ عَنْ عَبْدِ الْكَبِيرِ بْنِ الْحَكَمِ الْغِفَارِيِّ وَعَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ عُدَيْسَةَ عَنْ أَبِيهَاجَاءَ عَلِيُّ بْنُ أَبِي طَالِبٍ فَقَامَ عَلَى الْبَابِ فَقَالَ أَثَمَّ أَبُو مُسْلِمٍ قِيلَ نَعَمْ قَالَ يَا أَبَا مُسْلِمٍ مَا يَمْنَعُكَ أَنْ تَأْخُذَ نَصِيبَكَ مِنْ هَذَا الْأَمْرِ وَتُخِفْ فِيهِ قَالَ يَمْنَعُنِي مِنْ ذَلِكَ عَهْدٌ عَهِدَهُ إِلَيَّ خَلِيلِي وَابْنُ عَمِّكَ عَهِدَ إِلَيَّ أَنْ إِذَا كَانَتْ الْفِتْنَةُ أَنْ أَتَّخِذَ سَيْفًا مِنْ خَشَبٍ وَقَدْ اتَّخَذْتُهُ وَهُوَ ذَاكَ مُعَلَّقٌ","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] dia berkata, telah menceritakan kepada kami [Hammad] -yakni Ibnu Zaid- dari ['Abdul Kabir bin Hakam Al Ghifari] dan ['Abdullah bin 'Ubaid] dari ['Udaisah] dari [ayahnya], bahwa 'Ali bin Abu Thalib datang dan berdiri di depan pintu, kemudian dia berkata, \"Apakah di situ Abu Muslim?\" Dikatakan, \"Ya.\" Ali berkata, \"Wahai Abu Muslim, apa yang mencegahmu untuk ikut andil dari perkara ini, bahkan kamu bersembunyi di dalamnya?\" Abu Muslim menjawab, \"Yang mencegahku dari perkara itu adalah janji yang telah dijanjikan kepadaku oleh kekasihku dan juga anak pamanmu, beliau menjanjikan kepadaku jika terjadi fitnah maka hendaklah aku mengambil pedang dari kayu, dan sungguh aku telah mengambilnya, itu dia tergantung.\""},"4022":{"ar":"حَدَّثَنَا مُؤَمَّلٌ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ قَالَ حَدَّثَنَا شَيْخٌ يُقَالُ لَهُ أَبُو عَمْرٍو عَنْ ابْنَةٍ لِأُهْبَانَ بْنِ صَيْفِيٍّ عَنْ أَبِيهَا وَكَانَتْ لَهُ صُحْبَةٌأَنَّ عَلِيًّا لَمَّا قَدِمَ الْبَصْرَةَ بَعَثَ إِلَيْهِ فَقَالَ مَا يَمْنَعُكَ أَنْ تَتْبَعَنِي فَقَالَ أَوْصَانِي خَلِيلِي وَابْنُ عَمِّكَ فَقَالَ إِنَّهُ سَيَكُونُ فُرْقَةٌ وَاخْتِلَافٌ فَاكْسِرْ سَيْفَكَ وَاتَّخِذْ سَيْفًا مِنْ خَشَبٍ وَاقْعُدْ فِي بَيْتِكَ حَتَّى تَأْتِيَكَ يَدٌ خَاطِئَةٌ أَوْ مَنِيَّةٌ قَاضِيَةٌ فَفَعَلْتُ مَا أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ اسْتَطَعْتَ يَا عَلِيُّ أَنْ لَا تَكُونَ تِلْكَ الْيَدَ الْخَاطِئَةَ فَافْعَلْحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي عَمْرٍو الْقَسْمَلِيِّ عَنْ ابْنَةِ أُهْبَانَ عَنْ أَبِيهَا أَنَّ عَلِيًّا أَتَى أُهْبَانَ فَقَالَ مَا يَمْنَعُكَ مِنْ اتِّبَاعِي فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Mu'ammal] dia berkata, telah menceritakan kepada kami [Hammad] -yakni Ibnu Salamah- dia berkata, telah menceritakan kepada kami Syaikh yang biasa dipanggil dengan [Abu 'Amru] dari [Puterinya Uhban bin Shaifi] dari [ayahnya] dan dia termasuk dari salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, bahwa takala 'Ali sampai di Bashrah, dia mengutus seseorang kepadanya (Uhban) Ali sampaikan, 'Apa yang mencegahmu untuk tidak menyertaiku? ' maka di manjawab, 'Kekasihku dan anak pamanmu telah mewasiatkan kepadaku seraya bersabda: \"Sesungguhnya akan ada perpecahan dan perselisihan, patahkan pedangmu lalu ambillah pedang dari kayu, hendaklah kamu duduk di rumahmu sampai kamu menemui tangan yang bersalah atau kematian menjemput.\" Maka aku mengerjakan apa yang Rasulullah shallallahu 'alaihi wasallam perintahkan kepadaku. Wahai 'Ali, jika kamu mampu untuk tidak menjadi tangan yang salah itu maka lakukanlah.\" Telah menceritakan kepada kami [Aswad bin 'Amir] dia berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu 'Amru Al Qasmali] dari putrinya [Uhban] dari [ayahnya] bahwa 'Ali mendatangi Uhban seraya berkata, 'Apa yang mencegahmu untuk tidak mengikutiku…kemudian dia menyebutkan makna hadits tersebut.\""},"4023":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنِ ابْنِ قَارِبٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اغْفِرْ لِلْمُحَلِّقِينَ قَالَ رَجُلٌ وَالْمُقَصِّرِينَ قَالَ فِي الرَّابِعَةِ وَالْمُقَصِّرِينَ يُقَلِّلُهُ سُفْيَانُ بِيَدِهِ قَالَ سُفْيَانُ وَقَالَ فِي تِيكَ كَأَنَّهُ يُوَسِّعُ يَدَهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari [Ibnu Qarib] dari [ayahnya] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"Allahummaghfir lil muhalliqin (Ya Allah, ampunilah orang-orang yang menggundul rambutnya).\" Seorang laki-laki lalu berkata, \"Dan juga orang-orang yang mencukur, \" beliau mengucapkan pada kali keempatnya: \"Dan orang-orang yang mencukur.\" Sufyan mensedikitkan dengan berisyarat dengan tangannya. Sufyan berkata, \"Beliau bersabda seakan-akan melebarkan tangannya.\""},"4024":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْأَقْرَعِ بْنِ حَابِسٍأَنَّهُ نَادَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ وَرَاءِ الْحُجُرَاتِ فَقَالَ يَا مُحَمَّدُ إِنَّ حَمْدِي زَيْنٌ وَإِنَّ ذَمِّي شَيْنٌ فَقَالَ ذَاكُمْ اللَّهُ عَزَّ وَجَلَّكَمَا حَدَّثَ أَبُو سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي سَلَمَةَ عَنْ الْأَقْرَعِ بْنِ حَابِسٍ وَقَالَ مَرَّةً إِنَّ الْأَقْرَعَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Affan] dia berkata, telah menceritakan kepada kami [Wuhaib] dia berkata, telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Abu Salamah bin 'Abdurrahman] dari [Aqra' bin Habis] bahwa dia menyeru Rasulullah shallallahu 'alaihi wasallam dari balik kamar, dia berkata, \"Wahai Muhammad, sesungguhnya pujianku adalah hiasan, dan celaan terhadapku adalah aib.\" Maka beliau pun bersabda: \"Semoga Allah 'azza wajalla menghinakanmu, \" sebagaimana yang telah diceritakan oleh Abu Salamah dari Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami ['Abdul A'la bin Hammad] dia berkata, telah menceritakan kepada kami [Wuhaib] dari [Musa bin 'Uqbah] dari [Abu Salamah] dari [Al Aqra' bin Habis] dan dia berkata dikali yang lain, 'Sesungguhnya Al Aqra'…kemudian dia menyebutkan hadits yang semisal.\""},"4025":{"ar":"حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَدِيِّ بْنِ ثَابِتٍ الْأَنْصَارِيِّ عَنْ سُلَيْمَانَ بْنِ صُرَدٍسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَيْنِ وَهُمَا يَتَقَاوَلَانِ وَأَحَدُهُمَا قَدْ غَضِبَ وَاشْتَدَّ غَضَبُهُ وَهُوَ يَقُولُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ كَلِمَةً لَوْ قَالَهَا ذَهَبَ عَنْهُ الشَّيْطَانُ قَالَ فَأَتَاهُ رَجُلٌ فَقَالَ قُلْ أَعُوذُ بِاللَّهِ مِنْ الشَّيْطَانِ الرَّجِيمِ قَالَ هَلْ تَرَى بَأْسًا قَالَ مَا زَادَهُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Hafsh bin Ghiyats] dia berkata, telah menceritakan kepada kami [Al A'masy] dari ['Adi bin Tsabit Al Anshari] dari [Sulaiman bin Shurd] bahwa Nabi shallallahu 'alaihi wasallam mendengar dua orang yang beradu mulut, seorang di antara mereka telah memuncak amarahnya seraya mengatakan sesuatu, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku mengetahui satu kalimat yang jika dikatakan maka setan akan pergi darinya.\" Sulaiman berkata, \"Lalu datanglah seorang laki-laki kepada beliau, lantas beliau berkata: \"Ucapkanlah 'A'uudzubillahi minasy Syaithaanirrajiim (Aku berlindung kepada Allah dari godaan setan yang terkutuk) '.\" Laki-laki itu berkata, \"Apakah tuan melihat sesuatu (aib)?\" Beliau menjawab: \"Apa yang lebih dari itu.\""},"4026":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَاقَ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ صُرَدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ الْآنَ نَغْزُوهُمْ وَلَا يَغْزُونَا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dia berkata, telah menceritakan kepadaku [Abu Ishaq] dia berkata, aku mendengar [Sulaiman bin Shurd] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Ahzab: \"Sekarang kita yang akan memerangi mereka, bukan mereka.\""},"4027":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَيْسَرَةَ أَبُو لَيْلَى عَنْ أَبِي عُكَّاشَةَ الْهَمْدَانِيِّ قَالَ قَالَ رِفَاعَةُ الْبَجَلِيُّدَخَلْتُ عَلَى الْمُخْتَارِ بْنِ أَبِي عُبَيْدٍ قَصْرَهُ فَسَمِعْتُهُ يَقُولُ مَا قَامَ جِبْرِيلُ إِلَّا مِنْ عِنْدِي قَبْلُ قَالَ فَهَمَمْتُ أَنْ أَضْرِبَ عُنُقَهُ فَذَكَرْتُ حَدِيثًا حَدَّثَنَاهُ سُلَيْمَانُ بْنُ صُرَدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا أَمَّنَكَ الرَّجُلُ عَلَى دَمِهِ فَلَا تَقْتُلْهُ قَالَ وَكَانَ قَدْ أَمَّنَنِي عَلَى دَمِهِ فَكَرِهْتُ دَمَهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami ['Abdullah bin Maisarah Abu Laila] dari [Abu 'Ukasah Al Hamdani] dia berkata, [Rifa'ah Al Bajli] berkata, \"Aku menemui Mukhtar bin Abu Ubaid di istananya, aku mendengarnya berkata, \"Tidaklah Jibril berdiri kecuali dia sebelumnya berada di sampingku.\" Rifa'ah berkata, \"Sungguh, aku ingin menebas lehernya, namun aku ingat hadits yang dikatakan [Sulaiman bin Shurd] kepada kami, dari Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam: \"Jika seseorang memberimu keamanan maka janganlah kamu bunuhnya, \" dan dia telah memberiku keamanan dengan jaminan darahnya, maka aku tidak ingin menumpahkan darahnya.\""},"4028":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ وَسُرَيْجُ بْنُ النُّعْمَانِ قَالَا حَدَّثَنَا خَلَفٌ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي","id":"Telah menceritakan kepada kami [Husain bin Muhammad] dan [Suraij bin Nu'man] keduanya berkata, telah menceritakan kepada kami [Khalaf] dari [Abu Malik Al Asyja'i] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihatku dalam mimpi, sungguh ia telah melihatku.\""},"4029":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا خَلَفٌ عَنْ أَبِي مَالِكٍ قَالَكَانَ أَبِي قَدْ صَلَّى خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ سِتَّ عَشْرَةَ سَنَةً وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ فَقُلْتُ لَهُ أَكَانُوا يَقْنُتُونَ قَالَ لَا أَيْ بُنَيَّ مُحْدَثٌ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Khalaf] dari [Abu Malik] dia berkata, \"Ayahku dulu shalat di balakang Rasulullah shallallahu 'alaihi wasallam -saat masih berumut enam belas tahun-, bersama Abu Bakar, 'Umar dan Utsman. Aku lalu bertanya kepadanya, \"Apakah mereka melakukan qunut?\" Dia menjawab, \"Wahai anakku, itu adalah perkara yang diada-adakan.\""},"4030":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا أَبُو مَالِكٍ قَالَكَانَ أَبِي قَدْ صَلَّى خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ سِتَّ عَشْرَةَ سَنَةً وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ فَقُلْتُ لَهُ أَكَانُوا يَقْنُتُونَ قَالَ لَا أَيْ بُنَيَّ مُحْدَثٌ","id":"Telah menceritakan kepada kami [Yazid] dia berkata, telah menceritakan kepada kami [Abu Malik] dia berkata, \" [Ayahku] dulu shalat di balakang Rasulullah shallallahu 'alaihi wasallam -saat masih berumut enam belas tahun-, bersama Abu Bakar, 'Umar dan Utsman. Aku lalu bertanya kepadanya, \"Apakah mereka melakukan qunut?\" Dia menjawab, \"Wahai anakku, itu adalah perkara yang diada-adakan.\""},"4031":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا أَبُو مَالِكٍ قَالَ حَدَّثَنِي أَبِي أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا أَتَاهُ الْإِنْسَانُ يَسْأَلُهُ قَالَ يَا نَبِيَّ اللَّهِ كَيْفَ أَقُولُ حِينَ أَسْأَلُ رَبِّي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاهْدِنِي وَارْزُقْنِي وَقَبَضَ كَفَّهُ إِلَّا الْإِبْهَامَ وَقَالَ هَؤُلَاءِ يَجْمَعْنَ لَكَ خَيْرَ دُنْيَاكَ وَآخِرَتِكَ قَالَ وَسَمِعْتُهُ يَقُولُ لِلْقَوْمِ مَنْ وَحَّدَ اللَّهَ وَكَفَرَ بِمَا يُعْبَدُ مِنْ دُونِهِ حُرِّمَ مَالُهُ وَدَمُهُ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yazid] berkata, telah menceritakan kepada kami [Abu Malik] berkata, telah menceritakan kepadaku [ayahku], bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, yakni ketika seseorang datang kepada beliau dan bertanya, \"Wahai Nabi Allah, apa yang harus aku ucapakan jika aku meminta kepada Rabbku?\" Beliau menjawab: \"Ucapkanlah 'ALLAHUMMAGHFIRLII WAR HAMNII WAH DINII WARZUQNII (Ya Allah, ampunilah aku, rahmatilah aku, tunjukilah aku dan berilah aku rizqi) ', kemudian beliau menggenggamkan telapak tangannya kecuali ibu jari, lalu beliau bersabda: \"Semua itu akan terkumpul padamu kebaikan dunia dan akhiratmu.\" Bapakku berkata, \"Aku juga mendengar beliau bersabda terhadap suatu kaum: \"Barangsiapa mengesakan Allah dan mengingkari peribadatan selain-Nya maka harta dan darahnya menjadi haram, sedangkan hisabnya atas Allah Azza Wa Jalla.\""},"4032":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ قَالَ حَدَّثَنِي أَبِي قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ وَحَّدَ اللَّهَ وَكَفَرَ بِمَا يُعْبَدُ مِنْ دُونِهِ حَرَّمَ اللَّهُ مَالَهُ وَدَمَهُ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] dia berkata, telah menceritakan kepada kami [Abu Malik Al Asyja'i] dia berkata, telah menceritakan kepadaku [ayahku] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengesakan Allah dan mengingkari selain apa yang diibadahinya (Allah), maka Allah mengharamkan harta dan darahnya, sedangkan hisabnya atas Allah Azza Wa Jalla.\""},"4033":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ سَمِعْتُ الْأَعْمَشَ يَرْوِي عَنْ شَقِيقٍ عَنْ خَبَّابٍ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمِنَّا مَنْ مَاتَ وَلَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ لَمْ يَتْرُكْ إِلَّا نَمِرَةً إِذَا غَطَّوْا بِهَا رَأْسَهُ بَدَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَهُ بَدَا رَأْسُهُ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطُّوا رَأْسَهُ وَجَعَلْنَا عَلَى رِجْلَيْهِ إِذْخِرًا قَالَ وَمِنَّا مَنْ أَيْنَعَ الثِّمَارَ فَهُوَ يَهْدِبُهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Idris] dia berkata, aku mendengar [Al A'masy] menceritakan dari [Syaqiq] dari [Khabbab] dia berkata, \"Kami hijrah bersama Rasululah shallallahu 'alaihi wasallam, maka di antara kami ada yang meninggal sebelum menerima hasilnya, di antaranya adalah Mush'ab bin 'Umair. Saat wafat dia tidak meninggalkan kecuali selembar kain, jika orang-orang menutupi kepalanya maka kakinya tersingkap, dan jika kami menutupi kakinya maka kepalanya terbuka, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada kami: \"Tutupilah kepalanya, \" kemudian kami menjadikan idzhir (sejenis tumbuhan) untuk menutupi kakinya.\" Khabbab berkata, \"Di antara kami ada juga yang memanen dan menikmati hasilnya.\""},"4034":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ قَالَقُلْنَا لِخَبَّابٍ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قَالَ فَقُلْنَا بِأَيِّ شَيْءٍ كُنْتُمْ تَعْرِفُونَ ذَلِكَ قَالَ فَقَالَ بِاضْطِرَابِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dia berkata, \"Kami bertanya kepada [Khabbab], apakah Rasulullah shallallahu 'alaihi wasallam pernah membaca (surat) pada waktu shalat zhuhur dan ashar? Dia menjawab, \"Ya.\" Ma'mar berkata, \"Maka kami berkata, \"Dengan apa kalian mengetahuinya?\" Dia menjawab, \"Dengan bergetarnya jenggot beliau.\""},"4035":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنَا قَيْسٌ قَالَأَتَيْتُ خَبَّابًا أَعُودُهُ وَقَدْ اكْتَوَى سَبْعًا فِي بَطْنِهِ فَسَمِعْتُهُ يَقُولُ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il] dia berkata, telah menceritakan kepada kami [Qais] dia berkata, \"Aku datang menjenguk [Khabbab], sungguh di perutnya terdapat tujuh bekas luka, kemudian aku mendengar dia berkata, \"Seandainya Rasulullah shallallahu 'alaihi wasallam tidak melarang berdo'a meminta kamatian, niscaya aku akan berdoa minta kematian.\""},"4036":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنَا قَيْسٌ عَنْ خَبَّابٍ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَوَسِّدٌ بُرْدَةً فِي ظِلِّ الْكَعْبَةِ فَقُلْنَا أَلَا تَسْتَنْصِرُ لَنَا اللَّهَ عَزَّ وَجَلَّ أَوْ أَلَا يَعْنِي تَسْتَنْصِرُ لَنَا فَقَالَ قَدْ كَانَ الرَّجُلُ فِيمَنْ كَانَ قَبْلَكُمْ يُؤْخَذُ فَيُحْفَرُ لَهُ فِي الْأَرْضِ فَيُجَاءُ بِالْمِيشَارِ فَيُوضَعُ عَلَى رَأْسِهِ فَيُجْعَلُ بِنِصْفَيْنِ فَمَا يَصُدُّهُ ذَلِكَ عَنْ دِينِهِ وَيُمْشَطُ بِأَمْشَاطِ الْحَدِيدِ مَا دُونَ عَظْمِهِ مِنْ لَحْمٍ أَوْ عَصَبٍ فَمَا يَصُدُّهُ ذَلِكَ عَنْ دِينِهِ وَاللَّهِ لَيُتِمَّنَّ اللَّهُ هَذَا الْأَمْرَ حَتَّى يَسِيرَ الرَّاكِبُ مِنْ الْمَدِينَةِ إِلَى حَضْرَمَوْتَ لَا يَخَافُ إِلَّا اللَّهَ عَزَّ وَجَلَّ وَالذِّئْبَ عَلَى غَنَمِهِ وَلَكِنَّكُمْ تَسْتَعْجِلُونَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il] dia berkata, telah menceritakan kepada kami [Qais] dari [Khabbab] dia berkata, \"Kami mengadu kepada Rasulullah shallallahu 'alaihi wasallam yang sedang duduk beralaskan kain burdah di bawah naungan Ka'bah, kami katakan, \"Tidakkah tuan mintakan pertolongan kepada Allah Azza wa Jalla, atau tidakkah tuan minta pertolongan untuk kami?\" Beliau menjawab: \"Sungguh, telah ada seseorang dari kaum sebelum kalian yang ditangkap lalu dikubur dalam tanah, lalu didatangkan kepadanya gergaji di atas kepalanya, ia pun dibelah menjadi dua, dan itu tidak menjadikannya keluar dari agamanya. Dan ada yang di sisir kulitnya dengan besi hingga tinggal tulangnya, dan itu tidak menjadikannya keluar dari agama Allah, demi Allah, sesungguhnya Allah akan menyempurnakan perkara ini hingga seorang penunggang berjalan dari Madinah menuju ke Hadramaut, ia tidak takut kecuali hanya kepada Allah Azza wa Jalla, dan tidak mengkawatirkan kambingnya akan dimakan serigala, kalian adalah kaum yang tergesa-gesa.\""},"4037":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا أَبُو يُونُسَ الْقُشَيْرِيُّ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابِ بْنِ الْأَرَتِّ قَالَ حَدَّثَنِي أَبِي خَبَّابُ بْنُ الْأَرَتِّ قَالَإِنَّا لَقُعُودٌ عَلَى بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَنْتَظِرُ أَنْ يَخْرُجَ لِصَلَاةِ الظُّهْرِ إِذْ خَرَجَ عَلَيْنَا فَقَالَ اسْمَعُوا فَقُلْنَا سَمِعْنَا ثُمَّ قَالَ اسْمَعُوا فَقُلْنَا سَمِعْنَا فَقَالَ إِنَّهُ سَيَكُونُ عَلَيْكُمْ أُمَرَاءُ فَلَا تُعِينُوهُمْ عَلَى ظُلْمِهِمْ وَلَا تُصَدِّقُوهُمْ بِكَذِبِهِمْ فَإِنَّ مَنْ أَعَانَهُمْ عَلَى ظُلْمِهِمْ وَصَدَّقَهُمْ بِكَذِبِهِمْ فَلَنْ يَرِدَ عَلَيَّ الْحَوْضَ","id":"Telah menceritakan kepada kami [Rauh] dia berkata, telah menceritakan kepada kami [Abu Yunus Al Qusyairy] dari [Simak bin Harb] dari ['Abdullah bin Khabbab bin Al Art] dia berkata, telah menceritakan kepadaku ayahku [Khabbab bin Al Art] dia berkata, \"Sungguh, saat itu kami sedang duduk-duduk depan pintu Rasulullah Shollallahu 'alaihi wa Sallam, menunggu beliau keluar untuk melaksanakan shalat zhuhur, tatkala beliau keluar beliau bersabda: \"Dengarkanlah.\" Maka kami menjawab, \"Kami mendengar.\" Kemudian beliau bersabda: \"Dengarkanlah.\" Maka kami berkata, \"Kami mendengar.\" Kemudian beliau bersabda: \"Sesungguhnya akan datang pemimpin atas kalian, maka janganlah kalian membantu kezhalimannya dan jangan pula kalian membenarkan kedustaannya, maka barangsiapa membantu akan kezhalimannya dan membenarkan atas kedustaannya, sungguh dia tidak akan minum dari telagaku.\""},"4038":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ قَالَدَخَلْتُ عَلَى خَبَّابٍ وَقَدْ اكْتَوَى سَبْعًا فَقَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَمَنَّ أَحَدُكُمْ الْمَوْتَ لَتَمَنَّيْتُهُ وَلَقَدْ رَأَيْتُنِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَمْلِكُ دِرْهَمًا وَإِنَّ فِي جَانِبِ بَيْتِي الْآنَ لَأَرْبَعِينَ أَلْفَ دِرْهَمٍ قَالَ ثُمَّ أُتِيَ بِكَفَنِهِ فَلَمَّا رَآهُ بَكَى وَقَالَ لَكِنَّ حَمْزَةَ لَمْ يُوجَدْ لَهُ كَفَنٌ إِلَّا بُرْدَةٌ مَلْحَاءُ إِذَا جُعِلَتْ عَلَى رَأْسِهِ قَلَصَتْ عَنْ قَدَمَيْهِ وَإِذَا جُعِلَتْ عَلَى قَدَمَيْهِ قَلَصَتْ عَنْ رَأْسِهِ حَتَّى مُدَّتْ عَلَى رَأْسِهِ وَجُعِلَ عَلَى قَدَمَيْهِ الْإِذْخِرُ","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Haritsah bin Mudlarrib] dia berkata, \"Aku menemui [Khabbab], sementara pada tubuhnya ada tujuh bekas luka, kemudian dia berkata, \"Kalau seandainya aku tidak pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berangan-angan untuk mati, \" niscaya aku akan berangan-angan untuk mati, sungguh aku pernah bersama Rasulullah shallallahu 'alaihi wasallam tidak memiliki sepeserpun dari uang dirham, adapun sekarang, di samping rumahku telah terdapat empat puluh ribu dirham.\" Haritsah berkata, \"Kemudian kain kafannya diberikan kepadanya, saat melihat kafan tersebut, dia langsung meneteskan aiar mata seraya berkata, 'Sungguh, Hamzah tidak mendapatkan kain kafan melainkan kain burdah, jika digunakan menutupi kepala maka kakinya akan tersingkap, dan jika digunakan untuk menutupi kaki maka kepalanya akan tersingkap, sehingga kepalanya yang ditutup sementara kakinya ditutupi dengan daun idzhir.\""},"4039":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ عُمَرَ بْنِ نَبْهَانَ عَنْ أَبِي ثَعْلَبَةَ الْأَشْجَعِيِّ قَالَقُلْتُ مَاتَ لِي يَا رَسُولَ اللَّهِ وَلَدَانِ فِي الْإِسْلَامِ فَقَالَ مَنْ مَاتَ لَهُ وَلَدَانِ فِي الْإِسْلَامِ أَدْخَلَهُ اللَّهُ عَزَّ وَجَلَّ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ إِيَّاهُمَا قَالَ فَلَمَّا كَانَ بَعْدَ ذَلِكَ لَقِيَنِي أَبُو هُرَيْرَةَ قَالَ فَقَالَ أَنْتَ الَّذِي قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْوَلَدَيْنِ مَا قَالَ قُلْتُ نَعَمْ قَالَ فَقَالَ لَئِنْ قَالَهُ لِي أَحَبُّ إِلَيَّ مِمَّا غُلِّقَتْ عَلَيْهِ حِمْصُ وَفِلَسْطِينُ","id":"Telah menceritakan kepada kami [Hammad bin Mas'adah] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Zubair] dari ['Umar bin Nabhan] dari [Abu Tsa'labah Al Asyja'i] berkata, \"Aku berkata, \"Wahai Rasulullah, dua anakku meninggal dalam keadaan Islam?\" Beliau bersabda: \"Barangsiapa ditinggal mati oleh dua orang anaknya dalam keadaan Islam, maka Allah Azza wa Jalla akan memasukkannya ke dalam surga berkat karunia dan rahmat-Nya kepada keduanya.\" Abu Tsa'labah berkata, \"Setelah kejadian itu, Abu Hurairah menemuiku seraya berkata, \"Apakah kamu orang yang disabdakan oleh Rasulullah shallallahu 'alaihi wasallam tentang dua anak yang meninggal dalam Islam?\" Aku menjawab, \"Ya.\" Abu Tsa'labah berkata, \"Lalu Abu Hurairah berkata, \"Jika yang beliau sabdakan itu adalah untukku, maka itu lebih aku sukai daripada negeri Himso dan Palestina yang tidak ia peroleh.\""},"4040":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ طَارِقِ بْنِ عَبْدِ اللَّهِ الْمُحَارِبِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتَ فَلَا تَبْصُقْ عَنْ يَمِينِكَ وَلَا بَيْنَ يَدَيْكَ وَابْصُقْ خَلْفَكَ وَعَنْ شِمَالِكَ إِنْ كَانَ فَارِغًا وَإِلَّا فَهَكَذَا وَذَلِكَ تَحْتَ قَدَمِهِ وَلَمْ يَقُلْ وَكِيعٌ وَلَا عَبْدُ الرَّزَّاقِ وَابْصُقْ خَلْفَكَ وَقَالَا قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari [Manshur] dari [Rab'i] dari [Thariq bin 'Abdullah Al Muharibi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu shalat maka janganlah kamu meludah ke sebelah kanan atau depanmu, namun meludahlah ke belakangmu atau ke kirimu jika keadaannya kosong, jika tidak bisa, maka seperti ini, \" yaitu di bawah kakinya.\" Waqi' dan 'Abdurrazaq tidak menyebutkan, \"Namun meludahlah ke belakangmu, \" mereka berdua menyebutkan, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku.\""},"4041":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ رِبْعِيَّ بْنَ حِرَاشٍ عَنْ طَارِقِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا صَلَّيْتَ فَلَا تَبْصُقْ بَيْنَ يَدَيْكَ وَلَا عَنْ يَمِينِكَ وَلَكِنْ ابْصُقْ تِلْقَاءَ شِمَالِكَ إِنْ كَانَ فَارِغًا وَإِلَّا فَتَحْتَ قَدَمَيْكَ وَادْلُكْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Manshur] berkata, aku mendengar [Rib'I bin Hirasi] dari [Thariq bin 'Abdullah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Jika kalian sedang shalat maka janganlah meludah ke arah depan atau sampaing kananmu, tetapi meludahlah ke arah kiri jika kosong, bila tidak maka meludahlah ke bawah kakimu, lalu timbunlah.\""},"4042":{"ar":"حَدَّثَنَا عُبَيْدَةُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ طَارِقِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبْصُقْ أَمَامَكَ وَلَا عَنْ يَمِينِكَ وَلَكِنْ مِنْ تِلْقَاءِ شِمَالِكَ أَوْ تَحْتَ قَدَمِكَ ثُمَّ ادْلُكْهُ","id":"Telah menceritakan kepada kami ['Ubaidah bin Humaid] berkata, telah menceritakan kepadaku [Manshur] dari [Rib'I bin Hirasi] dari [Thariq bin 'Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu meludah ke arah depanmu atau kananmu, tetapi meludahlah ke arah kirimu atau bawah kakimu, kemudian timbunlah.\""},"4043":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ أَبِي وَهْبٍ الْخَوْلَانِيِّ عَنْ رَجُلٍ قَدْ سَمَّاهُ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلْتُ رَبِّي عَزَّ وَجَلَّ أَرْبَعًا فَأَعْطَانِي ثَلَاثًا وَمَنَعَنِي وَاحِدَةً سَأَلْتُ اللَّهَ عَزَّ وَجَلَّ أَنْ لَا يَجْمَعَ أُمَّتِي عَلَى ضَلَالَةٍ فَأَعْطَانِيهَا وَسَأَلْتُ اللَّهَ عَزَّ وَجَلَّ أَنْ لَا يُهْلِكَهُمْ بِالسِّنِينَ كَمَا أَهْلَكَ الْأُمَمَ قَبْلَهُمْ فَأَعْطَانِيهَا وَسَأَلْتُ اللَّهَ عَزَّ وَجَلَّ أَنْ لَا يَلْبِسَهُمْ شِيَعًا وَيُذِيقَ بَعْضَهُمْ بَأْسَ بَعْضٍ فَمَنَعَنِيهَا","id":"Telah menceritakan kepada kami [Yunus] dia berkata, telah menceritakan kepada kami [Laits] dari [Abu Wahb Al Khaulani] dari [seorang laki-laki] yang ia sebutkan namanya, dari [Abu Bashrah Al Ghifari] seorang sahabat Rasulullah shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku meminta kepada Rabbku Azza wa Jalla empat perkara, lalu Dia memberiku tiga perkara dan menolak satu perkara; aku meminta kepada Rabbku agar umatku tidak bersepakat atas kesesatan lalu Dia mengabulkannya, lalu aku meminta Allah Azza wa Jalla agar tidak membinasakan kalian dengan paceklik sebagaimana dibinasakannya umat sebelum kalian lalu Dia mengabulkannya, dan aku meminta Allah Azza wa Jalla agar tidak menjadikan mereka bergolong-golongan dan sebagian mereka memerangi sebagian yang lain, namuan Dia menolaknya.\""},"4044":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ حَبِيبٍ عَنْ خَيْرِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ السَّبَائِيِّ وَكَانَ ثِقَةً عَنْ أَبِي تَمِيمٍ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعَصْرِ فَلَمَّا انْصَرَفَ قَالَ إِنَّ هَذِهِ الصَّلَاةَ عُرِضَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَتَوَانَوْا فِيهَا وَتَرَكُوهَا فَمَنْ صَلَّاهَا مِنْكُمْ ضُعِّفَ لَهُ أَجْرُهَا ضِعْفَيْنِ وَلَا صَلَاةَ بَعْدَهَا حَتَّى يُرَى الشَّاهِدُ وَالشَّاهِدُ النَّجْمُ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Yazid bin Habib] dari [Khair bin Nu'aim Al Hadlrami] dari ['Abdullah bin Hubairah As Saba'i] dia adalah seorang yang tsiqah, dari [Abu Tamim] dari [Abu Bashrah Al Ghifari] dia berkata, Rasulullah shallallahu 'alaihi wasallam shalat Ashar bersama kami, ketika beliau beranjak, beliau bersabda: \"Sesungguhnya shalat ini telah dipaparkan pada umat sebelum kalian lalu mereka lalai dan meninggalkannya, maka barangsiapa diantara kalian yang melakukan shalat itu, ia akan dilipatkan pahalanya dua kali lipat, dan tidak ada shalat setelahnya hingga terlihat syahid, syahid itu adalah bintang.\""},"4045":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا هَاجَرْتُ وَذَلِكَ قَبْلَ أَنْ أُسْلِمَ فَحَلَبَ لِي شُوَيْهَةً كَانَ يَحْتَلِبُهَا لِأَهْلِهِ فَشَرِبْتُهَا فَلَمَّا أَصْبَحْتُ أَسْلَمْتُ وَقَالَ عِيَالُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيتُ اللَّيْلَةَ كَمَا بِتْنَا الْبَارِحَةَ جِيَاعًا فَحَلَبَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً فَشَرِبْتُهَا وَرَوِيتُ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَوِيتَ فَقُلْتُ يَا رَسُولَ اللَّهِ قَدْ رَوِيتُ مَا شَبِعْتُ وَلَا رَوِيتُ قَبْلَ الْيَوْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْكَافِرَ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ وَالْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] dari ['Abdullah bin Hubairah] dari [Abu Tamim Al Jaisyani] dari [Abu Bashrah Al Ghifari] dia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam ketika berhijrah, dan itu terjadi sebelum aku masuk Islam, kemudian beliau memerah untukku susu seekor kambing, yang beliau sering memerah susunya untuk keluarga beliau, lalu aku meminumnya. Pada pagi harinya aku masuk Islam, para keluarga Nabi shallallahu 'alaihi wasallam berkata, 'Malam ini kami akan bermalam seperti tadi malam dengan kehausan', kemudian Rasulullah shallallahu 'alaihi wasallam memerah untukku susu seekor kambing, lalu aku meminumnya sampai aku merasa kenyang, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Apakah kamu sudah kenyang?\" Aku menjawab, 'Sudah wahai Rasulullah, aku sudah kenyang, dan aku tidak pernah merasa kenyang sebelum hari ini.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Sesungguhnya orang kafir itu makan dengan tujuh usus sedangkan orang mukmin makan dengan satu usus.\""},"4046":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَادٍ مِنْ أَوْدِيَتِهِمْ يُقَالُ لَهُ الْمُخَمَّصُ صَلَاةَ الْعَصْرِ فَقَالَ إِنَّ هَذِهِ الصَّلَاةَ صَلَاةَ الْعَصْرِ عُرِضَتْ عَلَى الَّذِينَ مِنْ قَبْلِكُمْ فَضَيَّعُوهَا أَلَا وَمَنْ صَلَّاهَا ضُعِّفَ لَهُ أَجْرُهُ مَرَّتَيْنِ أَلَا وَلَا صَلَاةَ بَعْدَهَا حَتَّى تَرَوْا الشَّاهِدَقُلْتُ لِابْنِ لَهِيعَةَ مَا الشَّاهِدُ قَالَ الْكَوْكَبُ الْأَعْرَابُ يُسَمُّونَ الْكَوْكَبَ شَاهِدَ اللَّيْلِ حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنِي لَيْثُ بْنُ سَعْدٍ عَنْ خَيْرِ بْنِ نُعَيْمٍ عَنْ عَبْدِ اللَّهِ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] dari ['Abdullah bin Hubairah] dari [Abu Tamim] dari [Abu Bashrah Al Ghifari] dia berkata, \"Kami shalat Ashar bersama Rasulullah shallallahu 'alaihi wasallam di suatu lembah dari lembah-lembah milik mereka yang dinamakan dengan lembah Al Mukhammash, kemudian beliau bersabda: \"Sesungguhnya shalat ini adalah shalat ashar yang disodorkan pada umat sebelum kalian, lalu mereka lalai dan meninggalkannya, maka barangsiapa di antara kalian melakukan shalat itu, maka akan dilipatkan pahalanya dua kali lipat, dan tidak ada shalat setelahnya hingga kalian melihat syahid.\" Aku bertanya kepada Ibnu Lahi'ah, \"Apa yang dimaksud dengan syahid?\" Dia menjawab, \"Bintang-bintang, orang-orang arab badui menamakannya dengan saksi (bukti) malam.\" Telah menceritakan kepada kami [Yahya bin Ishaq] berkata, telah mengabarkan kepadaku [Laits bin Sa'd] dari [Khair bin Nua'im] dari ['Abdullah] dari [Abu Tamim Al Jaisyani] dari [Abu Bashrah Al Ghifari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami…lalu dia menyebutkan hadits tersebut.\""},"4047":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ هُبَيْرَةَ قَالَ سَمِعْتُ أَبَا تَمِيمٍ الْجَيْشَانِيَّ يَقُولُ سَمِعْتُ عَمْرَو بْنَ الْعَاصِ يَقُولُ أَخْبَرَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ زَادَكُمْ صَلَاةً فَصَلُّوهَا فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى صَلَاةِ الصُّبْحِ الْوَتْرُ الْوَتْرُ أَلَا وَإِنَّهُ أَبُو بَصْرَةَ الْغِفَارِيُّ قَالَ أَبُو تَمِيمٍ فَكُنْتُ أَنَا وَأَبُو ذَرٍّ قَاعِدَيْنِ قَالَ فَأَخَذَ بِيَدِي أَبُو ذَرٍّ فَانْطَلَقْنَا إِلَى أَبِي بَصْرَةَ فَوَجَدْنَاهُ عِنْدَ الْبَابِ الَّذِي يَلِي دَارَ عَمْرِو بْنِ الْعَاصِ فَقَالَ أَبُو ذَرٍّ يَا أَبَا بَصْرَةَ آنْتَ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ زَادَكُمْ صَلَاةً صَلُّوهَا فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى صَلَاةِ الصُّبْحِ الْوَتْرُ الْوَتْرُ قَالَ نَعَمْ قَالَ أَنْتَ سَمِعْتَهُ قَالَ نَعَمْ قَالَ أَنْتَ سَمِعْتَهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Ibnu Lahi'ah] telah mengabarkan kepada kami ['Abdullah bin Hubairah] berkata, aku mendengar [Abu Tamim Al Jaisyani] berkata, aku mendengar ['Amru bin 'Ash] berkata, telah mengabarkan kepadaku salah seorang sahabat Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Azza Wa Jalla menambah shalat terhadap kalian, maka laksanakanlah ia antara shalat isya' dan shalat shubuh, yaitu shalat witir, shalat witir.\" Dan hanyasanya dia adalah [Abu Bashrah Al Ghifari], Abu Tamim berkata, \"Aku bersama Abu Dzar sedang duduk-duduk. Abu Dzar lantas menggandeng tanganku, kemudian kami pergi menemui Abu Bashrah, yang saat itu kami mendapatinya sedang berada di samping pintu, depan rumahnya 'Amru bin 'Ash. Abu Dzar lalu berkata, \"Wahai Abu Bashrah, apakah kamu yang mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Azza Wa Jalla menambah shalat terhadap kalian, maka laksanakanlah ia antara shalat isya' dan shalat shubuh, yaitu shalat witir, shalat witir, \" Abu Bashrah menjawab, \"Ya.\" Abu Dzar berkata lagi, \"Apakah kamu mendengar darinya?\" Dia menjawab, \"Ya.\" Abu Dzar berkata lagi, \"Apakah kamu mendengar darinya?\" Dia menjawab, \"Ya.\""},"4048":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَلَقِيتُ أَبَا هُرَيْرَةَ وَهُوَ يَسِيرُ إِلَى مَسْجِدِ الطُّورِ لِيُصَلِّيَ فِيهِ قَالَ فَقُلْتُ لَهُ لَوْ أَدْرَكْتُكَ قَبْلَ أَنْ تَرْتَحِلَ مَا ارْتَحَلْتَ قَالَ فَقَالَ وَلِمَ قَالَ قَالَ فَقُلْتُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ الْمَسْجِدِ الْحَرَامِ وَالْمَسْجِدِ الْأَقْصَى وَمَسْجِدِي","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Martsad bin 'Abdullah Al Yazani] dari [Abu Bashrah Al Ghifari] dia berkata, \"Aku bertemu Abu Hurairah yang sedang berjalan menuju masjid Thuur untuk shalat.\" Abu Bashrah berkata, \"Lalu aku berkata kepadanya, \"Jika aku bertemu denganmu sebelum kamu berangkat, maka kamu tidak akan berangkat.\" Abu Hurairah berkata, \"Memang kenapa?\" Abu Bashrah menjawab, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu memberatkan perjalanan kecuali pada tiga Masjid; masjidil Haram, masjidil Aqsa dan masjidku ini.\""},"4049":{"ar":"حَدَّثَنَا حَجَّاجٌ وَيُونُسُ قَالَا حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ مَنْصُورٍ الْكَلْبِيِّ عَنْ دِحْيَةَ بْنِ خَلِيفَةَ أَنَّهُخَرَجَ مِنْ قَرْيَتِهِ إِلَى قَرِيبٍ مِنْ قَرْيَةِ عُقْبَةَ فِي رَمَضَانَ ثُمَّ أَنَّهُ أَفْطَرَ وَأَفْطَرَ مَعَهُ نَاسٌ وَكَرِهَ آخَرُونَ أَنْ يُفْطِرُوا قَالَ فَلَمَّا رَجَعَ إِلَى قَرْيَتِهِ قَالَ وَاللَّهِ لَقَدْ رَأَيْتُ الْيَوْمَ أَمْرًا مَا كُنْتُ أَظُنُّ أَنْ أَرَاهُ إِنَّ قَوْمًا رَغِبُوا عَنْ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ يَقُولُ ذَلِكَ لِلَّذِينَ صَامُوا ثُمَّ قَالَ عِنْدَ ذَلِكَ اللَّهُمَّ اقْبِضْنِي إِلَيْكَ","id":"Telah menceritakan kepada kami [Hajjaj] dan [Yunus] keduanya berkata, telah menceritakan kepada kami [Laits] berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Manshur Al Kalbi] dari [Dihyah bin Khalifah], bahwa dia keluar dari desanya menuju tempat di dekat desa 'Uqbah pada bulan Ramadan, lalu dia dan orang-orang yang bersamanya berbuka, namun sebagian yang enggan untuk berbuka.\" Manshur berkata, \"Ketika Dihyan kembali ke desanya, dia berkata, \"Demi Allah, sungguh aku telah melihat hari dimana aku tidak pernah melihatnya, sebagian kaum telah membenci petunjuk Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya, \" dia mengatakan hal itu bagi yang berpuasa, lalu dia mengucapkan, \"Ya Allah, genggamkanlah aku kepada-Mu.\""},"4050":{"ar":"حَدَّثَنَا عَتَّابٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ يَزِيدَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ كُلَيْبِ بْنِ ذُهْلٍ عَنْ عُبَيْدِ بْنِ جَبْرٍ قَالَرَكِبْتُ مَعَ أَبِي بَصْرَةَ مِنْ الْفُسْطَاطِ إِلَى الْإِسْكَنْدَرِيَّةِ فِي سَفِينَةٍ فَلَمَّا دَفَعْنَا مِنْ مَرْسَانَا أَمَرَ بِسُفْرَتِهِ فَقُرِّبَتْ ثُمَّ دَعَانِي إِلَى الْغَدَاءِ وَذَلِكَ فِي رَمَضَانَ فَقُلْتُ يَا أَبَا بَصْرَةَ وَاللَّهِ مَا تَغَيَّبَتْ عَنَّا مَنَازِلُنَا بَعْدُ فَقَالَ أَتَرْغَبُ عَنْ سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لَا قَالَ فَكُلْ فَلَمْ نَزَلْ مُفْطِرِينَ حَتَّى بَلَغْنَا مَاحُوزَنَاحَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا الْمُفَضَّلُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَيَّاشٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِ��بٍ عَنْ كُلَيْبِ بْنِ ذُهْلٍ الْحَضْرَمِيِّ عَنْ عُبَيْدِ بْنِ جَبْرٍ قَالَ رَكِبْتُ مَعَ أَبِي بَصْرَةَ السَّفِينَةَ وَهُوَ يُرِيدُ الْإِسْكَنْدَرِيَّةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami ['Attab] berkata, telah menceritakan kepada kami ['Abdullah] berkata, telah menceritakan kepada kami [Sa'id bin Yazid] dari [Yazid bin Abu Habib] dari [Kulaib bin Dzuhl] dari ['Ubaid bin Jabr] berkata, \"Aku pergi bersama [Abu Bashrah] dari Fusthath menuju Iskandariyah dengan mengendarai kapal, ketika kami berlabuh, dia memerintahkan untuk menyiapkan hidangan, lalu ia mendekat dan memanggilku untuk menyantap hidangan tersebut. Waktu itu adalah bulan Ramadan, maka aku berkata kepadanya, 'Wahai Abu Bashrah, demi Allah, rumah-rumah kami masih kelihatan! ' Dia lalu berkata, 'Apakah kamu membenci sunnah Rasulullah shallallahu 'alaihi wasallam? ' Aku menjawab, 'Tidak.' Dia lalu berkata, 'Maka, makanlah'. Dan kami masih dalam keadaan berbuka sampai kami tiba di tempat tujuan kami.\" Telah menceritakan kepada kami [Yahya bin Ghailan] dia berkata, telah menceritakan kepada kami [Mufadlal] dia berkata, telah menceritakan kepada kami [Abdullah bin 'Ayyasy] dari [Yazid bin Abu Habib] dari [Kulaib bin Dzuhl Al Hadlrami] dari [Ubaid bin Jabr] dia berkata, \"Aku berlayar bersama [Abu Bashrah] dengan mengendarai kapal menuju Iskandariyah…kemudian dia menyebutkan hadits ini.\""},"4051":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ يَعْنِي ابْنَ جَعْفَرٍ قَالَ أَخْبَرَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُمْ يَوْمًا إِنِّي رَاكِبٌ إِلَى يَهُودَ فَمَنْ انْطَلَقَ مَعِي فَإِنْ سَلَّمُوا عَلَيْكُمْ فَقُولُوا وَعَلَيْكُمْ فَانْطَلَقْنَا فَلَمَّا جِئْنَاهُمْ وَسَلَّمُوا عَلَيْنَا فَقُلْنَا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari ['Abdul Hamid] -yakni Ibnu Ja'far- berkata, telah mengabarkan kepadaku [Yazid bin Abu Habib] dari [Martsad bin 'Abdullah] dari [Abu Bashrah Al Ghifari] dia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabat: \"Sesungguhnya aku akan menuju ke perkampungan Yahudi, barangsiapa di antara kalian pergi bersamaku, jika mereka mengucapkan salam kepada kalian maka jawablah wa'alaikum.\" Kemudian kami berangkat bersama beliau, ketika kami mendatangi mereka, mereka mengucapkan salam kepada kami lalu kami menjawab wa'alaikum.\""},"4052":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ قَالَ سَمِعْتُ أَبَا بَصْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا غَادُونَ إِلَى يَهُودَ فَلَا تَبْدَءُوهُمْ بِالسَّلَامِ فَإِذَا سَلَّمُوا عَلَيْكُمْ فَقُولُوا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Abu Al Khair] berkata, aku mendengar [Abu Bashrah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kita besok akan mendatangi orang-orang Yahudi, maka janganlah kalian memulai untuk beruluk salam, jika mereka mengucapkan salam kepada kalian, maka jawablah 'wa'alakum'.\""},"4053":{"ar":"حَدَّثَنَا وَكِيعٌ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ قَالَ سَمِعْتُ عَلْقَمَةَ بْنَ وَائِلٍ عَنْ أَبِيهِأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ مِنْ خَثْعَمَ يُقَالُ لَهُ سُوَيْدُ بْنُ طَارِقٍ عَنْ الْخَمْرِ فَنَهَاهُ فَقَالَ إِنَّمَا هُوَ شَيْءٌ نَصْنَعُهُ دَوَاءً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هِيَ دَاءٌ","id":"Telah menceritakan kepada kami [Waki'] dan [Hajjaj] keduanya berkata, telah menceritakan kepada kami [Syu'bah] dari [Simak] dia berkata, aku mendengar ['Alqamah bin Wa'il] dari [ayahnya], bahwa dia menyaksikan Nabi shallallahu 'alaihi wasallam, ditanya oleh seorang laki-laki Khaitsam yang biasa disebut Suwaid bin Thariq, mengenai khamer (minuman keras), kemudian beliau melarangnya. Laki-laki itu kemudian berkata, \"Kami membuatnya hanya sebagai obat, \" maka Nabi shallallahu 'alaihi wasallam bersabda: \"Justru itu adalah penyakit.\""},"4054":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَهُ أَرْضًا قَالَ فَأَرْسَلَ مَعِي مُعَاوِيَةَ أَنْ أَعْطِهَا إِيَّاهُ أَوْ قَالَ أَعْلِمْهَا إِيَّاهُ قَالَ فَقَالَ لِي مُعَاوِيَةُ أَرْدِفْنِي خَلْفَكَ فَقُلْتُ لَا تَكُونُ مِنْ أَرْدَافِ الْمُلُوكِ قَالَ فَقَالَ أَعْطِنِي نَعْلَكَ فَقُلْتُ انْتَعِلْ ظِلَّ النَّاقَةِ قَالَ فَلَمَّا اسْتُخْلِفَ مُعَاوِيَةُ أَتَيْتُهُ فَأَقْعَدَنِي مَعَهُ عَلَى السَّرِيرِ فَذَكَّرَنِي الْحَدِيثَفَقَالَ سِمَاكٌ فَقَالَ وَدِدْتُ أَنِّي كُنْتُ حَمَلْتُهُ بَيْنَ يَدَيَّ","id":"Telah menceritakan kepada kami [Hajjaj] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Simak bin Harb] dari ['Alqamah bin Wa'il] dari [ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam memberikan tanah untuknya. Dia berkata, \"Lalu beliau mengutusku bersama Mu'awiyah untuk memberikan tanah itu padanya, atau dia menyebutkan, \"Beritahukanlah tanah itu kepadanya.\" Wail berkata, \"Mu'awiyah lalu berkata kepadaku, \"Boncengkan aku di belakangmu, \" aku pun menjawab, \"Janganlah kamu menjadi raja yang diboncengkan.\" Wail berkata, \"Mu'awiyah lantas berkata, \"Berikan sandalmu kepadaku, \" lalu aku menjawab, \"Pakailah sandal di bawah naungan unta.\" Wail melanjutkan, \"Ketika Mu'awiyah diangkat menjadi khalifah, aku mendatanginya, lalu dia mendudukkan aku di atas dipan bersamanya. Lalu dia mengingatkan aku sebuah hadits.\" Simak berkata, \"Kemudian dia berkata, \"Sungguh, aku berharap membawanya di hadapanku.\""},"4055":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَخَرَجَتْ امْرَأَةٌ إِلَى الصَّلَاةِ فَلَقِيَهَا رَجُلٌ فَتَجَلَّلَهَا بِثِيَابِهِ فَقَضَى حَاجَتَهُ مِنْهَا وَذَهَبَ وَانْتَهَى إِلَيْهَا رَجُلٌ فَقَالَتْ لَهُ إِنَّ الرَّجُلَ فَعَلَ بِي كَذَا وَكَذَا فَذَهَبَ الرَّجُلُ فِي طَلَبِهِ فَانْتَهَى إِلَيْهَا قَوْمٌ مِنْ الْأَنْصَارِ فَوَقَعُوا عَلَيْهَا فَقَالَتْ لَهُمْ إِنَّ رَجُلًا فَعَلَ بِي كَذَا وَكَذَا فَذَهَبُوا فِي طَلَبِهِ فَجَاءُوا بِالرَّجُلِ الَّذِي ذَهَبَ فِي طَلَبِ الرَّجُلِ الَّذِي وَقَعَ عَلَيْهَا فَذَهَبُوا بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هُوَ هَذَا فَلَمَّا أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجْمِهِ قَالَ الَّذِي وَقَعَ عَلَيْهَا يَا رَسُولَ اللَّهِ أَنَا هُوَ فَقَالَ لِلْمَرْأَةِ اذْهَبِي فَقَدْ غَفَرَ اللَّهُ لَكِ وَقَالَ لِلرَّجُلِ قَوْلًا حَسَنًا فَقِيلَ يَا نَبِيَّ اللَّهِ أَلَا تَرْجُمُهُ فَقَالَ لَقَدْ تَابَ تَوْبَةً لَوْ تَابَهَا أَهْلُ الْمَدِينَةِ لَقُبِلَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Muhamad bin 'Abdullah bin Az Zubair] dia berkata, telah menceritakan kepada kami [Isra'il] dari [Simak] dari ['Alqamah bin Wa'il] dari [ayahnya] dia berkata, \"Seorang wanita keluar untuk mengerjakan shalat, tiba-tiba dia bertemu dengan seorang laki-laki yang kemudian memperkosanya, laki-laki itu kemudian pergi meninggalkan wanita tersebut. Setelah itu ada seorang laki-laki yang mendatangi wanita tersebut, wanita itu lalu berkata, \"Sungguh, seorang laki-laki telah melakukan ini dan itu kepadaku!\" maka laki-laki tersebut pergi untuk mencari laki-laki yang memperkosanya. Kemudian ada sekelompok orang-orang Anshar menemukan wanita tersebut, wanita itu lalu berkata, \"Sungguh, seorang laki-laki telah melakukan ini dan itu kepadaku!\" maka orang-orang Anshar pergi untuk mencari laki-laki yang memperkosanya. Kemudian orang-orang Anshar tersebut (justru) menangkap laki-laki yang mencari laki-laki yang telah memperkosanya, dan membawanya ke hadapan Nabi shallallahu 'alaihi wasallam. Sang wanita lalu berkata, \"Inilah dia!\" Tatkala Nabi shallallahu 'alaihi wasallam memerintahkan untuk merajamnya, maka berkatalah laki-laki yang telah memperkosanya, \"Wahai Rasulullah, yang dimaksud adalah aku!\" Maka beliau berkata kepada si wanita: \"Pergilah sesungguhnya Allah telah mengampunimu.\" Dan beliau bersabda kepada laki-laki dengan perkataan yang baik, maka dikatakan, \"Wahai Nabiyallah, apakah tuan tidak merajamnya?\" Maka beliau bersabda: \"Sesungguhnya dia telah bertaubat dengan taubat yang sekiranya penduduk Madinah bertaubat, niscaya akan diterima dari mereka.\""},"4056":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنِي كَثِيرُ بْنُ كَثِيرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ سَمِعَ بَعْضَ أَهْلِهِ يُحَدِّثُ عَنْ جَدِّهِ أَنَّهُرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِمَّا يَلِي بَابَ بَنِي سَهْمٍ وَالنَّاسُ يَمُرُّونَ بَيْنَ يَدَيْهِ وَلَيْسَ بَيْنَهُ وَبَيْنَ الْكَعْبَةِ سُتْرَةٌ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata, telah menceritakan kepadaku [Katsir bin Katsir bin Al Mutthalib bin Abu Wada'ah] dia pernah mendengar [sebagian keluarganya] menceritakan kepadanya dari [kakeknya] bahwa dia melihat Nabi shallallahu 'alaihi wasallam melakukan shalat di depan gerbang Bani Sahm, dan orang-orang lewat di depan beliau, sedangkan antara beliau dengan Ka'bah tidak ada penghalang.\""},"4057":{"ar":"و قَالَ سُفْيَانُ مَرَّةً أُخْرَى حَدَّثَنِي كَثِيرُ بْنُ كَثِيرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَمَّنْ سَمِعَ جَدَّهُ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِمَّا يَلِي بَابَ بَنِي سَهْمٍ وَالنَّاسُ يَمُرُّونَ بَيْنَ يَدَيْهِ لَيْسَ بَيْنَهُ وَبَيْنَ الْكَعْبَةِ سُتْرَةٌ","id":"Dan sekali waktu [Sufyan] berkata; telah menceritakan kepadaku [Katsir bin Katsir bin Al Mutthalib bin Abu Wada'ah] dari [orang] yang pernah mendengar [kakeknya] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat di sisi pintu Bani Sahm sedangkan manusia lalu lalang di antara kedua tangannya, sementara antara beliau dengan Ka'bah tidak ada penghalang.\""},"4058":{"ar":"قَالَ سُفْيَانُ وَكَانَ ابْنُ جُرَيْجٍ أَخْبَرَنَا عَنْهُ قَالَ حَدَّثَنَا كَثِيرٌ عَنْ أَبِيهِ فَسَأَلْتُهُ فَقَالَ لَيْسَ مِنْ أَبِي سَمِعْتُهُ وَلَكِنْ مِنْ بَعْضِ أَهْلِي عَنْ جَدِّيأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى مِمَّا يَلِي بَابَ بَنِي سَهْمٍ لَيْسَ بَيْنَهُ وَبَيْنَ الطَّوَافِ سُتْرَةٌ","id":"[Sufyan] berkata, Ibnu Juraij mengabarkan kepada kami darinya, dia berkata; telah menceritakan kepada kami [Katsir] dari ayahnya aku bertanya kepadanya, dan dia menjawab, \"Aku tidak mendengar dari ayahku, tapi dari [sebagian keluargaku] dari [kakekku] bahwa Nabi shallallahu 'alaihi wasallam mengerjakan shalat di dekat pintu Bani Sahm, sedangkan antara beliau dengan Thawaf (Ka'bah) tidak ada penghalang.\""},"4059":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي كَثِيرُ بْنُ كَثِيرٍ عَنْ أَبِيهِ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ فَرَغَ مِنْ أُسْبُوعِهِ أَتَى حَاشِيَةَ الطَّوَافِ فَصَلَّى رَكْعَتَيْنِ وَلَيْسَ بَيْنَهُ وَبَيْنَ الطَّوَافِ أَحَدٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Katsir bin Katsir] dari [ayahnya] dari [Al Mutthalib bin Abu Wada'ah] dia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam setelah selesai dari tujuh putaran, beliau menuju sisi Thawaf (Ka'bah) lalu mendirikan shalat dua rakaat, sedangkan antara beliau dengan Thawaf (Ka'bah) tidak ada seseorang (penghalang).\""},"4060":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ فِيهَا وَسَجَدَ مَنْ عِنْدَهُ فَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَوَلَمْ يَكُنْ أَسْلَمَ يَوْمَئِذٍ الْمُطَّلِبُ وَكَانَ بَعْدُ لَا يَسْمَعُ أَحَدًا قَرَأَهَا إِلَّا سَجَدَ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khlaid] dari [Ja'far bin Al Mutthalib bin Abu Wada'ah As Sahmi] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca surat An Najm di Makkah lantas beliau sujud, kemudian orang-orang yang bersama beliau juga ikut sujud, namun aku mengangkat kepalaku dan enggan untuk sujud. Dan Mutthalib pada saat itu belum masuk Islam, akan tetapi setelah itu, tidaklah salah seorang membacanya (surat An Najm) melainkan dia sujud.\""},"4061":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي النَّجْمِ وَسَجَدَ النَّاسُ مَعَهُقَالَ الْمُطَّلِبُ وَلَمْ أَسْجُدْ مَعَهُمْ وَهُوَ يَوْمَئِذٍ مُشْرِكٌ قَالَ الْمُطَّلِبُ وَلَا أَدَعُ السُّجُودَ فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami ['Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Al Mutthalib bin Abu Wada'ah] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam sujud dalam surat An Najm, dan orang-orang ikut bersujud bersama beliau, Al Mutthalib berkata, \"Sedangkan aku tidak sujud bersama mereka, \" dan dia (Al Mutthalib) pada saat itu masih musyrik.\" Al Mutthalib berkata, \"Maka aku tidak lagi meninggalkan sujud di dalam (surat An Najm) selamanya.\""},"4062":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ الْعَدَوِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا خَاطِئٌ","id":"Telah menceritakan kepada kami ['Abdah bin Sulaiman] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim At Taimi] dari [Sa'id bin Musayyab] dari [Ma'mar bin 'Abdullah Al 'Adawi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah mencela kecuali orang yang salah.\""},"4063":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ نَضْلَةَ الْقُرَشِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحْتَكِرُ إِلَّا خَاطِئٌ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim At Taimi] dari [Sa'id bin Musayyab] dari [Ma'mar bin 'Abdullah bin Nadllah Al Qurasyi] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah mencela kecuali orang yang salah.\""},"4064":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ الْمِصْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُقْبَةَ مَوْلَى مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ نَافِعِ بْنِ نَضْلَةَ الْعَدَوِيِّ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ قَالَكُنْتُ أَرْحَلُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ قَالَ فَقَالَ لِي لَيْلَةً مِنْ اللَّيَالِي يَا مَعْمَرُ لَقَدْ وَجَدْتُ اللَّيْلَةَ فِي أَنْسَاعِي اضْطِرَابًا قَالَ فَقُلْتُ أَمَا وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ شَدَدْتُهَا كَمَا كُنْتُ أَشُدُّهَا وَلَكِنَّهُ أَرْخَاهَا مَنْ قَدْ كَانَ نَفَسَ عَلَيَّ لِمَكَانِي مِنْكَ لِتَسْتَبْدِلَ بِي غَيْرِي قَالَ فَقَالَ أَمَا إِنِّي غَيْرُ فَاعِلٍ قَالَ فَلَمَّا نَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدْيَهُ بِمِنًى أَمَرَنِي أَنْ أَحْلِقَهُ قَالَ فَأَخَذْتُ الْمُوسَى فَقُمْتُ عَلَى رَأْسِهِ قَالَ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِي وَقَالَ لِي يَا مَعْمَرُ أَمْكَنَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ شَحْمَةِ أُذُنِهِ وَفِي يَدِكَ الْمُوسَى قَالَ فَقُلْتُ أَمَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّ ذَلِكَ لَمِنْ نِعْمَةِ اللَّهِ عَلَيَّ وَمَنِّهِ قَالَ فَقَالَ أَجَلْ إِذًا أُقِرُّ لَكَ قَالَ ثُمَّ حَلَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Yazid bin Abu Habib Al Mishri] dari ['Abdurrahman bin 'Uqbah] bekas budak Ma'mar bin 'Abdullah bin Nafi' bin Nadllah Al 'Adawi, dari [Ma'mar bin 'Abdullah] dia berkata, \"Aku menemani Rasulullah shallallahu 'alaihi wasallam safar waktu beliau haji wada', pada suatu malam beliau bersabda kepadaku: \"Wahai Ma'mar, sesungguhnya aku telah mendapati malam berjalan dengan kegoncangan, \" Ma'mar berkata, \"Aku berkata, \"Demi yang mengutusmu dengan kebenaran, aku telah terdesak karenanya sebagaimana aku mendesaknya, tapi yang memberiku nafas telah melepaskannya karena melihat kedudukanku terhadapmu, agar tuan menggantikan aku dengan selainku.\" Beliau berkata: \"Aku tidak akan melakukannya.\" Ma'mar berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam menyembelih hadyu (Kurban) di Mina, beliau menyuruhku untuk mencukur rambutnya.\" Ma'mar berkata, \"Lalu aku mengambil pisau dan berdiri di samping kepala beliau. Lalu beliau melihat wajahku dan bersabda kepadaku: \"Wahai Ma'mar, Rasulullah shallallahu 'alaihi wasallam menempatkanmu pada lemak telinganya dan di tanganmu sebilah pisau.\" Ma'mat berkata, \"Aku lalu berkata, \"Demi Allah, ya Rasulullah, sesungguhnya hal itu adalah nikmat dan pemberian dari Allah untukku, \" Ma'mar berkata, \"Beliau lalu bersabda: \"Benar, maka aku memilihmu.\" Ma'mar berkata, \"Kemudian aku mencukur rambut Rasulullah shallallahu 'alaihi wasallam.\""},"4065":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا أَبُو النَّضْرِ أَنَّ بُسْرَ بْنَ سَعِيدٍ حَدَّثَهُ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِأَنَّهُ أَرْسَلَ غُلَامًا لَهُ بِصَاعٍ مِنْ قَمْحٍ فَقَالَ لَهُ بِعْهُ ثُمَّ اشْتَرِ بِهِ شَعِيرًا فَذَهَبَ الْغُلَامُ فَأَخَذَ صَاعًا وَزِيَادَةَ بَعْضِ صَاعٍ فَلَمَّا جَاءَ مَعْمَرًا أَخْبَرَهُ بِذَلِكَ فَقَالَ لَهُ مَعْمَرٌ أَفَعَلْتَ انْطَلِقْ فَرُدَّهُ وَلَا تَأْخُذْ إِلَّا مِثْلًا بِمِثْلٍ فَإِنِّي كُنْتُ أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الطَّعَامُ بِالطَّعَامِ مِثْلًا بِمِثْلٍ وَكَانَ طَعَامُنَا يَوْمَئِذٍ الشَّعِيرَ قِيلَ فَإِنَّهُ لَيْسَ مِثْلَهُ قَالَ إِنِّي أَخَافُ أَنْ يُضَارِعَحَدَّثَنَا هَارُونُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّ أَبَا النَّضْرِ حَدَّثَهُ أَنَّ بُسْرَ بْنَ سَعِيدٍ حَدَّثَهُ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Hasan] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Abu An Nadlr] bahwa [Busra bin Sa'id] telah menceritakan kepadanya dari [Ma'mar bin 'Abdullah] bahwa dia menyuruh pembantunya dengan satu sha' tepung, lalu ia berkata kepadanya, \"Juallah ini, lalu belilah gandum.\" Lalu pembantunya pergi dan mengambil satu sha' lebih, ketika Ma'mar datang, pembantunya mengabarkan hal itu kepadanya. Maka Ma'mar pun berkata kepadanya, 'Apakah kamu melakukannya? ' Pulang dan kembalikan, dan janganlah kamu mengambil kecuali sama timbangannya, karena sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanan dengan makanan sama timbangannya, \" dan makanan kami ketika itu adalah gandum.\" Dikatakan kepadanya, \"Tapi itu bukan seperti itu.\" Ma'mar lalu berkata, \"Sesungguhnya aku takut akan jatuh dalam riba.\" Telah menceritakan kepada kami [Harun] berkata, telah menceritakan kepada kami [Ibnu Wahab] berkata, telah mengabarkan kepadaku ['Amru] bahwa [Abu Nadlr] berkata kepadanya, bahwa [Busr bin Said] berkata kepadanya dari [Ma'mar bin' Abdullah], lalu ia menyebutkan maknanya.\""},"4066":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا عَامِرٌ الْأَحْوَلُ قَالَ حَدَّثَنَا مَكْحُولٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَيْرِيزٍ أَنَّ أَبَا مَحْذُورَةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَّنَهُ الْأَذَانَ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةَ سَبْعَ عَشْرَةَ كَلِمَةً اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ وَالْإِقَامَةُ مَثْنَى مَثْنَى لَا يُرَجِّعُ","id":"Telah menceritakan kepada kami ['Abdus Shamad] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami ['Amir Al Ahwal] berkata, telah menceritakan kepada kami [Makhul] telah menceritakan kepada kami ['Abdullah bin Muhairiz] bahwa [Abu Mahdzurah] berkata kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melafadzkan adzan kepadanya dengan sembilan belas kalimat dan iqamah sebanyak tujuh belas kalimat, yaitu; ALLAHU AKBAR ALLAHU AKBAR, ALLAHUAKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLALLAH ASYHADU AN LAA ILAAHA ILLALLAHU, ASYHADU ANNA MUHAMMADAR RASULULLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH, HAYYA 'ALASH SHALAAH HAYYA 'ALASH SHALAAH, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLALLAH (Allah Maha Besar, Allah Maha Besar. Allah Maha Besar, Allah Maha Besar. Aku bersaksia bahwa tidak tuhan yang berhak untuk disembah selain Allah, Aku bersaksia bahwa tidak ada tuhan yang berhak untuk disembah selain Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah, Aku bersaksi bahwa Muhammad adalah utusan Allah. Mari menuju shalat, Mari menuju shalat. Mari menuju kemenangan, Mari menuju kemenangan. Allah Maha Besar, Allah Maha Besar. Tidah tuhan yang berhak untuk disembah selain Allah) '. Sedangkan iqamah dua-dua, dan tidak diulang.\""},"4067":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا هُذَيْلُ بْنُ بِلَالٍ عَنِ ابْنِ أَبِي مَحْذُورَةَ عَنْ أَبِيهِ أَوْ عَنْ جَدِّهِ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَذَانَ لَنَا وَلِمَوَالِينَا وَالسِّقَايَةَ لِبَنِي هَاشِمٍ وَالْحِجَابَةَ لِبَنِي عَبْدِ الدَّارِ","id":"Telah menceritakan kepada kami [Khalaf bin Walid] berkata, telah menceritakan kepada kami [Hudzail bin Bilal] dari [Ibnu Abu Mahdzurah] dari [ayahnya] atau dari kakeknya dia berkata, \"Rasulullah shallallahu 'alaihi wasallam adzan untuk kami dan budak-budak kami, memberi minum jamaah haji untuk Bani Hasyim, dan bekam untuk Bani Abdul Bar.\""},"4068":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ سُوَيْدَ بْنَ قَيْسٍ أَخْبَرَهُ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمًا فَسَلَّمَ وَانْصَرَفَ وَقَدْ بَقِيَ مِنْ الصَّلَاةِ رَكْعَةٌ فَأَدْرَكَهُ رَجُلٌ فَقَالَ نَسِيتَ مِنْ الصَّلَاةِ رَكْعَةً فَرَجَعَ فَدَخَلَ الْمَسْجِدَ وَأَمَرَ بِلَالًا فَأَقَامَ الصَّلَاةَ فَصَلَّى بِالنَّاسِ رَكْعَةً فَأَخْبَرْتُ بِذَلِكَ النَّاسَ فَقَالُوا لِي أَتَعْرِفُ الرَّجُلَ قُلْتُ لَا إِلَّا أَنْ أَرَاهُ فَمَرَّ بِي فَقُلْتُ هُوَ هَذَا فَقَالُوا طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Hajjaj] berkata, Telah menceritakan kepada kami [Laits] berkata, Telah menceritakan kepadaku [Yazid bin Abu Habib] bahwa [Suwaid bin Qais] telah mengabarkan kepadanya dari [Mu'awiyah bin Khudaij], bahwa pada suatu hari Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat, lalu beliau salam dan beranjak pergi, sementara shalat masih tersisa satu rakaat. Kemudian seseorang menemuinya dan berkata, 'Tuan lupa mengerjakan satu rakaat!, lantas beliau kembali memasuki masjid dan memerintahkan Bilal untuk iqamah, kemudian beliau mengimami shalat satu rakaat. Hal itu kemudian aku kabarkan kepada orang-orang, mereka pun berkata kepadaku, \"Apakah kamu kenal orang yang memberitahu beliau?\" Aku menjawab, 'Tidak, kecuali jika aku melihatnya (maka aku akan ingat).' Lalu seseorang lewat di depanku, aku lantas berkata, 'Itu orangnya! ' kemudian mereka berkata, \"Dia adalah Thalhah bin Ubaidullah Radliyallahu'anhu.\""},"4069":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ غَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Khudaij] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berangkat di pagi dan sore hari untuk berperang di jalan Allah lebih baik daripada dunia dan seisinya.\""},"4070":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ التُّجِيبِيِّ مِنْ كِنْدَةَ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ فِي شَيْءٍ شِفَاءٌ فَفِي شَرْطَةٍ مِنْ مِحْجَمٍ أَوْ شَرْبَةٍ مِنْ عَسَلٍ أَوْ كَيَّةٍ بِنَارٍ تُصِيبُ أَلَمًا وَمَا أُحِبُّ أَنْ أَكْتَوِيَ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] berkata, Telah menceritakan kepada kami [Sa'id bin Abu Ayyub] berkata, Telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Suwaid bin Qais At Tujibi] dari penduduk Kindah, dari [Mu'awiyah bin Khudaij] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dalam sesuatu ada obat, maka sesuatu itu adalah bekam, atau minum madu, atau sengatan dengan api ke bagian yang sakit, dan aku tidak suka untuk melakukan sengatan dengan api.\""},"4071":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ يَزِيدَ عَنْ عَلِيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ حُدَيْجٍ يَقُولُهَاجَرْنَا عَلَى عَهْدِ أَبِي بَكْرٍ فَبَيْنَا نَحْنُ عِنْدَهُ طَلَعَ عَلَى الْمِنْبَرِ","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] berkata, Telah menceritakan kepada kami [Abdullah] berkata, Telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, Telah menceritakan kepadaku [Al Harits bin Yazid] dari [Ali bin Rabah] dia berkata, aku telah mendengar [Mu'awiyah bin Khadij] berkata, \"Kami berhijrah pada masa Abu Bakar, maka ketika kami berada di sisinya dia naik ke atas mimbar.\""},"4072":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ صَالِحٍ أَبِي حُجَيْرٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ قَالَ وَكَانَتْ لَهُ صُحْبَةٌ قَالَمَنْ غَسَّلَ مَيِّتًا وَكَفَّنَهُ وَتَبِعَهُ وَوَلِيَ جُثَّتَهُ رَجَعَ مَغْفُورًا لَهُقَالَ أَبُو عَبْد الرَّحْمَنِ قَالَ أَبِي لَيْسَ بِمَرْفُوعٍ","id":"Telah menceritakan kepada kami [Affan] berkata, Telah menceritakan kepada kami [Hammad bin Salamah] berkata, Telah menceritakan kepada kami [Tsabit] dari [Shalih Abu Hujair] dari [Mu'awiyah bin Hudaij] salah seorang sahabat, ia berkata, \"Barangsiapa memandikan mayat, mengkafani, menggiring dan mengurus jenazahnya, maka dia kembali dalam keadaan terampuni dosanya.\" Abu 'Abdurrahman berkata, \"Bapakku berkata, \"Hadits tidak marfu' (sampai kepada Nabi).\""},"4073":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ يَحْيَى بْنِ الْحُصَيْنِ عَنْ أُمِّ الْحُصَيْنِ جَدَّتِهِ حَدَّثَتْهُ قَالَتْحَجَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةَ الْوَدَاعِ فَرَأَيْتُ أُسَامَةَ بْنَ زَيْدٍ وَبِلَالًا وَأَحَدُهُمَا آخِذٌ بِخِطَامِ نَاقَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ رَافِعٌ ثَوْبَهُ يَسْتُرُهُ مِنْ الْحَرِّ حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah] dari [Abu Abdurrahim] dari [Zaid bin Abu Unaisah] dari [Yahya bin Al Hushain] dari [Ummul Husain] neneknya, telah menceritakan kepadanya, dia berkata, \"Aku melaksanakan haji bersama Nabi shallallahu 'alaihi wasallam pada waktu haji Wada', kemudian aku melihat Usamah bin Zaid dan Bilal, salah seorang dari keduanya memegang tali unta Nabi shallallahu 'alaihi wasallam, sementara yang lain mengangkat kainnya untuk menutupi beliau dari terik panas, sehingga selesai dari melempar jumrah 'aqabah.\""},"4074":{"ar":"حَدَّثَنَا أَبُو قَطَنٍ قَالَ حَدَّثَنَا يُونُسُ يَعْنِي ابْنَ أَبِي إِسْحَاقَ عَنِ الْعَيْزَارِ بْنِ حُرَيْثٍ عَنْ أُمِّ الْحُصَيْنِ الْأَحْمَسِيَّةِ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ يَخْطُبُ عَلَى الْمِنْبَرِ عَلَيْهِ بُرْدٌ لَهُ قَدْ الْتَفَعَ بِهِ مِنْ تَحْتِ إِبْطِهِ قَالَتْ فَأَنَا أَنْظُرُ إِلَى عَضَلَةِ عَضُدِهِ تَرْتَجُّ فَسَمِعْتُهُ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ فَاسْمَعُوا لَهُ وَأَطِيعُوا مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Qathn] berkata, Telah menceritakan kepada kami [Yunus] -yakni Ibnu Abu Ishaq- dari [Al 'Aizar bin Huraits] dari [Ummu Hushain Al Ahmasiyah] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam pada waktu haji Wada', beliau berkhutbah di atas mimbar dengan mengenakan kain burdah yang beliau lilitkan dari bawah ketiaknya.\" Ummul Hushain berkata, \"Aku lihat urat lengannya beliau bergetar, kemudian aku mendengar beliau bersabda: \"Wahai manusia, bertakwalah kalian kepada Allah sekalipun yang memerintah kalian adalah seorang budak Habsyah yang pesek hidungnya, dengar dan taatlah selama dia menegakkan Kitabullah Azza Wa jalla di tengah-tengah kalian.\""},"4075":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ الْحُصَيْنِ عَنْ جَدَّتِهِ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ يَرْحَمُ اللَّهُ الْمُحَلِّقِينَ قَالُوا فِي الثَّالِثَةِ وَالْمُقَصِّرِينَ قَالَ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami [Waki'] berkata, Telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hushain] dari [neneknya] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Semoga Allah merahmati orang-orang yang mencukur habis rambutnya, semoga Allah merahmati orang-orang yang mencukur habis rambutnya.\" Para sahabat berkata dikali yang ketiga, \"Dan orang-orang yang mencukur pendek rambutnya?\" Beliau bersabda: \"Dan orang-orang yang mencukur pendeknya rambutnya.\" "},"4076":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ يَحْيَى بْنِ الْحُصَيْنِ عَنْ أُمِّهِ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَاسْمَعُوا وَأَطِيعُوا وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Yahya bin Al Husain] dari [Ibunya] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam berkhutbah pada waktu haji wada', beliau bersabda: \"Bertakwalah kepada Allah, dengar dan patuhilah walaupun kalian diperintah oleh budak Habsy yang pesek hidungnya, selagi ia menegakkan kitabullah 'azza wajalla.\""},"4077":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ الْحُصَيْنِ بْنِ عُرْوَةَ قَالَ حَدَّثَتْنِي جَدَّتِي قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَلَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata, telah menceritakan kepada kami [Yahya bin Hushain bin 'Urwah] berkata, telah menceritakan kepadaku [nenekku] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian dipimpin oleh seorang budak dengan Kitabullah, maka taat dan dengarlah.\""},"4078":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ يَحْيَى بْنَ حُصَيْنٍ قَالَ سَمِعْتُ جَدَّتِي تَقُولُسَمِعْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ يَخْطُبُ يَقُولُ غَفَرَ اللَّهُ لِلْمُحَلِّقِينَ ثَلَاثَ مِرَارٍ قَالُوا وَالْمُقَصِّرِينَ فَقَالَ وَالْمُقَصِّرِينَ فِي الرَّابِعَةِ قَالَتْ وَسَمِعْتُهُ يَقُولُ إِنْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] berkata, aku mendengar [Yahya bin Hushain] berkata, aku mendengar [nenekku] berkata, \"Aku mendengar Nabi Allah shallallahu 'alaihi wasallam berkhutbah di Arafah, beliau bersabda: \"Semoga Allah mengampuni para orang-orang yang menggundul rambutnya, \" -tiga kali-, para sahabat berkata, \"Dan yang memendekkan rambutnya?\" Beliau bersabda: \"Dan orang yang memendekkan rambutnya, \" -pada kali keempatnya-. Nenekku berkata, \"Aku juga mendengar beliau bersabda: \"Jika kalian dipimpin oleh seorang budak dengan Kitabullah, maka dengar dan taatlah.\""},"4079":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ الْحُصَيْنِ قَالَ سَمِعْتُ جَدَّتِي تُحَدِّثُ أَنَّهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ يَقُولُ لَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ عَزَّ وَجَلَّ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hushain] berkata, aku mendengar [nenekku] menceritakan, bahwa dia mendengar Nabi shallallahu 'alaihi wasallam khutbah pada waktu haji wada', beliau bersabda: \"Jika kalian diperintah oleh seorang budak yang memimpin kalian dengan kitabullah 'azza wajalla, maka dengarkan dan patuhilah dia.\""},"4080":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ عَنِ الْعَيْزَارِ بْنِ حُرَيْثٍ عَنْ أُمِّ الْحُصَيْنِ الْأَحْمَسِيَّةِ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِعَرَفَةَ وَعَلَيْهِ بُرْدَةٌ قَدْ الْتَفَعَ بِهَا وَهُوَ يَقُولُ اسْمَعُوا وَأَطِيعُوا وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ","id":"Telah menceritakan kepada kami [Waki'] dari [Yunus] dari [Al 'Aizar bin Hurais] dari [Ummu Al Hushain Al A'masiyah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda, waktu itu beliau berada di Arafah dengan mengenakan selendang burdah, beliau katakan: \"Dengar dan patuhilah, jika kalian diperintah oleh seorang budak habsy selagi ia menegakkan kitabullah.\""},"4081":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ الْعَيْزَارِ بْنِ حُرَيْثٍ قَالَ سَمِعْتُ أُمَّ الْحُصَيْنِ الْأَحْمَسِيَّةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ عَلَيْهِ بُرْدٌ قَدْ الْتَفَعَ بِهِ مِنْ تَحْتِ إِبْطِهِ فَأَنَا أَنْظُرُ إِلَى عَضَلَةِ عَضُدِهِ تَرْتَجُّ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَأَطِيعُوا وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ فَاسْمَعُوا وَأَطِيعُوا مَا أَقَامَ فِيكُمْ كِتَابَ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Yunus] dari [Al 'Aizar bin Huraits] berkata, aku mendengar [Ummu Hushain Al Ahmasiyah] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam pada waktu Haji Wada' mengenekan selendang yang terbelih dari bawah ketiaknya, dan aku lihat urat lengannya yang besar bergetar, beliau bersabda: \"Wahai sekalian manusia, bertakwalah kepada Allah dan patuhlah meskipun kalian diperintah oleh seorang budak yang pesek batang hidungnya, selagi dia menegakkan kitabullah di antara kalian.\""},"4082":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا يَحْيَى بْنُ الْحُصَيْنِ أَخْبَرَنِي أَنَّهُ سَمِعَ جَدَّتَهُ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بِعَرَفَاتٍ وَهُوَ يَقُولُ وَلَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ فَاسْمَعُوا لَهُ وَأَطِيعُواقَالَ عَبْد اللَّهِ و سَمِعْت أَبِي يَقُولُ إِنِّي لَأَرَى لَهُ السَّمْعَ وَالطَّاعَةَ فِي الْعُسْرِ وَالْيُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Yahya bin Al Hushain] telah mengabarkan kepadaku, bahwa dia mendengar [neneknya] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah di Arafah, beliau bersabda: \"Meskipunkalian diperintah oleh seorang budak, jika ia berlaku dengan kitabullah maka dengar dan taatlah.\" Abdullah berkata, \"Aku mendengar bapakku berkata, \"Sungguh, menurutku wajib untuk selalu mendengar dan taat kepadanya, baik saat susah atau mudah, enak atau tidak enak.\""},"4083":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أُمِّ كُلْثُومٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَيْسَ الْكَاذِبُ بِأَنْ يَقُولَ الرَّجُلُ فِي إِصْلَاحِ مَا بَيْنَ النَّاسِ","id":"Telah menceritakan kepada kami [Bisyr bin Al Mufadlal] berkata, telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari Ibunya [Ummu Kultsum] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Bukanlah dikatakan pendusta, seorang lelaki yang berkata untuk tujuan mendamaikan di antara manusia.\""},"4084":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمِ بْنِ عُبَيْدِ اللَّهِ بْنِ شِهَابٍ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُ أَنَّ أُمَّهُ أُمَّ كُلْثُومٍ بِنْتَ عُقْبَةَ أَخْبَرَتْهُ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ الْكَذَّابُ الَّذِي يُصْلِحُ بَيْنَ النَّاسِ فَيَنْمِي خَيْرًا أَوْ يَقُولُ خَيْرًا","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [Bapakku] dari [Shalih bin Kaisan] berkata, telah menceritakan kepada kami [Muhammad bin Muslim bin 'Ubaidullah bin Syihab] bahwa [Humaid bin Abdurrahman bin 'Auf] mengabarkan kepadanya, bahwa ibunya [Ummu Kultsum binti 'Uqbah] telah mengabarkan kepadanya, bahwa dirinya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dikatakan pendusta seseorang yang ingin mendamaikan antara manusia, kemudian ia menyampaikan kabar dengan baik atau berkata baik.\""},"4085":{"ar":"وَقَالَتْلَمْ أَسْمَعْهُ يُرَخِّصُ فِي شَيْءٍ مِمَّا يَقُولُ النَّاسُ إِلَّا فِي ثَلَاثٍ فِي الْحَرْبِ وَالْإِصْلَاحِ بَيْنَ النَّاسِ وَحَدِيثِ الرَّجُلِ امْرَأَتَهُ وَحَدِيثِ الْمَرْأَةِ زَوْجَهَاوَكَانَتْ أُمُّ كُلْثُومٍ بِنْتُ عُقْبَةَ مِنْ الْمُهَاجِرَاتِ اللَّاتِي بَايَعْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan [Ummu Kultsum] berkata, \"Aku belum pernah mendengar beliau memberikan keringanan atas sesuatupun yang dibicarakan oleh manusia kecuali dalam tiga hal; dalam peperangan, mendamaikan antara manusia dan seorang suami mengatakan kepada isterinya, atau seorang isteri mengatakan kepada suaminya.\" Ummu Kultsum binti Uqbah termasuk wanita yang ikut berhijrah dan berbaiat kepada Rasulullah shallallahu 'alaihi wasallam."},"4086":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ الْكَذَّابُ مَنْ أَصْلَحَ بَيْنَ النَّاسِ فَقَالَ خَيْرًا أَوْ نَمَى خَيْرًا وَقَالَ مَرَّةً وَنَمَى خَيْرًا","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari Ibunya [Ummu Kultsum binti 'Uqbah] dia termasuk dari wanita yang ikut berhijrah pertama kali, dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dikatakan sebagai pendusta seseorang yang mendamaikan antara manusia, lalu ia mengatakan sesuatu yang baik, atau menyampaikan berita yang baik.\" Dan sekali waktu ia menyebutkan, \"Dan menyampaikan berita yang baik.\""},"4087":{"ar":"حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ ابْنُ أَخِي الزُّهْرِيِّ عَنْ عَمِّهِ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أَنَّهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Umayyah bin Khalid] berkata, telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Muslim] anak saudara laki-lakinya Az Zuhri, dari pamannya [Az Zuhri] dari [Humaid bin Abdurrahman] dari [Ibunya] bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"QUL HUWALLAAHU AHAD (Katakanlah (wahai Muhammad) dialah Allah yang Maha Esa) menyamai sepertiga Al Qur'an.\""},"4088":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ عَنْ يَزِيدَ يَعْنِي ابْنَ الْهَادِ عَنْ عَبْدِ الْوَهَّابِ عَنِ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ قَالَتْمَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي شَيْءٍ مِنْ الْكَذِبِ إِلَّا فِي ثَلَاثٍ الرَّجُلِ يَقُولُ الْقَوْلَ يُرِيدُ بِهِ الْإِصْلَاحَ وَالرَّجُلِ يَقُولُ الْقَوْلَ فِي الْحَرْبِ وَالرَّجُلِ يُحَدِّثُ امْرَأَتَهُ وَالْمَرْأَةِ تُحَدِّثُ زَوْجَهَا","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Laits] -yakni Ibnu Sa'd- dari [Yazid] -yakni Ibnu Al Hadi- dari [Abdul Wahab] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman bin 'Auf] dari ibunya [Ummu Kultsum binti 'Uqbah] dia berkata, \"Aku belum pernah mendengar Rasulullah shallallahu 'alaihi wasallam memberikan keringanan sedikitpun dari kedustaan kecuali dalam tiga perkara; seseorang yang mengatakan suatu perkataan dengan maksud untuk mendamaikan, seseorang yang mengatakan perkataan dalam peperangan dan seorang (suami) yang mengatakan kepada isterinya, atau isteri mengatakan kepada suaminya.\""},"4089":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُسْلِمُ بْنُ خَالِدٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ قَالَ أَبِي و حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُسْلِمٌ فَذَكَرَهُ وَقَالَ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ أَبِي سَلَمَةَ قَالَتْلَمَّا تَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ سَلَمَةَ قَالَ لَهَا إِنِّي قَدْ أَهْدَيْتُ إِلَى النَّجَاشِيِّ حُلَّةً وَأَوَاقِيَّ مِنْ مِسْكٍ وَلَا أَرَى النَّجَاشِيَّ إِلَّا قَدْ مَاتَ وَلَا أَرَى إِلَّا هَدِيَّتِي مَرْدُودَةً عَلَيَّ فَإِنْ رُدَّتْ عَلَيَّ فَهِيَ لَكِ قَالَ وَكَانَ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُدَّتْ عَلَيْهِ هَدِيَّتُهُ فَأَعْطَى كُلَّ امْرَأَةٍ مِنْ نِسَائِهِ أُوقِيَّةَ مِسْكٍ وَأَعْطَى أُمَّ سَلَمَةَ بَقِيَّةَ الْمِسْكِ وَالْحُلَّةَ","id":"Telah menceritakan kepada kami [Yazid Bin Harun] berkata, telah mengabarkan kepada kami [Muslim Bin Khalid] dari [Musa Bin Uqbah] dari ibunya [Ummu Kultsum]. Abdullah berkata; dan telah menceritakan kepada kami [Husain bin Muhammad] dia berkata, telah menceritakan kepada kami [Muslim] -kemudian dia menyebutkan- dan dia menyebutkan dari Ibunya [Ummu Kultsum binti Abu Salamah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam menikahi Ummu Salamah, beliau berkata kepadanya: \"Sesungguhnya aku telah memberikan hadiah perhiasan dan beberapa Uqiyah minyak misik kepada Najasyi, dan aku tidak melihat Najasyi kecuali dia sudah meninggal, sementara hadiahku dikembalikan kepadaku. Jika benar haidah tersebut kembali kepadaku, maka dia menjadi milikmu.\" Musa bin Uqbah berkata, \"Maka dilakukanlah sebagaimana yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam, hadiahnya dikembalikan lagi kepada beliau, maka beliau memberikan kepada setiap dari isterinya satu uqiyah minyak misik dan memberikan semua sisa perhiasan dan minyak kepada Ummu Salamah.\" "},"4090":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ الْكَذَّابُ مَنْ أَصْلَحَ بَيْنَ النَّاسِ فَقَالَ خَيْرًا أَوْ نَمَى خَيْرًا","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari ibunya [Ummu Kultsum binti 'Uqbah] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dikatakan pendusta seseorang yang mendamaikan di antara manusia, kemudian dia berkata baik atau menyampaikan berita dengan baik.\""},"4091":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنِ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ أَنَّهَا قَالَتْرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْكَذِبِ فِي ثَلَاثٍ فِي الْحَرْبِ وَفِي الْإِصْلَاحِ بَيْنَ النَّاسِ وَقَوْلِ الرَّجُلِ لِامْرَأَتِهِ","id":"Telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman bin Auf] dari ibunya [Ummu Kultsum binti 'Uqbah] bahwa dia berkata, \"Nabi shallallahu 'alaihi wasallam memberikan keringanan untuk berbohong pada tiga tempat; pada saat perang, pada saat mendamaikan antara manusia dan perkataan seseorang kepada isterinya (untuk menumbuhkan kecintaan).\""},"4092":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ قَالَ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ بِالْكَذَّابِ مَنْ أَصْلَحَ بَيْنَ النَّاسِ فَقَالَ خَيْرًا أَوْ نَمَى خَيْرًا وَقَالَ مَرَّةً وَنَمَى خَيْرً","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah menceritakan kepadaku [Humaid bin Abdurrahman bin Auf] dari ibunya [Ummu Kultsum binti 'Uqbah] dia berkata, \"Ummu Kultsum termasuk dari wanita yang ikut berhijrah pertama kali, dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dikatakan pendusta seseorang yang mendamaikan antara manusia, kemudian dia berkata baik atau menyampaikan berita dengan baik, \" beliau bersabda lagi: \"Dan menyampaikan berita yang baik.\""},"4093":{"ar":"حَدَّثَنَا رَوْحٌ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ وَلَدِ شَيْبَةَأَنَّهَا أَبْصَرَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَسْعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ يَقُولُ لَا يُقْطَعُ الْأَبْطَحُ إِلَّا شَدًّا","id":"Telah menceritakan kepada kami [Rauh] dan [Abu Nu'aim] keduanya berkata, telah menceritakan kepada kami [Hisyam bin Abu Abdullah] dari [Budail bin Maisarah] dari [Shafiyah binti Syaibah] dari [Ummu Walad] milik Syaibah, bahwa dia melihat Nabi shallallahu 'alaihi wasallam sedang melaksanakan sa'i antara Shafa dan Marwah sambil berkata: \"Lembah ini tidak dapat dilalui kecuali dengan susah payah.\" "},"4094":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا بُدَيْلُ بْنُ مَيْسَرَةَ عَنِ الْمُغِيرَةِ بْنِ حَكِيمٍ عَنْ صَفِيَّةَ بِن��تِ شَيْبَةَ عَنِ امْرَأَةٍ مِنْهُمْ أَنَّهَارَأَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَوْخَةٍ وَهُوَ يَسْعَى فِي بَطْنِ الْمَسِيلِ وَهُوَ يَقُولُ لَا يُقْطَعُ الْوَادِي إِلَّا شَدًّا وَأَظُنُّهُ قَالَ وَقَدْ انْكَشَفَ الثَّوْبُ عَنْ رُكْبَتَيْهِ ثُمَّ قَالَ حَمَّادٌ بَعْدُ لَا يُقْطَعُ أَوْ قَالَ الْأَبْطَحُ إِلَّا شَدًّا وَسَمِعَتْهُ يَقُولُ لَا يُقْطَعُ الْأَبْطَحُ إِلَّا شَدًّا","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Budail bin Maisarah] dari [Mughirah bin Hakim] dari [Shafiyah binti Syaibah] dari [seorang wanita] di antara mereka, bahwa dirinya melihat Nabi shallallahu 'alaihi wasallam dari pintu kecil sedangkan beliau baru melaksanakan sa'i di tengah saluran air, beliau bersabda: \"Lembah ini tidak dapat dilalui kecuali dengan susah payah.\" Dan menurutku ia menyebutkan, \"Sungguh kain beliau tersingkap dari lututnya, \" kemudian Hammad menyebutkan, \"tidak bisa dilalui, \" atau berkata, \"lembah, kecuali dengan susah payah.\" Wanita itu juga mendengar beliau mengatakan: \"Lembah yang tidak bisa dilalui kecuali dengan susah payah.\""},"4095":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ عَبْدِ اللَّهِ بْنِ جُمَيْعٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَلَّادٍ الْأَنْصَارِيُّ وَجَدَّتِي عَنْ أُمِّ وَرَقَةَ بِنْتِ عَبْدِ اللَّهِ بْنِ الْحَارِثِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَزُورُهَا كُلَّ جُمُعَةٍ وَأَنَّهَا قَالَتْ يَا نَبِيَّ اللَّهِ يَوْمَ بَدْرٍ أَتَأْذَنُ فَأَخْرُجُ مَعَكَ أُمَرِّضُ مَرْضَاكُمْ وَأُدَاوِي جَرْحَاكُمْ لَعَلَّ اللَّهَ يُهْدِي لِي شَهَادَةً قَالَ قَرِّي فَإِنَّ اللَّهَ عَزَّ وَجَلَّ يُهْدِي لَكِ شَهَادَةً وَكَانَتْ أَعْتَقَتْ جَارِيَةً لَهَا وَغُلَامًا عَنْ دُبُرٍ مِنْهَا فَطَالَ عَلَيْهِمَا فَغَمَّاهَا فِي الْقَطِيفَةِ حَتَّى مَاتَتْ وَهَرَبَا فَأَتَى عُمَرُ فَقِيلَ لَهُ إِنَّ أُمَّ وَرَقَةَ قَدْ قَتَلَهَا غُلَامُهَا وَجَارِيَتُهَا وَهَرَبَا فَقَامَ عُمَرُ فِي النَّاسِ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَزُورُ أُمَّ وَرَقَةَ يَقُولُ انْطَلِقُوا نَزُورُ الشَّهِيدَةَ وَإِنَّ فُلَانَةَ جَارِيَتَهَا وَفُلَانًا غُلَامَهَا غَمَّاهَا ثُمَّ هَرَبَا فَلَا يُؤْوِيهِمَا أَحَدٌ وَمَنْ وَجَدَهُمَا فَلْيَأْتِ بِهِمَا فَأُتِيَ بِهِمَا فَصُلِبَا فَكَانَا أَوَّلَ مَصْلُوبَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Al Walid bin Abdullah bin Jumai'] berkata, telah menceritakan kepadaku [Abdurrahman bin Khallad Al Anshari], dan [nenekku] dari [Ummu Waraqah binti Abdillah bin Al Harits] bahwa Nabiyullah shallallahu 'alaihi wasallam mengunjunginya setiap hari Jum'at, Ummu Waraqah berkata kepada beliau, \"Wahai Nabiyullah, ini adalah hari perang Badar, apakah tuan mengizinkan aku ikut keluar bersamamu untuk merawat orang-orang yang sakit dan mengobati orang yang terluka dari kalian, mudah-mudahan Allah memberikan mati syahid kepadaku?\" Kemudian Nabi menjawab: \"Menetaplah kamu di rumah karena sesungguhnya Allah Azza Wa Jalla akan memberikan mati syahid kepadamu.\" Sementara wanita tersebut telah memberikan janji merdeka kepada budak wanita dan budak laki-lakinya setelah ia meninggal. Kemudian Ummu Waraqah tinggal sekian lama bersama kedua budaknya, namun kemudian, keduanya mendekapnya dengan kain tebal hingga ia pun meninggal. Kedua budak tersebut kemudian kabur, ketika Umar datang, diceritakanlah kejadian tersebut kepadanya, bahwa Ummu Waraqah telah dibunuh oleh budak laki-laki dan budak perempuannya, kemudian keduanya melarikan diri. Maka Umar pun berdiri di hadapan orang-orang dan berpidato, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi Ummu Waraqah dan bersabda: \"Berangkatlah kalian, kita akan mengunjungi As Syahidah (seorang perempuan yang mati Syahid), \" dan sesungguhnya Fulanah dan Fulan budak miliknya telah menutupinya dengan kain tebal, kemudian keduanya melarikan diri. Maka jangan ada satu orangpun yang melindungi mereka berdua, barangsiapa mendapatkan keduanya hendaklah ia bawa keduanya.\" Maka dibawalah keduanya dan kemudian disalib, maka inilah awal mula orang yang disalib dalam Islam.\""},"4096":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَتْنِي جَدَّتِي عَنْ أُمِّ وَرَقَةَ بِنْتِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ الْأَنْصَارِيِّوَكَانَتْ قَدْ جَمَعَتْ الْقُرْآنَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَرَهَا أَنْ تَؤُمَّ أَهْلَ دَارِهَا وَكَانَ لَهَا مُؤَذِّنٌ وَكَانَتْ تَؤُمُّ أَهْلَ دَارِهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepadaku [nenekku] dari [Ummu Waraqah binti Abdullah Bin Al Harits Al Anshari] dan ia pernah ikut mengumpulkan Al-Qur'an, sedangkan Nabi shallallahu 'alaihi wasallam telah memerintahkan kepadanya untuk memimpin shalat keluarganya, ia mempunyai tukang adzan dan ia menjadi imam di rumahnya.\""},"4097":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ سَلْمَى بِنْتِ حَمْزَةَأَنَّ مَوْلَاهَا مَاتَ وَتَرَكَ ابْنَةً فَوَرَّثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَتَهُ النِّصْفَ وَوَرَّثَ يَعْلَى النِّصْفَ وَكَانَ ابْنَ سَلْمَى","id":"Telah menceritakan kepada kami [Abdus Shamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Salma binti Hamzah] bahwa budaknya meninggal dunia dan meninggalkan seorang anak perempuan, kemudian Nabi shallallahu 'alaihi wasallam mewaritskan separuh untuk anak perempun budak dan separuhnya lagi kepada Ya'la, dan Ya'la adalah anak dari Salma.\""},"4098":{"ar":"حَدَّثَنَا رَوْحٌ وَمُحَمَّدُ بْنُ مُصْعَبٍ قَالَا حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّ مَعْقِلٍ الْأَسَدِيَّةِ أَنَّهَاقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْحَجَّ وَجَمَلِي أَعْجَفُ فَمَا تَأْمُرُنِي قَالَ اعْتَمِرِي فِي رَمَضَانَ فَإِنَّ عُمْرَةً فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Rauh] dan [Muhammad bin Mush'ab] keduanya berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Ummu Ma'qil Al Asadiyah] bahwa dia berkata, \"Wahai Rasulullah, sesungguhnya aku ingin menunaikan haji, sedangkan untaku lemah, apa yang tuan perintahkan buatku?\" Beliau bersabda: \"Umrahlah kamu pada bulan Ramadan, sesungguhnya umrah pada bulan Ramadan menyamai (pahala) haji.\""},"4099":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ قَالَأَرْسَلَ مَرْوَانُ إِلَى أُمِّ مَعْقِلٍ الْأَسَدِيَّةِ يَسْأَلُهَا عَنْ هَذَا الْحَدِيثِ فَحَدَّثَتْهُ أَنَّ زَوْجَهَا جَعَلَ بَكْرًا لَهَا فِي سَبِيلِ اللَّهِ وَأَنَّهَا أَرَادَتْ الْعُمْرَةَ فَسَأَلَتْ زَوْجَهَا الْبَكْرَ فَأَبَى فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَأَمَرَهُ أَنْ يُعْطِيَهَا وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجُّ وَالْعُمْرَةُ مِنْ سَبِيلِ اللَّهِ وَقَالَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً أَوْ تُجْزِئُ حَجَّةً وَقَالَ حَجَّاجٌ تَعْدِلُ بِحَجَّةٍ أَوْ تُجْزِئُ بِحَجَّةٍحَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي إِسْمَاعِيلَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ الْقُرَشِيِّ عَنْ مَعْقِلِ بْنِ أَبِي مَعْقِلٍ أَنَّ أُمَّهُ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Hajjaj] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhajir] dari [Abu Bakr bin Abdurrahman bin Al Harits] dia berkata; \"Marwan pernah mengutus seseorang kepada [Ummu Ma'qil Al Asadiyah] menanyakan mengenai hadits ini, kemudian Ummu Ma'qil menceritakan hadits tersebut kepadanya, bahwa suaminya (Abu Ma'qil) telah menginfakkan dua ekor unta mudanya di jalan Allah, padahal Ummu Ma'qil hendak pergi haji, maka ia meinta seekor unta muda kepada suaminya, namun suaminya enggan, ia pun pergi menemui Nabi shallallahu 'alaihi wasallam dan memberitahukan hal itu kepada beliau, maka beliau memerintahkan suaminya supaya memberikan sekor unta kepada isterinya, Nabi shallallahu 'alaihi wasallam bersabda: \"Haji dan 'Umrah di jalan Allah -dan bersabda- Umrah di bulan Ramadhan setara dengan melaksanakan haji atau mencukupkan dari melaksanakan haji.\" [Hajjaj] mengatakan; \"Setara dengan melakukan haji atau mencukupkan dari melaksanakan haji.\" Telah menceritakan kepada kami [Ibnu Numair] dia berkata; telah menceritakan kepada kami [Muhammad bin Abu Isma'il] dari [Ibrahim bin Muhajir] dari [Abu Bakr bin Abdurrahman Al Qurasyi] dari [Ma'qil bin Abu Ma'qil] bahwa ibunya datang menemui Rasulullah shallallahu 'alaihi wasallam, dan berkata, lalu ia menyebutkan hadits yang semakna.\""},"4100":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنِ امْرَأَةٍ مِنْ بَنِي أَسَدِ بْنِ خُزَيْمَةَ يُقَالُ لَهَا أُمُّ مَعْقِلٍ قَالَتْأَرَدْتُ الْحَجَّ فَضَلَّ بَعِيرِي فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اعْتَمِرِي فِي شَهْرِ رَمَضَانَ فَإِنَّ عُمْرَةً فِي شَهْرِ رَمَضَانَ تَعْدِلُ حَجَّةًحَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنَا يَحْيَى بْنُ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ الْحَارِثِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ قَالَ كُنْتُ فِيمَنْ رَكِبَ مَعَ مَرْوَانَ حِينَ رَكِبَ إِلَى أُمِّ مَعْقِلٍ قَالَ وَكُنْتُ فِيمَنْ دَخَلَ عَلَيْهَا مِنْ النَّاسِ مَعَهُ وَسَمِعْتُهَا حِينَ حَدَّثَتْ هَذَا الْحَدِيثَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ مَعْقِلِ بْنِ أُمِّ مَعْقِلٍ الأَسَدِيَّةِ عَنْ أُمِّ مَعْقِلٍ الْأَسَدِيَّةِ قَالَتْ أَرَدْتُ الْحَجَّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ حَدِيثِ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari seorang wanita bani Asad bin Khuzaimah yang disebut dengan [Ummu Ma'qil] dia berkata, \"Aku hendak melaksanakan ibadah haji, tiba-tiba hewan tungganganku tersesat, maka aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Laksanakanlah umrah di bulan Ramadan, sebab umrah di bulan Ramadan seperti pahala haji.\" Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepada kami [Yahya bin 'Abbad bin Abdullah bin Zubair] dari [Harits bin Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [Bapaknya] dia berkata, \"Aku adalah orang yang ikut serta bersama Marwan sewaktu dia pergi menemui [Ummu Ma'qal Al Asadiyah], Abu Bakar berkata, \"Dan aku termasuk orang yang ikut menemui Ummu Ma'qal ketika dia menceritakan hadits ini.\" Telah menceritakan kepada kami [Abdul Malik bin Amru] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Ma'qil bin Ummu Al Asadiyah] dari [Ummu Ma'qil] ia berkata, \"Aku hendak melaksanakan ibadah haji bersama Rasulullah shallallahu 'alaihi wasallam, aku lalu menyebutkan hal itu kepada Nabi shallallahu 'alaihi wasallam, kemudian ia menyebutkan seperti hadits Al Auza'I, dari Yahya bin Abu Katsir.\""},"4101":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ أَبِي مَعْقِلٍ عَنْ أُمِّ مَعْقِلٍ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمْرَةٌ فِي رَمَضَانَ ت��عْدِلُ حَجَّةً","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Aswad] dari [Abu Ma'qil] dari [Ummu Ma'qil] bahwa dia bertanya kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu menjawab: \"Umrah di bulan Ramadan seperti melaksanakan ibadah haji.\""},"4102":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ يَحْيَى الْأَنْصَارِيُّ عَنْ أَبِي زَيْدٍ مَوْلَى ثَعْلَبَةَ أَخْبَرَهُ عَنْ مَعْقِلِ بْنِ أَبِي مَعْقِلٍ الْأَنْصَارِيِّ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُسْتَقْبَلَ الْقِبْلَتَانِ لِلْغَائِطِ وَالْبَوْلِ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Amru bin Yahya Al Ansharii] dari [Abu Zaid] bekas budak Tsa'labah, telah mengabarkan kepadanya, dari [Ma'qil bin Abu Ma'qil Al Anshari] dari para sahabat Nabi shallallahu 'alaihi wasallam, dia menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam melarang menghadap kiblat bagi orang yang buang air besar atau orang yang buang air kecil.\""},"4103":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ حَزْمٍ قَالَسَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ يُحَدِّثُ أَبِي قَالَ ذَاكَرَنِي مَرْوَانُ مَسَّ الذَّكَرِ فَقُلْتُ لَيْسَ فِيهِ وُضُوءٌ فَقَالَ إِنَّ بُسْرَةَ بِنْتَ صَفْوَانَ تُحَدِّثُ فِيهِ فَأَرْسَلَ إِلَيْهَا رَسُولًا فَذَكَرَ الرَّسُولُ أَنَّهَا تُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَّ ذَكَرَهُ فَلْيَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Isma'il bin 'Ulaiyah] berkata, telah menceritakan kepada kami [Abdullah bin Abu Bakar Bin Hazm] dia berkata, aku mendengar [Urwah Bin Zubair] menceritakan kepada Bapakku dia berkata, \" [Marwan] mengingatkan aku tentang menyentuh kemaluan, kemudian aku katakan, \"Tidak ada wudlu padanya.\" Kemudian dia berkata, \"Sungguh [Busrah binti Shafwan] telah menceritakan tentang itu, maka diutuslah [seseorang] untuk menemuinya, utusan itu kemudian menyebutkan bahwa Busrah binti Shafwan menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Barangsiapa menyentuh kemaluannya hendaklah ia berwudlu.\""},"4104":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنَّهُ سَمِعَهُ مِنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَهُوَ مَعَ أَبِيهِ يُحَدِّثُ أَنَّ مَرْوَانَ أَخْبَرَهُ عَنْ بُسْرَةَ بِنْتِ صَفْوَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَّ فَرْجَهُ فَلْيَتَوَضَّأْ قَالَ فَأَرْسَلَ إِلَيْهَا رَسُولًا وَأَنَا حَاضِرٌ فَقَالَتْ نَعَمْ فَجَاءَ مِنْ عِنْدِهَا بِذَاكَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Abu Bakr bin Muhammad bin Amru bin Hazm] bahwa dia mendengarnya dari [Urwah bin Zubair] - dia bersama bapaknya- menceritakan, bahwa [Marwan] telah mengabarkan dari [Busrah binti Shafwan] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyentuh kemaluannya, hendaklah ia berwudlu.\" Marwan berkata, \"Lalu diutuslah seseorang menemui Busrah binti Shafwan, sementara aku ada, Busrah lantas menjawab, \"Ya.\" keudian utusan itu datang dengan membawa jawaban tersebut.\""},"4105":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ حَدَّثَنِي أَبِي أَنَّ بُسْرَةَ بِنْتَ صَفْوَانَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَّ ذَكَرَهُ فَلَا يُصَلِّ حَتَّى يَتَوَضَّأَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata, telah menceritakan kepadaku [Bapakku] bahwa [Busrah binti Shafwan] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyentuh kemaluannya, maka janganlah shalat sehingga ia bewudlu.\""},"4106":{"ar":"قَالَ عَبْد اللَّهِ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ حَزْمٍ الْأَنْصَارِيُّ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ يَقُولُ ذَكَرَ مَرْوَانُ فِي إِمَارَتِهِ عَلَى الْمَدِينَةِ أَنَّهُ يُتَوَضَّأُ مِنْ مَسِّ الذَّكَرِ إِذَا أَفْضَى إِلَيْهِ الرَّجُلُ بِيَدِهِ فَأَنْكَرْتُ ذَلِكَ عَلَيْهِ فَقُلْتُ لَا وُضُوءَ عَلَى مَنْ مَسَّهُ فَقَالَ مَرْوَانُ أَخْبَرَتْنِي بُسْرَةُ بِنْتُ صَفْوَانَ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ مَا يُتَوَضَّأُ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُتَوَضَّأُ مِنْ مَسِّ الذَّكَرِ قَالَ عُرْوَةُ فَلَمْ أَزَلْ أُمَارِي مَرْوَانَ حَتَّى دَعَا رَجُلًا مِنْ حَرَسِهِ فَأَرْسَلَهُ إِلَى بُسْرَةَ يَسْأَلُهَا عَمَّا حَدَّثَتْ مِنْ ذَلِكَ فَأَرْسَلَتْ إِلَيْهِ بُسْرَةُ بِمِثْلِ الَّذِي حَدَّثَنِي عَنْهَا مَرْوَانُ","id":"Abdullah berkata; aku mendapatkan dalam kitab ayahku dengan tulisannya sendiri; telah menceritakan kepada kami [Abu Al Yaman] berkata, telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah menceritakan kepadaku [Abdullah bin Abu Bakar bin Hazm Al Anshari] bahwa dia telah mendengar [Urwah bin Zubair] berkata, \" [Marwan] menyebutkan pada masa kekuasaanya atas Madinah, bahwa jika seorang laki-laki menyentuh kemaluannya dengan tangannya maka dia harus berwudlu, kemudian aku mengingkari perkataannya. Aku katakan, \"Tidak ada wudlu bagi siapa yang telah menyentuhnya.\" Marwan kemudian berkata, \" [Busrah binti Shafwan] telah mengabarkan kepadaku, bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang apa yang menyebabkan seseorang harus berwudlu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menyentuh kemaluah itu mengharuskan berwudlu.\" Urwah berkata, \"Aku terus saja mendebat Marwan hingga ia mengutus salah seorang dari pengawalnya untuk menemui Busrah, menanyakan tentang apa yang telah ia katakan. Busrah lalu mengutus balik dengan keterangan sebagaimana yang Marwan ceritakan kepadaku darinya.\""},"4107":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نُغَسِّلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَآذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُقَالَ مُحَمَّدٌ وَحَدَّثَتْنَاهُ حَفْصَةُ قَالَتْ فَجَعَلْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyah], bahwa Rasulullah shallallahu 'alaihi wasallam keluar menemui kami saat kami sedang memandikan puterinya. Beliau bersabda: \"Mandikanlah sebanyak tiga kali, atau lima kali, atau lebih dari itu, jika kalian berkehendak maka jadikanlah yang terakhir kalinya dengan menggunkan kapur barus, atau sesuatu yang menyerupai kapur barus. Jika kalian telah selesai, maka beritahukanlah aku.\" Kami pun memberitahukan kepada beliau (masuk), beliau lalu memberikan kain penutupnya kepada kami seraya bersabda: \"Sisirlah rambutnya.\" [Muhammad] berkata, \" [Hafshah] telah menceritakannya kepada kami, ia katakan, \"Lalu kami membuat tiga ikatan pada rambutnya.\""},"4108":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا إِلَى قَوْلِهِ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَتْ كَانَ فِيهِ النِّيَاحَةُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِلَّا آلَ فُلَانٍ فَإِنَّهُمْ قَدْ كَانُوا أَسْعَدُونِي فِي الْجَاهِلِيَّةِ فَلَا بُدَّ لِي مِنْ أَنْ أُسْعِدَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا آلَ فُلَانٍ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Hafshah] dari [Ummu 'Athiyah] dia berkata, \"Tatkala ayat ini turun: '(hendaknya kalian tidak menyekutukan Allah dengan sesuatu apapun) ', sampai firman-Nya: '(dan tidak mendurhakaimu dalam kebaikan) ', Ummu Athiyah berkata, \"Termasuk di dalamnya adalah meratapi mayat, \" Ia lalu berkata, \"Wahai Rasulullah, kecuali keluarga fulan, sesungguhnya mereka adalah orang yang membahagiakan aku di masa jahiliyah, oleh karenanya aku harus membahagiakan mereka?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kecuali keluarga fulan.\""},"4109":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ الْأَزْرَقُ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلْنَهَا بِسِدْرٍ وَاغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي قَالَتْ فَلَمَّا فَرَغْنَا آذَنَّاهُ عَلَيْهِ الصَّلَاة وَالسَّلَامُ فَأَلْقَى إِلَيْنَا حَقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] berkata, telah mengabarkan kepada kami [Hisyam] dari [Hafshah] dari [Ummu Athiyah] dia berkata, \"Salah seorang puteri Nabi shallallahu 'alaihi wasallam meninggal dunia, Rasulullah shallallahu 'alaihi wasallam kemudian mendatangi kami, beliau bersabda: \"Mandikanlah dia dengan daun bidara, dan mandikanlah ia dengan bilangan ganjil, tiga kali, atau lima kali, atau lebih dari itu. Jika kalian menghendaki maka jadikanlah bilasan yang terakhir dengan kapur barus, atau sesuatu yang menyerupainya, jika kalian telah selesai maka beritahukanlah aku.\" Ummu Athiyah berkata, \"Setelah selesai, kami lalu memberitahukannya kepada beliau, sehingga beliau pun masuk dan memberikan pakaian penutupnya kepada kami, beliau bersabda: \"Sisirlah rambutnya.\""},"4110":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ خَالِدٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْبَعَثَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ مِنْ الصَّدَقَةِ فَبَعَثْتُ إِلَى عَائِشَةَ بِشَيْءٍ مِنْهَا فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَائِشَةَ قَالَ هَلْ عِنْدَكُمْ مِنْ شَيْءٍ قَالَتْ لَا إِلَّا أَنَّ نُسَيْبَةَ بَعَثَتْ إِلَيْنَا مِنْ الشَّاةِ الَّتِي بَعَثْتُمْ بِهَا إِلَيْهَا فَقَالَ إِنَّهَا قَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Khalid] dari [Hafshah] dari [Ummu 'Atiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus seseorang kepadaku dengan membawa daging kambing sedekah, kemudian aku berikan kepada 'Aisyah sebagian darinya, namun ketika Rasulullah shallallahu 'alaihi wasallam datang kepada 'Aisyah, beliau pun bertanya: \"Apakah kamu mempunyai sesuatu?\" 'Aisyah menjawab, \"Tidak, kecuali kiriman daging kambing dari Nusaibah kepada kita yang pernah tuan berikan kepadanya, \" maka beliau bersabda: \"Sesungguhnya dia telah sampai ke tempatnya.\""},"4111":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ خَالِدٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمْ فِي غُسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami [Isma'il] dari [Khalid] dari [Hafshah] dari [Ummu Athiyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka sewaktu mereka memandikan puterinya: \"Mulailah dari yang sebelah kanan dan pada bagian wudlunya.\""},"4112":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْنُهِيَ عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Muhammad] dari [Ummu 'Athiyah] dia berkata, \"Mengiringi jenazah telah dilarang, namun tidak dipaksakan kepada kami.\""},"4113":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْكَانَ تَعْنِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ عَلَيْنَا فِي الْبَيْعَةِ أَنْ لَا نَنُوحَ فَمَا وَفَتْ امْرَأَةٌ مِنَّا غَيْرَ خَمْسٍ أُمُّ سُلَيْمٍ وَامْرَأَةُ مُعَاذٍ وَابْنَةُ أَبِي سَبْرَةَ وَامْرَأَةٌ أُخْرَى","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Hisyam] dari [Hafshah] dari [Ummu Athiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaiat kami untuk tidak melakukan niyahah, dan tidak ada yang bisa memenuhi itu selian lima orang wanita; Ummu Sulaim, isterinya Mu'adz, puteri Abu Sabrah dan seorang wanita lain.\""},"4114":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَيَزِيدُ بْنُ هَارُونَ قَالَا أَنَا هِشَامٌ عَنْ حَفْصَةَ قَالَتْ حَدَّثَتْنِي أُمُّ عَطِيَّةَ قَالَتْتُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلْنَهَا بِسِدْرٍ وَاغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَنَّنِي قَالَتْ فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُ قَالَتْ أُمُّ عَطِيَّةَ وَضَفَرْنَا رَأْسَ ابْنَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ قُرُونٍ وَأَلْقَيْنَا خَلْفَهَا قَرْنَيْهَا وَنَاصِيَتَهَا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dan [Yazid bin Harun] keduanya berkata, aku [Hisyam] dari [Hafshah] dia berkata, telah menceritakan kepadaku [Ummu 'Athiyah] dia berkata, \"Salah seorang puteri Nabi shallallahu 'alaihi wasallam meninggal dunia, kemudian Rasulullah shallallahu 'alaihi wasallam menemui kami dan bersabda: \"Mandikanlah dia dengan air daun bidara dan mandikanlah dia dengan bilangan ganji, tiga kali, atau lima kali, atau lebih dari itu. Jika kalian berkehendak maka jadikanlah pada bilasan yang terakhir dengan campuran kampur barus atau sesuatu yang menyerupai kapur barus, dan jika telah selesai maka beritahukanlah aku.\" Maka kami pun memberitahukan kepada beliau, beliau kemudian memberikan pakaian penutupnya kepada kami seraya bersabda: \"Sisirlah rambutnya.\" Ummu Athiyah berkata: \"Kami lalu mengepang rambut puteri Nabi shallallahu 'alaihi wasallam menjadi tiga kepang, dan kami menaruh jambul (kepang tengah) dan kedua kepangnya (kanan dan kiri) kebelakang.\""},"4115":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا هِشَامٌ وحَبِيبٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ عَلَى النِّسَاءِ فِيمَا أَخَذَ أَنْ لَا يَنُحْنَ فَقَالَتْ امْرَأَةٌ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَةً أَسْعَدَتْنِي أَفَلَا أُسْعِدُهَا فَقَبَضَتْ يَدَهَا وَقَبَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَلَمْ يُبَايِعْهَا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah mengabarkan kepada kami [Hisyam] dan [Habib] dari [Muhammad bin Sirin] dari [Ummu Athiyah] bahwa Rasulullah shallallahu 'alaihi wasallam mengambil janji pada kaum wanita, dan di antara isinya itu adalah tidak meratapi mayait, maka salah seorang wanita berkata, \"Wahai Rasulullah, sesungguhnya ada seorang wanita yang membahagiakan aku, apakah aku harus membahagiakannya?\" Wanita itu kemudian menggenggam tangannya sendiri, demikian juga dengan Rasulullah shallallahu 'alaihi wasallam; beliau tidak bersedia untuk membaiatnya.\""},"4116":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا إِسْحَاقُ أَبُو يَعْقُوبَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ أَبُو عَبْدِ الرَّحْمَنِ بْنِ عَطِيَّةَ عَنْ جَدَّتِهِ أُمِّ عَطِيَّةَ قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ جَمَعَ نِسَاءَ الْأَنْصَارِ فِي بَيْتٍ ثُمَّ أَرْسَلَ إِلَيْهِنَّ عُمَرَ بْنَ الْخَطَّابِ فَقَامَ عَلَى الْبَابِ فَسَلَّمَ عَلَيْهِنَّ فَرَدَدْنَ السَّلَامَ فَقَالَ أَنَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكُنَّ فَقُلْنَ مَرْحَبًا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولِهِ فَقَالَ تُبَايِعْنَ عَلَى أَنْ لَا تُشْرِكْنَ بِاللَّهِ شَيْئًا وَلَا تَسْرِقْنَ وَلَا تَزْنِينَ وَلَا تَقْتُلْنَ أَوْلَادَكُنَّ وَلَا تَأْتِينَ بِبُهْتَانٍ تَفْتَرِينَهُ بَيْنَ أَيْدِيكُنَّ وَأَرْجُلِكُنَّ وَلَا تَعْصِينَ فِي مَعْرُوفٍ فَقُلْنَ نَعَمْ فَمَدَّ عُمَرُ يَدَهُ مِنْ خَارِجِ الْبَابِ وَمَدَدْنَ أَيْدِيَهُنَّ مِنْ دَاخِلٍ ثُمَّ قَالَ اللَّهُمَّ اشْهَدْ وَأَمَرَنَا أَنْ نُخْرِجَ فِي الْعِيدَيْنِ الْعُتَّقَ وَالْحُيَّضَ وَنُهِينَا عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَا جُمُعَةَ عَلَيْنَا فَسَأَلْتُهُ عَنْ الْبُهْتَانِ وَعَنْ قَوْلِهِ{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَ هِيَ النِّيَاحَةُ","id":"Telah menceritakan kepada kami [Abdus Shamad] berkata, telah menceritakan kepada kami [Ishaq Abu Ya'qub] berkata, telah menceritakan kepada kami [Isma'il Abu Abdurrahman bin 'Athiyah] dari neneknya [Ummu Athiyah] dia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam sampai di Madinah, maka para wanita Anshar berkumpul di sebuah rumah. Umar bin Khatthab lalu diutus untuk menemui mereka, Umar kemudian berdiri di depan pintu dan memberi salam kepada mereka, mereka pun menjawab salamnya. Umar lalu berkata, \"Aku adalah utusan Rasulullah shallallahu 'alaihi wasallam kepada kalian, \" mereka menjawab, \"Selamat datang wahai Rasulullah dan utusannya.\" Umar berkata, \"Apakah kalian bersedia baiat untuk tidak menyekutukan Allah dengan sesuatu pun, tidak mencuri, tidak berzina, tidak membunuh anak-anak, tidak mengada-ngada dengan kedustaan yang diperbuat oleh tangan-tangan dan kaki-kaki kalian, serta tidak durhaka di dalam hal yang ma'ruf?\" Mereka menjawab, \"Ya.\" Kemudian Umar mengulurkan tangannya dari luar pintu, dan mereka pun mengulurkan tangan mereka dari dalam pintu, kemudian Umar berkata, \"Ya Allah, saksikanlah.\" Umar kemudian menyuruh kami untuk keluar pada dua hari raya (idul fitri dan idul adha), baik seorang budak atau yang sedang haid, dan kami dilarang untuk ikut mengiringi jenazah dan tidak ada kewajiban shalat jumat. Kemudian aku bertanya kepadanya mengenai kedustaan dan tentang firman Allah: '(dan tidak akan mendurhakaimu dalam urusan yang baik) ' (Qs. Al Mumtahanah: 12), Umar menjawab, \"Maksudnya adalah meratapi mayat.\""},"4117":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدٍ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ أَحَدَكُمْ إِذَا نَزَلَ مَنْزِلًا قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ فِي ذَلِكَ الْمَنْزِلِ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْهُ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Wuhaib bin Khalid] berkata, telah menceritakan kepada kami [Muhammad bin Ajlan] dari [Ya'qub bin Abdullah bin Al Asyaj] dari [Sa'id bin Musayyab] dari [Sa'd] dari [Khaulah binti Hakim] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya salah seorang dari kalian saat singgah di suatu tempat mengucapkan: 'A'UUDZUU BIKALIMAATILLAAHIT TAAMMAAT MIN SYARRI MAA KHALAQA (Aku berlindung dengan nama Allah yang Maha sempurna, dari kejahatan apa-apa yang Dia ciptakan) ', maka tidak ada sesuatu yang membahayakan kepadanya di tempat itu hingga ia meninggalkannya.\""},"4118":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ عَنْ حَجَّاجٍ وَيَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا الْحَجَّاجُ عَنِ الرَّبِيعِ بْنِ مَالِكٍ قَالَ قَالَتْ خَوْلَةُ بِنْتُ حَكِيمٍ قَالَ مُحَمَّدُ بْنُ يَزِيدَ امْرَأَةُ عُثْمَانَ بْنِ مَظْعُونٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يَنْزِلُ مَنْزِلًا فَيَقُولُ حِينَ يَنْزِلُ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ شَرِّ مَا خَلَقَ وَقَالَ يَزِيدُ ثَلَاثًا إِلَّا وُقِيَ شَرَّ مَنْزِلِهِ ذَلِكَ حَتَّى يَظْعَنَ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yazid] dari [Hajjaj], dan [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Al Hajjaj] dari [Ar Rabi' bin Malik] berkata; [Khaulah binti Hakim], [Muhammad bin Yazid] berkata; bahwa dia (Khaulah) adalah isteri Utsman bin Math'un, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang Muslim singgah di suatu tempat kemudian sewaktu singgah dia mengucapkan: 'A'UUDZUU BIKALIMAATILLAAHIT TAAMMAAT MIN SYARRI MAA KHALAQA (Aku berlindung dengan nama Allah yang Maha sempurna, dari kejahatan apa-apa yang Dia ciptakan) ' -Yazid berkata; Sebanyak tiga kali.- melainkan ia akan dijaga dari kejahatan tempat tersebut hingga ia meninggalkannya.\""},"4119":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ أَنَّهَاسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ فَقَالَ لَيْسَ عَلَيْهَا غُسْلٌ حَتَّى يَنْزِلَ الْمَاءُ كَمَا أَنَّ الرَّجُلَ لَيْسَ عَلَيْهِ غُسْلٌ حَتَّى يُنْزِلَ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ali bin Yazid bin Jud'an] dari [Sa'id bin Musayyab] dari [Khaulah binti Hakim], bahwa dia bertanya kepada Nabi shallallahu 'alaihi wasallam tentang seorang wanita yang bermimpi waktu tidurnya sabagaimana yang dimimpikan laki laki (bersetubuh). Maka Nabi menjawab: \"Tidak ada mandi di dalamnya sehingga dia mengeluarkan cairan sebagaimana tidak ada mandi bagi laki-laki hingga ia mengeluarkan cairan (mani).\""},"4120":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ عَطَاءً الْخُرَاسَانِيَّ يُحَدِّثُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ خَوْلَةَ بِنْتَ حَكِيمٍ السُّلَمِيَّةَ وَهِيَ إِحْدَى خَالَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَحْتَلِمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِتَغْتَسِلْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata, telah menceritakan kepadaku [Syu'bah] berkata, aku mendengar [Atha' Al Khurasani] menceritakan dari [Sa'id bin Musayyab] bahwa Khaulah binti Hakim As Sulamiyah -dia adalah salah seorang bibi Nabi shallallahu 'alaihi wasallam-, dia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai seorang wanita yang mimpi basah, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya ia mandi.\""},"4121":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنِ ابْنِ أَبِي سُوَيْدٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ قَالَزَعَمَتْ الْمَرْأَةُ الصَّالِحَةُ خَوْلَةُ بِنْتُ حَكِيمٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مُحْتَضِنًا أَحَدَ ابْنَيْ ابْنَتِهِ وَهُوَ يَقُولُ وَاللَّهِ إِنَّكُمْ لَتُجَبِّنُونَ وَتُبَخِّلُونَ وَإِنَّكُمْ لَمِنْ رَيْحَانِ اللَّهِ عَزَّ وَجَلَّ وَإِنَّ آخِرَ وَطْأَةٍ وَطِئَهَا اللَّهُ بِوَجٍّ وَقَالَ سُفْيَانُ مَرَّةً إِنَّكُمْ لَتُبَخِّلُونَ وَإِنَّكُمْ لَتُجَبِّنُونَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari [Abu Suwaid] dari [Umar bin Abdul Aziz] dia berkata, \"Seorang wanita shalihah, [Khaulah binti Hakim], menyatakan bahwa Rasulullah shallallahu 'alaihi wasallam keluar sambil mendekap salah satu dari dua anak lelaki dari anak perempuannya, dan beliau bersabda: \"Demi Allah, sungguh kalian akan menjadikan bakhil, takut dan bodoh. Dan sesungguhnya kalian adalah rizki dan rahmat dari Allah dan yang paling terakhir Allah lewatkan dengan cepat.\" Dalam riwayat lain Shafwan berkata: \"Sesungguhnya kalian pasti menjadikan bakhil dan takut.\""},"4122":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لَكَ حَوْضًا قَالَ نَعَمْ وَأَحَبُّ مَنْ وَرَدَهُ عَلَيَّ قَوْمُكِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] dan aku telah mendengarnya dari [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Khaulah binti Hakim] dia berkata, \"Aku bertanya, \"Wahai Rasulullah, apakah tuan memiliki Haudl (telaga)?\" beliau menjawab: \"Ya, dan aku menginginkan orang yang mengunjungiku adalah kaummu.\""},"4123":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ يُحَنَّسَأَنَّ حَمْزَةَ بْنَ عَبْدِ الْمُطَّلِبِ لَمَّا قَدِمَ الْمَدِينَةَ تَزَوَّجَ خَوْلَةَ بِنْتَ قَيْسِ بْنِ قَهْدٍ الْأَنْصَارِيَّةَ مِنْ بَنِي النَّجَّارِ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزُورُ حَمْزَةَ فِي بَيْتِهَا وَكَانَتْ تُحَدِّثُهُ عَنْهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ قَالَتْ جَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقُلْتُ يَا رَسُولَ اللَّهِ بَلَغَنِي عَنْكَ أَنَّكَ تُحَدِّثُ أَنَّ لَكَ يَوْمَ الْقِيَامَةِ حَوْضًا مَا بَيْنَ كَذَا إِلَى كَذَا قَالَ أَجَلْ وَأَحَبُّ النَّاسِ إِلَيَّ أَنْ يَرْوَى مِنْهُ قَوْمُكِ قَالَتْ فَقَدَّمْتُ إِلَيْهِ بُرْمَةً فِيهَا خُبْزَةٌ أَوْ حَرِيرَةٌ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فِي الْبُرْمَةِ لِيَأْكُلَ فَاحْتَرَقَتْ أَصَابِعُهُ فَقَالَ حَسِّ ثُمَّ قَالَ ابْنُ آدَمَ إِنْ أَصَابَهُ الْبَرْدُ قَالَ حَسِّ وَإِنْ أَصَابَهُ الْحَرُّ قَالَ حَسِّ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata, telah menceritakan kepada kami [Jarir] -yakni Ibnu Hazim- dari [Yahya bin Sa'id] dari [Yuhannas], bahwa sewaktu Hamzah bin Abdul Mutthalib sampai di Madinah, dia menikahi [Khaulah binti Qais bin Qahd Al Anshariyah] dari bani Najjar.\" Yuhannas berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa mengunjungi Hamzah di rumah isterinya -dan isteri Hamzah biasa meriwayatkan hadits dari Rasulullah shallallahu 'alaihi wasallam- dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami di suatu hari, kemudian aku berkata, \"Wahai Rasulullah, telah sampai kepadaku mengenai dirimu, bahwa tuan telah menceritakan bahwa tuan memiliki telaga pada hari Kiamat, yang jaraknya antara ini sampai ini?\" Beliau menjawab: \"Ya, dan aku lebih suka dari manusia yang meminumnya adalah kaummu.\" Khaulah berkata, \"Kemudian aku memberikan kepada beliau sebuah periuk yang berisikan roti, atau air panas, kemudian Rasulullah shallallahu 'alaihi wasallam memasukkan tangannya ke dalam periuk untuk makan sehingga jarinya kepanasan. Beliau pun berteriak: \"Auh!\" Kemudian beliau bersabda: \"Jika anak adam terkena sesuatu yang dingin, ia berkata Auh, dan jika terkena sesuatu yang panas ia mengatakan Auh.\""},"4124":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ أَنَّ عُمَرَ بْنَ كَثِيرِ بْنِ أَفْلَحَ أَخْبَرَهُ أَنَّهُ سَمِعَ عُبَيْدَ سَنُوطَا يُحَدِّثُ أَنَّهُ سَمِعَ خَوْلَةَ بِنْتَ قَيْسٍ وَقَدْ قَالَ خَوْلَةُ الْأَنْصَارِيَّةُ الَّتِي كَانَتْ عِنْدَ حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِ تُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى حَمْزَةَ بَيْتَهُ فَتَذَاكَرُوا الدُّنْيَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الدُّنْيَا خَضِرَةٌ حُلْوَةٌ مَنْ أَخَذَهَا بِحَقِّهَا بُورِكَ لَهُ فِيهَا وَرُبَّ مُتَخَوِّضٍ فِي مَالِ اللَّهِ وَمَالِ رَسُولِهِ لَهُ النَّارُ يَوْمَ يَلْقَى اللَّهَ","id":"Telah menceritakan kepada kami [Yazid Bin Harun] berkata, telah menceriatakn kepada kami [Yahya bin Sa'id Al Anshari] bahwa [Umar bin Katsir bin Aflah] telah mengabarkan kepadanya, bahwa dia telah mendengar [Ubaid Sanuth] menceritakan, bahwa dia telah mendengar [Khaulah binti Qais], Ubaid berkata; Khaulah al Anshariyah, isteri Hamzah bin Abdu Muthalib, menceritakan bahwa Rasulullah shallallahu 'alaihi wasallamdatang pernah ke rumah Hamzah, sementara para sahabat sedang membicarakan tentang dunia, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya dunia itu hijau dan manis, barangsiapa mengambilnya sesuai dengan haknya maka dia mendapat keberkahannya. Dan berapa banyak orang yang membelanjakan harta Allah dan Rasul-Nya kemudian baginya adalah api neraka ketika dia bertemu dengan Allah.\""},"4125":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنِ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ الزُّرَقِيِّ عَنْ خَوْلَةَ بِنْتِ ثَامِرٍ الْأَنْصَارِيَّةِ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الدُّنْيَا خَضِرَةٌ حُلْوَةٌ وَإِنَّ رِجَالًا يَتَخَوَّضُونَ فِي مَالِ اللَّهِ عَزَّ وَجَلَّ بِغَيْرِ حَقٍّ لَهُمْ النَّارُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] berkata, telah menceritakan kepada kami [Sa'id] -yakni anak laki-lakinya Abu Ayyub- dia berkata, telah menceritakan kepadaku [Abu Al Aswad] dari [Nu'man bin Abu Ayyasy Az Zuraqi] dari [Khaulah binti Tsamir Al Anshariyah] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dunia itu hijau dan manis, dan sungguh ada beberapa laki-laki yang membelanjakan harta Allah dengan tanpa hak, kemudian mendapatkan api neraka pada hari Kiamat.\""},"4126":{"ar":"حَدَّثَنَا سَعْدُ بْنُ إِبْرَاهِيمَ وَيَعْقُوبُ قَالَا حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي مَعْمَرُ بْنُ عَبْدِ اللَّهِ بْنِ حَنْظَلَةَ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ خَوْلَةَ بِنْتِ ثَعْلَبَةَقَالَتْ وَاللَّهِ فِيَّ وَفِي أَوْسِ بْنِ صَامِتٍ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ صَدْرَ سُورَةِ الْمُجَادَلَةِ قَالَتْ كُنْتُ عِنْدَهُ وَكَانَ شَيْخًا كَبِيرًا قَدْ سَاءَ خُلُقُهُ وَضَجِرَ قَالَتْ فَدَخَلَ عَلَيَّ يَوْمًا فَرَاجَعْتُهُ بِشَيْءٍ فَغَضِبَ فَقَالَ أَنْتِ عَلَيَّ كَظَهْرِ أُمِّي قَالَتْ ثُمَّ خَرَجَ فَجَلَسَ فِي نَادِي قَوْمِهِ سَاعَةً ثُمَّ دَخَلَ عَلَيَّ فَإِذَا هُوَ يُرِيدُنِي عَلَى نَفْسِي قَالَتْ فَقُلْتُ كَلَّا وَالَّذِي نَفْسُ خُوَيْلَةَ بِيَدِهِ لَا تَخْلُصُ إِلَيَّ وَقَدْ قُلْتَ مَا قُلْتَ حَتَّى يَحْكُمَ اللَّهُ وَرَسُولُهُ فِينَا بِحُكْمِهِ قَالَتْ فَوَاثَبَنِي وَامْتَنَعْتُ مِنْهُ فَغَلَبْتُهُ بِمَا تَغْلِبُ بِهِ الْمَرْأَةُ الشَّيْخَ الضَّعِيفَ فَأَلْقَيْتُهُ عَنِّي قَالَتْ ثُمَّ خَرَجْتُ إِلَى بَعْضِ جَارَاتِي فَاسْتَعَرْتُ مِنْهَا ثِيَابَهَا ثُمَّ خَرَجْتُ حَتَّى جِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسْتُ بَيْنَ يَدَيْهِ فَذَكَرْتُ لَهُ مَا لَقِيتُ مِنْهُ فَجَعَلْتُ أَشْكُو إِلَيْهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَلْقَى مِنْ سُوءِ خُلُقِهِ قَالَتْ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا خُوَيْلَةُ ابْنُ عَمِّكِ شَيْخٌ كَبِيرٌ فَاتَّقِي اللَّهَ فِيهِ قَالَتْ فَوَاللَّهِ مَا بَرِحْتُ حَتَّى نَزَلَ فِيَّ الْقُرْآنُ فَتَغَشَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَ يَتَغَشَّاهُ ثُمَّ سُرِّيَ عَنْهُ فَقَالَ لِي يَا خُوَيْلَةُ قَدْ أَنْزَلَ اللَّهُ فِيكِ وَفِي صَاحِبِكِ ثُمَّ قَرَأَ عَلَيَّ{ قَدْ سَمِعَ اللَّهُ قَوْلَ الَّتِي تُجَادِلُكَ فِي زَوْجِهَا وَتَشْتَكِي إِلَى اللَّهِ وَاللَّهُ يَسْمَعُ تَحَاوُرَكُمَا إِنَّ اللَّهَ سَمِيعٌ بَصِيرٌ إِلَى قَوْلِهِ وَلِلْكَافِرِينَ عَذَابٌ أَلِيمٌ }فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرِيهِ فَلْيُعْتِقْ رَقَبَةً قَالَتْ فَقُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا عِنْدَهُ مَا يُعْتِقُ قَالَ فَلْيَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَتْ فَقُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّهُ شَيْخٌ كَبِيرٌ مَا بِهِ مِنْ صِيَامٍ قَالَ فَلْيُطْعِمْ سِتِّينَ مِسْكِينًا وَسْقًا مِنْ تَمْرٍ قَالَتْ قُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا ذَاكَ عِنْدَهُ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّا سَنُعِينُهُ بِعَرَقٍ مِنْ تَمْرٍ قَالَتْ فَقُلْتُ وَأَنَا يَا رَسُولَ اللَّهِ سَأُعِينُهُ بِعَرَقٍ آخَرَ قَالَ قَدْ أَصَبْتِ وَأَحْسَنْتِ فَاذْهَبِي فَتَصَدَّقِي عَنْهُ ثُمَّ اسْتَوْصِي بِابْنِ عَمِّكِ خَيْرًا قَالَتْ فَفَعَلْتُقَالَ سَعْدٌ الْعَرَقُ الصَّنُّ","id":"Telah menceritakan kepada kami [Sa'd bin Ibrahim] dan [Ya'qub] keduanya berkata, [ayahku] berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] berkata, telah menceritakan kepadaku [Ma'mar bin Abdullah bin Hanzhalah] dari [Yusuf bin Abdullah bin Salam] dari [Khaulah binti Tsa'labah] dia berkata, \"Demi Allah, pada diriku dan diri Aus bin Shamit, Allah telah menurunkan surat Al Mujadalah.\" Khaulah berkata, \"Aku adalah isterinya (Aus bin Shamit), dia adalah laki-laki yang telah lanjut usia, buruk akhlaknya dan suka marah.\" Khaulah melanjutkan, \"Suatu hari dia (suaminya) masuk menemuiku, namun aku menolaknya dengan sesuatu hingga ia pun marah seraya berkata, 'kamu bagiku seperti punggung ibuku! ' Khaulah berkata, \"Kemudian Aus pergi dan duduk bersama kaumnya, kemudian masuk kembali menemuiku dan menginginkan untuk bersetubuh. Aku lalu berkata, \"Demi jiwa Khaulah yang berada di genggaman-Nya, kamu tidak akan dapat menguasai diriku, sungguh kamu telah menetapkan sesuatu yang kamu ucapkan sampai Allah dan Rasul-Nya menghukumi di antara kita dengan hukum-Nya.\" Khaulah berkata, \"Namun kemudian dia memaksaku, tapi aku dapat menolaknya dan mengalahkannya sebagaimana seorang wanita mengalahkan orang yang tua yang lemah, kemudian aku melemparkannya.\" Khaulah berkata, \"Kemudian aku keluar ke salah satu rumah tetanggaku, aku pun meminjam baju darinya, setelah itu aku keluar menemui Rasulullah shallallahu 'alaihi wasallam, aku lalu duduk di hadapannya dan melaporkan atas apa yang telah menimpaku, aku adukan kepada beliau perihal akhlaknya yang buruk.\" Khaulah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Khuwailah, anak pamanmu adalah seorang yang telah lanjut usia, hendaklah kamu bertakwa kepada Allah dalam perkaranya.\" Khaulah berkata, \"Demi Allah, tidaklah aku meninggalkan tempat tersebut sehingga turun ayat dalam al Qur'an tentang diriku, Rasulullah shallallahu 'alaihi wasallam pingsan terhadap sesuatu yang menimpanya, kemudian beliau siuman dan bersabda kepadaku: \"Wahai Khuwailah, sungguh Allah telah menurunkan kepadamu dan kepada suamimu, \" kemudian beliau membaca untukku: '(Sesungguhnya Allah telah mendengar perkataan wanita yang memajukan gugatan kepada kamu tentang suaminya, dan mengadukan (halnya) kepada Allah. Dan Allah mendengar soal jawab antara kamu berdua. Sesungguhnya Allah Maha Mendengar lagi Maha Melihat), sampai firman-Nya: '(dan bagi orang-orang kafir ada siksaan yang sangat pedih) '. (Qs. Al Mujadalah: 1-4). Kemudian Rasulullah shallallahu 'alaihi wasallambersabda kepadaku: \"Suruhlah dia untuk memerdekakan budak.\" Khaulah berkata, \"Maka aku berkata, \"Demi Allah, wahai Rasulullah, dia tidak mempunyai sesuatu untuk memerdekakan budak!\" Beliau bersabda: \"Suruhlah dia untuk berpuasa dua bulan berturut-turut.\" Khaulah berkata, \"Maka aku berkata, \"Demi Allah, wahai Rasulullah, sesungguhnya dia adalah orang yang sudah lanjut usia, dan tidak sanggup untuk berpuasa.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Suruhlah dia untuk memberi makan enam puluh orang miskin, atau kurma satu wasaq.\" Khaulah berkata, \"Dan aku berkata, \"Demi Allah, wahai Rasulullah, dia tidak memiliki yang seperti itu.\" Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya aku akan membantunya dengan sekeranjang kurma, \" Khaulah lantas berkata, \"Wahai Rasulullah, dan aku akan membantunya juga dengan sekeranjang yang lain.\" Beliau bersabda: \"Sungguh, kamu tepat dan telah berbuat baik, maka pergilah kamu dan bersedekahlah darinya, kemudian berwasiatlah terhadap anak pamanmu dengan kebaikan.\" Khaulah berkata, \"Maka aku pun melaksanakannya.\" Sa'd bekata, \"Al Araq adalah sejenis keranjang.\""},"4127":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ قَالَ سَمِعْتُ فَاطِمَةَ بِنْتَ قَيْسٍ تَقُولُأَرْسَلَ إِلَيَّ زَوْجِي أَبُو عَمْرِو بْنُ حَفْصِ بْنِ الْمُغِيرَةِ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ بِطَلَاقِي وَأَرْسَلَ إِلَيَّ خَمْسَةَ آصُعِ شَعِيرٍ فَقُلْتُ مَا لِي نَفَقَةٌ إِلَّا هَذَا وَلَا أَعْتَدُّ إِلَّا فِي بَيْتِكُمْ قَالَ لَا فَشَدَدْتُ عَلَيَّ ثِيَابِي ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ كَمْ طَلَّقَكِ قُلْتُ ثَلَاثًا قَالَ صَدَقَ لَيْسَ لَكِ نَفَقَةٌ وَاعْتَدِّي فِي بَيْتِ ابْنِ عَمِّكِ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ ضَرِيرُ الْبَصَرِ تُلْقِينَ ثِيَابَكِ عَنْكِ فَإِذَا انْقَضَتْ عِدَّتُكِ فَآذِنِينِي قَالَتْ فَخَطَبَنِي خُطَّابٌ فِيهِمْ مُعَاوِيَةُ وَأَبُو جَهْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مُعَاوِيَةَ تَرِبٌ خَفِيفُ الْحَالِ وَأَبُو جَهْمٍ يَضْرِبُ النِّسَاءَ وَلَكِنْ أَيْ فِيهِ شِدَّةٌ عَلَى النِّسَاءِ عَلَيْكِ بِأُسَامَةَ بْنِ زَيْدٍ أَوْ قَالَ انْكِحِي أُسَامَةَ بْنَ زَيْدٍحَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ تَمِيمٍ مَوْلَى فَاطِمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Bakar bin Abu Jahm] dia berkata, aku mendengar [Fatimah binti Qais] berkata, \"Suamiku, Abu Amru bin Amru bin Mughirah, mengutus Ayasy bin Abu Rabi'ah kepadaku mengabarkan bahwa dia telah mentakku, dan ia juga mengirimkan untukku lima sha' gandum, maka aku berkata, \"Aku tidak memiliki nafkah kecuali ini, dan aku tidak memiliki tempat tinggal kecuali di tempatmu.\" Abu Amru berkata, \"Tidak!\" Fatimah berkata, \"Maka aku mengencangkan pakaianku lalu aku menemui Nabi shallallahu 'alaihi wasallam dan menyebutkan hal itu kepada beliau, maka beliau bersabda: \"Berapa kali dia menceraikanmu?\" aku menjawab, \"Tiga kali, \" beliau bersabda: \"Dia benar, kamu tidak lagi mendapatkan nafkah, dan tinggalah di rumah anak pamanmu, Ibnu Ummi Maktum, sesungguhnya dia adalah laki-laki yang buta, tidak mengapa kamu menanggalkan pakaianmu, jika iddahmu telah berakhir maka beritahukanlah kepadaku.\" Fatimah berkata, \"Maka datanglah beberapa orang untuk meminangku, di antaranya adalah Mu'awiyah dan Abu Jahm, Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sesungguhnya Mu'awiyah adalah orang yang miskin dan juga ringan dalam setiap keadaan, sedangkan Abu Jahm suka memukul wanita. Akan tetapi manakah ada yang keras terhadap wanita pada diri Usamah bin Zaid, \" atau beliau bersabda: \"menikahlah dengan Usamah bin Zaid.\" Telah menceritakan kepada kami [Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari [Tamim] bekas budak Fatimah dari [Fatimah binti Qais], seperti hadits tersebut.\""},"4128":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ قَالَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍأَنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا فَأَمَرَهَا رَسُولُ ال��َّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَعْتَدَّ عِنْدَ ابْنِ أُمِّ مَكْتُومٍ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Zakaria] dari [Amir] berkata, telah menceritakan kepadaku [Fatimah binti Qais], bahwa suaminya telah menceraikannya dengan talak tiga, Rasulullah shallallahu 'alaihi wasallam kemudian menyuruhnya untuk menunggu masa iddahnya di (rumah) Ibnu Ummi Maktum.\""},"4129":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ سَمِعَهُ مِنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ سَمِعْتُ فَاطِمَةَ بِنْتَ قَيْسٍ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحْلَلْتِ فَآذِنِينِي فَآذَنَتْهُ فَخَطَبَهَا مُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ وَأَبُو الْجَهْمِ وَأُسَامَةُ بْنُ زَيْدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مُعَاوِيَةُ فَرَجُلٌ تَرِبٌ لَا مَالَ لَهُ وَأَمَّا أَبُو الْجَهْمِ فَرَجُلٌ ضَرَّابٌ لِلنِّسَاءِ وَلَكِنْ أُسَامَةَ قَالَ فَقَالَتْ بِيَدِهَا هَكَذَا أُسَامَةُ تَقُولُ لَمْ تُرِدْهُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَاعَةُ اللَّهِ وَطَاعَةُ رَسُولِهِ خَيْرٌ لَكِ فَتَزَوَّجَتْهُ فَاغْتَبَطَتْهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dia mendengarnya dari [Abu Bakar bin Abu Jahm] aku mendengar dari [Fatimah binti Qais] di berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku, \"Jika kamu telah hahal kabarkanlah kepadaku.\" Fatimah kemudian memberitahukan kepada beliau, lalu dia pun dipinang oleh Mu'awiyah bin Abu Sufyan, Abu Jahm dan juga Usamah bin Zaid, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Mu'awiyah adalah laki-laki yang miskin dan tidak mempunyai kekayaan, sedangkan Abu Jahm adalah laki-laki yang suka memukul wanita, akan tetapi Usamah, Abu Bakar berkata, \"Fatimah lalu berkata dengan isyarat tangannya seperti ini, maksudnya dia tidak suka.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepadanya: \"Taat kepada Allah dan Rasul-Nya, itu lebih baik bagimu.\" Maka Fatimah pun menikah dengannya, dan ia pun bahagia.\""},"4130":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي عَاصِمٍ عَنِ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الْمَدِينَةَ فَقَالَ هِيَ طَيْبَةُ","id":"Telah menceritakan kepada kami [Waki'] dari [Abu Ashim] dari [As Sya'bi] dari [Fatimah binti Qais] dari Nabi shallallahu 'alaihi wasallam, tentang kota kota Madinah, beliau bersabda: \"Dia adalah tempat yang baik.\""},"4131":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ أَبَا عَمْرِو بْنِ حَفْصٍ طَلَّقَهَا الْبَتَّةَ وَهُوَ غَائِبٌ فَأَرْسَلَ إِلَيْهَا وَكِيلَهُ بِشَعِيرٍ فَتَسَخَّطَتْهُ فَقَالَ وَاللَّهِ مَا لَكِ عَلَيْنَا مِنْ شَيْءٍ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ لَيْسَ لَكِ نَفَقَةٌ عَلَيْهِ فَأَمَرَهَا أَنْ تَعْتَدَّ فِي بَيْتِ أُمِّ شَرِيكٍ ثُمَّ قَالَ تِلْكَ امْرَأَةٌ يَغْشَاهَا أَصْحَابِي فَاعْتَدِّي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ أَعْمَى تَضَعِينَ ثِيَابَكِ عِنْدَهُ فَإِذَا حَلَلْتِ فَآذِنِينِي فَلَمَّا حَلَلْتُ ذَكَرْتُ لَهُ أَنَّ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ وَأَبَا الْجَهْمِ خَطَبَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَبُو الْجَهْمِ فَلَا يَضَعُ عَصَاهُ وَأَمَّا مُعَاوِيَةُ فَصُعْلُوكٌ لَا مَالَ لَهُ انْكِحِي أُسَامَةَ بْنَ زَيْدٍحَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّ أَبَا عَمْرِو بْنَ حَفْصٍ طَلَّقَهَا الْبَتَّةَ وَهُوَ غَائِبٌ فَذَكَرَ مَعْنَاهُ وَقَالَ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ فَكَرِهْتُهُ فَقَالَ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ فَنَكَحْتُهُ فَجَعَلَ اللَّهُ لِي فِيهِ خَيْرًا","id":"Abdullah berkata; Aku membacakannya di hadapan [Abdurrahman bin Mahdi]: [Malik] dari [Abdullah bin Yazid] bekas budak Al Aswad bin Sufyan, dari [Abu Salamah bin Abdurrahman] dari [Fatimah binti Qais], bahwa Abu Amru bin Hafsh telah menceraikannya dengan talak tiga, sedangkan dia (Abu Amru) tidak ada di tempat, sehingga dia mengutus wakilnya untuk memberikan gandum kepada Fatimah. Hal itu menjadikan Fatimah marah, maka Abu Amru pun berkata, \"Demi Allah, sebenarnya kamu tidak mempunyai hak lagi atas kami sedikitpun!\" Fatimah kemudian datang menemui Rasulullah shallallahu 'alaihi wasallam dan mengadukan hal itu kepada beliau, maka beliau bersabda: \"Kamu tidak berhak lagi untuk mendapatkan nafkah atasnya.\" Kemudian beliau menyuruhnya untuk menunggu masa iddahnya di tempatnya Ummu Syarik, lalu beliau bersabda: \"Wanita itu sering dikunjungi oleh para sahabatku, maka tunggulah masa iddahmu bersama dengan Ibnu Ummi Maktum, sesungguhnya dia seorang yang buta matanya, sehingga kamu bisa menanggalkan pakaianmu, jika kamu telah halal maka beritahukanlah aku.\" Saat aku telah halal, aku pun memberitahukan kepada beliau bahwa Mu'awiyah bin Abu Sufyan dan Abu Jahm datang melamarku, lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Abu Jahm tidak pernah menaruh tongkatnya (suka memukul), sedangkan Mu'awiyah adalah seorang yang miskin dan tidak memiliki harta benda. Menikahlah dengan Usamah bin Zaid.\" Tela menceritakan kepada kami [Ishaq bin 'Isa] dia berkata, telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Yazid] bekas budak Al Aswad bin Sufyan, dari [Abu Salamah bin Abdurrahman] dari [Fatimah binti Qais] bahwa Abu Amru bin Hafsh telah menceraikannya dengan talak tiga, sedangkan dia tidak ada di tempatnya… kemudian dia menyebutkan maknanya, beliau bersabda: \"Menikahlah dengan Usamah bin Zaid, \" namun Fatimah membencinya, dan beliau tetap bersabda: \"Menikahlah dengan Usamah bin Zaid.\" Aku pun menikah dengannya, dan Allah menjadikan kebaikan padaku dalam pernikahan tersebut.\""},"4132":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا الْحَسَنُ يَعْنِي ابْنَ صَالِحٍ عَنِ السُّدِّيِّ عَنِ الْبَهِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَمْ يَجْعَلْ لَهَا سُكْنَى وَلَا نَفَقَةًقَالَ حَسَنٌ قَالَ السُّدِّيُّ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ وَالشَّعْبِيِّ فَقَالَا قَالَ عُمَرُ لَا تُصَدِّقْ فَاطِمَةَ لَهَا السُّكْنَى وَالنَّفَقَةُ","id":"Telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Al Hasan] -yakni Ibnu Shalih- dari [As Sudi] dari [Al Bahi] dari [Fatimah binti Qais] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau tidak menjadikan baginya tempat tinggal dan juga nafkah, Hasan berkata, As Sudi berkata, kemudian aku menyebutkan hal itu kepada Ibrahim dan As Sya'bi maka keduanya berkata, Umar berkata, \"Fatimah tidak mendapatkan tempat tinggal dan nafkah (setelah talak tiga).\""},"4133":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ ذَاتَ يَوْمٍ مُسْرِعًا فَصَعِدَ الْمِنْبَرَ فَنُودِيَ فِي النَّاسِ الصَّلَاةُ جَامِعَةٌ وَاجْتَمَعَ النَّاسُ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي لَمْ أَدْعُكُمْ لِرَغْبَةٍ نَزَلَتْ وَلَا لِرَهْبَةٍ وَلَكِنَّ تَمِيمًا الدَّارِيَّ أَخْبَرَنِي أَنَّ نَاسًا مِنْ أَهْلِ فِلَسْطِينَ رَكِبُوا الْبَحْرَ فَقَذَفَتْهُمْ الرِّيحُ إِلَى جَزِيرَةٍ مِنْ جَزَائِرِ الْبَحْرِ فَإِذَا هُمْ بِدَابَّةٍ أَشْعَرَ لَا يُدْرَى أَذَكَرٌ أَمْ أُنْثَى مِنْ كَثْرَةِ شَعْرِهِ فَقَالُوا مَنْ أَنْتَ فَقَالَتْ أَنَا الْجَسَّاسَةُ قَالُوا فَأَخْبِرِينَا قَالَتْ مَا أَنَا بِمُخْبِرَتِكُمْ وَلَا بِمُسْتَخْبِرَتِكُمْ وَلَكِنْ فِي هَذَا الدَّيْرِ رَجُلٌ فَقِيرٌ إِلَى أَنْ يُخْبِرَكُمْ وَيَسْتَخْبِرَكُمْ فَدَخَلُوا الدَّيْرَ فَإِذَا رَجُلٌ ضَرِيرٌ وَمُصَفَّدٌ فِي الْحَدِيدِ فَقَالَ مَنْ أَنْتُمْ قُلْنَا نَحْنُ الْعَرَبُ قَالَ هَلْ بُعِثَ فِيكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا نَعَمْ قَالَ فَهَلْ اتَّبَعَهُ الْعَرَبُ قَالُوا نَعَمْ قَالَ ذَاكَ خَيْرٌ لَهُمْ قَالَ مَا فَعَلَتْ فَارِسُ هَلْ ظَهَرَ عَلَيْهَا قَالُوا لَمْ يَظْهَرْ عَلَيْهَا بَعْدُ قَالَ أَمَا إِنَّهُ سَيَظْهَرُ عَلَيْهَا ثُمَّ قَالَ مَا فَعَلَتْ عَيْنُ زُغَرَ قَالُوا هِيَ تَدْفُقُ مَلْأَى قَالَ فَمَا فَعَلَتْ بُحَيْرَةُ طَبَرِيَّةَ قَالُوا هِيَ تَدْفُقُ مَلْأَى قَالَ فَمَا فَعَلَتْ نَخْلُ بَيْسَانَ هَلْ أَطْعَمَ بَعْدُ قَالُوا قَدْ أَطْعَمَ أَوَائِلُهُ قَالَ فَوَثَبَ وَثْبَةً ظَنَنَّا أَنَّهُ سَيَفْلِتُ فَقُلْنَا مَنْ أَنْتَ قَالَ أَنَا الدَّجَّالُ أَمَا إِنِّي سَأَطَأُ الْأَرْضَ كُلَّهَا غَيْرَ مَكَّةَ وَطَيْبَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْشِرُوا مَعْشَرَ الْمُسْلِمِينَ فَإِنَّ هَذِهِ طَيْبَةُ لَا يَدْخُلُهَا الدَّجَّالُ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah mengabarkan kepada kami [Daud] dari [Amir] dari [Fatimah binti Qais], bahwa suatu hari Nabi shallallahu 'alaihi wasallam datang dengan tergesa-gesa kemudian naik mimbar, lalu diserulah 'Ash Shalaatu Jaami'ah (Mari shalat berjama'ah). Orang-orang pun berkumpul, beliau kemudian bersabda: \"Wahai sekalian manusia, sesungguhnya aku tidak menyeru kalian karena suatu hal yang membuat kalian terkejut, akan tetapi Tamim Ad Dary telah mengabarkan kepadaku, bahwa orang-orang dari penduduk Palestina telah mengarungi lautan, mereka diterpa oleh angin topan sehingga membuat mereka terdampar di sebuah pulau, tiba-tiba mereka bertemu dengan makhluk berambut gondrong sehingga tidak ketahuan apakah dia laki-laki atau perempuan, karena rambutnya lebat. Mereka bertanya, 'siapakah kamu? ' makhluk itu menjawab, 'Aku adalah Jasasah', lalu mereka bertanya, 'Mahukah kamu bercerita kepada kami? ' Makhluk itu menjawab, 'Aku bukanlah orang yang bercerita dan bukan pula yang meminta cerita kepada kalian, akan tetapi pergilah ke tempat peribadatan (biara) ini, di dalamnya ada seorang laki-laki yang yang sangat menanti berita kalian, kemudian mereka masuk ke sebuah biara dan mereka mendapatkan seorang laki-laki buta yang dibelenggu rantai, kemudian laki-laki itu bertanya, 'Siapa kalian? ' mereka menjawab, 'Kami orang-orang Arab', laki-laki itu bertanya, 'Apakah pada kalian telah diutus seorang Nabi shallallahu 'alaihi wasallam? ' mereka menjawab, 'Ya, ' laki-laki itu bertanya lagi, 'Apakah orang-orang arab mengikutinya? ' Mereka menjawab, 'Ya.' Laki-laki itu berkata, 'Itu lebih baik bagi mereka.' Kemudian laki-laki itu berkata lagi, 'Apa yang dilakukan oleh orang-orang Persia? Apakah dia dapat menguasainya (Persia)? Mereka berkata, 'Dia belum mampu mengalahkannya.' Laki-laki itu berkata, 'Sungguh, suatu saat dia akan menguasainya.' Laki-laki itu bertanya lagi, 'Apa yang terjadi dengan 'Ainu Zughar (nama mata air)? ' mereka menjawab, 'Airnya meluap, ' kemudian dia bertanya lagi, 'Apa yang terjadi dengan perahu Thabariyah? ' mereka menjawab, 'Penuh.' Laki-laki itu bertanya lagi, 'Apa yang terjadi dengan pohon kurma yang ada di Baisan, apakah memberikan kecukupan makanan? ' mereka menjawab, 'Sungguh, orang-orang yang pertama telah memakannya.' Tamim berkata, \"Tiba-tiba ia melompat, dan kami mengira ia akan lepas, maka kami berkata, 'Siapakah sebenarnya dirimu? ' Laki-laki itu menjawab, 'Aku adalah Dajjal, sesungguhnya aku akan melalui bumi seluruhnya, selain Makkah dan Thaybah (nama kota Madinah).' Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku memberikan kabar gembira kepada kalian wahai kaum Muslimin, sesungguhnya (bumi) ini adalah Thayibah yang tidak akan dimasuki oleh Dajjal.\""},"4134":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ قَالَدَخَلْتُ أَنَا وَأَبُو سَلَمَةَ عَلَى فَاطِمَةَ بِنْتِ قَيْسٍ قَالَ فَقَالَتْ طَلَّقَنِي زَوْجِي فَلَمْ يَجْعَلْ لِي سُكْنَى وَلَا نَفَقَةً قَالَتْ وَوَضَعَ لِي عَشْرَةَ أَقْفِزَةٍ عِنْدَ ابْنِ عَمٍّ لَهُ خَمْسَةً شَعِيرٍ وَخَمْسَةً تَمْرٍ قَالَتْ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ ذَاكَ لَهُ قَالَ فَقَالَ صَدَقَ فَأَمَرَنِي أَنْ أَعْتَدَّ فِي بَيْتِ فُلَانٍ قَالَ وَكَانَ طَلَّقَهَا طَلَاقًا بَائِنًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bakar bin Abu Al Jahm] berkata, \"Aku dan Abu Salamah menemui Fatimah binti Qais.\" Abu Bakar berkata, \" [Fatimah] berkata, \"Suamiku telah menceraikan aku, dan dia tidak lagi memberikan tempat tinggal dan nafkah kepadaku.\" Fatimah berkata, \"Namun dia memberiku sepuluh gantang (takaran) di tempat anak pamannya; lima gantang gandum dan lima gantang kurma.\" Fatimah berkata, \"Aku lalu menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Apakah itu miliknya?\" Beliau menjawab: \"Benar.\" Kemudian beliau memerintahkan aku untuk merampungkan iddah di rumah Fulan.\" Abu Bakar berkata, \"Suaminya telah mentalaknya dengan talak tiga.\""},"4135":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَكَتَبْتُ ذَاكَ مِنْ فِيهَا كِتَابًا فَقَالَتْ كُنْتُ عِنْدَ رَجُلٍ مِنْ بَنِي مَخْزُومٍ فَطَلَّقَنِي الْبَتَّةَ فَأَرْسَلْتُ إِلَى أَهْلِهِ أَبْتَغِي النَّفَقَةَ فَقَالُوا لَيْسَ لَكِ عَلَيْنَا نَفَقَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَكِ عَلَيْهِمْ نَفَقَةٌ وَعَلَيْكِ الْعِدَّةُ انْتَقِلِي إِلَى أُمِّ شَرِيكٍ وَلَا تَفُوتِينِي بِنَفْسِكِ ثُمَّ قَالَ إِنَّ أُمَّ شَرِيكٍ يَدْخُلُ عَلَيْهَا إِخْوَتُهَا مِنْ الْمُهَاجِرِينَ الْأُوَلِ انْتَقِلِي إِلَى ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ قَدْ ذَهَبَ بَصَرُهُ فَإِنْ وَضَعْتِ مِنْ ثِيَابِكِ شَيْئًا لَمْ يَرَ شَيْئًا قَالَتْ فَلَمَّا حَلَلْتُ خَطَبَنِي مُعَاوِيَةُ وَأَبُو جَهْمِ بْنُ حُذَيْفَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مُعَاوِيَةُ فَعَائِلٌ لَا مَالَ لَهُ وَأَمَّا أَبُو جَهْمٍ فَإِنَّهُ رَجُلٌ لَا يَضَعُ عَصَاهُ عَنْ عَاتِقِهِ أَيْنَ أَنْتُمْ مِنْ أُسَامَةَ بْنِ زَيْدٍ وَكَانَ أَهْلُهَا كَرِهُوا ذَلِكَ فَقَالَتْ لَا أَنْكِحُ إِلَّا الَّذِي دَعَانِي إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَكَحَتْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Fatimah binti Qais] berkata, \"Aku telah menulis naskah dari mulutnya, ia (Fatimah) Berkata, \"Aku menjadi isteri dari seorang laki-laki dari bani Mahzum, kemudian dia mentalakku, maka aku mengirim utusan kepada keluarganya untuk minta hak nafkah, namun mereka berkata, 'Kamu tidak lagi mendapatkan nafkah dari kami!\" Dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada kewajiban atas mereka untuk menafkahi kamu, dan rampungkanlah masa iddahmu di tempatnya Ummu Syarik, dan jangan lupa kabari aku.\" Kemudian beliau berkata, \"Sesungguhnya saudara laki-lakinya Ummu Syarik dari orang-orang Muhajirin sering mengunjunginya, maka pindahlah ke tempat Ibnu Ummi Maktum, karena dia adalah laki-laki buta, jika kamu melepas pakainmu maka dia tidak akan melihatnya.\" Fatimah berkata, \"Tatkala aku sudah halal, maka Mu'awiyah dan Abu Jahm bin Hudzaifah melamarku, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mu'awiyah adalah laki-laki miskin yang tidak punya harta benda, sedangkan Abu Jahm adalah laki-laki yang tidak menaruh tongkat dari bahunya (suka memukul), bagaimana jika kamu menikah dengan Usamah bin Zaid?\" -Namun keluarga Fatimah tidak suka jika ia harus menikah dengan Usamah-. Maka Fatimah berkata, \"Aku tidak akan menikah kecuali yang Rasulullah shallallahu 'alaihi wasallam telah rekomendasikan, ' maka Fatimah pun menikah dengannya.\""},"4136":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَاصِمِ بْنِ ثَابِتٍ أَنَّ فَاطِمَةَ بِنْتَ قَيْسٍ أُخْتَ الضَّحَّاكِ بْنِ قَيْسٍ أَخْبَرَتْهُ وَكَانَتْ عِنْدَ رَجُلٍ مِنْ بَنِي مَخْزُومٍ فَأَخْبَرَتْهُأَنَّهُ طَلَّقَهَا ثَلَاثًا وَخَرَجَ إِلَى بَعْضِ الْمَغَازِي وَأَمَرَ وَكِيلًا لَهُ أَنْ يُعْطِيَهَا بَعْضَ النَّفَقَةِ فَاسْتَقَلَّتْهَا وَانْطَلَقَتْ إِلَى إِحْدَى نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ عِنْدَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ هَذِهِ فَاطِمَةُ بِنْتُ قَيْسٍ طَلَّقَهَا فُلَانٌ فَأَرْسَلَ إِلَيْهَا بِبَعْضِ النَّفَقَةِ فَرَدَّتْهَا وَزَعَمَ أَنَّهُ شَيْءٌ تَطَوَّلَ بِهِ قَالَ صَدَقَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَقِلِي إِلَى مَنْزِلِ ابْنِ أُمِّ مَكْتُومٍ و قَالَ أَبِي وَقَالَ الْخَفَّافُ أُمِّ كُلْثُومٍ فَاعْتَدِّي عِنْدَهَا ثُمَّ قَالَ لَا أُمُّ كُلْثُومٍ يَكْثُرُ عُوَّادُهَا وَلَكِنْ انْتَقِلِي إِلَى عَبْدِ اللَّهِ بْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ أَعْمَى فَانْتَقَلَتْ إِلَى عَبْدِ اللَّهِ فَاعْتَدَّتْ عِنْدَهُ حَتَّى انْقَضَتْ عِدَّتُهَا ثُمَّ خَطَبَهَا أَبُو جَهْمٍ وَمُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْتَأْمِرُهُ فِيهِمَا فَقَالَ أَبُو جَهْمٍ أَخَافُ عَلَيْكِ قَسْقَاسَتَهُ لِلْعَصَا أَوْ قَالَ أَخَافُ قَصْقَاصَتَهُ لِلْعَصَا وَأَمَّا مُعَاوِيَةُ فَرَجُلٌ أَخْلَقُ مِنْ الْمَالِ فَتَزَوَّجَتْ أُسَامَةَ بْنَ زَيْدٍ بَعْدَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Atha'] berkata, telah mengabarkan kepadaku [Abdurrahman bin Ashim bin Tsabit] bahwa [Fatimah binti Qais] saudarinya Dlahak bin Qais, telah mengabarkan kepadanya -ia adalah isteri seorang laki-laki dari bani Makhzum- ia mengabarkan kepadanya, bahwa suaminya telah menceraikannya dengan talak tiga, kemudian suaminya tersebut keluar untuk ikut serta dalam salah satu peperangan. Laki-laki itu kemudian memerintahkan wakilnya untuk memberikan nafkah, sementara dirinya (Fatimah) terasa berat untuk menerimanya. Kemudian ia pergi menemui salah satu isteri Nabi shallallahu 'alaihi wasallam, ketika Nabi shallallahu 'alaihi wasallam masuk, ia masih bersama isteri beliau. Isteri beliau kemudian berkata, \"Wahai Rasulullah, ini adalah Fatimah binti Qais, dia telah diceraikan oleh fulan, kemudian suaminya tersebut mengirim sebagian nafkah untuknya, namun ia menolaknya, kawatir jika itu hanyalah alat untuk menguur-ulur waktu saja (antara cerai atau rujuk kembali).\" Beliau bersabda: \"Dia benar.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda lagi: \"Pindahlah kamu ke rumahnya Ibnu Ummi Maktum.\" Bapakku berkata, \"Khaffaf menyebutkan, \"Ummu Kultsum, pindahlah kamu ke rumahnya, \" kemudian beliau bersabda: \"Tidak, Ummu Kultsum sering dikunjungi tamu, akan tetapi pindahlah ke tempatnya Abdullah bin Ummi Maktum, sebab dia buta.\" Kemudian ia pun pindah ke tempatnya Abdullah dan menunggu masa iddahnya di sana hingga selesai. Kemudian Abdullah bin Jahm dan Mu'awiyah bin Abu Sufyan datang untuk melamarnya, maka datang pula Rasulullah shallallahu 'alaihi wasallam, Fatimah lantas meminta pertimbangan kepada beliau tentang keduanya, maka beliau bersabda: \"Kalau Abu Jahm, aku mengkawatirkan dirimu akan tongkatnya yang tidak pernah ia taruh -atau beliau katakan- 'tidak pernah manaruh tongkatnya, sedangkan Mu'awiyah adalah seorang yang tidak memiliki harta benda.\" Setelah itu dia menikah dengan Usamah bin Zaid."},"4137":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شَرِيكُ بْنُ عُبَيْدِ اللَّهِ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ عَنْ مُنْذِرٍ الثَّوْرِيِّ عَنِ الْحَسَنِ بْنِ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَتْنِي امْرَأَةٌ مِنَ الْأَنْصَارِ وَهِيَ حَيَّةٌ الْيَوْمَ إِنْ شِئْتَ أَدْخَلْتُكَ عَلَيْهَا قُلْتُ لَا قَالَتْدَخَلْتُ عَلَى أُمِّ سَلَمَةَ فَدَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّهُ غَضْبَانُ فَاسْتَتَرْتُ بِكُمِّ دِرْعِي فَتَكَلَّمَ بِكَلَامٍ لَمْ أَفْهَمْهُ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ كَأَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَضْبَانَ قَالَتْ نَعَمْ أَوَمَا سَمِعْتِيهِ قَالَتْ قُلْتُ وَمَا قَالَ قَالَتْ قَالَ إِنَّ السُّوءَ إِذَا فَشَا فِي الْأَرْضِ فَلَمْ يُتَنَاهَ عَنْهُ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ بَأْسَهُ عَلَى أَهْلِ الْأَرْضِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ وَفِيهِمْ الصَّالِحُونَ قَالَ نَعَمْ وَفِيهِمْ الصَّالِحُونَ يُصِيبُهُمْ مَا أَصَابَ النَّاسَ ثُمَّ يَقْبِضُهُمْ اللَّهُ عَزَّ وَجَلَّ إِلَى مَغْفِرَتِهِ وَرَحْمَتِهِ أَوْ إِلَى رَحْمَتِهِ وَمَغْفِرَتِهِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Syarik bin 'Ubaidullah] dari [Jami' bin Abu Rasyid] dari [Mundzir Ats Tsauri] dari [Hasan bin Muhammad bin Ali] dia berkata, \" [Seorang wanita Anshar] menceritakan kepadaku -hari ini wanita itu masih hidup, jika mau akan aku ajak kamu untuk menemuinya? Aku menjawab; tidak- Wanita Anshar itu berkata, \"Aku pernah menemui [Ummu Salamah], kemudian datanglah Rasulullah shallallahu 'alaihi wasallam kepadanya dan seakan-akan beliau marah, maka aku pun menutupi diriku dengan kain jubahku, beliau lalu berbicara dengan pembicaraan yang aku tidak bisa memahaminya. Aku lalu berkata, \"Wahai Ummul Mukminin, sepertinya aku melihat Rasulullah shallallahu 'alaihi wasallam marah?\" Ummu Salamah menjawab, \"Benar, tidakkah kamu mendengarnya?\" Wanita Anshar) itu berkata, \"Aku bertanya, \"Apa yang dikatakan beliau?\" Ummu Salamah menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya apabila kejahatan sudah menyebar di muka bumi dan tidak ada yang mencegahnya, maka Allah 'azza wajalla akan menurunkan hukumannya kepada penduduk bumi.\" Ummu Salamah berkata, \"Aku lalu bertanya, \"Wahai Rasulullah, sekalipun di dalamnya ada orang orang shalih?\" beliau menjawab: \"Ya, sekalipun di dalamnya ada orang orang shalih, mereka akan tertimpa apa yang menimpa manusia. Kemudian Allah 'azza wajalla akan mengambil mereka dan menempatkan mereka kepada ampunan dan Rahmat-Nya, atau kepada Rahmat dan ampunan-Nya.\""},"4138":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى وَيَعْلَى قَالَ حَدَّثَنَا يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ حُصَيْنِ بْنِ مِحْصَنٍأَنَّ عَمَّةً لَهُ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَفَرَغَتْ مِنْ حَاجَتِهَا فَقَالَ لَهَا أَذَاتُ زَوْجٍ أَنْتِ قَالَتْ نَعَمْ قَالَ فَأَيْنَ أَنْتِ مِنْهُ قَالَ يَعْلَى فَكَيْفَ أَنْتِ لَهُ قَالَتْ مَا آلُوهُ إِلَّا مَا عَجَزْتُ عَنْهُ قَالَ انْظُرِي أَيْنَ أَنْتِ مِنْهُ فَإِنَّهُ جَنَّتُكِ وَنَارُكِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya], dan [Ya'la] berkata, telah menceritakan kepada kami [Yahya] dari [Busyair bin Yasar] dari [Husain bin Mihshan] bahwa bibinya datang kepada Nabi shallallahu 'alaihi wasallam dan menyampaikan keperluannya, beliau lalu bertanya: \"Apakah kamu memiliki suami?\" Dia menjawab, \"Ya.\" Beliau bertanya lagi: \"Bagaimana perasaanmu darinya?\" [Ya'la] menyebutkan, \"Bagaimana perasaanmu untuknya?\" dia menjawab, \"Aku tidak kembali kepadanya kecuali karena aku sudah tidak mampu lagi.\" Kemudian beliau bersabda: \"Lihatlah di mana posisimu karena sesungguhnya dia adalah Surga dan Nerakamu.\""},"4139":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ أَبِي سُلَيْمٍ قَالَ حَدَّثَنِي طَاوُسٌ عَنْ أُمِّ مَالِكٍ الْبَهْزِيَّةِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ النَّاسِ فِي الْفِتْنَةِ رَجُلٌ مُعْتَزِلٌ فِي مَالِهِ يَعْبُدُ رَبَّهُ وَيُؤَدِّي حَقَّهُ وَرَجُلٌ آخِذٌ بِرَأْسِ فَرَسِهِ فِي سَبِيلِ اللَّهِ يُخِيفُهُمْ وَيُخِيفُونَهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] dia berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] dia berkata, telah menceritakan kepada kami [Laits] -yakni Ibnu Abu Sulaim- dia berkata, telah menceritakan kepadaku [Thawus] dari [Ummu Malik Al Bahziyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik manusia pada zaman fitnah adalah orang yang mengasingkan diri dengan hartanya, dia beribadah kepada Allah dan melaksanakan haknya, serta orang yang mengambil kudanya di jalan Allah sehingga dia dapat menakuti mereka (musuh) dan mereka menakuti dirinya.\""},"4140":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ صَالِحًا يَعْنِي أَبَا الْخَلِيلِ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ أَنَّ أُمَّ حَكِيمٍ بِنْتَ الزُّبَيْرِ حَدَّثَتْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى ضُبَاعَةَ بِنْتِ الزُّبَيْرِ فَنَهَسَ مِنْ كَتِفٍ عِنْدَهَا ثُمَّ صَلَّى وَمَا تَوَضَّأَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] dia berkata, telah mengabarkan kepada kami [Sa'id] dari [Qatadah] bahwa [Shalih] -yakni Abu Khalil- telah menceritakan kepadanya dari [Abdullah bin Harits bin Naufal] bahwa [Ummu Hakim binti Zubair] telah menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah menemui Dzuba'ah binti Zubair, kemudian beliau mengambil pundak kambing darinya, kemudian beliau shalat dan tidak wudlu lagi.\""},"4141":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ أُمِّ حَكِيمٍ بِنْتِ الزُّبَيْرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى أُخْتِهَا ضُبَاعَةَ بِنْتِ الزُّبَيْرِ فَنَهَسَ مِنْ كَتِفٍ ثُمَّ قَامَ إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْقَالَ أَبِي و قَالَ الْخَفَّافُ هِيَ أُمُّ حَكِيمٍ بِنْتُ الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Rauh] dia berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Shalih Abu Khallil] dari ['Abdullah bin Harits bin Naufal] dari [Ummu Hakim binti Zubair] bahwa Rasulullah shallallahu 'alaihi wasallam menemui saudarinya, Dzuba'ah binti Zubair, kemudian beliau mengambil pundak kambing, lalu beliau mengerjakan shalat dan tidak berwudlu.\" Bapakku berkata, \"Dan [Khaffaf] berkata, \"Dia adalah [Ummu Hakim binti Zubair].\""},"4142":{"ar":"حَدَّثَنَا مُعَاذٌ يَعْنِي ابْنَ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ أُمِّ حَكِيمٍ بِنْتِ الزُّبَيْرِأَنَّهَا نَاوَلَتْ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتِفًا مِنْ لَحْمٍ فَأَكَلَ مِنْهُ ثُمَّ صَلَّى","id":"Telah menceritakan kepada kami [Mu'adz] -yakni Ibnu Hisyam- dia berkata, telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Ishaq bin 'Abdullah bin Harits bin Naufal] dari [Ummu Hakim binti Zubair] bahwa dia menyuguhkan kepada Nabi shallallahu 'alaihi wasallam pundak kambing, lalu beliau memakannya kemudian shalat.\""},"4143":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ جَدَّتِهِ أُمِّ حَكِيمٍ عَنْ أُخْتِهَا ضُبَاعَةَ بِنْتِ الزُّبَيْرِأَنَّهَا دَفَعَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمًا فَانْتَهَسَ مِنْهُ ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ قَالَ أَبِي قَالَ عَفَّانُ دَفَعَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمًا","id":"Telah menceritakan kepada kami ['Abdus Shamad] dan ['Affan] keduanya berkata, telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Ishaq bin 'Abdullah bin Harits] dari neneknya [Ummu Hakim] dari saudarinya [Dluba'ah binti Zubair], bahwa dirinya pernah menghidangkan daging kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memakannya kemudian melaksanakan shalat dan tanpa berwudlu lagi.\" Bapakku berkata; Affan berkata, \"Aku memberikan daging kepada Nabi shallallahu 'alaihi wasallam.\""},"4144":{"ar":"حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ حَجَّاجٍ الصَّوَّافِ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ضُبَاعَةَ بِنْتِ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْرِمِي وَقُولِي إِنَّ مَحِلِّي حَيْثُ تَحْبِسُنِي فَإِنْ حُبِسْتِ أَوْ مَرِضْتِ فَقَدْ أَحْلَلْتِ مِنْ ذَلِكَ شَرْطُكِ عَلَى رَبِّكَ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Dlahak bin Muhlid] dari [Hajjaj As Shawwaf] dia berkata, telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Ikrimah] dari [Dluba'ah binti Zubair bin 'Abdul Mutthalib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berihram dan katakanlah 'sesungguhnya tempat Miqatku adalah dimana aku tertahan', jika kamu tertahan atau sakit maka kamu telah halal dengan syarat yang kamu berikan kepada Rabbmu Azza Wa Jalla.\""},"4145":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ قَالَ حَدَّثَنِي مَنْ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُ حَدَّثَتْنِي ضُبَاعَةُ أَنَّهَاقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْحَجَّ فَقَالَ لَهَا حُجِّي وَاشْتَرِطِي","id":"Telah menceritakan kepada kami [Muhammad bin Mush'ab] dia berkata, telah menceritakan kepada kami [Al Auza'i] dari ['Abdul Karim Al Jazari] dia berkata, telah menceritakan kepadaku [seseorang] yang mendengar [Ibnu Abbas] berkata, telah menceritakan kepadaku [Dluba'ah] bahwa dia bertanya, \"Wahai Rasulullah, sesungguhnya aku ingin melaksanakan haji, \" maka beliau pun bersabda kepadanya: \"Berhaji dan tentukanlah syarat.\""},"4146":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنِ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ حَدَّثَتْهُأَنَّهَا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكَ عِرْقٌ فَانْظُرِي فَإِذَا أَتَاكِ قُرْؤُكِ فَلَا تُصَلِّي فَإِذَا مَرَّ الْقُرْءُ فَتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقُرْءِ إِلَى الْقُرْءِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] dia berkata, telah menceritakan kepada kami [Laits bin Sa'd] dia berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bukair bin 'Abdullah] dari [Mundzir bin Mughirah] dari ['Urwah bin Zubair] bahwa [Fatimah binti Abu Hubaisi] telah menceritakan kepadanya, bahwa dia datang menemui Nabi shallallahu 'alaihi wasallam dan mengadukan kepadanya mengenai darah kebiasaan wanita, Rasulullah shallallahu 'alaihi wasallam kemudian menjawab: \"Itu adalah darah kotor (keringat), lihatlah jika datang kepadamu masa Quru' (masa haid) maka jangan kamu melaksanakan shalat, dan jika telah selesai masa haidmu maka bersucilah kemudian laksanakan shalat antara masa haid dengan masa haid berikutnya.\""},"4147":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ قَالَ سَمِعْتُ جَابِرًا قَالَ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ امْرَأَةِ زَيْدِ بْنِ حَارِثَةَ قَالَتْدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَائِطٍ فَقَالَ لَكِ هَذَا فَقُلْتُ نَعَمْ فَقَالَ مَنْ غَرَسَهُ مُسْلِمٌ أَوْ كَافِرٌ قُلْتُ مُسْلِمٌ قَالَ مَا مِنْ مُسْلِمٍ يَزْرَعُ أَوْ يَغْرِسُ غَرْسًا فَيَأْكُلُ مِنْهُ طَائِرٌ أَوْ إِنْسَانٌ أَوْ سَبُعٌ أَوْ شَيْءٌ إِلَّا كَانَ لَهُ صَدَقَةًقَالَ أَبِي وَلَمْ يَكُنْ فِي النُّسْخَةِ سَمِعْتُ جَابِرًا فَقَالَ ابْنُ نُمَيْرٍ سَمِعْتَ عَامِرًا","id":"Telah menceritakan kepada kami [Ibnu Numair] dia berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dia berkata, aku mendengar [Jabir] berkata, telah menceritakan kepadaku [Ummu Mubasyir] isteri Zaid bin Haritsah, dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam di sebuah kebuh, beliaulalu bertanya: \"Apakah ini milikmu?\" aku menjawab, \"Ya.\" Beliau bertanya lagi: \"Apakah orang yang menanam ini seorang Muslim ataukah kafir?\" aku menjawab, \"Seorang Muslim.\" Beliau bersabda: \"Tidaklah seorang Muslim yang menanam tanaman, kemudian burung-burung memakannya, atau orang lain, atau hewan, atau sesuatu memakannya kecuali itu akan menjadi sedekah baginya.\" Bapakku berkata, \"Dalam dalam lembaran catatan, aku tidak mendengar Jabir.\" Sedangkan Ibnu Numair berkata, \"Aku mendengar Amir.\""},"4148":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا قَالَ حَدَّثَتْنِي أُمُّ مُبَشِّرٍ أَنَّهاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ حَفْصَةَ يَقُولُ لَا يَدْخُلُ النَّارَ إِنْ شَاءَ اللَّهُ مِنْ أَصْحَابِ الشَّجَرَةِ أَحَدٌ الَّذِينَ بَايَعُوا تَحْتَهَا فَقَالَتْ بَلَى يَا رَسُولَ اللَّهِ فَانْتَهَرَهَا فَقَالَتْ حَفْصَةُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا وَنَذَرُ الظَّالِمِينَ فِيهَا جِثِيًّا }","id":"Telah menceritakan kepada kami [Hajjaj] dia berkata, telah mengabarkan kepadaku [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Zubair] bahwa dia mendengar [Jabir] berkata, telah menceritakan kepadaku [Ummu Mubasyir] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam waktu berada di samping Hafshah, beliau bersabda: \"Insyaallah tidak akan masuk Neraka orang-orang yang pernah berbaiat di bawah pohon.\" Hafshah berkata, \"Tentu wahai Rasulullah, \" namun beliau menghardiknya hingga Hafshah pun membaca: '(Dan tidak ada seorang pun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71), lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah Azza Wa Jalla telah berfirman: '(Kemudian Kami akan menyelamatkan orang-orang yang bertakwa dan membiarkan orang-orang yang lalim di dalam neraka dalam keadaan berlutut) ' (Qs. Maryam: 72)."},"4149":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا سَعْدُ بْنُ إِسْحَاقَ بْنِ كَعْبِ بْنِ عُجْرَةَ الْأَنْصَارِيُّ عَنْ عَمَّتِهِ زَيْنَبَ بِنْتِ كَعْبٍ أَنَّ فُرَيْعَةَ بِنْتَ مَالِكِ بْنِ سِنَانٍ أُخْتَ أَبِي سَعِيدٍ الْخُدْرِيِّ حَدَّثَتْهَاأَنَّ زَوْجَهَا خَرَجَ فِي طَلَبِ أَعْلَاجٍ لَهُمْ فَأَدْرَكَهُمْ بِطَرَفِ الْقَدُومِ فَقَتَلُوهُ فَأَتَاهَا نَعْيُهُ وَهِيَ فِي دَارٍ مِنْ دُورِ الْأَنْصَارِ شَاسِعَةٍ عَنْ دَارِ أَهْلِهَا فَكَرِهَتْ الْعِدَّةَ فِيهَا فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ أَتَانِي نَعْيُ زَوْجِي وَأَنَا فِي دَارٍ مِنْ دُورِ الْأَنْصَارِ شَاسِعَةٍ عَنْ دُورِ أَهْلِي إِنَّمَا تَرَكَنِي فِي مَسْكَنٍ لَا يَمْلِكُهُ وَلَمْ يَتْرُكْنِي فِي نَفَقَةٍ يُنْفَقُ عَلَيَّ وَلَمْ أَرِثْ مِنْهُ مَالًا فَإِنْ رَأَيْتَ أَنْ أَلْحَقَ بِإِخْوَتِي وَأَهِلِي فَيَكُونَ أَمَرُنَا جَمِيعًا فَإِنَّهُ أَحَبُّ إِلَيَّ فَأَذِنَ لِي أَنْ أَلْحَقَ بِأَهْلِي فَخَرَجْتُ مَسْرُورَةً بِذَلِكَ حَتَّى إِذَا كُنْتُ فِي الْحُجْرَةِ أَوْ الْمَسْجِدِ دَعَانِي أَوْ أَمَرَ بِي فَدُعِيتُ فَقَالَ لِي كَيْفَ زَعَمْتِ فَأَعَدْتُ عَلَيْهِ فَقَالَ امْكُثِي فِي مَسْكَنِ زَوْجِكِ الَّذِي جَاءَكِ فِيهِ نَعْيُهُ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ قَالَتْ فَاعْتَدَدْتُ فِيهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Bisyr bin Mufadlal] dia berkata, telah menceritakan kepada kami [Ibnu Ishaq bin Ka'b bin 'Ujrah Al Anshari] dari bibinya [Zainab binti Ka'b] bahwa [Furai'ah binti Malik bin Sinan] saudarinya Abu Sa'id Al Khudri, bahwa dia telah menceritakan kepadanya, bahwa suaminya keluar untuk mencari budaknya, namun kemudian mereka membunuhnya dengan kapak. Kemudian saat berita duka itu datang ia berada di salah satu rumah orang-orang Anshar yang sangat jauh dari rumah keluarganya, sehingga ia tidak ingin saat iddah berada di rumah tersebut (rumah suami). Kemudian dia menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, saat berita kematian suamiku datang aku berada di salah satu rumah orang-orang Anshar, dan jauh dari rumah keluargaku. Suamiku meninggalkan aku di rumah yang bukan miliknya, dan ia juga tidak meninggalkan nafkah untukku, bahkan tidak ada yang bisa aku warisi dari hartanya. Bagaimana pendapat tuan jika aku pindah ke rumah saudara dan keluargaku, sehingga perkara semuanya mudah, dan itu lebih aku cintai?\" kemudian beliau mengizinkan aku untuk tinggal bersama saudara dan keluargaku, akupun keluar dengan perasaan gembira. Sehingga ketika aku sampai di kamar atau di masjid, beliau memanggilku, atau menyuruh utusan untuk memanggilku, beliau bersabda kepadaku: \"Bagaimana perasaanmu, \" maka aku kembali menegaskan kepada beliau (tentang keinginanku) kepada beliau.\" Beliau kemudian bersabda: \"Tinggallah kamu di tempat suamimu, sehingga selesai masa iddahmu.\" Furai'ah berkata, \"Kemudian aku menunggu masa iddah di rumahnya selama empat bulan sepuluh hari.\""},"4150":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ مَكْحُولٍ عَنْ أُمِّ أَيْمَنَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتْرُكْ الصَّلَاةَ مُتَعَمِّدًا فَإِنَّهُ مَنْ تَرَكَ الصَّلَاةَ مُتَعَمِّدًا فَقَدْ بَرِئَتْ مِنْهُ ذِمَّةُ اللَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Walid bin Muslim] dia berkata, telah mengabarkan kepada kami [Sa'id bin 'Abdul Aziz] dari [Makhul] dari [Ummu Aiman] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu meninggalkan shalat dengan sengaja, karena siapa yang meninggalkan shalat dengan sengaja maka perlindungan Allah dan Rasul-Nya akan terlepas darinya.\""},"4151":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ الْحَمِيدِ بْنُ جُبَيْرِ بْنِ شَيْبَةَ وَابْنُ بَكْرٍ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ وَرَوْحٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جُبَيْرِ بْنِ شَيْبَةَ أَنَّ ابْنَ الْمُسَيَّبِ أَخْبَرَهُ أَنَّ أُمَّ شَرِيكٍ أَخْبَرَتْهُأَنَّهَا اسْتَأْمَرَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَتْلِ الْوَزَغَاتِ فَأَمَرَهَا بِقَتْلِ الْوَزَغَاتِقَالَ ابْنُ بَكْرٍ وَرَوْحٌ وَأُمُّ شَرِيكٍ إِحْدَى نِسَاءِ بَنِي عَامِرِ بْنِ لُؤَىٍّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] berkata, telah menceritakan kepada kami Yahya bin Sa'id dari Ibnu Juraij dia berkata, telah menceritakan kepada kami [Abdul Hamid bin Jubair bin Syaibah], dan [Ibnu Bakar] dia berkata, telah menceritakan kepada kami [Ibnu Juraij], dan [Rauh] dia berkata, telah bercerita kepada kami [Ibnu Juraij] dia berkata, telah menceritakan kepada kami [Abdul Hamid bin Jubair bin Syaibah] bahwa [Ibnul Musayyab] menceritakan kepadanya bahwa, [Ummu Syarik] mengabarkan kepadanya, bahwa ia pernah minta tolong kepada Nabi shallallahu 'alaihi wasallam untuk membunuh cicak, kemudian Nabi menyuruhnya untuk membunuhnya.\" [Ibnu Bakar], dan [Rauh] berkata, \"Ummu Syarik adalah salah seorang wanita bani Amir Bin Lu'Abu Isa berkata, \".\""},"4152":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي دَيْلَمٌ أَبُو غَالِبٍ الْقَطَّانُ قَالَ حَدَّثَنِي الْحَكَمُ بْنُ جَحْلٍ قَالَ حَدَّثَتْنِي أُمُّ الْكِرَامِأَنَّهَا حَجَّتْ قَالَتْ فَلَقِيتُ امْرَأَةً بِمَكَّةَ كَثِيرَةَ الْحَشَمِ لَيْسَ عَلَيْهِنَّ حُلِيٌّ إِلَّا الْفِضَّةُ فَقُلْتُ لَهَا مَا لِي لَا أَرَى عَلَى أَحَدٍ مِنْ حَشَمِكِ حُلِيًّا إِلَّا الْفِضَّةَ قَالَتْ كَانَ جَدِّي عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ عَلَيَّ قُرْطَانِ مِنْ ذَهَبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شِهَابَانِ مِنْ نَارٍ فَنَحْنُ أَهْلَ الْبَيْتِ لَيْسَ أَحَدٌ مِنَّا يَلْبَسُ حُلِيًّا إِلَّا الْفِضَّةَ","id":"Telah menceritakan kepada kami ['Abdus Shamad] berkata, telah menceritakan kepadaku [Dailam Abu Ghalib AL Qatthan] berkata, telah menceritakan kepadaku [Al Hakam bin Jahl] berkata, telah menceritakan kepadaku [Ummul Kiram], bahwa dia melaksanakan haji.\" Kemudian dia berkata, \"Aku lalu bertemu dengan [seorang wanita] di Makkah yang memiliki banyak pelayan, dia tidak memiliki perhiasan kecuali perak, maka aku bertanya kepadanya, 'Kenapa aku tidak melihat salah seorang dari pelayanmu memakai perhiasan kecuali dari perak? ' dia menjawab, 'Dulu ketika kakekku ada di sisi Rasulullah shallallahu 'alaihi wasallam, sementara aku yang saat itu bersamanya mengenakan anting-anting, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Dua kilauan api neraka! Kami adalah Ahlul Bait, dan tidak ada satu orangpun dari kami yang memakai perhiasan kecuali dari perak.\""},"4153":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُؤَمَّلِ عَنْ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا عَطَاءٌ عَنْ حَبِيبَةَ بِنْتِ أَبِي تَجْرَاةَ قَالَتْدَخَلْنَا دَارَ أَبِي حُسَيْنٍ فِي نِسْوَةٍ مِنْ قُرَيْشٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَتْ وَهُوَ يَسْعَى يَدُورُ بِهِ إِزَارُهُ مِنْ شِدَّةِ السَّعْيِ وَهُوَ يَقُولُ لِأَصْحَابِهِ اسْعَوْا فَإِنَّ اللَّهَ كَتَبَ عَلَيْكُمْ السَّعْيَ","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Abdullah bin Al Muammal] dari [Umar bin Abdurrahman] berkata, telah menceritakan kepada kami [Atha'] dari [Habibah binti Abu Tajrah] dia berkata, \"Kami masuk ke dalam rumah Abu Husain yang sedang berkumpul di dalamnya para wanita Quraisy, sementara Nabi shallallahu 'alaihi wasallam sedang melaksanakan Sa'i antara shafa dan Marwah.\" Habibah berkata, \"Beliau melaksanakan sa'i sambil melingkarkan kain ihramnya karena payahnya melaksanakan sa'I, dan beliau berkata kepada para sahabatnya: \"Lakukanlah sa'i karena Allah akan mencatat pahala sa'i kalian.\""},"4154":{"ar":"حَدَّثَنَا سُرَيْجٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُؤَمَّلِ عَنْ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ حَبِيبَةَ بِنْتِ أَبِي تَجْرَاةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفُ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَالنَّاسُ بَيْنَ يَدَيْهِ وَهُوَ وَرَاءَهُمْ وَهُوَ يَسْعَى حَتَّى أَرَى رُكْبَتَيْهِ مِنْ شِدَّةِ السَّعْيِ يَدُورُ بِهِ إِزَارُهُ وَهُوَ يَقُولُ اسْعَوْا فَإِنَّ اللَّهَ كَتَبَ عَلَيْكُمْ السَّعْيَ","id":"Telah menceritakan kepada kami [Suraij] berkata, telah menceritakan kepada kami [Abdullah bin Al Muammal] dari Umar bin Abdurrahman dari [Atha' bin Rabah] dari [Shafiyah binti Syaibah] dari [Habibah binti Abu Tajrah] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam thawaf antara Shafa dan Marwa, sedangkan orang-orang berada di samping kanan dan kirinya, dan Beliau berada di belakang mereka. Aku melihat beliau melakukan sa'i sambil melingkarkan kain ihramnya di kedua lututnya karena payahnya melaksanakan sa'i. Kemudian beliau berkata kepada para sahabatnya: \"Lakukanlah sa'i karena Allah akan mencatat pahala sa'i kalian.\""},"4155":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا مَنْصُورٌ عَنْ عَطَاءٍ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ الْخُزَاعِيَّةِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعَقِيقَةِ فَقَالَ عَنْ الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Manshur] dari [Atha'] dari [Habibah binti Maisarah] dari [Ummu Kurz Al Ka'biyyah Al Khuzaiyyah] dari Nabi shallallahu 'alaihi wasallam tentang akikah: \"Anak laki-laki dengan dua kambing dan anak perempuan dengan satu kambing.\""},"4156":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أُمِّ كُرْزٍ الْخُزَاعِيَّةِ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُلَامٍ فَبَالَ عَلَيْهِ فَأَمَرَ بِهِ فَنُضِحَ وَأُتِيَ بِجَارِيَةٍ فَبَالَتْ عَلَيْهِ فَأَمَرَ بِهِ فَغُسِلَ","id":"Telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata; telah menceritakan kepada kami [Usamah bin Zaid] dari [Amru Bin Syu'aib] dari [Ummu Kurzi Al Khuza'i] dia berkata, \"Dihadapkan kepada Nabi shallallahu 'alaihi wasallam seorang bayi laki laki yang kemudian megencinginya, beliau lalu memerintahkan untuk memercikinya, lantas sisa kencingnya itu pun diperciki air. Dan dihadapkan pula seorang bayi perempuan, ketika bayi itu mengencinginya, beliau memerintahkan untuk mencucinya, maka sisa kencingnya pun dicuci.\""},"4157":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ حَدَّثَنِي عَطَاءٌ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ عَنْ أُمِّ بَنِي كُرْزٍ الْكَعْبِيَّةِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُلَامِ شَاتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] telah menceritakan kepadaku [Atha'] dari [Habibah binti Maisarah] dari [Ummu Bani Kurz Al Ka'biyah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Untuk bayi laki-laki dua ekor kambing dan untuk bayi perempuan satu ekor kambing.\""},"4158":{"ar":"حَدَّثَنَا حَجَّاجٌ عَنِ ابْنِ جُرَيْجٍ وَعَبْدِ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ بْنِ أَبِي خُثَيْمٍ عَنْ أُمِّ بَنِي كُرْزٍ الْكَعْبِيَّةِ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَقَالَ عَنْ الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌقُلْتُ لِعَطَاءٍ مَا الْمُكَافَأَتَانِ قَالَ الْمِثْلَانِ قَالَ حَجَّاجٌ فِي حَدِيثِهِ وَالضَّأْنُ أَحَبُّ إِلَيَّ مِنْ الْمَعْزِ وَذَكَرَ أَنَّهَا أَحَبُّ إِلَيَّ مِنْ إِنَاثِهَا قَالَ وَنُحِبُّ أَنْ يَجْعَلَهُ سَوَادَهَا مِنْهُ","id":"Telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dan [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Atha'] dari [Habibah binti Maisarah bin Abu Hutsaim] dari [Ummu Bani Kurz Al Ka'biyah] bahwa dia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan akikah, maka beliau bersabda: \"Untuk anak laki-laki dua ekor kambing yang layak, sedangkan untuk anak perempuan satu ekor kambing.\" Aku bertanya kepada Atha', \"Apa maksud dari mukafatani (yang layak)?\" Dia lalu menjawab, \"Yaitu yang sama.\" [Hajjaj] menyebutkan dalam haditsnya, \"Dan domba lebih aku sukai daripada kambing kacang (sejenis kambing yang kecil), dan jantan lebih aku sukai daripada yang betina.\" Dia berkata, \"kami lebih suka jika jumlahnya lebih banyak darinya.\""},"4159":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ عَنْ سِبَاعِ بْنِ ثَابِتٍ أَنَّ مُحَمَّدَ بْنَ ثَابِتِ بْنِ سِبَاعٍ أَخْبَرَهُ أَنَّ أُمَّ كُرْزٍ أَخْبَرَتْهُ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَقَالَ يُعَقُّ عَنْ الْغُلَامِ شَاتَانِ وَعَنْ الْأُنْثَى وَاحِدَةٌ وَلَا يَضُرُّكُمْ أَذُكْرَانًا كُنَّ أَوْ إِنَاثًاحَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّ سِبَاعَ بْنَ ثَابِتِ بْنِ عَمْرٍو عَنْ مُحَمَّدِ بْنِ ثَابِتِ بْنِ سِبَاعٍ أَخْبَرَهُ أَنَّ أُمَّ كُرْزٍ أَخْبَرَتْهُ أَنَّهَا سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Ubaidullah bin Abu Yazid] dari [Siba' bin Tsabit] bahwa [Muhammad bin Tsabit bin Siba'] telah mengabarkan kepadanya, bahwa [Ummu Kurz] telah mengabarkan kepadanya, bahwa dia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan akikah, maka beliau bersabda: \"Anak laki-laki diakikahi dengan dua ekor kambing sedangkan anak perempuan dengan satu ekor kambing. Dan kalian tidak berdosa apakah kambing iti jantan atau betina.\" Telah menceritakan kepada kami [Muhammad bin Bakr] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Ubaidullah bin Abu Yazid] bahwa [Siba' bin Tsabit bin Amru] dari [Muhammad bin Tsabit bin Siba'] telah mengabarkan kepadanya, bahwa [Ummu Kurz] telah mengabarkan kepadanya, bahwa dia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai hewan akikah…kemudian dia menyebutkan hadits tersebut.\""},"4160":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ أُمِّهِ سَلْمَى بِنْتِ قَيْسٍ قَالَتْبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ مِنْ الْ��َنْصَارِ قَالَتْ كَانَ فِيمَا أَخَذَ عَلَيْنَا أَنْ لَا تَغُشَّنَّ أَزْوَاجَكُنَّ قَالَتْ فَلَمَّا انْصَرَفْنَا قُلْنَا وَاللَّهِ لَوْ سَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا غِشُّ أَزْوَاجِنَا قَالَتْ فَرَجَعْنَا فَسَأَلْنَاهُ قَالَ أَنْ تُحَابِينَ أَوْ تُهَادِينَ بِمَالِهِ غَيْرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] dari [seorang laki-laki Anshar] dari ibunya [Salma binti Qais] dia berkata, \"Aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam bersama dengan beberapa wanita dari Anshar.\" Salma berkata, \"Dan yang beliau ambil janjinya dari kami adalah; 'hendaknya kalian tidak menipu suami-suami kalian', \" Salma berkata, \"Ketika kami telah berlalu pergi, kami pun berkata, \"Demi Allah, sekiranya kita bertanya kepada Rasulullah shallallahu 'alaihi wasallam apa maksud dari 'tidak menipu suami-suami kami? ' Maka kami kembali kepada beliau dan bertanya, beliau lalu menjawab: \"Kalian mencintainya, atau menggunakan hartanya untuk selain dia (suami).\""},"4161":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا الْحُرُّ بْنُ الصَّيَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنِ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ تِسْعَ ذِي الْحِجَّةِ وَيَوْمَ عَاشُورَاءَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ وَخَمِيسَيْنِ","id":"Telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Abu Awanah] berkata, telah menceritakan kepada kami [Al Hurr bin As Shayyah] dari [Hunaidah bin Khalid] dari [isterinya] dari [sebagian isteri] Nabi shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan puasa pada tanggal sembilan Dzul Hijah, hari Asyura, tiga hari pada tiap bulan dan hari Senin dan Kamis tiap awal bulan.\""},"4162":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ عَنْ أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ وَهِيَ خَالَتُهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ أَوْ قَالَ فِي بَيْتِهَا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا يُضْحِكُكَ فَقَالَ عُرِضَ عَلَيَّ نَاسٌ مِنْ أُمَّتِي يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ الْأَخْضَرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ إِنَّكِ مِنْهُمْ ثُمَّ نَامَ فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ عُرِضَ عَلَيَّ نَاسٌ مِنْ أُمَّتِي يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ الْأَخْضَرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَقَالَ فَتَزَوَّجَهَا عُبَادَةُ بْنُ الصَّامِتِ فَأَخْرَجَهَا مَعَهُ فَلَمَّا جَازَ الْبَحْرَ بِهَا رَكِبَتْ دَابَّةً فَصَرَعَتْهَا فَقَتَلَتْهَا حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ حَدَّثَتْنِي أُمُّ حَرَامٍ بِنْتُ مِلْحَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي بَيْتِهَا يَوْمًا فَاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَضْحَكُ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdus Shamad] berkata, telah menceritakan kepadaku [ayahku] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepadaku [Muhammad bin Yahya bin Habban] berkata, telah menceritakan kepadaku [Anas bin Malik] dari [Ummu Haram binti Milhan] dan dia adalah bibinya, bahwa Rasulullah shallallahu 'alaihi wasallam tidur -atau dia menyebutkan- tidur siang di rumahnya, tiba-tiba beliau bangun dan tertawa, Maka aku berkata, \"Wahai Rasulullah, apa yang menyebabkan tuan tertawa?\" Beliau bersabda: \"Ditampakkan kepadaku sekelompok manusia dari ummatku, mereka berlayar di laut hijau ini seperti para raja di atas singgasana.\" Ummu Haram lalu berkata, \"Aku berkata, \"Wahai Rasulullah, do'akanlah agar aku menjadi bagian dari mereka.\" Beliau pun bersabda: \"Sesungguhnya kamu termasuk dari mereka.\" Kemudian Beliau tertidur kembali dan bangun dengan tertawa, maka aku bertanya, \"Wahai Rasulullah, apa yang menyebabkan tuan tertawa?\" Beliau menjawab: \"Ditampakkan kepadaku sekelompok manusia dari ummatku, mereka berlayar di laut hijau ini seperti raja-raja di atas singgasana.\" Ummu Haram berkata, \"Kemudian aku berkata, \"Wahai Rasulullah, do'akanlah agar aku menjadi bagian dari mereka.\" Beliau pun bersabda: \"Kamu adalah termasuk yang pertama-tama.\" Anas berkata, \"Kemudian Ummu Haram menikah dengan Ubadah bin Shamit dan ikut berperang bersamanya, tatkala dia menyeberangi lautan, dia menaiki seekor bighal dan terjatuh hingga ia pun gugur.\" Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Anas bin Malik] berkata, telah menceritakan kepadaku [Ummu Haram binti Milhan], bahwa suatu hari Nabi shallallahu 'alaihi wasallam bersabda di dalam rumahnya, tiba-tiba Rasulullah shallallahu 'alaihi wasallam bangun dari tudurnya dengan tertawa…kemudian dia menyebutkan maknanya.\""},"4163":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أُمِّ هَانِئٍأَنَّهَا ذَهَبَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ قَالَتْ فَوَجَدْتُهُ يَغْتَسِلُ وَفَاطِمَةُ تَسْتُرُهُ بِثَوْبٍ فَسَلَّمْتُ وَذَلِكَ ضُحًى فَقَالَ مَنْ هَذَا قُلْتُ أَنَا أُمُّ هَانِئٍ قُلْتُ يَا رَسُولَ اللَّهِ زَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلٌ رَجُلًا أَجَرْتُهُ فُلَانَ ابْنَ هُبَيْرَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غُسْلِهِ قَامَ فَصَلَّى ثَمَانِ رَكَعَاتٍ مُلْتَحِفًا فِي ثَوْبٍ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Malik] dari [Abu An Nadlr] dari [Abu Murrah] bekas budak Aqil bin Abu Thalib, dari [Ummu Hani'] bahwa dia pergi menemui Nabi shallallahu 'alaihi wasallam pada hari penaklukan kota Makkah.\" Ummu Hani` berkata, \"Kemudian aku mendapati beliau sedang mandi sementara Fatimah menutupinya dengan kain, kemudian aku mengucapkan salam kepadanya, dan ketika itu adalah waktu dluha. Nabi lalu bertanya: \"Siapa ini?\" aku menjawab, \"Aku Ummu Hani', \" aku lalu berkata, \"Wahai Rasulullah, anak laki-laki dari ibuku mengaku telah membunuh seseorang yang aku berikan perlindungan kepadanya, Fulan Ibnu Hubairah?\" Rasulullah shallallahu 'alaihi wasallam kemudian menjawab: \"Kami telah memberikan perlindungan kepada siapa yang kamu beri perlindungan wahai Ummu Hani'.\" maka ketika Rasulullah shallallahu 'alaihi wasallam selesai dari mandinya, beliau berdiri dan melaksanakan shalat delapan rakaat dengan berselimutkan pakaian.\""},"4164":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلٍ عَنْ أُمِّ هَانِئٍ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِأَعْلَى مَكَّةَ فَلَمْ أَجِدْهُ وَوَجَدْتُ فَاطِمَةَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ أَثَرُ الْغُبَارِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي قَدْ أَجَرْتُ حَمْوَيْنِ لِي وَزَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلُهُمَا قَالَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ وَوُضِعَ لَهُ غُسْلٌ فِي جَفْنَةٍ فَلَقَدْ رَأَيْتُ أَثَرَ الْعَجِينِ فِيهَا فَتَوَضَّأَ أَوْ قَالَ اغْتَسَلَ أَنَا أَشُكُّ وَصَلَّى الْفَجْرَ فِي ثَوْبٍ مُشْتَمِلًا بِهِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Ajlan] dari [Sa'id] dari [Abu Murrah] bekas budak Aqil, dari [Ummu Hani'] dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam yang saat itu berada di ujung kota Makkah, aku pun tidak menemukan beliau dan hanya menemukan Fatimah. Rasulullah shallallahu 'alaihi wasallam lalu datang dengan bekas debu, lantas aku berkata, \"Wahai Rasulullah, sesungguhnya aku telah menanggung kedua saudara iparku, sedangkan anak laki-laki dari ibuku mengaku akan membunuh keduanya?\" Beliau pun bersabda: \"Sungguh, aku telah menjamin siapa saja yang kamu jamin.\" Kemudian beliau diberi air dalam bejana untuk mandi, dan sungguh aku melihat bekas adonan dalam bejana tersebut. Kemudian beliau berwudlu atau mandi -aku ragu-, kemudian beliau shalat fajar dengan berselimutkan kain.\""},"4165":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا مِسْعَرٌ عَنْ أَبِي الْعَلَاءِ الْعَبْدِيِّ عَنْ ابْنِ جَعْدَةَ بْنِ هُبَيْرَةَ عَنْ أُمِّ هَانِئٍ قَالَتْكُنْتُ أَسْمَعُ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عَلَى عَرِيشِي","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Mis'ar] dari [Abu Al Ala' Al Abdi] dari [Abu Ja'dah bin Hubairah] dari [Ummu Hani'] dia berkata, \"Aku mendengar bacaan Nabi shallallahu 'alaihi wasallam, sedangkan aku berada di ruanganku.\""},"4166":{"ar":"حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ أَبِي صَالِحٍ مَوْلَى أُمِّ هَانِئٍ عَنْ أُمِّ هَانِئٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ وَتَأْتُونَ فِي نَادِيكُمْ الْمُنْكَرَ }قَالَ كَانُوا يَخْذِفُونَ أَهْلَ الطَّرِيقِ وَيَسْخَرُونَ مِنْهُمْ فَذَلِكَ الْمُنْكَرُ الَّذِي كَانُوا يَأْتُونَ","id":"Telah menceritakan kepada kami [Abu Usamah] berkata, telah mengabarkan kepadaku [Hatim bin Abu Shaghirah] dari [Simak bin Harb] dari [Abu Shalih] bekas budak Ummu Hani', dari [Ummu Hani'] dia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai firman-Nya: '(menyamun dan mengerjakan kemungkaran di tempat-tempat pertemuanmu?) ' (Qs. Al Ankabuut: 29), beliau bersabda: \"Mereka mencela orang-orang yang berjalan dan mengejeknya, itulah kemungkaran yang mereka perbuat.\""},"4167":{"ar":"حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَ حَدَّثَنَا أَبُو يُونُسَ الْقُشَيْرِيُّ حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ أَبِي صَالِحٍ عَنْ أُمِّ هَانِئٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا يَوْمَ الْفَتْحِ فَأَتَتْهُ بِشَرَابٍ فَشَرِبَ مِنْهُ ثُمَّ فَضُلَتْ مِنْهُ فَضْلَةً فَنَاوَلَهَا فَشَرِبَتْهُ ثُمَّ قَالَتْ يَا رَسُولَ اللَّهِ لَقَدْ فَعَلْتُ شَيْئًا مَا أَدْرِي يُوَافِقُكَ أَمْ لَا قَالَ وَمَا ذَاكَ يَا أُمَّ هَانِئٍ قَالَتْ كُنْتُ صَائِمَةً فَكَرِهْتُ أَنْ أَرُدَّ فَضْلَكَ فَشَرِبْتُهُ قَالَ تَطَوُّعًا أَوْ فَرِيضَةً قَالَتْ قُلْتُ بَلْ تَطَوُّعًا قَالَ فَإِنَّ الصَّائِمَ الْمُتَطَوِّعَ بِالْخِيَارِ إِنْ شَاءَ صَامَ وَإِنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Shafwan bin Isa] berkata, telah menceritakan kepada kami [Abu Yunus Al Qusyairi Hatim bin Abu Shaghirah] dari [Simak bin Harb] dari [Abu Shalih] dari [Ummu Hani'] bahwa Nabi shallallahu 'alaihi wasallam menemuinya pada waktu penaklukan kota Makkah, Ummu Hani' lalu menyuguhkan air minum untuk beliau dan beliau pun meminumnya. Kemudian beliau memberikan sisanya kepada Ummu Hani', dan ia pun meminumnya. Setelah itu ia berkata, \"Wahai Rasulullah, sesungguhnya aku telah melakukan tindakan yang aku sendiri tidak tahu apakah tuan menyetujuinya atau tidak?\" Beliau balik bertanya: \"Apa itu wahai Ummu Hani`?\" Ummu Hani' menjawab, \"Sebetulnya aku sedang berpuasa, akan tetapi aku tidak suka jika aku mengembalikan sisa (minuman) tuan, oleh karenanya aku meminumnya.\" Beliau bersabda: \"Apakah kamu puasa sunnah ataukah wajib?\" Ummu Hani' berkata, \"Aku menjawab, \"Puasa sunnah.\" Beliau bersabda: \"Sesungguhnya orang yang puasa sunnah boleh menentukan dua pilihan, jika ia berkehendak maka boleh berpuasa dan jika berkehendak dia boleh berbuka.\""},"4168":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا زُهَيْرٌ عَ��ْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ قَالَ حَدَّثَنِي يُوسُفُ بْنُ مَاهَكَ أَنَّهُدَخَلَ عَلَى أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ فَسَأَلَهَا عَنْ مَدْخَلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَسَأَلَهَا هَلْ صَلَّى عِنْدَكِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ دَخَلَ فِي الضُّحَى فَسَكَبْتُ لَهُ فِي صَحْفَةٍ لَنَا مَاءً إِنِّي لَأَرَى فِيهَا وَضَرَ الْعَجِينِ قَالَ يُوسُفُ مَا أَدْرِي أَيَّ ذَلِكَ أَخْبَرَتْنِي أَتَوَضَّأَ أَمْ اغْتَسَلَ ثُمَّ رَكَعَ فِي هَذَا الْمَسْجِدِ مَسْجِدٍ فِي بَيْتِهَا أَرْبَعَ رَكَعَاتٍقَالَ يُوسُفُ فَقُمْتُ فَتَوَضَّأْتُ مِنْ قِرْبَةٍ لَهَا وَصَلَّيْتُ فِي ذَاكَ الْمَسْجِدِ أَرْبَعَ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Zuhair] dari [Abdullah bin Utsman bin Hutsaim] berkata, telah menceritakan kepadaku [Yusuf bin Mahak] bahwa dia menemui [Ummu Hani' binti Abu Thalib] dan bertanya perihal masuknya Rasulullah shallallahu 'alaihi wasallam pada waktu penaklukan kota Makkah.\" Yusuf tanyakan, \"Apakah Nabi shallallahu 'alaihi wasallam shalat di sisimu?\" Ummu Hani` lalu menjawab, \"Beliau masuk (Makkah) pada waktu Dluha, kemudian aku menuangkan air ke dalam bejana untuk beliau. Sungguh, aku melihat di dalamnya ada bekas adonan -Yusuf berkata; aku tidak tahu apakah Ummu Hani' mengabarkan kepadaku bahwa Nabi hanya sekedar wudlu ataukah mandi-, kemudian beliau mendirikan shalat empat rakaat di dalam masjid ini, yaitu masjid yang ada di dalam rumahnya.\" Yusuf berkata, \"Kemudian aku bangun dan berwudlu dari bejana miliknya (Ummu Hani`), lalu aku shalat empat rakaat di masjid tersebut.\""},"4169":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا أَبُو الْأَسْوَدِ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ أَنَّهُ سَم��عَ دُرَّةَ بِنْتَ مُعَاذٍ تُحَدِّثُ عَنْ أُمِّ هَانِئٍ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَتَزَاوَرُ إِذَا مِتْنَا وَيَرَى بَعْضُنَا بَعْضًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ النَّسَمُ طَيْرًا تَعْلُقُ بِالشَّجَرِ حَتَّى إِذَا كَانُوا يَوْمَ الْقِيَامَةِ دَخَلَتْ كُلُّ نَفْسٍ فِي جَسَدِهَا","id":"Telah menceritakan kepada kami [Hasan] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Abu Al Aswad Muhammad bin Abdurrahman bin Naufal] bahwa dia mendengar [Durrah binti Mu'adz] menceritakan dari [Ummu Hani'], bahwa dia bertanya kepada Rasulullah shallallahu 'alaihi wasallam, apakah ketika sudah meninggal kita bisa saling mengunjungi dan melihat satu sama yang lain? Kemudian Rasulullah shallallahu 'alaihi wasallam menjawab: \"Suatu saat nanti ruh akan menjadi burung yang menggantung di pohon sehingga apabila Kiamat tiba, maka tiap jiwa akan masuk kembali ke jasadnya.\""},"4170":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍ قَالَتْقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ مَرَّةً وَلَهُ أَرْبَعُ غَدَائِرَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Hani'] dia berkata, \"Suatu saat Nabi shallallahu 'alaihi wasallam datang ke Makkah, sedangkan beliau saat itu menawan empat pendusta.\""},"4171":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ قَالَ سَمِعْتُ ابْنَ أَبِي نَجِيحٍ يَذْكُرُ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍ قَالَتْرَأَيْتُ فِي رَأْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَفَائِرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Ibrahim bin Nafi'] berkata, aku mendengar [Ibnu Abu Najih] menyebutkan dari [Mujahid] dari [Ummu Hani'] dia berkata, \"Aku melihat di kepala Rasulullah shallallahu 'alaihi wasallam terdapat empat jalinan rambut.\""},"4172":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا مَالِكٌ عَنْ مُوسَى بْنِ مَيْسَرَةَ عَنْ أَبِي مُرَّةَ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ تَقُولُصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنْزِلِي ثَمَانِيَ رَكَعَاتٍ فِي ثَوْبٍ وَاحِدٍ مُلْتَحِفًا بِهِ","id":"Telah menceritakan kepada kami [Ustman bin Umar] berkata, telah menceritakan kepada kami [Malik] dari [Musa bin Maisarah] dari [Abu Murrah] bahwa dia mendengar [Ummu Hani'] berkata, \"Rasulullah shallallahu 'alaihi wasallam mendirikan shalat delapan rakaat di rumahku dengan berselimutkan satu kain.\""},"4173":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُتْبَةَ بْنِ أَبِي سُفْيَانَ حَدَّثَتْنِي عَمَّتِي أُمُّ حَبِيبَةَ بِنْتُ أَبِي سُفْيَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَانَ عِنْدَهَا فِي يَوْمِهَا أَوْ لَيْلَتِهَا فَسَمِعَ الْمُؤَذِّنَ قَالَ كَمَا يَقُولُ الْمُؤَذِّنُ","id":"Telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Abu Al Malih bin Usamah] berkata, telah menceritakan kepadaku [Abdullah bin Utbah bin Abu Sufyan] telah menceritakan kepadaku bibiku [Ummu Habibah binti Abu Sufyan] bahwa Rasulullah shallallahu 'alaihi wasallam apabila berada di sisinya baik di siang atau malam pada hari gilirannya, bila mendengar suara Mu'adzin maka beliau mengucapkan apa yang diucapkan Mu'adzin.\""},"4174":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ سَالِمَ بْنَ شَوَّالٍ يَقُولُ عَنْ أُمِّ حَبِيبَةَ قَالَتْكُنَّا نُغَلِّسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَمْعٍ إِلَى مِنًى وَقَالَ سَمُرَةُ كُنَّا نُغَلِّسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُزْدَلِفَةِ إِلَى مِنًى","id":"Telah menceritakan kepada kami [Sufyan] dari [Amru] berkata; aku mendengar [Salim bin Syawwal] berkata dari [Ummu Habibah] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami berpagi-pagi meninggalkan Jam' (nama tempat) menuju Mina.\" Dan Samurah berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami berpagi-pagi bertolak dari Muzdalifah menuju Mina.\""},"4175":{"ar":"حَدَّثَنَا عُبَيْدَةُ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ سَالِمٍ عَنْ أَبِي الْجَرَّاحِ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جَرَسٌ","id":"Telah menceritakan kepada kami [Ubaidah] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Salim] dari [Abu Al Jarrah] dari [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Para Malaikat tidak akan menyertai rombongan yang di dalamnya ada lonceng.\""},"4176":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ أَبِي ذِئْبٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سُفْيَانَ بْنِ سَعِيدٍ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Abu Dzi'b] berkata, telah menceritakan kepadaku [Az Zuhri] dari [Abu Salamah] dari [Abu Sufyan bin Sa'id] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Berwudlulah dari sesuatu yang disentuh oleh Api.\""},"4177":{"ar":"حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ سَالِمٍ عَنْ أَبِي الْجَرَّاحِ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جَرَسٌ","id":"Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] berkata, telah mengabarkan kepadaku [Nafi'] dari [Salim] dari [Abu Al Jarrah] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Para Malaikat tidak akan menyertai suatu rombongan yang di dalamnya ada lonceng.\""},"4178":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ قَالَ حَدَّثَ سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جَرَسٌقَالَ فَقُلْتُ لَهُ تَعِسْتَ يَا أَبَا عَبْدِ اللَّهِ قَالَ لِي كَيْفَ هُوَ قُلْتُ حَدَّثَنِي عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ سَالِمٍ عَنْ أَبِي الْجَرَّاحِ عَنْ أُمِّ حَبِيبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَدَقْتَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Khallad] berkata, aku mendengar [Yahya bin Sa'id] berkata, Sufyan telah menceritakan dari ['Ubaidullah bin 'Umar] dari [Nafi'] dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan menyertai perkumpulan yang di dalamnya terdapat lonceng.\" Nafi' lalu berkata, \"Aku lalu berkata kepadanya, \"Celaka kamu wahai Abu Abdullah.\" Kemudian dia ganti bertanya kepadaku, \"Terus bagaimana (yang benar)?\" Aku lalu menyebutkan, \"Telah menceritakan kepada kami ['Ubaidullah] dia berkata, telah menceritakan kepadaku [Nafi'] dari [Salim] dari [Abu Al Jarrah] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam.\" Lalu Abdullah bin Umar berkata, \"Kamu benar.\""},"4179":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ وَيَزِيدُ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ عَنْ أَبِيهِ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُخْتِهِ أُمِّ حَبِيبَةَ قَالَ يَزِيدُ بِنْتِ أَبِي سُفْيَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الْمُقْرِيُّ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى أَرْبَعَ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعًا بَعْدَهَا حَرَّمَ اللَّهُ عَلَيْهِ النَّارَ","id":"Telah menceritakan kepada kami [Abu Abdurrahman Al Muqri] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Asy Syu'aitsi], dan [Yazid] berkata; telah mengabarkan kepada kami [Muhammad bin Abdullah Asy Syu'aitsi] dari [ayahnya] dari [Anbasah bin Abu Sufyan] dari sudara perempuannya [Ummu Habibah], [Yazid] berkata; (Ummu Habibah adalah) [Binti Abu Sufyan] dari Nabi shallallahu 'alaihi wasallam, dan [Al Muqri] berkata, (Ummu Habibah) adalah [isteri Nabi] shallallahu 'alaihi wasallam, bahwa dia telah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan shalat empat rakaat sebelum zhuhur dan empat rakaat setelahnya, maka Allah akan mengharamkan Neraka kepadanya.\""},"4180":{"ar":"حَدَّثَنَا حَجَّاجٌ وَشُعَيْبُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ أَنَّهُسَأَلَ أُخْتَهُ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الْوَاحِدِ الَّذِي يُجَامِعُهَا فِيهِ قَالَتْ نَعَمْ إِذَا لَمْ يَكُنْ فِيهِ أَذًى","id":"Telah menceritakan kepada kami [Hajjaj] dan [Syua'ib bin Harb] keduanya berkata, telah menceritakan kepada kami [Laits] berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah bin Abu Sufyan] bahwa dia bertanya kepada saudara perempuannya [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, apakah Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan menggunakan satu pakaian yang dipakainya untuk bersetubuh?\" Dia menjawab, \"Ya, jika tidak terdapat kotoran padanya.\""},"4181":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ جُرَيْجٍ وَرَوْحٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ وَمُحَمَّدُ بْنُ بَكْرٍ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ أَنَّهُ أَخْبَرَهُ ابْنُ شَوَّالٍ أَنَّهُدَخَلَ عَلَى أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ فَأَخْبَرَتْهُ أَنَّهَا بَعَثَ وَقَالَ ابْنُ بَكْرٍ أَنَّهُ بَعَثَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَمْعٍ بِلَيْلٍ وَقَالَ يَحْيَى قَدَّمَهَا مِنْ جَمْعٍ بِلَيْلٍ","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dan [Rauh] berkata, telah menceritakan kepada kami [Ibnu Juraij] dan [Muhammad bin Bakr] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Atha'] bahwa [Ibnu Syawal] telah mengabarkan kepadanya, bahwa dia menemui [Ummu Habibah binti Abu Sufyan], lalu Ummu Habibah mengabarkan kepadanya bahwa dia berangkat, sedangkan [Ibnu Bakr] menyebutkan, bahwa Nabi shallallahu 'alaihi wasallam berangkat menuju Mina dari Jam' semenjak malam hari.\" Dan [Yahya] menyebutkan bahwa beliau berangkat menuju Mina dari Jam' sejak malam.\""},"4182":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا دَرَّاجٌ عَنْ عُمَرَ بْنِ الْحَكَمِ أَنَّهُ حَدَّثَهُ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَأَنَّ أُنَاسًا مِنْ أَهْلِ الْيَمَنِ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْلَمَهُمْ الصَّلَاةَ وَالسُّنَنَ وَالْفَرَائِضَ ثُمَّ قَالُوا يَا رَسُولَ اللَّهِ إِنَّ لَنَا شَرَابًا نَصْنَعُهُ مِنْ الْقَمْحِ وَالشَّعِيرِ قَالَ فَقَالَ الْغُبَيْرَاءُ قَالُوا نَعَمْ قَالَ لَا تَطْعَمُوهُ ثُمَّ لَمَّا كَانَ بَعْدَ ذَلِكَ بِيَوْمَيْنِ ذَكَرُوهُمَا لَهُ أَيْضًا فَقَالَ الْغُبَيْرَاءُ قَالُوا نَعَمْ قَالَ لَا تَطْعَمُوهُ ثُمَّ لَمَّا أَرَادُوا أَنْ يَنْطَلِقُوا سَأَلُوهُ عَنْهُ فَقَالَ الْغُبَيْرَاءُ قَالُوا نَعَمْ قَالَ لَا تَطْعَمُوهُ قَالُوا فَإِنَّهُمْ لَا يَدَعُونَهَا قَالَ مَنْ لَمْ يَتْرُكْهَا فَاضْرِبُوا عُنُقَهُ","id":"Telah menceritakan kepada kami [Hasan] dia berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Darraj] dari [Umar bin Hakam] bahwa dia telah menceritakan kepadanya dari [Ummu Habibah binti Abu Sufyan], bahwa orang-orang dari penduduk Yaman datang kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau mengajarkan kepada mereka tentang shalat, sunnah-sunnah dan kewajiban-kewajiban. Mereka kemudian berkata, \"Wahai Rasulullah, sesungguhnya kami memiliki minuman yang terbuat dari gandum dan tepung?\" Beliau balik bertanya: \"Al Ghubaira'?\" mereka menjawab, \"Ya.\" Nabi lalu bersabda: \"Jangan kalian mengkonsumsinya.\" Dua hari setelah itu mereka menanyakan hal itu lagi kepada beliau, maka beliau pun bertanya: \"Al Ghubaira'?\" mereka menjawab, \"Ya.\" Lantas beliau bersabda: \"Jangan kalian mengkonsumsinya.\" Hingga ketika mereka hendak pergi, mereka masih bertanya tentang minuman itu kepada beliau, dan beliau bertanya lagi: \"Al Ghubaira'?\" mereka menjawab, \"Ya.\" Nabi pun bersabda: \"Jangan kalian mengkonsumsinya.\" Kemudian para sahabat berkomentar, \"Sungguh, mereka adalah suatu kaum yang susah untuk meninggalkannya.\" Maka beliau pun bersabda: \"Barangsiapa tidak meninggalkannya maka potonglah lehernya.\""},"4183":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ حَبِيبَةَ بِنْتِ أُمِّ حَبِيبَةَ بِنْتِ أَبِي س��فْيَانَ عَنْ أُمِّهَا أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سُفْيَانُ أَرْبَعُ نِسْوَةٍ قَالَتِاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَوْمٍ وَهُوَ مُحْمَرٌّ وَجْهُهُ وَهُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَحَلَّقَ قُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِذَا كَثُرَ الْخَبَثُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Urwah] dari [Zainab binti Abu Salamah] dari [Habibah binti Ummu Habibah biti Abu Sufyan] dari ibunya [Ummu Habibah] dari [Zainab] isteri Nabi shallallahu 'alaihi wasallam, Sufyan menyebutkan, \"Empat orang wanita.\" Ia (isteri Nabi) Berkata, \"Nabi shallallahu 'alaihi wasallam bangun dari tidurnya dengan wajah merah sambil bersabda: \"LAA ILAAHA ILLALLAAH (Tidak ada tuhan yang berhak untuk disembah selain Allah), celakalah orang-orang arab dari keburukan yang telah dekat, hari ini telah dibukakan pemisah antara Ya'juj dan Ma'juj seperti ini, \" kemudian Nabi membuat lingkaran, maka aku bertanya, \"Wahai Rasulullah, apakah kita akan dibinasakan padahal ada orang-orang shalih di tengah-tengah kita?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ya, apabila kerusakan sudah merajalela.\""},"4184":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ يَعْنِي ابْنَ كَيْسَانَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَزِعًا يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذَا قَالَ وَحَلَّقَ بِأُصْبُعَيْهِ الْإِبْهَامِ وَالَّتِي تَلِيهَا قَالَتْ زَيْنَبُ بِنْتُ جَحْشٍ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخَبَثُ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Shalih] -yakni Ibnu Kaisan-, [Ibnu Syihab] berkata, telah menceritakan kepadaku [Urwah bin Zubair] bahwa [Zainab binti Abu Salamah] mengabarkan dari [Ummu Habibah binti Abu Sufyan] dari [Zainab binti Jahsy] dia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam menemuinya dalam keadaan terkejut seraya bersabda: \"LAA ILAAHA ILLALLAAH (Tidak ada tuhan yang berhak untuk disembah selain Allah), celakalah orang-orang arab dari keburukan yang telah dekat, hari ini telah dibukakan pemisah antara Ya'juj dan Ma'juj seperti ini, \" dia berkata, kemudian beliau melingkarkan kedua jarinya, yaitu ibu jari dengan jari telunjuk.\" Zainab binti Jahsy berkata, \"Lalu aku pun bertanya, \"Wahai Rasulullah, apakah kita akan dibinasakan padahal ada orang-orang shalih di tengah-tengah kita?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ya, apabila kerusakan sudah merajalela.\""},"4185":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ طَلْحَةَ بْنِ يَزِيدَ بْنِ رُكَانَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِي الْجَرَّاحِ مَوْلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أُمِّ حَبِيبَةَ أَنَّهَا حَدَّثَتْهُ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ كَمَا يَتَوَضَّئُونَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Muhammad bin Thalhah bin Yazid bin Rukanah] dari [Salim bin Abdullah bin Umar] dari [Abu Al Jarrah] bekas budak Ummu Habibah, isteri Nabi shallallahu 'alaihi wasallam, dari [Ummu Habibah] bahwa dia menceritakan kepadanya dari [Zainab binti Jahsy] dia berkata, \"Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya tidak memberatkan terhadap ummatku pasti aku perintahkan kepada mereka untuk bersiwak pada setiap waktu shalat sebagaimana mereka melakukan wudlu.\""},"4186":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ ذَكَرَ ابْنُ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَاقِدٌ بِأُصْبُعَيْهِ السَّبَّابَةِ بِالْإِبْهَامِ وَهُوَ يَقُولُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ مَوْضِعِ الدِّرْهَمِ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِذَا كَثُرَ الْخَبَثُ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] berkata, [Ibnu Syihab] menyebutkan dari [Urwah bin Zubair] dari [Zainab binti Abu Salamah] dari [Ummu Habibah binti Abu Sufyan] dari [Zainab binti Jahsy] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku sedangkan beliau melingkarkan kedua jarinya, yaitu jari telunjuk dengan ibu jari seraya bersabda: \"Celakalah orang-orang arab dari keburukan yang telah dekat, hari ini telah dibukakan pemisah antara Ya'juj dan Ma'juj seperti wadah mata uang perak, \" dia menyebutkan, \"Lantas aku bertanya, \"Wahai Rasulullah, apakah kita akan dibinasakan padahal ada orang-orang shalih di tengah-tengah kita?\" beliau shallallahu 'alaihi wasallam menjawab: \"Ya, apabila kerusakan sudah merajalela.\""},"4187":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ الْعَمِّيُّ أَبُو عَبْدِ الصَّمَدِ حَدَّثَنَا مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ مَوْلًى لِابْنِ الزُّبَيْرِ يُقَالُ لَهُ يُوسُفُ بْنُ الزُّبَيْرِ أَوْ الزُّبَيْرُ بْنُ يُوسُفَ عَنِ ابْنِ الزُّبَيْرِ عَنْ سَوْدَةَ بِنْتِ زَمْعَةَ قَالَتْجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ أَنْ يَحُجَّ قَالَ أَرَأَيْتَكَ لَوْ كَانَ عَلَى أَبِيكَ دَيْنٌ فَقَضَيْتَهُ عَنْهُ قُبِلَ مِنْكَ قَالَ نَعَمْ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاللَّهُ أَرْحَمُ حُجَّ عَنْ أَبِيكَ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdus Shamad Al 'Amiy Abu Abdus Shamad] telah menceritakan kepada kami [Manshur] dari [Mujahid] dari budak milik Ibnu Zubair yang biasa disebut [Yusuf bin Zubair] atau Zubair bin Yusuf dari [Ibnu Zubair] dari [Saudah Binti Zam'ah] dia berkata, \"Seseorang datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian dia berkata, \"Sesungguhnya bapakku adalah seorang yang sudah tua dan tidak mampu lagi untuk melaksanakan haji.\" Beliau menjawab: \"Apa pedapatmu sekiranya bapakmu mempunyai hutang, apakah kamu akan melunasinya?\" dia menjawab, \"Ya.\" Kemudian beliau shallallahu 'alaihi wasallam bersabda: \"Allah lebih penyayang, maka lakukanlah haji untuk bapakmu.\""},"4188":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ إِسْمَاعِيلَ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍ عَنْ سَوْدَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَاتَتْ شَاةٌ لَنَا فَدَبَغْنَا مَسْكَهَا فَمَا زِلْنَا نَنْبِذُ بِهِ حَتَّى صَارَ شَنًّا","id":"Telah menceritakan kepada kami [Ibnu Numair] dari [Isma'il] dari [Ikrimah] dari [Ibnu Abbas] dari [Saudah] isteri Nabi shallallahu 'alaihi wasallam, dia berkata, \"Seekor kambing milik kami mati kemudian kulitnya kami samak, dan kami terus saja mengerjakannya hingga menjadi geribah (wadah air dari kulit).\""},"4189":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ مَوْلًى لِآلِ الزُّبَيْرِ قَالَإِنَّ بِنْتَ زَمْعَةَ قَالَتْ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ أَبِي زَمْعَةَ مَاتَ وَتَرَكَ أُمَّ وَلَدٍ لَهُ وَإِنَّا كُنَّا نَظُنُّهَا بِرَجُلٍ وَإِنَّهَا وَلَدَتْ فَخَرَجَ وَلَدُهَا يُشْبِهُ الرَّجُلَ الَّذِي ظَنَنَّاهَا بِهِ قَالَ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَا أَمَّا أَنْتِ فَاحْتَجِبِي مِنْهُ فَلَيْسَ بِأَخِيكِ وَلَهُ الْمِيرَاثُ","id":"Telah menceritakan kepada kami [Aswad bin Amir] telah meceritakan kepada kami [Isra'il] dari [Manshur] dari [Mujahid] dari [seorang budak] milik keluarga Zubair, dia berkata bahwa [anak perempuan Zam'ah] berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam, kemudian aku berkata, \"Sesungguhnya ayahku, Zam'ah, telah wafat dan meninggalkan Ummu Walad. Dan kami mencurigai dia telah melakukan perselingkuhan dengan laki-laki lain hingga melahirkan seorang anak, yang juga mirip dengan lelaki selingkuhannya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada anak perempuan Zam'ah: \"Hendaklah kamu berhijab darinya, ia bukan saudaramu, namun ia masih mempunyai hak waris.\" "},"4190":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَقَالَ هَلْ مِنْ طَعَامٍ قُلْتُ لَا إِلَّا عَظْمًا أُعْطِيَتْهُ مَوْلَاةٌ لَنَا مِنْ الصَّدَقَةِ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرِّبِيهِ فَقَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaid bin Sabaq] dari [Juwairiyah binti Al Harits] dia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam datang kepadaku lantas bertanya \"Apakah ada makanan?\" Aku menjawab, \"Tidak, kecuali tulang pemberian budak kita dari harta sedekah.\" Beliau kemudian bersabda: \"Dekatkanlah kepadaku karena dia telah sampai kepada tempatnya.\""},"4191":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ قَالَ سَمِعْتُ كُرَيْبًا يُحَدِّثُ عَنِ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى جُوَيْرِيَةَ بَكَرًا وَهِيَ فِي الْمَسْجِدِ تَدْعُو ثُمَّ مَرَّ عَلَيْهَا قَرِيبًا مِنْ نِصْفِ النَّهَارِ فَقَالَ مَا زِلْتِ عَلَى حَالِكِ قَالَتْ نَعَمْ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُعَلِّمُكِ كَلِمَاتٍ تَعْدِلُهُنَّ بِهِنَّ وَلَوْ وُزِنَ بِهِنَّ وُزِنَ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ ثَلَاثًا سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ وَكَانَ اسْمُهَا بَرَّةَ فَسَمَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُوَيْرِيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Abdurrahman] bekas budak keluarga Thalhah, berkata; aku pernah mendengar [Kuraib] menceritakan dari [Ibnu Abbas] dari [Juwairiyah] dia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melewati Juwairiyah di pagi hari, ketika itu dia berada di masjid sedang berdoa. Kemudian menjelang tengah hari beliau kembali melewatinya seraya bertanya: \"Apakah kamu masih pada posisimu?\" dia menjawab, \"Ya.\" Belaiu lalu bersabda: \"Maukah aku beritahukan kepadamu beberapa kalimat yang dapat menyamainya, yang seandainya ditimbang maka akan menyamainya, yaitu; SUBHAANALLAAH 'ADADA KHALQIHI, SUBHAANALLAAH 'ADADA KHALQIHI (Maha suci Allah sebanyak ciptaan-Nya, Maha suci Allah sebanyak ciptaan-Nya) tiga kali, SUBHAANALLAAH RIDLAA NAFSIHI, SUBHAANALLAAH RIDLAA NAFSIHI, SUBHAANALLAAH RIDLA NAFSIHI (Maha suci Allah sebagaimna Dia ridla terhadap diri-Nya) tiga kali, SUBHAANALLAAH ZINATA 'ARSYIHI, SUBHAANALLAAH ZINATA 'ARSYIHI, SUBHAANALLAAH ZINATA 'ARSYIHI (Maha suci Allah sebanyak hiasan yang ada di atas Arsy-Nya) tiga kali, SUBHAANALLAAH MIDAADA KALIMAATIHI, SUBHAANALLAAH MIDAADA KALIMAATIHI, SUBHAANALLAH MIDAADA KALIMAATIHI (Maha suci Allah sebanyak tinta kalimat-Nya) tiga kali.\" Dulu namanya adalah Barrah, kemudian Rasulullah shallallahu 'alaihi wasallam memberinya nama dengan Juwairiyah.\""},"4192":{"ar":"حَدَّثَنَا مُحَمَّدٌ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي أَيُّوبَ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِ قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فِي يَوْمِ جُمُعَةٍ وَهِيَ صَائِمَةٌ فَقَالَ لَهَا أَصُمْتِ أَمْسِ قَالَتْ لَا قَالَ أَفَتُرِيدِينَ أَنْ تَصُومِي غَدًا قَالَتْ لَا قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفْطِرِي إِذًا","id":"Telah menceritakan kepada kami [Muhammad] dan [Hajjaj] keduanya berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Ayyub] dari [Juwairiyah binti Al Harits] dia berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam pada hari Jum'at datang menemuinya, yang ketika itu dia sedang berpuasa. Beliau kemudian bertanya kepadanya: \"Apakah kamu kemarin berpuasa?\" dia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah kamu besok mau berpuasa?\" dia menjawab, \"Tidak.\" Maka beliau pun bersabda: \"Berbukalah kamu.\""},"4193":{"ar":"حَدَّثَنَا أَسْوَدُ يَعْنِي ابْنَ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ جَابِرٍ عَنْ خَالَتِهِ أُمِّ عُثْمَانَ عَنِ الطُّفَيْلِ ابْنِ أَخِي جُوَيْرِيَةَ عَنْ جُوَيْرِيَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَبِسَ ثَوْبَ حَرِيرٍ فِي الدُّنْيَا أَلْبَسَهُ اللَّهُ تَعَالَى ثَوْبَ مَذَلَّةٍ أَوْ ثَوْبًا مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Aswad] -yakni Ibnu Amir- telah menceritakan kepada kami [Syarik] dari [Jabir] dari bibinya [Ummu Utsman] dari [Thufail] anak laki-laki, dari saudaranya Juwairiyah dari [Juwairiyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mengenakan pakaian dari sutera di dunia, maka Allah Ta'ala akan memakaikan kepadanya pakaian kehinaan, atau pakaian dari api Neraka.\""},"4194":{"ar":"حَدَّثَنَا عَاصِمٌ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنِي ابْنُ شِهَابٍ قَالَ إِنَّ عُبَيْدَ بْنَ السَّبَّاقِ يَزْعُمُ أَنَّ جُوَيْرِيَةَ زَوْجَ النَّبِىِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَقَالَ هَلْ مِنْ طَعَامٍ قَالَتْ لَا وَاللَّهِ مَا عِنْدَنَا طَعَامٌ إِلَّا عَظْمًا مِنْ شَاةٍ أُعْطِيَتْهَا مَوْلَاتِي مِنْ الصَّدَقَةِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرِّبِيهِ فَقَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami [Ashim] telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepadaku [Ibnu Syihab] berkata, bahwa [Ubaid bin Sabbaq] menyakini bahwa [Juwairiyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah menemuinya, kemudian beliau bersabda: \"Apakah ada makanan?\" Juwairiyah menjawab, \"Kami tidak memiliki makanan, kecuali tulang kambing pemberian budakku dari harta sedekah.\" Beliau lantas bersabda: \"Dekatkanlah kepadaku karena dia telah sampai kepada tempatnya.\""},"4195":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنِى أَبُو أَيُّوبَ الْعَتَكِىُّ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِ قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا يَوْمَ جُمُعَةٍ وَهِيَ صَائِمَةٌ فَقَالَ لَهَا أَصُمْتِ أَمْسِ قَالَتْ لَا قَالَ أَتُرِيدِينَ أَنْ تَصُومِي غَدًا قَالَتْ لَا قَالَ فَأَفْطِرِي","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepadaku [Abu Ayyub Al Ataki] dari [Juwairiyah binti Al Harits] dia berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam pernah menemuinya pada hari Jum'at, yang saat itu dia sedang berpuasa. Beliau lalu bertanya kepadanya: \"Apakah kemarin kamu berpuasa?\" dia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah kamu besok hendak berpuasa?\" dia menjawab, \"Tidak.\" Maka beliau pun bersabda: \"Berbukalah.\""},"4196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ سُلَيْمٍ أَنَّهَاقَالَتْ يَا رَسُولَ اللَّهِ أَنَسٌ خَادِمُكَ ادْعُ اللَّهَ لَهُ قَالَ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيمَا أَعْطَيْتَهُقَالَ حَجَّاجٌ فِي حَدِيثِهِ قَالَ فَقَالَ أَنَسٌ أَخْبَرَنِي بَعْضُ وَلَدِي أَنَّهُ قَدْ دُفِنَ مِنْ وَلَدِي وَوَلَدِ وَلَدِي أَكْثَرُ مِنْ مِائَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] telah menceritakan kepadaku [Syu'bah] berkata, aku mendengar [Qatadah] telah menceritakan dari [Anas bin Malik] dari [Ummu Sulaim] bahwa dia berkata, \"Wahai Rasulullah, Anas pelayanmu, do'akanlah kepada Allah untuknya.\" Anas lalu berkata, \"Maka Nabi shallallahu 'alaihi wasallam pun berdoa: \"Ya Allah, berilah dia harta dan anak yang banyak, dan berkahilah apa yang telah Engkau berikan padanya.\" Hajjaj menyebutkan dalam haditsnya, dia berkata, \"Anas lalu berkata, \"Sebagian anakku mengabarkan kepadaku, bahwa anak dan cucu-cucuku yang sudah dimakamkan lebih dari seratus.\""},"4197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَرَوْحٌ الْمَعْنَى قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ أَنَّهُكَانَ بَيْنَ ابْنِ عَبَّاسٍ وَزَيْدِ بْنِ ثَابِتٍ فِي الْمَرْأَةِ تَحِيضُ بَعْدَمَا تَطُوفُ بِالْبَيْتِ يَوْمَ النَّحْرِ مُقَاوَلَةٌ فِي ذَلِكَ فَقَالَ زَيْدٌ لَا تَنْفِرُ حَتَّى يَكُونَ آخِرُ عَهْدِهَا بِالْبَيْتِ وَقَالَ ابْنُ عَبَّاسٍ إِذَا طَافَتْ يَوْمَ النَّحْرِ وَحَلَّتْ لِزَوْجِهَا نَفَرَتْ إِنْ شَاءَتْ وَلَا تَنْتَظِرُ فَقَالَتْ الْأَنْصَارُ يَا ابْنَ عَبَّاسٍ إِنَّكَ إِذَا خَالَفْتَ زَيْدًا لَمْ نُتَابِعْكَ فَقَالَ ابْنُ عَبَّاسٍ سَلُوا أُمَّ سُلَيْمٍ فَسَأَلُوهَا عَنْ ذَلِكَ فَأَخْبَرَتْ أَنَّ صَفِيَّةَ بِنْتَ حُيَيِّ بْنِ أَخْطَبَ أَصَابَهَا ذَلِكَ فَقَالَتْ عَائِشَةُ الْخَيْبَةُ لَكِ حَبَسْتِينَا فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَنْفِرَ وَأَخْبَرَتْ أُمُّ سُلَيْمٍ أَنَّهَا لَقِيَتْ ذَلِكَ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَنْفِرَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Rauh] secara makna, keduanya berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Ikrimah], bahwa telah terjadi perdebatan di antara [Ibnu Abbas] dan Zaid bin Tsabit tentang seorang wanita yang datang masa haidnya setelah dia melakukan Thawaf di Ka'bah pada hari Nahr (Iedul Adla). Zaid berpendapat, \"Janganlah kamu meninggalkan (Makkah) sehingga akhir yang kamu lakukan adalah Thawaf di Ka'bah.\" Sedangkan Ibnu Abbas berkata, \"Jika ia (seorang wanita) Telah melakukan thawaf dan halal untuk suaminya, maka jika mau ia sudah boleh meninggalkan Makkah dan tidak perlu menunggu.\" Orang-orang Anshar lalu berkata kepada Ibnu Abbas, \"Wahai Ibnu Abbas, jika kamu menyelisihi Zaid maka kami tidak akan mengikutimu!\" Kemudian Ibnu Abbas berkata, \"Tanyakanlah kepada Ummu Sulaim.\" Maka mereka menanyakan tentang hal itu kepada Ummu Sulaim, lalu [Ummu Sulaim] memberitahukan bahwa Shafiyah binti Huyay bin Akhtab pernah mengalami hal itu, lalu 'Aisyah berkata, \"Kerugian atas kamu! Kamu telah menahan kami.\" Maka hal itu disampaikan kepada Rasulullah shallallahu 'alaihi wasallam, sehingga beliau memerintahkan untuk meninggalkan Makkah, dan Ummu Sulaim menceritakan bahwa dia menemui hal yang sama kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk meninggalkan Makkah.\""},"4198":{"ar":"حَدَّثَنَا حَجَّاجٌ عَنِ ابْنِ جُرَيْجٍ وَرَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ الْكَرِيمِ أَنَّ الْبَرَاءَ بْنَ زَيْدِ ابْنِ بِنْتِ أَنَسِ بْنِ مَالِكٍ أَخْبَرَهُ أَنَّ أَنَسَ بْنَ مَالِكٍ يُحَدِّثُ عَنْ أُمِّ أَنَسِ بْنِ مَالِكٍ قَالَتْدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا وَقِرْبَةٌ مُعَلَّقَةٌ فِيهَا مَاءٌ فَشَرِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا مِنْ فِي الْقِرْبَةِ فَقَامَتْ أُمُّ سُلَيْمٍ إِلَى فِي الْقِرْبَةِ فَقَطَعَتْهُ","id":"Telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dan [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Abdul Karim] bahwa [Barra' bin Zaid] cucunya Anas bin Malik, telah mengabarkan kepadanya, bahwa [Anas bin Malik] telah menceritakan dari [Ummu Anas bin Malik] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah menemui kami, sedangkan geribah yang berisikan air mengantung, kemudian Nabi shallallahu 'alaihi wasallam pun meminumnya sambil berdiri melalui mulut geriba.\" Ummu Sulaim lalu bangun dan memotong mulut geribah.\""},"4199":{"ar":"حَدَّثَنَا يَعْلَى وَمُحَمَّدٌ قَالَا حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ عَنْ عَمْرٍو الْأَنْصَارِيِّ عَنْ أُمِّ سُلَيْمٍ بِنْتِ مِلْحَانَ وَهِيَ أُمُّ أَنَسِ بْنِ مَالِكٍ قَالَ مُحَمَّدٌ أَخْبَرَتْهُ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمَيْنِ يَمُوتُ لَهُمَا ثَلَاثَةُ أَوْلَادٍ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُمَا اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ قَالَهَا ثَلَاثًا قِيلَ يَا رَسُولَ اللَّهِ وَاثْنَانِ قَالَ وَاثْنَانِ","id":"Telah menceritakan kepada kami [Ya'la] dan [Muhammad] keduanya berkata, telah menceritakan kepada kami [Utsman bin Hakim] dari [Amru Al Anshari] dari [Ummu Sulaim binti Milhan] dia adalah ibunya Anas bin Malik, [Muhammad] berkata, \"Ummu Sulaim mengabarkan kepadanya, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dua orang muslim ditinggal mati oleh ketiga anaknya yang belum berumur baligh, melainkan Allah akan memasukkan keduanya ke dalam surga dengan karuania dan rahmatnya.\" Beliau mengucapkannya hingga tiga kali. Maka ditanyakan kepada beliau, \"Wahai Rasulullah, bagaimana jika hanya dua?\" Beliau menjawab: \"Meskipun dua.\""},"4200":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ الْكَرِيمِ الْجَزَرِيُّ عَنِ الْبَرَاءِ ابْنِ بِنْتِ أَنَسٍ عَنْ أَنَسٍ عَنْ أُمِّهِ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَيْتِ قِرْبَةٌ مُعَلَّقَةٌ فَشَرِبَ مِنْهَا قَائِمًا فَقَطَعْتُ فَاهَا وَإِنَّهُ لَعِنْدِي","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdul Karim Al Jazari] dari [Barra'] cucunya Anas, dari [Anas] dari [ibunya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah menemuinya, sedangkan di dalam rumahnya terdapat geribah yang menggantung, kemudian beliau minum darinya dengan berdiri, maka aku memotong mulut geriba tersebut, dan geriba itu sekarang bersamaku.\""},"4201":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ وَقَالَ عِكْرِمَةُ بْنُ خَالِدٍ عَنْ زَيْدٍ وَابْنِ عَبَّاسٍ قَالَ ابْنُ عَبَّاسٍ لِزَيْدٍ فَاسْأَلْ نِسَاءَكَ أُمَّ سُلَيْمٍ وَصَوَاحِبَهَا هَلْ أَمَرَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُنَّ زَيْدٌ فَقُلْنَ نَعَمْ قَدْ أَمَرَنَا بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ قَالَإِنَّ زَيْدَ بْنَ ثَابِتٍ وَابْنَ عَبَّاسٍ اخْتَلَفَا فِي الْمَرْأَةِ تَحِيضُ بَعْدَ الزِّيَارَةِ فِي يَوْمِ النَّحْرِ بَعْدَمَا طَافَتْ بِالْبَيْتِ فَقَالَ زَيْدٌ يَكُونُ آخِرَ عَهْدِهَا الطَّوَافُ بِالْبَيْتِ وَقَالَ ابْنُ عَبَّاسٍ تَنْفِرُ إِنْ شَاءَتْ فَقَالَ الْأَنْصَارُ لَا نُتَابِعُكَ يَا ابْنَ عَبَّاسٍ وَأَنْتَ تُخَالِفُ زَيْدًا وَقَالَ وَاسْأَلُوا صَاحِبَتَكُمْ أُمَّ سُلَيْمٍ فَقَالَتْ حِضْتُ بَعْدَمَا طُفْتُ بِالْبَيْتِ يَوْمَ النَّحْرِ فَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَنْفِرَ وَحَاضَتْ صَفِيَّةُ فَقَالَتْ لَهَا عَائِشَةُ الْخَيْبَةُ لَكِ إِنَّكِ لَحَابِسَتُنَا فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرُوهَا فَلْتَنْفِرْ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata, dan [Ikrimah bin Khalid] berkata dari [Zaid] dan [Ibnu Abbas], Ibnu Abbas berkata kepada Zaid; tanyalah kepada isterimu [Ummu Sulaim] dan sahabat-sahabatnya, apakah Rasulullah shallallahu 'alaihi wasallam menyuruh mereka?\" Maka Zaid pun menanyakannya kepada kami, dan kami pun menjawab, \"Benar, Rasulullah shallallahu 'alaihi wasallam telah memerintahkan seperti itu.\" Telah menceritakan kepada kami [Abdus Shamad] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Ikrimah] dia berkata, \"Sesungguhnya Zaid bin Tsabit berselisih dengan Ibnu Abbas mengenai seorang wanita yang haid setelah ia melakukan Ziyarah di hari raya nahr (idul Adla) setelah melakukan Thawaf di Ka'bah. Zaid berkata, \"Amalan yang terakhir dilakukan adalah Thawaf di Ka'bah.\" Sedangkan Ibnu Abbas berkata, \"Ia boleh meninggalkan Makkah jika ia menghendaki.\" Maka orang-orang Anshar berkata, \"Kami tidak akan mengikutimu wahai Ibnu Abbas, selagi kamu menyelisihi Zaid.\" Kemudian [Ibnu Abbas] berkata, \"Tanyakanlah kepada saudari kalian, [Ummu Sulaim].\" Ummu Sulaim lalu menerangkan, \"Aku pernah haid sehabis Thawaf di Ka'bah pada hari Nahr (Idul Adla), Rasulullah shallallahu 'alaihi wasallam kemudian menyuruhku untuk meninggalkan (Makkah), dan Shafiyah juga pernah mengalami haid, maka 'Aisyah berkata kepadanya, 'Kerugian atas kamu! Kamu telah menahan kami.' Maka hal itu disampaikan kepada Rasulullah shallallahu 'alaihi wasallam, lantas beliau pun bersabda: \"Perintahkanlah agar dia meninggalkan Makkah.\""},"4202":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ أَخْبَرَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَيْرَةَ عَنْ دُرَّةَ بِنْتِ أَبِي لَهَبٍ قَالَتْكُنْتُ عِنْدَ عَائِشَةَ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ائْتُونِي بِوَضُوءٍ قَالَتْ فَابْتَدَرْتُ أَنَا وَعَائِشَةُ الْكُوزَ فَأَخَذْتُهُ أَنَا فَتَوَضَّأَ فَرَفَعَ بَصَرَهُ إِلَيَّ أَوْ طَرْفَهُ إِلَيَّ وَقَالَ أَنْتِ مِنِّي وَأَنَا مِنْكِ قَالَتْ فَأُتِيَ بِرَجُلٍ فَقَالَ مَا أَنَا فَعَلْتُهُ إِنَّمَا قِيلَ لِي قَالَتْ وَكَانَ سَأَلَهُ عَلَى الْمِنْبَرِ مَنْ خَيْرُ النَّاسِ فَقَالَ أَفْقَهُهُمْ فِي دِينِ اللَّهِ وَأَوْصَلُهُمْ لِرَحِمِهِذَكَرَ فِيهِ شَرِيكٌ شَيْئَيْنِ آخَرَيْنِ لَمْ أَحْفَظْهُمَا","id":"Telah menceritakan kepada kami [Aswad bin Amir] telah mengabarkan kepada kami [Syarik] dari [Simak] dari [Abdullah bin Umairah] dari [Durrah binti Abu Lahab] dia berkata, \"Saat aku berada disisi 'Aisyah, tiba-tiba Nabi shallallahu 'alaihi wasallam masuk dan bersabda: \"Berilah aku air untuk berwudlu.\" Durrah berkata, \"Maka aku dan 'Aisyah segera mengambil bejana, lalu beliau berwudlu' dan melihat aku, atau melirik aku. Beliau lalu bersabda: \"Kamu termasuk dari bagianku dan aku termasuk dari bagianmu.\" Durrah berkata, --kemudian ada seseorang disidangkan kepada beliau, namun ia menyatakan 'Aku tidak melakukan, itu hanya sebuah berita saja.\" Durrah berkata, \"Kemudian saat masih berada di mimbar beliau ditanya 'Siapakah orang yang paling baik? ' Beliau menjawab: \"Mereka yang fakih dalam agama Allah dan yang paling sering menyambung tali silatur rahmi.\" Kemudian dalam hadits tersebut menyebutkan dua hal yang aku tidak menghafalnya.\""},"4203":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَيْرَةَ عَنْ زَوْجِ دُرَّةَ بِنْتِ أَبِي لَهَبٍ عَنْ دُرَّةَ بِنْتِ أَبِي لَهَبٍ قَالَتْقَامَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ خَيْرٌ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ النَّاسِ أَقْرَؤُهُمْ وَأَتْقَاهُمْ وَآمَرُهُمْ بِالْمَعْرُوفِ وَأَنْهَاهُمْ عَنْ الْمُنْكَرِ وَأَوْصَلُهُمْ لِلرَّحِمِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdul Malik] telah menceritakan kepada kami [Syarik] dari [Simak] dari [Abdullah bin Umairah] dari [Suaminya Durrah binti Abu Lahab] dari [Durrah binti Abu Lahab] dia berkata, \"Seorang laki-laki berdiri di hadapan Nabi shallallahu 'alaihi wasallam, sedangkan beliau berada di atas mimbar. Laki-laki itu bertanya, \"Wahai Rasulullah, siapakah manusia yang paling baik?\" Beliau bersabda: \"Manusia yang paling baik adalah yang paling mengerti (kitabullah), paling bertakwa, paling sering amar ma'ruf nahi munkar, dan yang paling sering menjalin tali silatur rahmi.\""},"4204":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَأَرْسَلَ مَرْوَانُ عَبْدَ اللَّهِ بْنَ عُتْبَةَ إِلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ يَسْأَلُهَا عَمَّا أَفْتَاهَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْهُ أَنَّهَا كَانَتْ تَحْتَ سَعْدِ ابْنِ خَوْلَةَ فَتُوُفِّيَ عَنْهَا فِي حَجَّةِ الْوَدَاعِ وَكَانَ بَدْرِيًّا فَوَضَعَتْ حَمْلَهَا قَبْلَ أَنْ يَنْقَضِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ مِنْ وَفَاتِهِ فَلَقِيَهَا أَبُو السَّنَابِلِ يَعْنِي ابْنَ بَعْكَكٍ حِينَ تَعَلَّتْ مِنْ نِفَاسِهَا وَقَدْ اكْتَحَلَتْ فَقَالَ لَهَا ارْبَعِي عَلَى نَفْسِكِ أَوْ نَحْوَ هَذَا لَعَلَّكِ تُرِيدِينَ النِّكَاحَ إِنَّهَا أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ مِنْ وَفَاةِ زَوْجِكِ قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ مَا قَالَ أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حَلَلْتِ حِينَ وَضَعْتِ حَمْلَكِحَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ إِنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ كَتَبَ إِلَى عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ يَأْمُرُهُ أَنْ يَدْخُلَ عَلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ يَسْأَلُهَا عَمَّا أَفْتَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزَعَمَتْ أَنَّهَا كَانَتْ تَحْتَ سَعْدِ ابْنِ خَوْلَةَ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِيهِ قَالَ كَتَبْتُ إِلَى عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ آمُرُهُ أَنْ يَدْخُلَ عَلَى سُبَيْعَةَ الْأَسْلَمِيَّةِ فَيَسْأَلَهَا عَنْ شَأْنِهَا قَالَ فَدَخَلَ عَلَيْهَا فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dia berkata, Marwan mengutus [Abdullah bin Utbah] kepada [Subai'ah binti Al Harits] untuk menanyakan tentang sesuatu yang Rasulullah shallallahu 'alaihi wasallam fatwakan kepadanya, lalu Subai'ah menceritakan, bahwa dirinya adalah isteri dari Sa'ad bin Khaulah, kemudian dia ditinggal mati olehnya pada saat haji Wada' dan dia termasuk orang yang ikut serta dalam perang Badar. Kemudian dia melahirkan sebelum berlalu masa empat bulan sepuluh hari dari kematian suaminya, lalu dia bertemu dengan Abu As Sanabil -yaitu Ibnu Ba'kak- setelah suci dari nifasnya dan menggunakan celak. Kemudian Abu As Sanabil berkata kepadanya, \"Tahanlah dirimu -atau kalimat yang serupa dengannya-, mungkin kamu menghendaki nikah, sesungguhnya masa iddahmu adalah empat bulan sepuluh hari dari kematian suamimu.\" Subai'ah lalu berkata, \"Maka aku menemui Nabi shallallahu 'alaihi wasallam dan menceritakan kepada beliau apa yang telah dikatakan oleh Abu As Sanabil bin Ba'kak.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Kamu telah halal untuk menikah sejak kamu melahirkan kandunganmu.\" Telah menceritakan kepada kami [Ibrahim bin Khalid] dia berkata telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Uthbah] dia berkata, \"Ubaidullah bin Abdullah bin Utsbah telah menulis surat kepada Abdullah bin Al Arqam, memerintahkan kepadanya untuk datang menemui [Subai'ah binti Al Harits], untuk bertanya kepadanya tentang sesuatu yang telah Rasulullah shallallahu 'alaihi wasallam fatwakan kepadanya. Kemudian Subai'ah mengaku bahwa dia adalah isteri dari Sa'ad bin Khaulah…kemudian dia menyebutkan hadits yang semakna dengannya.\" Telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia berkata, telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] dia berkata, telah menceritakan kepadaku [Az Zuhri] dari [Ubaidullah bin Abdullah bin Uthbah] dari [bapaknya] dia berkata, \"Aku telah menulis surat kepada Abdullah bin Al Arqam, memerintahkan kepadanya untuk datang menemui [Subai'ah Al Aslamiyah] dan menanyakan tentang perkara dia.\" Perawi berkata, \"Kemudian Abdullah datang menemui Subai'ah…lalu dia menyebutkan hadits tersebut.\""},"4205":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَدَخَلْتُ عَلَى سُبَيْعَةَ بِنْتِ أَبِي بَرْزَةَ الْأَسْلَمِيَّةِ فَسَأَلْتُهَا عَنْ أَمْرِهَا فَقَالَتْ كُنْتُ عِنْدَ سَعْدِ ابْنِ خَوْلَةَ فَتُوُفِّيَ عَنِّي فَلَمْ أَمْكُثْ إِلَّا شَهْرَيْنِ حَتَّى وَضَعْتُ قَالَتْ فَخَطَبَنِي أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ أَخُو بَنِي عَبْدِ الدَّارِ فَتَهَيَّأْتُ لِلنِّكَاحِ قَالَتْ فَدَخَلَ عَلَيَّ حَمَوَيَّ وَقَدْ اخْتَضَبْتُ وَتَهَيَّأْتُ فَقَالَ مَاذَا تُرِيدِينَ يَا سُبَيْعَةُ قَالَتْ فَقُلْتُ أُرِيدُ أَنْ أَتَزَوَّجَ قَالَ وَاللَّهِ مَا لَكِ مِنْ زَوْجٍ حَتَّى تَعْتَدِّينَ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا قَالَتْ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِي قَدْ حَلَلْتِ فَتَزَوَّجِي","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin Abdurrahman] berkata, \"Aku menemui [Subai'ah binti Abu Barzah Al Aslamiyah], kemudian aku bertanya kepadanya tentang masalahnya, ia pun berkata, \"Aku adalah isteri Sa'd bin Khaulah, kemudian dia wafat, tidak sampai dua bulan aku berdiam diri (iddah), aku pun melahirkan.\" Subai'ah melanjutkan, \"Kemudian Abu As Sanabil bin Ba'kak, saudara bani Abdu Daar datang melamar dan aku pun telah siap.\" Subai'ah melanjutkan, \"Kemudian kedua saudara iparku datang kepadaku, sungguh aku telah menyiapkan dan berhias diri, iparku berkata, \"Apa yang kamu kehendaki wahai Subai'ah?\" Aku menjawab, \"Aku hendak menikah.\" Iparku lalu berkata, \"Demi Allah, kamu tidak akan mendapatkan suami sehingga kamu selesai dari masa iddahmu, yaitu empat bulan sepuluh hari.\" Kemudian Subai'ah berkata, \"Maka aku menemui Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal itu kepada beliau, beliau kemudian bersabda kepadaku: \"Sungguh, kamu telah halal, maka menikahlah.\""},"4206":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبٍ قَالَ سَمِعْتُ عَمَّتِي تَقُولُ وَكَانَتْ حَجَّتْ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ ابْنَ أُمِّ مَكْتُومٍ يُنَادِي بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ بِلَالٌ أَوْ إِنَّ بِلَالًا يُنَادِي بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ ابْنُ أُمِّ مَكْتُومٍوَكَانَ يَصْعَدُ هَذَا وَيَنْزِلُ هَذَا فَنَتَعَلَّقُ بِهِ فَنَقُولُ كَمَا أَنْتَ حَتَّى نَتَسَحَّرَ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Syu'bah] dari [Hubaib] berkata, saya mendengar [bibiku] berkata -saat itu ia sedang berhaji bersama Rasulullah shallallahu 'alaihi wasallam-, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Ibnu Ummi Maktum mengumandangkan adzan pada malam hari, maka makan dan minumlah kalian sehingga Bilal mengumandangkan adzan, atau sesungguhnya Bilal mengumandangkan adzan di malam hari, maka makan dan minumlah kalian sehingga Ibnu Ummi Maktum mengumandangkan adzan. Terkadang yang ini naik dan yang lain turun, maka kita berpegangan padanya, kami mengatakan sebagaimana kamu sehingga kami makan sahur.\""},"4207":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا مَنْصُورٌ يَعْنِي ابْنَ زَاذَانَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمَّتِهِ أُنَيْسَةَ بِنْتِ خُبَيْبٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَذَّنَ ابْنُ أُمِّ مَكْتُومٍ فَكُلُوا وَاشْرَبُوا وَإِذَا أَذَّنَ بِلَالٌ فَلَا تَأْكُلُوا وَلَا تَشْرَبُواقَالَتْ وَإِنْ كَانَتْ الْمَرْأَةُ لَيَبْقَى عَلَيْهَا مِنْ سُحُورِهَا فَنَقُولُ لِبِلَالٍ أَمْهِلْ حَتَّى أَفْرُغَ مِنْ سُحُورِي","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Manshur] -yakni Ibnu Zadzan- dari [Hubaib bin Abdurrahman] dari bibinya [Unaisah binti Khubaib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Ibnu Ummi Maktum mengumandangkan adzan, maka makan dan minumlah kalian, namun jika Bilal mengumandangkan adzan, maka janganlah kalian makan dan minum.\" Ia (perawi) Berkata, \"Jika ada seorang wanita masih makan sahur, maka kami mengatakan kepada Bilal, pelan-pelanlah sehingga dia selesai sahur.\""},"4208":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمَّتِهِ قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ ابْنَ أُمِّ مَكْتُومٍ أَوْ بِلَالًا يُنَادِي بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ بِلَالٌ أَوْ ابْنُ أُمِّ مَكْتُومٍفَمَا كَانَ إِلَّا أَنْ يُؤَذِّنَ أَحَدُهُمَا وَيَصْعَدَ الْآخَرُ فَنَأْخُذَهُ بِيَدِهِ وَنَقُولَ كَمَا أَنْتَ حَتَّى نَتَسَحَّرَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [bibinya] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Ibnu Ummi Maktum atau Bilal menyerukan adzan di malam hari, maka makan dan minumlah kalian sehingga Bilal atau Ibnu Ummi Maktum mengumandangkan (adzan).\" Maka tidaklah salah seorang dari keduanya adzan melainkan yang lainnya akan naik, maka kami menarik tangannya dan berkata sebagaimana kamu, sehingga kami selesai makan sahur.\""},"4209":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَخْبَرَهُ أَبُوهُ قَالَ نَزَلْتُ عَلَى أُمِّ أَيُّوبَ الَّذِي نَزَلَ عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلْتُ عَلَيْهَا فَحَدَّثَتْنِي بِهَذَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ تَكَلَّفُوا طَعَامًا فِيهِ بَعْضُ هَذِهِ الْبُقُولِ فَقَرَّبُوهُ فَكَرِهَهُ وَقَالَ لِأَصْحَابِهِ كُلُوا إِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ إِنِّي أَخَافُ أَنْ أُوذِيَ صَاحِبِي يَعْنِي الْمَلَكَ","id":"Telah menceritakan kepada kami [Shafyan bin 'Uyainah] telah menceritakan kepada kami ['Ubaidullah bin Abu Yazid] yang [bapaknya] telah menceritakan kepadanya, bahwa dia berkata, \"Aku singgah di tempatnya [Ummu Ayyub], setiap tempat yang Rasulullah shallallahu 'alaihi wasallam pernah singgah kepada mereka, maka akupun menyinggahinya. Kemudian Ummu Ayyub menceritakan hadits ini kepadaku dari Rasulullah shallallahu 'alaihi wasallam. Bahwa para sahabat bersusah payah menyiapkan makanan yang di dalamnya ada sayuran, ketika mereka mendekatkannya kepada beliau, ternyata beliau tidak menyukainya seranya mengatakan: \"Makanlah oleh kalian, sesungguhnya aku tidak seperti salah seorang dari kalian, aku khawatir akan mengganggu sahabatku, yaitu Malaikat.\""},"4210":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عَنْ أُمِّ أَيُّوبَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَزَلَ الْقُرْآنُ عَلَى سَبْعَةِ أَحْرُفٍ أَيُّهَا قَرَأْتَ أَجْزَأَكَ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [ayahnya] dari [Ummu Ayyub] dia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Qur'an diturunkan dengan tujuh huruf, mana saja yang kamu baca maka itu berpahala bagimu.\""},"4211":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ الْأَنْصَارِيَّةِ أَنَّهَا أَخْبَرَتْهُ عَنْ حَبِيبَةَ بِنْتِ سَهْلٍ الْأَنْصَارِيَّةِ قَالَتْ إِنَّهَاكَانَتْ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ وَأَنَّ النَّبِيَّ صَلَّى اللَّ��ُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الصُّبْحِ فَوَجَدَ حَبِيبَةَ بِنْتَ سَهْلٍ عَلَى بَابِهِ بِالْغَلَسِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذِهِ قَالَتْ أَنَا حَبِيبَةُ بِنْتُ سَهْلٍ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكِ قَالَتْ لَا أَنَا وَلَا ثَابِتُ بْنُ قَيْسٍ لِزَوْجِهَا فَلَمَّا جَاءَ ثَابِتٌ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ حَبِيبَةُ بِنْتُ سَهْلٍ قَدْ ذَكَرَتْ مَا شَاءَ اللَّهُ أَنْ تَذْكُرَ قَالَتْ حَبِيبَةُ يَا رَسُولَ اللَّهِ كُلُّ مَا أَعْطَانِي عِنْدِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِثَابِتٍ خُذْ مِنْهَا فَأَخَذَ مِنْهَا وَجَلَسَتْ فِي أَهْلِهَا","id":"Abdullah berkata; Aku bacakan di hadapan ['Abdurrahman bin Mahdi]; [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman bin Sa'd bin Zurarah Al Anshariyah] bahwa dia telah mengabarkan dari [Habibah binti Sahal Al Anshariyah] dia mengatakan bahwa dia adalah isteri dari Tsabit Bin Qais bin Syammas, ketika Nabi shallallahu 'alaihi wasallam keluar menuju masjid untuk shalat Shubuh, beliau mendapati Habibah binti Sahal berada di depan pintu, lantas Nabi shallallahu 'alaihi wasallam pun bertanya: \"Siapa ini?\" dia menjawab, \"Aku Habibah binti Sahl.\" Nabi shallallahu 'alaihi wasallam lalu bertanya: \"Ada apa denganmu?\" dia menjawab, \"Antara aku dan Tsabit bin Qais tidak ada kecocokan.\" Maka ketika Tsabit datang, Nabi berkata kepadanya: \"Ini Habibah binti Sahl, ia telah menyebutkan Atas kehendak Allah untuk menyebutkannya.\" Habibah berkata, \"Wahai Rasulullah, seluruh apa yang telah dia berikan ada padaku.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda kepada Tsabit: \"Ambillah milikmu.\" Kemudian Tsabit mengambilnya dari Habibah dan dia (Habibah) kembali tinggal di rumah keluarganya.\""},"4212":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ ابْنِ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ جَحْشٍ أَنَّهَااسْتُحِيضَتْ فَسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا بِالْغُسْلِ عِنْدَ كُلِّ صَلَاةٍ وَإِنْ كَانَتْ لَتَخْرُجُ مِنْ الْمِرْكَنِ وَقَدْ عَلَتْ حُمْرَةُ الدَّمِ عَلَى الْمَاءِ فَتُصَلِّي","id":"Telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Ibnu Ishaq] dari [Az Zuhri] dari ['Urwah] dari [Ummu Habibah binti Jahsy] bahwa dia mengalami istahadlah (darah penyakit), kemudian dia menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, lantas beliau pun memerintahkan dia untuk mandi pada setiap kali mau melaksanakan shalat, yaitu: \"Jika keluar darah dari bejana dan warna merah darah sudah hilang di atas air maka shalatlah.\""},"4213":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ جَحْشٍ قَالَتْاسْتُحِضْتُ سَبْعَ سِنِينَ فَاشْتَكَيْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ تِلْكَ بِالْحَيْضَةِ وَلَكِنْ عِرْقٌ فَاغْتَسِلِي فَكَانَتْ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ فَكَانَتْ تَغْتَسِلُ فِي الْمِرْكَنِ فَنَرَى صُفْرَةَ الدَّمِ فِي الْمِرْكَنِ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Amrah] dari [Ummu Habibah binti Jahsy] dia berkata, \"Aku pernah mengalami istihadlah selama tujuh tahun, kemudian aku mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Itu bukanlah darah haid, tetapi itu adalah darah kotor, maka mandilah.\" Ummu Habibah lalu mandi setiap hendak shalat, dan dia mandi di dalam bejana hingga kami dapat melihat warna merah darah di dalam air bak.\""},"4214":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ أُخْتِ عُكَّاشَةَ قَالَتْحَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاسٍ وَهُوَ يَقُولُ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ فَنَظَرْتُ فِي الرُّومِ وَفَارِسَ فَإِذَا هُمْ يُغِيلُونَ أَوْلَادَهُمْ وَلَا يَضُرُّ أَوْلَادَهُمْ ذَلِكَ شَيْئًا ثُمَّ سَأَلُوهُ عَنْ الْعَزْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ الْوَأْدُ الْخَفِيُّ وَهُوَ{ وَإِذَا الْمَوْءُودَةُ سُئِلَتْ }","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id] -yakni Ibnu Abu Ayyub- dia berkata, telah menceritakan kepadaku [Abul Aswad] dari ['Urwah] dari ['Aisyah] dari [Judamah binti Wahb] saudari perempuan 'Ukasyah, dia berkata, \"Aku menghadiri Rasulullah shallallahu 'alaihi wasallam saat beliau bersama orang banyak, beliau mengatakan: \"Sesungguhnya aku berkeinginan untuk melarang dari perbuatan Ghilah, kemudian aku melihat orang-orang Romawi dan Persi melakukan perbuatan Ghilah kepada anak-anak mereka dan tidak membahayakan anak-anak mereka sedikitpun.\" Kemudian para sahabat bertanya kepada Nabi tentang 'Azl (menumpahkan air mani di luar kemaluan wanita), maka beliau menjawab: \"Itu adalah Al Wa'dul Khafi (pembunuhan terselubung), itu seperti firman Allah; '(Dan apabila bayi-bayi perempuan yang dikubur hidup-hidup ditanya) ' (Qs. At Takwiir: 8)."},"4215":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ الْأَنْصَارِيِّ عَنْ جَدَّةٍ لَهُ قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا قِرْبَةٌ فَشَرِبَ مِنْ فِيهَا وَهُوَ قَائِمٌوَقُرِئَ عَلَيْهِ هَذَا الْحَدِيثُ يَعْنِي سُفْيَانَ سَمِعْتُ يَزِيدَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ جَدَّتِي وَهِيَ كُبَيْشَةُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Yazid bin Yazid bin Jabir Al Anshari] dari [neneknya] dia berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam masuk menemuinya sedangkan di sisinya ada sebuah Qirbah (bejana dari kulit), kemudian beliau minum dari mulut geriba tersebut sambil berdiri.\" Lalu hadits ini dibacakan di hadapannya, yakni [Sufyan] dia berkata, \"Aku mendengar [Yazid] dari ['Abdurrahman bin Abu 'Amrah] dari nenekku, yaitu [Kubaisyah].\""},"4216":{"ar":"حَدَّثَنَا رَوْحٌ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَشْهَلِيِّ عَنْ جَدَّتِهِ أَنَّهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا نِسَاءَ الْمُؤْمِنَاتِ لَا تَحْقِرَنَّ إِحْدَاكُنَّ لِجَارَتِهَا وَلَوْ كُرَاعُ شَاةٍ مُحْرَقٌ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari ['Amru bin Mu'adz Al Asyhali] dari [neneknya] bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai para wanita mukminah, janganlah salah seorang dari kalian meremehkan untuk berbuat baik kepada tetangganya meskipun dengan memberi kaki kambing bakar.\""},"4217":{"ar":"حَدَّثَنَا رَوْحٌ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنِ ابْنِ بُجَيْدٍ الْأَنْصَارِيِّ عَنْ جَدَّتِهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُدُّوا السَّائِلَ وَلَوْ بِظِلْفٍ مُحْرَقٍ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [Ibnu Bujaid Al Anshari] dari [neneknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kepada orang yang meminta-minta walaupun sekalipun hanya secuil daging bakar.\""},"4218":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ زَيْدٍ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَنْصَارِيِّ قَالَإِنَّ سَائِلًا وَقَفَ عَلَى بَابِهِمْ فَقَالَتْ لَهُ جَدَّتُهُ حَوَّاءُ أَطْعِمُوهُ تَمْرًا قَالُوا لَيْسَ عِنْدَنَا قَالَتْ فَاسْقُوهُ سَوِيقًا قَالُوا الْعَجَبُ لَكِ نَسْتَطِيعُ أَنْ نُطْعِمَهُ مَا لَيْسَ عِنْدَنَا قَالَتْ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَرُدُّوا السَّائِلَ وَلَوْ بِظِلْفٍ مُحْرَقٍ","id":"Telah menceritakan kepada kami [Abdul Malik bin Amru] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Zaid] dari [Amru bin Mu'adz Al Anshari] berkata, \"Sungguh, seorang peminta-minta berhenti di depan pintu mereka, lantas neneknya, [Hawwa'], berkata kepadanya, \"Berilah ia kurma.\" Mereka berkata, \"Kami tidak memilikinya.\" Hawwa' lalu berkata, \"Berilah ia minum sawiq.\" Mereka berkata, \"Aku heran denganmu, bagaimana kami disuruh untuk memberinya makan dari sesuatu yang kami tidak memilikinya.\" Hawwa` berkata, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu menolak peminta walaupun dengan secuil daging panggang.\""},"4219":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُعَاوِيَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِيسَى عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ قَالَ وَكَانَ رَجُلَ صِدْقٍ عَنِ امْرَأَةٍ مِنْ بَنِى عَبْدِ الْأَشْهَلِ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لَنَا طَرِيقًا إِلَى الْمَسْجِدِ مُنْتِنَةً فَكَيْفَ نَصْنَعُ إِذَا مُطِرْنَا قَالَ أَلَيْسَ بَعْدَهَا طَرِيقٌ هِيَ أَطْيَبُ مِنْهَا قَالَتْ قُلْتُ بَلَى قَالَ فَهَذِهِ بِهَذِهِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Zuhair] -yakni Ibnu Mu'awiyah- telah menceritakan kepada kami [Abdullah bin 'Isa] dari [Musa bin Abdullah] -dia adalah seorang lelaki yang jujur- dari [seorang wanita Bani 'Abdul Asyhal] bahwa dia berkata, \"Aku bertanya, \"Wahai Rasulullah, jalan kami menuju masjid bejek, bagaimana jika hujan?\" Beliau lalu menjawab: \"Bukankah ada jalan yang lebih baik darinya.\" Wanita itu lalu berkata, \"Maka aku menjawab, \"Tentu.\" Beliau bersabda: \"Maka yang ini di ganti dengan ini.\""},"4220":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِسْرَائِيلُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنِ امْرَأَةٍ مِنْ بَنِي عَبْدِ الْأَشْهَلِ أَنَّهَا قَالَتْقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَمُرُّ فِي طَرِيقٍ لَيْسَ بِطَيِّبٍ فَقَالَ أَلَيْسَ مَا بَعْدَهُ أَطْيَبُ مِنْهُ قَالَتْ بَلَى قَالَ إِنَّ هَذِهِ تَذْهَبُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Isra'il] dari [Abdullah bin 'Isa] dari dari [Musa bin Abdullah bin Yazid] dari [seorang wanita Bani 'Abdul Asyhal] bahwa dia berkata, \"Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Sungguh, aku melintasi jalan yang rusak!\" Beliau lalu menjawab: \"Bukankah setelah itu ada jalan yang lebih baik?\" dia menjawab, \"Ya.\" Kemudian beliau bersabda: \"Sesungguhnya ini akan hilang dengan hal itu.\""},"4221":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّ امْرَأَةً حَدَّثَتْهُ قَالَتْنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ تَضْحَكُ مِنِّي يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنْ مِنْ قَوْمٍ مِنْ أُمَّتِي يَخْرُجُونَ غُزَاةً فِي الْبَحْرِ مَثَلُهُمْ مَثَلُ الْمُلُوكِ عَلَى الْأَسِرَّةِ قَالَتْ ثُمَّ نَامَ ثُمَّ اسْتَيْقَظَ أَيْضًا يَضْحَكُ فَقُلْتُ تَضْحَكُ يَا رَسُولَ اللَّهِ مِنِّي قَالَ لَا وَلَكِنْ مِنْ قَوْمٍ مِنْ أُمَّتِي يَخْرُجُونَ غُزَاةً فِي الْبَحْرِ فَيَرْجِعُونَ قَلِيلَةً غَنَائِمُهُمْ مَغْفُورًا لَهُمْ قَالَتْ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا لَهَاقَالَ فَأَخْبَرَنِي عَطَاءُ بْنُ يَسَارٍ قَالَ فَرَأَيْتُهَا فِي غَزَاةٍ غَزَاهَا الْمُنْذِرُ بْنُ الزُّبَيْرِ إِلَى أَرْضِ الرُّومِ هِيَ مَعَنَا فَمَاتَتْ بِأَرْضِ الرُّومِ","id":"Telah menceritakan kepada kami ['Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari [Atha' bin Yasar] bahwa [seorang wanita] telah menceritakan kepadanya, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidur kemudian terbangun sambil tertawa, maka aku bertanya, \"Wahai Rasulullah, apakah tuan mentertawakan aku?\" beliau menjawab: \"Tidak, akan tetapi suatu kaum dari ummatku yang mereka keluar berperang di lautan, perumpamaan mereka seperti para raja di atas singgasana.\" Wanita itu lalu berkata, \"Kemudian beliau tidur dan bangun kembali sambil tertawa, maka aku pun bertanya, \"Wahai Rasulullah, apakah tuan mentertawakan aku?\" Beliau menjawab: \"Tidak, akan tetapi suatu kaum dari ummatku yang mereka keluar berperang di lautan kemudian mereka kembali dengan membawa sedikit Ghanimah (harta rampasan perang) dalam keadaan diampuni oleh Allah.\" Wanita itu lalu berkata, \"Berdoalah kepada Allah agar aku termasuk dari mereka.\" Kemudian beliau mendo'akan untuknya.\" Zaid bin Aslam berkata, \" 'Atha' bin Yasar mengabarkan kepadaku, ia berkata, \"Aku pernah melihat wanita itu dalam pertempuran yang dipimpin oleh Al Mundzir bin Az Zubair menuju negeri Romawi, wanita itu bersama kami dan meninggal di bumi Romawi.\""},"4222":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ ابْنِ أَخِي عَمْرَةَ سَمِعْتُهُ مِنْهُ قَبْلَ أَنْ يَجِيءَ الزُّهْرِيُّ عَنْ امْرَأَةٍ مِنَ الْأَنْصَارِ قَالَتْكَانَ تَنُّورُنَا وَتَنُّورُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا فَمَا حَفِظْتُ ق إِلَّا مِنْهُ كَانَ يَقْرَؤُهَا","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin 'Abdurrahman bin Sa'd bin Zurarah] anak laki-laki saudara 'Amrah -aku mendengar darinya sebelum kedatangan Az Zuhri-, dari [seorang wanita Anshar] dia berkata, \"Tungku masakku bergabung dengan tungku masak Nabi shallallahu 'alaihi wasallam, sehingga aku tidak hafal surat Qaaf kecuali darinya yang beliau bacakan.\""},"4223":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ قَالَتْلَقَدْ كَانَ تَنُّورُنَا وَتَنُّورُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا سَنَتَيْنِ أَوْ سَنَةً وَبَعْضَ سَنَةٍ وَمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا عَلَى لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ بِهَا كُلَّ يَوْمِ جُمُعَةٍ عَلَى الْمِنْبَرِ إِذَا خَطَبَ النَّاسَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Abdullah bin Muhammad bin Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Yahya bin Abdullah bin 'Abdurrahman bin Sa'ad bin Zurarah] dari [Ummu Hisyam binti Haritsah] dia berkata, \"Dahulu tungku masakku bergabung dengan tungku masak Nabi shallallahu 'alaihi wasallam selama dua tahun, atau satu tahun beberapa bulan, dan tidaklah aku mendapatkan surat 'Qaaf Wal Qur'aanil majiid', kecuali dari lisan Rasulullah shallallahu 'alaihi wasallam yang beliau bacakan setiap hari jumat di atas mimbar saat berkhutbah di hadapan manusia.\""},"4224":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ وَيَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ شِهَابٍ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أُمِّ الْعَلَاءِ الْأَنْصَارِيَّةِ وَهِيَ امْرَأَةٌ مِنْ نِسَائِهِمْ قَالَ يَعْقُوبُ أَخْبَرْتُهُأَنَّهَا بَايَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُثْمَانُ بْنُ مَظْعُونٍ فِي السُّكْنَى قَالَ يَعْقُوبُ طَارَ لَهُمْ فِي السُّكْنَى حِينَ اقْتَرَعَتْ الْأَنْصَارُ عَلَى سُكْنَى الْمُهَاجِرِينَ قَالَتْ أُمُّ الْعَلَاءِ فَاشْتَكَى عُثْمَانُ بْنُ مَظْعُونٍ عِنْدَنَا فَمَرَّضْنَاهُ حَتَّى إِذَا تُوُفِّيَ أَدْرَجْنَاهُ فِي أَثْوَابِهِ فَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رَحْمَةُ اللَّهِ عَلَيْكَ يَا أَبَا السَّائِبِ شَهَادَتِي عَلَيْكَ لَقَدْ أَكْرَمَكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يُدْرِيكِ أَنَّ اللَّهَ أَكْرَمَهُ قَالَتْ فَقُلْتُ لَا أَدْرِي بِأَبِي أَنْتَ وَأُمِّي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هُوَ فَقَدْ جَاءَهُ الْيَقِينُ مِنْ رَبِّهِ وَإِنِّي لَأَرْجُو الْخَيْرَ لَهُ وَاللَّهِ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَا يُفْعَلُ بِي قَالَ يَعْقُوبُ بِهِ قَالَتْ وَاللَّهِ لَا أُزَكِّي أَحَدًا بَعْدَهُ أَبَدًا فَأَحْزَنَنِي ذَلِكَ فَنِمْتُ فَأُرِيتُ لِعُثْمَانَ عَيْنًا تَجْرِي فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ عَمَلُهُحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ خَارِجَةَ بْنِ زَيْدٍ قَالَ كَانَتْ أُمُّ الْعَلَاءِ الْأَنْصَارِيَّةُ تَقُولُ لَمَّا قَدِمَ الْمُهَاجِرُونَ الْمَدِينَةَ اقْتَرَعَتْ الْأَنْصَارُ عَلَى سَكَنِهِمْ فَطَارَ لَنَا عُثْمَانُ بْنُ مَظْعُونٍ فِي السُّكْنَى فَذَكَرَتْ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَا يُفْعَلُ بِي وَلَا بِكُمْ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab], dan [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Syihab] dari [Kharijah bin Zaid bin Tsabit] dari [Ummul 'Ala' Al Anshariyah] -dia adalah salah seorang wanita dari mereka-, [Ya'qub] berkata, \"Aku menceritakan kepadanya, bahwa wanita itu adalah orang yang pernah berbaiat kepada Rasulullah shallallahu 'alaihi wasallam.\" Sedangkan 'Utsman bin Madz'un menyebutkan, (bahwa hal itu berkaitan dengan) Sukna (tempat tinggal).\" Ya'qub berkata, \"Panah undian itu mengarah kepada mereka ketika orang-orang Anshar melakukan undian tentang tempat tinggal orang-orang Muhajirin.\" [Ummul 'Ala'] berkata, \"Selanjutnya Utsman bin Madz'un mengeluhkan sakitnya di sisi kami kemudian kami merawatnya sampai ketika dia meninggal kami menyelimutinya dengan bajunya, kemudian datanglah Rasulullah shallallahu 'alaihi wasallam kepada kami, dan akupun berkata, \"Semoga Rahmat Allah senantiasa di curahkan kepadamu wahai Abu As Sa'ib. Aku bersaksi atas kamu. Sungguh, Allah telah memuliakanmu.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Dari mana kamu tahu bahwa Allah telah memuliakannya?\" Ummul 'Ala` berkata, \"Maka aku menjawab, \"Bapak dan ibuku sebagai tebusanmu. Aku tidak tahu.\" Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kematian dari Rabbnya telah datang kepadanya, aku berharap dia mendapatkan kebaikan. Demi Allah, mekipun aku seorang Nabi, aku tidak tahu apa yang akan aku rasakan.\" Ya'qub berkata, \"Karena ucapan itu, maka Ummu 'Ala` itu pun berkata, \"Demi Allah, aku tidak akan lagi memuji seseorang setelahnya, sehingga hal itu membuat aku sedih. Kemudian aku bermimpi dan diperlihatkan kepadaku bahwa 'Utsman mendapatkan mata air yang mengalir, maka aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal itu kepadanya, beliau lalu bersabda: \"Itu adalah amalan Utsman.\" Telah menceritakan kepada kami [Abdurrazaq] dia berkata telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Kharijah bin Zaid] dia berkata, [Ummul 'Ala' Al Anshariyah] pernah berkata, \"Ketika orang-orang Muhajirin tiba di Madinah, maka orang-orang Anshar melakukan Qur'ah (undian) untuk menentukan tempat tinggal mereka, maka keluarlah pilihan untuk kami 'Utsman bin Madz'un…kemudian dia menyebutkan lafadz hadits. Hanya saja dia menyebutkan lafadz, \"Meskipun aku Rasulullah, aku tidak tahu apa yang akan Allah terhadap aku dan juga kalian.\""},"4225":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي النَّضْرِ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ أُمِّهِ قَالَتْإِنَّ عُثْمَانَ بْنَ مَظْعُونٍ لَمَّا قُبِضَ قَالَتْ أُمُّ خَارِجَةَ بِنْتُ زَيْدٍ طِبْتَ أَبَا السَّائِبِ خَيْرُ أَيَّامِكَ الْخَيْرُ فَسَمِعَهَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هَذِهِ قَالَتْ أَنَا قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يُدْرِيكِ فَقُلْتُ يَا رَسُولَ اللَّهِ عُثْمَانُ بْنُ مَظْعُونٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ عُثْمَانُ بْنُ مَظْعُونٍ مَا رَأَيْنَا إِلَّا خَيْرًا وَهَذَا أَنَا رَسُولُ اللَّهِ وَاللَّهِ مَا أَدْرِي مَا يُصْنَعُ بِي","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Abu An Nadlr] dari [Kharijah bin Zaid] dari [Ibunya] dia berkata, \"Ketika 'Utsman bin Madz'un wafat, Ummu Kharijah binti Zaid berkata, \"Alangkah baiknya kamu wahai Abu Sa'ib, semua hari-harimu adalah baik.\" Kemudian ucapan itu terdengar oleh Nabi Allah shallallahu 'alaihi wasallam, kemudian beliau bertanya: \"Siapa ini?\" dia menjawab, \"Aku.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Ada apa dengan kamu?\" Aku berkata, \"Wahai Rasulullah, 'Utsman bin Madz'un.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Benar, Utsman bin Madz'un. Kami tidak melihatnya kecuali kebaikan, Aku adalah utusan Allah, demi Allah aku tidak tahu apa yang akan terjadi padaku.\""},"4226":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ طَارِقِ بْنِ عَلْقَمَةَ أَخْبَرَهُ عَنْ أُمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ مَكَانًا مِنْ دَارِ يَعْلَى نَسَبَهُ عُبَيْدُ اللَّهِ اسْتَقْبَلَ الْبَيْتَ فَدَعَا","id":"Telah menceritakan kepada kami [Muhammad bin Bakar] dia berkata, telah mengabarkan kepada kami [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] bahwa ['Abdurrahman bin Thariq bin Al Qamah] telah menceritakan kepadanya dari [ibunya] bahwa apabila Nabi shallallahu 'alaihi wasallam memasuki suatu tempat di rumah Ya'la -'Ubaidullah lupa dimana tempatnya-, beliau menghadap kiblat dan berdo'a.\""},"4227":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ قَالَ إِنَّ عَبْدَ الرَّحْمَنِ بْنَ طَارِقِ بْنِ عَلْقَمَةَ أَخْبَرَهُ عَنْ أُمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ مَكَانًا فِي دَارِ يَعْلَى نَسَبَهُ عُبَيْدُ اللَّهِ اسْتَقْبَلَ الْبَيْتَ فَدَعَا","id":"Telah menceritakan kepada kami ['Abdurrazaq] dia berkata, telah mengabarkan kepada kami [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] dia berkata, bahwa ['Abdurrahman bin Thariq bin Al Qamah] telah mengabarkan kepadanya dari [ibunya] bahwa apabila Nabi shallallahu 'alaihi wasallam memasuki suatu tempat di rumah Ya'la -'Ubaidullah lupa dimana tempatnya-, beliau menghadap kiblat dan berdo'a.\""},"4228":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ حَدَّثَنَا عَبْدُ اللَّهِ وَعَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ طَارِقِ بْنِ عَلْقَمَةَ أَخْبَرَهُ عَنْ أُمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ مَكَانًا مِنْ دَارِ يَعْلَى نَسَبَهُ عُبَيْدُ اللَّهِ اسْتَقْبَلَ الْبَيْتَ فَدَعَاقَالَ وَكُنْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ كَثِيرٍ إِذَا جِئْنَا ذَلِكَ الْمَوْضِعَ اسْتَقْبَلَ الْبَيْتَ فَدَعَا","id":"Telah menceritakan kepada kami [Ahmad bin Hajjaj] dia berkata, telah menceritakan kepada kami [Abdullah] dan ['Ali bin Ishaq] dia berkata, telah mengabarkan kepada kami [Abdullah bin Mubarak] dia berkata, telah mengabarkan kepada kami [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] dia berkata, bahwa ['Abdurrahman bin Thariq bin Alqamah] mengabarkan kepadanya dari [ibunya], bahwa apabila Nabi shallallahu 'alaihi wasallam memasuki tempat di kediaman Ya'la -'Ubaidullah lupa dimana tempatnya-, beliau menghadap kiblat dan berdo'a.\" 'Ubaidullah berkata, \"Aku dan Abdullah bin Katsir apabila datang ke tempat itu, maka kami menghadap kiblat dan berdo'a.\""},"4229":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ وَاصِلٍ مَوْلَى أَبِي عُيَيْنَةَ عَنْ مُوسَى بْنِ عُبَيْدٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ أَنَّ امْرَأَةً أَخْبَرَتْهَا أَنَّهَا��َمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الصَّفَا وَالْمَرْوَةِ يَقُولُ كُتِبَ عَلَيْكُمْ السَّعْيُ فَاسْعَوْا","id":"Telah menceritakan kepada kami ['Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Washil] bekas budak Abu 'Uyainah, dari [Musa bin Ubaid] dari [Shafiyah binti Syaibah] bahwa [seorang wanita] menceritakan kepadanya, bahwa dia telah mendengar Nabi shallallahu 'alaihi wasallam bersabda ketika di Shafa dan Marwah: \"Sa'i telah diwajibkan atas kalian, maka laksanakanlah.\""},"4230":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ جَدَّتِهِ عَنِ امْرَأَةٍ مِنْ نِسَائِهِمْ وَكَانَتْ قَدْ صَلَّتْ الْقِبْلَتَيْنِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اخْتَضِبِي تَتْرُكُ إِحْدَاكُنَّ الْخِضَابَ حَتَّى تَكُونَ يَدُهَا كَيَدِ الرَّجُلِقَالَتْ فَمَا تَرَكَتْ الْخِضَابَ حَتَّى لَقِيَتْ اللَّهَ تَعَالَى وَإِنْ كَانَتْ لَتَخْتَضِبُ وَهِيَ بِنْتُ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Dlamrah bin Sa'id] dari [neneknya] dari [seorang wanita] di antara para wanita Dlamrah, bahwa dia telah shalat bersama Nabi shallallahu 'alaihi wasallam di masjid Qiblatain. Wanita itu berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam datang menemuiku dan bersabda: \"Hendaklah kalian cat kuku kalian, jika kalian tidak lakukan itu maka kuku kalian seperti kuku lelaki.\" Wanita itu lalu berkata, \"Setelah itu ia tidak lagi meninggalkan untuk mengecat kukunya hingga ia berjumpa dengan Allah, dan dia tetap mengecat kukunya walaupun berumur delapan puluh tahun.\""},"4231":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ حَبِيبٍ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ رَجُلٍ عَنْ أُمِّ مُسْلِمٍ الْأَشْجَعِيَّةِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهَا وَهِيَ فِي قُبَّةٍ فَقَالَ مَا أَحْسَنَهَا إِنْ لَمْ يَكُنْ فِيهَا مَيْتَةٌ قَالَتْ فَجَعَلْتُ أَتَتَبَّعُهَا","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Habib] -yakni Ibnu Abu Tsabit- dari [seorang laki-laki] dari [Ummu Muslim Al Asyja'iyah] bahwa Nabi shallallahu 'alaihi wasallam datang menemuinya, yang saat itu ia sedang berada di tenda. Beliau bersabda: \"Alangkah bagusnya jika di dalamnya tidak ada bangkai, \" kemudian aku mencari-carinya.\""},"4232":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ وَيُونُسُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُثْمَانَ قَالَ إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ ابْنَ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ حَاطِبٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ مُحَمَّدِ بْنِ حَاطِبٍ عَنْ أُمِّهِ أُمِّ جَمِيلٍ بِنْتِ الْمُجَلِّلِ قَالَتْأَقْبَلْتُ بِكَ مِنْ أَرْضِ الْحَبَشَةِ حَتَّى إِذَا كُنْتُ مِنْ الْمَدِينَةِ عَلَى لَيْلَةٍ أَوْ لَيْلَتَيْنِ طَبَخْتُ لَكَ طَبِيخًا فَفَنِيَ الْحَطَبُ فَخَرَجْتُ أَطْلُبُهُ فَتَنَاوَلْتُ الْقِدْرَ فَانْكَفَأَتْ عَلَى ذِرَاعِكَ فَأَتَيْتُ بِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ هَذَا مُحَمَّدُ بْنُ حَاطِبٍ فَتَفَلَ فِي فَاكَ وَمَسَحَ عَلَى رَأْسِكَ وَدَعَا لَكَ وَجَعَلَ يَتْفُلُ عَلَى يَدِكَ وَيَقُولُ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ وَاشْفِ وَأَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًاقَالَتْ فَمَا قُمْتُ بِكَ مِنْ عِنْدِهِ حَتَّى بَرَأَتْ يَدُكَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abul Abbas] dan [Yunus bin Muhammad] keduanya berkata, telah menceritakan kepada kami ['Abdurrahman bin 'Utsman] bahwa [Ibrahim bin Abul Abbas bin Ibrahim] bin Muhammad bin Hatib dia berkata, telah menceritakan kepadaku [ayahku] dari kakeknya [Muhammad bin Hatib] dari ibunya [Ummu Jamil binti Al Mujallil] dia berkata, \"Aku datang denganmu dari negeri Habasyah sehingga ketika aku singgah di Madinah pada satu malam, atau dua malam, aku membuat masakkan untukmu namun kehabisan kayu bakar, kemudian aku keluar mencari kayu bakar dan kuambil panci, namun panci itu tumpah dan mengenai lenganmu. Kemudian aku membawamu menemui Nabi shallallahu 'alaihi wasallam, aku lalu sampaikan kepada beliau, \"Demi bapak dan ibuku sebagai tebusanmu, Wahai Rasulullah, ini adalah Muhammad bin Hatib.\" Kemudian beliau meludah ke mulutmu dan mengusap kepalamu sambil mendo'akanmu, kemudian beliau meludah ke tanganmu sambil membaca \"ADZHIBIL BA'SA RABBIN NAAS WASYFI WA ANTASY SYAAFI LAA SYIFAA'A ILLAA SYIFAA'UKA SYIFAA'AN LAA YUGHAADIRU SAQAMA (Hilangkanlah penyakit wahai Rabb manusia dan sembuhkanlah, Engkaulah Dzat yang Maha menyembuhkan, tidak ada kesembuhan kecuali dari Engkau kesembuhan yang tidak meninggalkan bekas kepada orang yang sakit) '.\" Ummu Jamil lalu berkata, \"Maka belum lagi aku membawamu pergi dari sisi beliau kecuali tanganmu telah sembuh.\""},"4233":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا مُوسَى الْجُهَنِيُّ قَالَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ عَلِيٍّ قَالَتْ حَدَّثَتْنِي أَسْمَاءُ بِنْتُ عُمَيْسٍ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا عَلِيُّ أَنْتَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى إِلَّا أَنَّهُ لَيْسَ بَعْدِي نَبِيٌّ","id":"Telah menceritakan kepada kami [Abdullah bin Numair] dia berkata, telah menceritakan kepada kami [Musa Al Juhani] dia berkata, telah menceritakan kepadaku [Fatimah binti Ali] dia berkata, telah menceritakan kepadaku [Asma' binti Umais] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ali, kedudukanmu dariku sebagaimana kedudukan Harun dari Musa, hanya saja tidak ada Nabi setelahku.\""},"4234":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ وَيَزِيدُ بْنُ هَارُونَ وَعَفَّانُ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ قَالَ يَزِيدُ فِي حَدِيثِهِ حَدَّثَنَا الْحَكَمُ وَقَالَ عَفَّانُ فِي حَدِيثِهِ سَمِعْتُ الْحَكَمَ بْنَ عُتَيْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنِ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْلَمَّا أُصِيبَ جَعْفَرٌ أَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُمِّي الْبَسِي ثَوْبَ الْحِدَادِ ثَلَاثًا ثُمَّ اصْنَعِي مَا شِئْتِقَالَ عَبْد اللَّهِ و حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Kamil] dan [Yazid bin Harun] dan ['Affan] mereka berkata, telah menceritakan kepada kami [Muhammad bin Thalhah], [Yazid] menyebutkan dalam haditsnya, telah menceritakan kepada kami [Al Hakam], dan ['Affan] menyebutkan dalam haditsnya, aku mendengar [Al Hakam bin 'Utaibah] dari [Abdullah bin Syaddad] dari [Asma' binti Umais] dia berkata, \"Ketika Ja'far meninggal dunia, Nabi shallallahu 'alaihi wasallam datang kepada kami seraya bersabda: \"Wahai ibuku, pakailah pakaian berkabung (tidak warna warni) selama tiga hari, setelah itu silahkan lakukan apa yang kamu kehendaki.\" Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Bakkar] dia berkata; telah menceritakan kepada kami [Muhammad bin Thalhah] dengan riwayat yang seperti itu.\""},"4235":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُهْرِىِّ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْأَوَّلُ مَا اشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ مَيْمُونَةَ فَاشْتَدَّ مَرَضُهُ حَتَّى أُغْمِيَ عَلَيْهِ فَتَشَاوَرَ نِسَاؤُهُ فِي لَدِّهِ فَلَدُّوهُ فَلَمَّا أَفَاقَ قَالَ مَا هَذَا فَقُلْنَا هَذَا فِعْلُ نِسَاءٍ جِئْنَ مِنْ هَاهُنَا وَأَشَارَ إِلَى أَرْضِ الْحَبَشَةِ وَكَانَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ فِيهِنَّ قَالُوا كُنَّا نَتَّهِمُ فِيكَ ذَاتَ الْجَنْبِ يَا رَسُولَ اللَّهِ قَالَ إِنَّ ذَلِكَ لَدَاءٌ مَا كَانَ اللَّهُ عَزَّ وَجَلَّ لَيَقْرَفُنِي بِهِ لَا يَبْقَيَنَّ فِي هَذَا الْبَيْتِ أَحَدٌ إِلَّا الْتَدَّ إِلَّا عَمُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي الْعَبَّاسَ قَالَ فَلَقَدْ الْتَدَّتْ مَيْمُونَةُ يَوْمَئِذٍ وَإِنَّهَا لَصَائِمَةٌ لِعَزْمَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdurrazaq] dia berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dia berkata, telah mengabarkan kepadaku [Abu Bakar bin 'Abdurrahman bin Harits bin Hisyam] dari [Asma' binti 'Umais] dia berkata, \"Pertama kali Rasulullah shallallahu 'alaihi wasallam merasakan sakit, beliau berada di rumah Maimunah, saat sakitnya semakin parah dan tidak sadarkan diri, maka para isteri beliau bermusyawarah untuk mengobatinya dengan meminumkan obat melalui mulut sampingnya, kemudian mereka pun melakukannya. Setelah sadarkan diri beliau bertanya: \"Apa ini?\" kami menjawab, \"Ini adalah perbuatan para wanita yang datang dari sini -kemudian ia menunjuk ke arah Habasyah-, dan ketika itu Asma' binti 'Umais ada bersama mereka. Mereka lalu berkata, \"Kami menganggap bahwa tuan terkena penykit TBC wahai Rasulullah.\" Beliau bersabda: \"Sungguh, itu adalah penyakit berbahaya, tidaklah Allah 'azza wajalla menjadikan menular terhadapku, maka janganlah seseorang tinggal di rumah ini kecuali dia harus meminum obat, kecuali paman Rasulullah shallallahu 'alaihi wasallam, Al Abbas.\" Abu Bakar bin 'Abdurrahman berkata, \"Sungguh, pada hari itu Maimunah meminum obat, padahal dia sedang berpuasa, karena anjuran Rasulullah shallallahu 'alaihi wasallam.\""},"4236":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عُرْوَةَ بْنِ عَامِرٍ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ الزُّرَقِيِّ قَالَ قَالَتْ أَسْمَاءُيَا رَسُولَ اللَّهِ إِنَّ بَنِي جَعْفَرٍ تُصِيبُهُمْ الْعَيْنُ أَفَأَسْتَرْقِي لَهُمْ قَالَ نَعَمْ فَلَوْ كَانَ شَيْءٌ سَابِقٌ الْقَدَرَ لَسَبَقَتْهُ الْعَيْنُ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari ['Urwah bin 'Amir] dari ['Ubaid bin Rifa'ah Az Zuraqi] dia berkata, [Asma'] berkata, \"Wahai Rasulullah, sesungguhnya Bani Ja'far terkena penyakit 'Ain, bolehkah aku membacakan ruqyah untuk mereka?\" beliau menjawab: \"Ya, sekiranya ada sesuatu yang mendahului takdir, maka itu adalah penyakit ain.\""},"4237":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا يُونُسُ يَعْنِى ابْنَ يَزِيدَ الْأَيْلِيَّ قَالَ حَدَّثَنَا أَبُو شَدَّادٍ عَنْ مُجَاهِدٍ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْكُنْتُ صَاحِبَةَ عَائِشَةَ الَّتِي هَيَّأَتْهَا وَأَدْخَلَتْهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي نِسْوَةٌ قَالَتْ فَوَاللَّهِ مَا وَجَدْنَا عِنْدَهُ قِرًى إِلَّا قَدَحًا مِنْ لَبَنٍ قَالَتْ فَشَرِبَ مِنْهُ ثُمَّ نَاوَلَهُ عَائِشَةَ فَاسْتَحْيَتْ الْجَارِيَةُ فَقُلْنَا لَا تَرُدِّي يَدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذِي مِنْهُ فَأَخَذَتْهُ عَلَى حَيَاءٍ فَشَرِبَتْ مِنْهُ ثُمَّ قَالَ نَاوِلِي صَوَاحِبَكِ فَقُلْنَا لَا نَشْتَهِهِ فَقَالَ لَا تَجْمَعْنَ جُوعًا وَكَذِبًا قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ قَالَتْ إِحْدَانَا لِشَيْءٍ تَشْتَهِيهِ لَا أَشْتَهِيهِ يُعَدُّ ذَلِكَ كَذِبًا قَالَ إِنَّ الْكَذِبَ يُكْتَبُ كَذِبًا حَتَّى تُكْتَبَ الْكُذَيْبَةُ كُذَيْبَةً","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] dia berkata, telah menceritakan kepada kami [Yunus] -yakni Ibnu Yazid Al Aila- dia berkata, telah menceritakan kepada kami [Abu Syaddad] dari [Mujahid] dari [Asma' binti 'Umais] dia berkata, \"Aku menemani A'isyah untuk meriasnya sebelum bertemu dengan Rasulullah, sedangkan aku bersama beberapa wanita.\" Asma berkata, \"Demi Allah, kami tidak mendapatkan hidangan dari sisi beliau (Nabi) kecuali sebuah mangkuk berisi susu.\" Asma berkata, \"Kemudian beliau meminumnya lalu memberikannya kepada A'isyah, namun A'isyah malu-malu, maka kami pun berkata, \"Jangan kamu tolak pemberian dari Rasulullah shallallahu 'alaihi wasallam, ambillah darinya.\" Kemudian dia mengambilnya sambil tersipu malu untuk kemudian meminumnya. Setelah itu beliau bersabda: \"Ambilkan untuk sahabat-sahabatmu.\" Namun kami menjawab, \"Kami tidak menginginkannya.\" Beliau bersabda: \"Jangan kalian kumpulkan rasa lapar dengan kebohongan.\" Asma berkata, \"Lalu aku bertanya, \"Wahai Rasulullah, jika salah seorang dari kami mengatakan 'aku tidak menginginkannya', padahal sebenarnya dia menginginkan sesuatu itu, apakah itu termasuk berbohong? ' Beliau menjawab: \"Sesungguhnya setiap bohong itu pasti akan ditulis sebagai kebohongan, sehingga seseorang perempuan yang berbohong akan disebut sebagai tukang bohong.\""},"4238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ مَوْلَاةٍ لَهُمْ يُقَالُ لَهَا لَيْلَى تُحَدِّثُ عَنْ جَدَّتِي وَهِيَ أُمُّ عُمَارَةَ بِنْتُ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَقَرَّبَتْ إِلَيْهِ طَعَامًا فَقَالَ لَهَا كُلِي فَقَالَتْ إِنِّي صَائِمَةٌ فَقَالَ إِنَّ الْمَلَائِكَةَ تُصَلِّي عَلَى الصَّائِمِ إِذَا أُكِلَ عِنْدَهُ حَتَّى يَفْرُغُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Habib] seorang laki-laki Anshar, dari budak mereka yang biasa disebut dengan [Laila] dia menceritakan dari nenekku [Ummu Amarah binti Ka'b] bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya, kemudian dia mendekatkan makanan kepada beliau, beliau lalu bersabda kepadanya: \"Makanlah.\" Ummu Amarah berkata, \"Sesungguhnya aku sedang berpuasa, \" maka beliau bersabda: \"Sesungguhnya Malaikat mendoakan orang yang berpuasa, ketika di sisinya ada orang yang makan hingga (orang yang makan itu) selesai.\""},"4239":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ زَيْدٍ الْأَنْصَارِيِّ عَنْ امْرَأَةٍ يُقَالُ لَهَا لَيْلَى عَنْ أُمِّ عُمَارَةَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَّبْنَا إِلَيْهِ طَعَامًا فَكَانَ بَعْضُ مَنْ عِنْدَهُ صَائِمًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُكِلَ عِنْدَ الصَّائِمِ الطَّعَامُ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Syu'bah] dari [Habib bin Zaid Al Anshari] dari seorang wanita yang dipanggil dengan sebutan [Laila] dari [Ummu Imarah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami, maka kami pun menyediakan makanan untuk beliau, sementara sebagian orang yang ada di sisi beliau sedang berpuasa. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jika ada makanan yang dimakan di sampingnya orang-orang yang berpuasa, maka para Malaikat akan bershalawat kepadanya.\""},"4240":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ الْخُرَاسَانِيَّ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ يَعْنِي ابْنَ عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ حَمْنَةَ بِنْتِ جَحْشٍ قَالَتْكُنْتُ أُسْتَحَاضُ حَيْضَةً شَدِيدَةً كَثِيرَةً فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَفْتِيهِ وَأُخْبِرُهُ فَوَجَدْتُهُ فِي بَيْتِ أُخْتِي زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي إِلَيْكَ حَاجَةً فَقَالَ وَمَا هِيَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ حَيْضَةً كَثِيرَةً شَدِيدَةً فَمَا تَرَى فِيهَا قَدْ مَنَعَتْنِي الصَّلَاةَ وَالصِّيَامَ قَالَ أَنْعَتُ لَكِ الْكُرْسُفَ فَإِنَّهُ يُذْهِبُ الدَّمَ قَالَتْ هُوَ أَكْثَرُ مِنْ ذَلِكَ قَالَ فَتَلَجَّمِي قَالَتْ إِنَّمَا أَثُجُّ ثَجًّا فَقَالَ لَهَا سَآمُرُكِ بِأَمْرَيْنِ أَيَّهُمَا فَعَلْتِ فَقَدْ أَجْزَأَ عَنْكِ مِنْ الْآخَرِ فَإِنْ قَوِيتِ عَلَيْهِمَا فَأَنْتِ أَعْلَمُ فَقَالَ لَهَا إِنَّمَا هَذِهِ رَكْضَةٌ مِنْ رَكَضَاتِ الشَّيْطَانِ فَتَحَيَّضِي سِتَّةَ أَيَّامٍ أَوْ سَبْعَةً فِي عِلْمِ اللَّهِ ثُمَّ اغْتَسِلِي حَتَّى إِذَا رَأَيْتِ أَنَّكِ قَدْ طَهُرْتِ وَاسْتَيْقَنْتِ وَاسْتَنْقَأْتِ فَصَلِّي أَرْبَعًا وَعِشْرِينَ لَيْلَةً أَوْ ثَلَاثًا وَعِشْرِينَ لَيْلَةً وَأَيَّامَهَا وَصُومِي فَإِنَّ ذَلِكَ يُجْزِئُكِ وَكَذَلِكَ فَافْعَلِي فِي كُلِّ شَهْرٍ كَمَا تَحِيضُ النِّسَاءُ وَكَمَا يَطْهُرْنَ بِمِيقَاتِ حَيْضِهِنَّ وَطُهْرِهِنَّ وَإِنْ قَوِيتِ عَلَى أَنْ تُؤَخِّرِي الظُّهْرَ وَتُعَجِّلِي الْعَصْرَ فَتَغْتَسِلِينَ ثُمَّ تُصَلِّينَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا ثُمَّ تُؤَخِّرِينَ الْمَغْرِبَ وَتُعَجِّلِينَ الْعِشَاءَ ثُمَّ تَغْتَسِلِينَ وَتَجْمَعِينَ بَيْنَ الصَّلَاتَيْنِ فَافْعَلِي وَتَغْتَسِلِينَ مَعَ الْفَجْرِ وَتُصَلِّينَ وَكَذَلِكَ فَافْعَلِي وَصَلِّي وَصُومِي إِنْ قَدَرْتِ عَلَى ذَلِكَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَعْجَبُ الْأَمْرَيْنِ إِلَيَّ","id":"Telah menceritakan kepada kami [Abdul Malik bin Amru] berkata, telah menceritakan kepada kami [Zuhair] -yakni Ibnu Muhammad Al Khurrasani, dari [Abdullah bin Muhammad] -yakni Ibnu Aqil bin Abu Thalib- dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran bin Thalhah] dari Ibunya [Hamnah binti Jahsi] dia berkata, \"Aku berkata, \"Aku mengeluarkan darah istihadlah (darah penyakit yang keluar setelah selesai masa haid) dengan banyak sekali, maka aku datang menghadap Rasulullah shallallahu 'alaihi wasallam untuk meminta fatwa dan menceritakan hal itu kepadanya. Maka aku pun menemui beliau saat berada di rumah saudariku, Zainab binti Jahsy.\" Hamnah berkata, \"Lantas aku bertanya, \"Wahai Rasulullah, aku ada perlu dengan tuan.\" Beliau menjawab: \"Apa keperluanmu?\" Aku berkata, \"Wahai Rasulullah, aku mengeluarkan darah istihadlah banyak sekali, maka apa yang tuan sarankan kepadaku, karena dia telah menghalangiku dari melaksanakan shalat dan puasa?\" Beliau menjawab: \"Aku sarankan kepadamu untuk menggunakan kain kapas karena dia dapat mencegah keluarnya darah.\" Hamnah bertanya lagi, \"(Namun) darahnya lebih banyak keluar.\" Beliau menjawab: \"Maka balutlah tempat keluarnya darah.\" Hamnah berkata lagi, \"Darahnya keluar dengan deras!\" Beliau bersabda: \"Aku perintahkan kepadamu dua hal, mana saja kamu lakukan dari keduanya maka itu sudah sah bagimu (sudah mewakili dari yang lain), jika kamu mampu melakukan keduanya maka kamu lebih mengetahuinya.\" Kemudian beliau berkata kepadanya: \"Ini hanyalah penyakit dari setan, maka tetapkanlah masa haidmu enam atau tujuh hari menurut ilmu Allah, kemudian hendaklah kamu mandi, sehingga apabila kamu merasa sudah suci dan yakin untuk membersihkan diri, maka laksanakanlah shalat yang dua puluh empat atau dua puluh tiga hari dan malamnya, dan laksanakanlah puasa karena itu sudah sah bagimu. Dan lakukanlah pada setiap bulannya sebagaimana umumnya para wanita mengalami haid, masa haid mereka dan masa suci mereka, jika kamu mampu untuk mengakhirkan shalat zhuhur dan mensegerakan shalat ashar maka kamu mandi lalu melaksanakan shalat zhuhur dan ashar dengan menggabungnya, kemudian kamu akhirkan shalat Maghrib dan mensegerakan shalat Isya' lalu kamu mandi dan melaksanakan dua shalat (Maghrib dan Isya') dengan menggabungnya maka lakukanlah, kemudian kamu mandi pada waktu shubuh lalu laksanakan shalat shubuh, demikian juga jika kamu mampu, maka lakukanlah shalat dan puasa.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan ini adalah dua hal yang paling mengagumkan bagiku.\""},"4241":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ حَمْنَةَ بِنْتِ جَحْشٍأَنَّهَا اسْتُحِيضَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي اسْتَحَضْتُ حَيْضَةً مُنْكَرَةً شَدِيدَةً فَقَالَ لَهَا احْتَشِي كُرْسُفًا قَالَتْ إِنِّي أَشَدُّ مِنْ ذَلِكَ إِنِّي أَثُجُّ ثَجًّا قَالَ تَلَجَّمِي وَتَحَيَّضِي فِي كُلِّ شَهْرٍ فِي عِلْمِ اللَّهِ سِتَّةَ أَيَّامٍ أَوْ سَبْعَةً ثُمَّ اغْتَسِلِي غُسْلًا وَصَلِّي وَصُومِي ثَلَاثًا وَعِشْرِينَ أَوْ أَرْبَعًا وَعِشْرِينَ وَأَخِّرِي الظُّهْرَ وَقَدِّمِي الْعَصْرَ وَاغْتَسِلِي لَهُمَا غُسْلًا وَأَخِّرِي الْمَغْرِبَ وَقَدِّمِي الْعِشَاءَ وَاغْتَسِلِي لَهُمَا غُسْلًا وَهَذَا أَحَبُّ الْأَمْرَيْنِ إِلَيَّ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Syarik bin Abdullah] dari [Abdullah bin Muhammad bin Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran bin Thalhah] dari ibunya [Hamnah binti Jahsi] bahwa dia mengeluarkan darah istihadlah pada masa Rasulullah shallallahu 'alaihi wasallam, maka dia mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya aku sedang istihadlah dengan mengeluarkan darah yang deras?\" maka beliau bersabda kepadanya: \"Balutlah dengan kapas.\" Hamnah berkata, \"Bahkan darahnya lebih dari itu, sesungguhnya ia keluar dengan deras.\" Beliau bersabda: \"Balutlah tempat keluarnya darah dengan kapas, dan tetapkanlah masa haidmu enam atau tujuh hari menurut ilmu Allah kemudian hendaklah kamu mandi lalu laksanakanlah shalat dan puasa yang dua puluh tiga atau dua puluh empat harinya. Kemudian kamu mandi dan shalat dengan mengakhirkan shalat zhuhur dan mensegerakan shalat ashar, lalu kamu mandi lagi untuk mengerjakan shalat dengan mengakhirkan shalat Maghrib dan mensegerakan shalat Isya' dengan satu kali mandi.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan ini adalah dua hal yang paling mengagumkan bagiku.\""},"4242":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنِ الْقَاسِمِ بْنِ غَنَّامٍ عَنْ أَهْلِ بَيْتِهِ عَنْ جَدَّتِهِ أُمِّ فَرْوَةَ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ عَنْ أَفْضَلِ الْأَعْمَالِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةُ لِأَوَّلِ وَقْتِهَا","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Abdullah bin Umar] dari [Qasim bin Ghannam] dari [anggota keluarganya] dari neneknya [Ummu Farwah] bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam, ditanya oleh seorang lelaki tentang amalan yang paling utama, maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Shalat pada awal waktunya.\""},"4243":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أُمِّ كُرْزٍ الْخُزَاعِيَّةِ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُلَامٍ فَبَالَ عَلَيْهِ فَأَمَرَ بِهِ فَنُضِحَ وَأُتِيَ بِجَارِيَةٍ فَبَالَتْ عَلَيْهِ فَأَمَرَ بِهِ فَغُسِلَ","id":"Telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari ['Amru bin Syu'aib] dari [Ummu Kurz Al Khuzaiyah] dia berkata, didatangkan kepada Nabi shallallahu 'alaihi wasallam bayi laki-laki, lalu bayi tersebut mengencingi beliau, maka beliau menyuruhnya untuk memerciki sisa kencingnya. Dan dihadapkan juga seorang bayi perempuan kepada Nabi shallallahu 'alaihi wasallam, lalu bayi tersebut mengencingi beliau, maka beliau menyuruh untuk mencucinya.\""},"4244":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي مَرْيَمَ الْغَسَّانِيُّ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ حَكِيمُ بْنُ عُمَيْرٍ وَحَبِيبُ بْنُ عُبَيْدٍ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدَعْ رَجُلٌ مِنْكُمْ أَنْ يَعْمَلَ لِلَّهِ أَلْفَ حَسَنَةٍ حِينَ يُصْبِحُ يَقُولُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ مِائَةَ مَرَّةٍ فَإِنَّهَا أَلْفُ حَسَنَةٍ فَإِنَّهُ لَا يَعْمَلُ إِنْ شَاءَ اللَّهُ مِثْلَ ذَلِكَ فِي يَوْمِهِ مِنْ الذُّنُوبِ وَيَكُونُ مَا عَمِلَ مِنْ خَيْرٍ سِوَى ذَلِكَ وَافِرًا","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abu Bakar bin Abdullah bin Abu Maryam Al Ghassani] berkata, telah menceritakan kepada kami [Abu Al Ahwash Hakim bin Umair] dan [Habib bin Ubaid] dari [Abu Darda'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian meninggalkan untuk beramal karena Allah pada waktu pagi dengan pahala seribu kebaikan; mengucapkan SUBHAANALLAH WABIHAMDIHI sebanyak seratus kali, maka ia telah mendapatkan seribu kebaikan. Insyaallah ia tidak akan melakukan dosa sebanyak itu (maksudnya seribu dosa) dalam seharinya, dan kebaikan yang dilakukannya justru lebih melimpah dari dosa yang dilakukannya.\""},"4245":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ عُقْبَةَ بْنِ رُومَانَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ زَحْزَحَ عَنْ طَرِيقِ الْمُسْلِمِينَ شَيْئًا يُؤْذِيهِمْ كَتَبَ اللَّهُ لَهُ بِهِ حَسَنَةً وَمَنْ كُتِبَ لَهُ عِنْدَهُ حَسَنَةٌ أَدْخَلَهُ اللَّهُ بِهَا الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepada kami [Abu Bakar bin Abu Maryam] berkata, telah menceritakan kepadaku [Humaid bin Uqbah bin Ruman] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa membuang sesuatu yang mengganggu jalan kaum muslimin maka Allah mencatat baginya satu kebaikan. Dan barangsiapa yang Allah catat satu kebaikan baginya di sisi-Nya maka Allah akan memasukkan dengannya ke Surga.\""},"4246":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا صَفْوَانُ قَالَ حَدَّثَنِي بَعْضُ الْمَشْيَخَةِ عَنْ أَبِي إِدْرِيسَ السَّكُونِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَأَوْصَانِي خَلِيلِي أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ لَا أَدَعُهُنَّ لِشَيْءٍ أَوْصَانِي بِصِيَامِ بِثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَأَنْ لَا أَنَامَ إِلَّا عَلَى وِتْرٍ وَسُبْحَةِ الضُّحَى فِي الْحَضَرِ وَالسَّفَرِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] berkata, telah menceritakan kepada kami [Shafwan] berkata, telah menceritakan kepadaku [sebagian Syaikh] dari [Abu Idris As Sakuni] dari [Jubair bin Nufair] dari [Abu Darda'] dia berkata, \"Kekasihkau, Abul Qasim shallallahu 'alaihi wasallam, memberiku nasihat dengan tiga hal, yang aku tidak akan meninggalkannya. Beliau nasihatkan kepadaku untuk puasa tiga hari setiap bulan, agar aku tidak tidur kecuali setelah melaksanakan shalat witir dan untuk selalu melaksankan shalat sunnah dluha baik dalam keadaan mukim atau safar.\""},"4247":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ أَبِي الدَّرْدَاءِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ اللَّهَ تَصَدَّقَ عَلَيْكُمْ بِثُلُثِ أَمْوَالِكُمْ عِنْدَ وَفَاتِكُمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah menceritakan kepada kami [Abu Bakar] dari [Dlamrah bin Habib] dari [Abu Darda'] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya Allah bersedekah kepada kalian dengan sepertiga harta kalian ketika kalian wafat.\""},"4248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنِي أَبُو بَكْرٍ عَنْ زَيْدِ بْنِ أَرْطَاةَ عَنْ بَعْضِ إِخْوَانِهِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ شَيْءٍ يَنْقُصُ إِلَّا الشَّرَّ فَإِنَّهُ يُزَادُ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mush'ab] berkata, telah menceritakan kepadaku [Abu Bakar] dari [Zaid bin Arthah] dari [sebagian saudaranya] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap sesuatu pasti akan berkurang kecuali kejahatan, ia akan terus bertambah.\""},"4249":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ قَالَ حَدَّثَنِي أَخٌ لِعَدِيِّ بْنِ أَرْطَاةَ عَنْ رَجُلٍ عَنْ أَبِي الدَّرْدَاءِ قَالَعَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَخْوَفَ مَا أَخَافُ عَلَيْكُمْ الْأَئِمَّةُ الْمُضِلُّونَ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepadaku [ayahku] dia berkata, telah menceritakan kepadaku [saudaranya Adi bin Arthah] dari [seorang laki-laki] dari [Abu Darda] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mewasiatkan kepada kami: \"Sesuatu yang paling aku takutkan atas kalian adalah para pemimpin yang menyesatkan.\""},"4250":{"ar":"حَدَّثَنَا هَيْثَمُ بْنُ خَارِجَةَ قَالَ أَخْبَرَنَا أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ عُتْبَةَ السُّلَمِيُّ عَنْ يُونُسَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ غُفِرَ لَكُمْ مَا تَأْتُونَ إِلَى الْبَهَائِمِ لَغُفِرَ لَكُمْ كَثِيرًا","id":"Telah menceritakan kepada kami [Husyaim bin Kharijah] berkata, telah mengabarkan kepada kami [Abu Ar Rabi' Sulaiman bin Utbah As Sulamii] dari [Yunus bin Maisarah bin Halbas] dari [Abu Idris] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seandainya kalian mendatangi hewan dan kalian akan diampuni, maka pasti kalian akan banyak diampuni.\""},"4251":{"ar":"حَدَّثَنَا هَيْثَمٌ وَسَمِعْتُهُ أَنَا مِنْهُ قَالَ حَدَّثَنَا أَبُو الرَّبِيعِ عَنْ يُونُسَ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَلَقَ اللَّهُ آدَمَ حِينَ خَلَقَهُ فَضَرَبَ كَتِفَهُ الْيُمْنَى فَأَخْرَجَ ذُرِّيَّةً بَيْضَاءَ كَأَنَّهُمْ الذَّرُّ وَضَرَبَ كَتِفَهُ الْيُسْرَى فَأَخْرَجَ ذُرِّيَّةً سَوْدَاءَ كَأَنَّهُمْ الْحُمَمُ فَقَالَ لِلَّذِي فِي يَمِينِهِ إِلَى الْجَنَّةِ وَلَا أُبَالِي وَقَالَ لِلَّذِي فِي كَفِّهِ الْيُسْرَى إِلَى النَّارِ وَلَا أُبَالِي","id":"Telah menceritakan kepada kami [Haitsam] dan aku telah mendengar darinya, dia berkata, telah menceritakan kepada kami [Abu Ar Rabi'] dari [Yunus] dari [Abu Idris] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ketika Allah menciptakan Adam, Allah memukul bahunya yang sebelah kanan, maka keluarlah keturunan berkulit putih seperti molekul, dan memukul bahu bagian kirinya kemudian keluar keturunan yang berkulit hitam seperti arang, maka Allah berkata kepada yang di bagian kanannya, 'Masuklah ke Surga dan Aku tidak perduli'. Kemudian berkata kepada yang di bagian kirinya, 'Masuklah ke dalam Neraka dan Aku tidak perduli'.\""},"4252":{"ar":"حَدَّثَنَا هَيْثَمٌ قَالَ أَخْبَرَنَا ��َبُو الرَّبِيعِ عَنْ يُونُسَ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى يَقُولُ يَوْمَ الْقِيَامَةِ لِآدَمَ عَلَيْهِ السَّلَام قُمْ فَجَهِّزْ مِنْ ذُرِّيَّتِكَ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ إِلَى النَّارِ وَوَاحِدًا إِلَى الْجَنَّةِ فَبَكَى أَصْحَابُهُ وَبَكَوْا ثُمَّ قَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفَعُوا رُءُوسَكُمْ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا أُمَّتِي فِي الْأُمَمِ إِلَّا كَالشَّعْرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ فَخَفَّفَ ذَلِكَ عَنْهُمْ","id":"Telah menceritakan kepada kami [Haitsam] berkata, telah mengabarkan kepada kami [Abu Ar Rabi'] dari [Yunus] dari [Abu Idris] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah Ta'ala pada hari Qiyamat berkata kepada Adam Alaihis Salam, 'Bangkit dan siapkan dari keturunanmu, sembilan ratus sembilan puluh sembilan orang untuk masuk ke dalam Neraka dan satu masuk Surga.\" Maka para sahabatpun menangis, lantas Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Angkatlah kepala kalian, maka demi Dzat yang jiwaku ada di tangan-Nya, tidaklah ummatku dari ummat-ummat yang lain kecuali seperti seutas rambut putih yang ada di kulit seekor sapi hitam, \" dan beliaupun meredakan tangis mereka.\""},"4253":{"ar":"حَدَّثَنَا هَيْثَمٌ قَالَ حَدَّثَنَا أَبُو الرَّبِيعِ عَنْ يُونُسَ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ شَيْءٍ حَقِيقَةٌ وَمَا بَلَغَ عَبْدٌ حَقِيقَةَ الْإِيمَانِ حَتَّى يَعْلَمَ أَنَّ مَا أَصَابَهُ لَمْ يَكُنْ لِيُخْطِئَهُ وَمَا أَخْطَأَهُ لَمْ يَكُنْ لِيُصِيبَهُقَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنِي الْهَيْثَمُ بْنُ خَارِجَةَ عَنْ أَبِي الرَّبِيعِ بِهَذِهِ الْأَحَادِيثِ كُلِّهَا إِلَّا أَنَّهُ أَوْقَفَ مِنْهَا حَدِيثَ لَوْ غُفِرَ لَكُمْ مَا تَأْتُونَ إِلَى الْبَهَائِمِ وَقَدْ حَدَّثَنَاهُ أَبِي عَنْهُ مَرْفُوعًا","id":"Telah menceritakan kepada kami [Haitsam] berkata, telah menceritakan kepada kami [Abu Ar Rabi'] dari [Yunus] dari [Abu Idris] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap sesuatu ada hakekatnya, dan seorang hamba tidak akan sampai pada hakekat Iman sehingga dia mengetahui bahwa apa saja yang telah ditetapkannya, tidak mungkin akan menyalahinya, dan apa yang tidak mengenainya tidak mungkin akan menimpanya.\" Abu Abdurrahman berkata; telah menceritakan kepadaku [Al Haitsam bin Kharijah] dari [Abu Rabi'] dengan hadits-hadits ini semuanya, hanya saja ia me-mauqufkan (sampai kepada sahabat) hadits berikut ini, \"Seandainya kalian mendatangi hewan kalian akan diampuni, \" dan bapakku telah menceritakan hadits ini kepada kami secara marfu' (sampai kepada Nabi).\""},"4254":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ زَائِدَةَ بْنِ قُدَامَةَ وَوَكِيعٌ قَالَ حَدَّثَنِي زَائِدَةُ بْنُ قُدَامَةَ عَنِ السَّائِبِ قَالَ وَكِيعٌ ابْنِ حُبَيْشٍ الْكَلَاعِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّ قَالَقَالَ لِي أَبُو الدَّرْدَاءِ أَيْنَ مَسْكَنُكَ قَالَ قُلْتُ فِي قَرْيَةٍ دُونَ حِمْصَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ ثَلَاثَةٍ فِي قَرْيَةٍ فَلَا يُؤَذَّنُ وَلَا تُقَامُ فِيهِمْ الصَّلَوَاتُ إِلَّا اسْتَحْوَذَ عَلَيْهِمْ الشَّيْطَانُ عَلَيْكَ بِالْجَمَاعَةِ فَإِنَّمَا يَأْكُلُ الذِّئْبُ الْقَاصِيَةَقَالَ ابْنُ مَهْدِيٍّ قَالَ السَّائِبُ يَعْنِي بِالْجَمَاعَةِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Zaidah bin Qudamah] dan [Waki'] berkata, telah menceritakan kepadaku [Zaidah bin Qudamah] dari [As Saib], [Waki' bin Hubais Al Kala'i] berkata, dari [Ma'dan bin Abu Thalhah Al Ya'marii] berkata, \" [Abu Darda'] berkata kepadaku, \"Dimanakah tempat tinggalmu?\" Ma'dan berkata, \"Aku berkata, \"Aku tinggal di kampung, bukan di kota.\" Abu Darda berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah tiga (keluarga) di sebuah perkampungan yang tidak dikumandangkan (adzan) dan tidak pula didirikan shalat (lima waktu) melainkan setan akan menguasai mereka, hendaklah kamu berjama'ah, hanyasanya serigala akan memangsa (kambing) yang hidup sendirian.\" [Ibnu Mahdi] berkata; [As Tsaib] berkata; \"Yaitu dengan shalat berjama'ah.\""},"4255":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ قَالَ سَمِعْتُ أَبَا عُمَرَ الصِّينِيَّ عَنْ أَبِي الدَّرْدَاءِأَنَّهُ إِذَا كَانَ نَزَلَ بِهِ ضَيْفٌ قَالَ يَقُولُ لَهُ أَبُو الدَّرْدَاءِ مُقِيمٌ فَنُسْرِجُ أَوْ ظَاعِنٌ فَنَعْلِفُ قَالَ فَإِنْ قَالَ لَهُ ظَاعِنٌ قَالَ لَهُ مَا أَجِدُ لَكَ شَيْئًا خَيْرًا مِنْ شَيْءٍ أَمَرَنَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا يَا رَسُولَ اللَّهِ ذَهَبَ الْأَغْنِيَاءُ بِالْأَجْرِ يَحُجُّونَ وَلَا نَحُجُّ وَيُجَاهِدُونَ وَلَا نُجَاهِدُ وَكَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَدُلُّكُمْ عَلَى شَيْءٍ إِنْ أَخَذْتُمْ بِهِ جِئْتُمْ مِنْ أَفْضَلِ مَا يَجِيءُ بِهِ أَحَدٌ مِنْهُمْ أَنْ تُكَبِّرُوا اللَّهَ أَرْبَعًا وَثَلَاثِينَ وَتُسَبِّحُوهُ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدُوهُ ثَلَاثًا وَثَلَاثِينَ فِي دُبُرِ كُلِّ صَلَاةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] berkata, aku mendengar [Abu Umar As Shini] dari [Abu Darda'] bahwa jika dia kedatangan tamu, Abu Darda' berkata kepadanya, \"Apakah kamu bermukim, maka aku akan memberimu jamuan? Ataukah langsung berangkat, sehingga kami akan memberimu bekal?\" Jika tamu tersebut menjawab, \"Melanjutkan perjalanan, \" maka Abu Darda' berkata kepadanya, \"Aku tidak mendapati pada dirimu kebaikan pun dari apa yang pernah Rasulullah shallallahu 'alaihi wasallam perintahkan. Kami berkata, \"Wahai Rasulullah, orang-orang kaya telah pergi dengan membawa pahala, mereka berhaji sedangkan kami tidak bisa berhaji, mereka berjihad sedangkan kami tidak mampu untuk berangkat jihad, seperti ini dan seperti ini, maka beliau pun bersabda: \"Maukah kalian aku tunjukkan terhadap sesuatu, jika kalian melakukannya maka kalian mendapatkan keutamaan yang lebih dari apa yang mereka kerjakan? Hendaknya kalian bertakbir kepada Allah sebanyak tiga puluh empat kali, bertasbih tiga puluh tiga kali dan bertahmid tiga puluh tiga kali di setiap selesai shalat.\""},"4256":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ أَبِي بَزَّةَ عَنْ عَطَاءٍ الْكَيْخَارَانِيِّ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ شَيْءٍ أَثْقَلُ فِي الْمِيزَانِ مِنْ خُلُقٍ حَسَنٍحَدَّثَنَاه يَزِيدُ قَالَ أَخْبَرَنَا شُعْبَةُ عَنِ الْكَيْخَارَانِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] berkata, aku mendengar [Al Qasim bin Abu Bazzah] dari [Atha' Al Kaikharani] dari [Ummu Darda'] dari [Abu Darda'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada sesuatu yang memberatkan dalam timbangan selain akhlak yang bagus.\" Telah menceritakan kepada kami [Yazid] berkata; telah mengabarkan kepada kami [Syu'bah] dari [Al Kaikharani].\""},"4257":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرِ بْنِ نُفَيْرٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَرَّ بِامْرَأَةٍ مُجِحٍّ عَلَى بَابِ فُسْطَاطٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّهُ يُرِيدُ أَنْ يُلِمَّ بِهَا فَقَالُوا نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ هَمَمْتُ أَنْ أَلْعَنَهُ لَعْنًا يَدْخُلُ مَعَهُ قَبْرَهُ كَيْفَ يُوَرِّثُهُ وَهُوَ لَا يَحِلُّ لَهُ كَيْفَ يَسْتَخْدِمُهُ وَهُوَ لَا يَحِلُّ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khumair] berkata, aku mendengar [Abdurrahman bin Jubair bin Nufair] menceritakan dari [ayahnya] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau melewati seorang wanita yang hamil berada di depan pintu tenda besar. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Mungkin (seseorang) Telah menggaulinya.\" Mereka menjawab, \"Benar.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sungguh, aku ingin melaknat (seseorang) dengan laknat yang akan masuk bersamanya ke dalam kubur. Bagaimana mungkin dia menggaulinya padahal ia tidak halal baginya, bagaimana mungkin dia memanfaatkannya padahal ia tidak halal baginya.\""},"4258":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ ذَكْوَانَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ شَيْخٍ عَنْ أَبِي الدَّرْدَاءِأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ هَذِهِ الْآيَةِ{ الَّذِينَ آمَنُوا وَكَانُوا يَتَّقُونَ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا }قَالَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُحَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ ابْنِ الْمُنْكَدِرِ سَمِعَهُ مِنْ عَطَاءِ بْنِ يَسَارٍ وَعَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ سَأَلْتُ أَبَا الدَّرْدَاءِ فَذَكَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Dzakwan] dari [Atha' bin Yasar] dari [seorang Syaikh] dari [Abu Darda'] bahwa dia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai ayat ini: '((Yaitu) orang-orang yang beriman dan mereka selalu bertakwa. Bagi mereka berita gembira di dalam kehidupan di dunia) ' (Qs. Yunus: 63-64), Beliau bersabda: \"Yaitu mimpi yang benar dari seorang Muslim, atau yang dimimpikan oleh orang Muslim.\" Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Munkadir] dia telah mendengarnya dari [Atha' bin Yasar] dan [Abdul Aziz bin Rufai'] dari [Abu Shalih] dari [Atha' bin Yasar] dari [seorang laki-laki] penduduk Mesir, \"Aku bertanya kepada [Abu Darda'], kemudian dia menyebutkannya dari Nabi shallallahu 'alaihi wasallam, lalu ia menyebutkan (riwayat) yang semisalnya.\""},"4259":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ زِيَادِ بْنِ أَبِي زِيَادٍ مَوْلَى ابْنِ عَيَّاشٍ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِخَيْرِ أَعْمَالِكُمْ وَأَزْكَاهَا عِنْدَ مَلِيكِكُمْ وَأَرْفَعِهَا لِدَرَجَاتِكُمْ وَخَيْرٍ لَكُمْ مِنْ إِعْطَاءِ الذَّهَبِ وَالْوَرِقِ وَخَيْرٍ لَكُمْ مِنْ أَنْ تَلْقَوْا عَدُوَّكُمْ فَتَضْرِبُوا رِقَابَهُمْ وَيَضْرِبُونَ رِقَابَكُمْ ذِكْرُ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Hajjaj bin Muhammad] telah menceritakan kepada kami [Abu Ma'syar] dari [Musa bin Uqbah] dari [Ziyad bin Abu Ziyad] bekas budak Ibnu Ayyas, dari [Abu Darda'] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kalian mau aku kabarkan amalan yang paling baik buat kalian amalkan? Dan yang paling bersih di sisi Raja (Allah) kalian, yang bisa mengangkat derajat kalian, lebih baik dari emas dan harta yang kalian berikan, dan lebih baik dari melawan musuh hingga kalian bisa menebas lutut musuh kalian, atau kalian ditebas lutut kalian oleh musuh kalian? Yaitu berdzikir kepada Allah Azza Wa Jalla.\""},"4260":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ ثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ عَنْ أَبِي الدَّرْدَاءِ قَالَأَتَاهُ رَجُلٌ فَقَالَ مَا تَقُولُ فِي قَوْلِ اللَّهِ{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ لَقَدْ سَأَلْتَ عَنْ شَيْءٍ مَا سَمِعْتُ أَحَدًا سَأَلَ عَنْهُ بَعْدَ رَجُلٍ سَأَلَ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُشْرَاهُمْ فِي الْحَيَاةِ الدُّنْيَا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ وَبُشْرَاهُمْ فِي الْآخِرَةِ الْجَنَّةُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Atha' bin Yasar] dari [seorang laki-laki] penduduk Mesir, dari [Abu Darda'] dia berkata, \"Seorang laki-laki datang kepadanya dan berkata, \"Apa pendatamu dengan firman Allah: '(Bagi mereka berita gembira di dalam kehidupan di dunia dan Akhirat) ' Abu Darda' berkata, \"Sungguh kamu telah menanyakan sesuatu yang belum pernah aku mendengar seorang pun bertanya seperti itu, setelah laki-laki yang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu, beliau bersabda: \"Bagi mereka berita gembira di dalam kehidupan dunia, yaitu mimpi benarnya seorang muslim atau yang dimimpikan oleh seorang Muslim, sedangkan kabar gembira dikehidupan akhirat adalah dengan surga.\""},"4261":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ قَالَكَانَ فِينَا رَجُلٌ فَذَكَرَ الْحَدِيثَ قَالَ فَرَحَلَ إِلَى أَبِي الدَّرْدَاءِ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوَالِدُ أَوْسَطُ أَبْوَابِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Sufyan] dari ['Atha' bin As Saib] dari [Abu Abdurrahman As Sulami] berkata, \"Di antara kami ada seorang laki-laki……kemudian dia menyebutkan hadits. Dia berkata, \"Kemudian dia pergi menemui [Abu Darda'], lalu Abu Darda' berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Orang tua ibarat pusat dari pintu-pintu surga.\""},"4262":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَكَانَ عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ يُرْسِلُ إِلَى أُمِّ الدَّرْدَاءِ فَتَبِيتُ عِنْدَ نِسَائِهِ وَيَسْأَلُهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ لَيْلَةً فَدَعَا خَادِمَهُ فَأَبْطَأَتْ عَلَيْهِ فَلَعَنَهَا فَقَالَتْ لَا تَلْعَنْ فَإِنَّ أَبَا الدَّرْدَاءِ حَدَّثَنِي أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّعَّانِينَ لَا يَكُونُونَ يَوْمَ الْقِيَامَةِ شُهَدَاءَ وَلَا شُفَعَاءَ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Zaid bin Aslam] berkata, Abdul Malik bin Marwan mengutus utusan kepada [Ummu Darda'], utusan itu kemudian bermalam di rumah isteri-isterinya dan menanyakan perihal Nabi shallallahu 'alaihi wasallam. Zaid Bin Aslam berkata, \"Suatu malam Abdul Malik bangun dan memanggil pembantunya namun pembantunya terlambat datang kepadanya sehingga dia melaknatnya, maka Ummu Darda' berkata, \"Janganlah kamu melaknat, karena aku telah mendengar [Abu Darda'] menceritakan kepadaku, bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang yang suka melaknat, mereka tidak akan menjadi saksi dan memberi syafaat pada hari kiyamat.\""},"4263":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنِي أَبُو الزَّاهِرِيَّةِ حُدَيْرُ بْنُ كُرَيْبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ قَالَ سَمِعْتُ أَبَا الدَّرْدَاءِ يَقُولُسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفِي كُلِّ صَلَاةٍ قِرَاءَةٌ قَالَ نَعَمْ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَجَبَتْ هَذِهِفَالْتَفَتَ إِلَيَّ أَبُو الدَّرْدَاءِ وَكُنْتُ أَقْرَبَ الْقَوْمِ مِنْهُ فَقَالَ يَا ابْنَ أَخِي مَا أَرَى الْإِمَامَ إِذَا أَمَّ الْقَوْمَ إِلَّا قَدْ كَفَاهُمْ","id":"Telah menceritakan kepada kami [Zaid bin Khubab] telah menceritakan kepada kami [Mu'awiyah bin Shalih] telah menceritakan kepadaku [Abu Az Zahiriyyah Hudair bin Kuraib] dari [Katsir bin Murrah Al hadhrami] dia berkata, \"Aku mendengar [Abu Darda'] berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, apakah disetiap shalat ada bacaan? Beliau menjawab: \"Ya, \" maka seorang laki-laki dari Anshar"},"4264":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا فُضَيْلٌ يَعْنِي ابْنَ غَزْوَانَ قَالَ سَمِعْتُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ بْنِ كَرِيزٍ قَالَ سَمِعْتُ أُمَّ الدَّرْدَاءِ قَالَتْ سَمِعْتُ أَبَا الدَّرْدَاءِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ يُسْتَجَابُ لِلْمَرْءِ بِظَهْرِ الْغَيْبِ لِأَخِيهِ فَمَا دَعَا لِأَخِيهِ بِدَعْوَةٍ إِلَّا قَالَ الْمَلَكُ وَلَكَ بِمِثْلٍ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Fudlail] -yakni Ibnu Ghazwan- berkata, aku mendengar [Thalhah bin Ubaidullah bin Kariz] berkata, aku telah mendengar [Ummu Darda'] berkata, \"Aku mendengar [Abu Darda'] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan dikabulkan do'a seseorang untuk saudaranya tanpa sepengetahuannya, tidaklah dia berdo'a untuk saudaranya dengan sebuah do'a kecuali pasti para Malaikat akan berkata, 'Dan bagimu yang semisalnya'.\""},"4265":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ عَنْ أَبِي الزُّبَيْرِ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِوَكَانَتْ تَحْتَهُ أُمُّ الدَّرْدَاءِ فَأَتَاهُمْ فَوَجَدَ أُمَّ الدَّرْدَاءِ فَقَالَتْ لَهُ أَتُرِيدُ الْحَجَّ الْعَامَ فَقَالَ نَعَمْ قَالَتْ فَادْعُ لَنَا بِخَيْرٍ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِنَّ دَعْوَةَ الْمَرْءِ الْمُسْلِمِ مُسْتَجَابَةٌ لِأَخِيهِ بِظَهْرِ الْغَيْبِ عِنْدَ رَأْسِهِ مَلَكٌ مُوَكَّلٌ بِهِ كُلَّمَا دَعَا لِأَخِيهِ بِخَيْرٍ قَالَ آمِينَ وَلَكَ بِمِثْلٍقَالَ فَخَرَجْتُ إِلَى السُّوقِ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَحَدَّثَنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ ذَلِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Abdul Malik] dari [Abu Zubair] dari [Shafwan bin Abdullah] -yang dia menanggung Ummu Darda', kemudian dia mendatangi mereka- dan mendapati Ummu Darda', maka [Ummu Darda'] berkata kepadanya, \"Apakah kamu hendak melaksanakan haji tahun ini?\" Dia menjawab, \"Ya.\" Ummu Darda' lalu berkata, \"Tolong do'akan kebaikan untuk kami, karena Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya do'anya seorang Muslim kepada saudaranya yang berada di tempat yang jauh adalah dikabulkan, dan di sisikepalanya ada para Malaikat yang ditugaskan kepadanya, setiap kali berdo'a kepada saudaranya dengan kebaikan para Malaikat berkata, 'Amiin, dan bagimu yang semisalnya'.\" Shafwan berkata, \"Kemudian aku keluar ke pasar dan bertemu dengan [Abu Darda'], lalu ia menceritakan kepadaku tentang hadits dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"4266":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ أَبِي وَقُرِئَ عَلَى سُفْيَانَ سَمِعْتُ ابْنَ أَبِي حُسَيْنٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي حُسَيْنٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْمَعْنَ جُوعًا وَكَذِبًا","id":"Telah menceritakan kepada kami [Sufyan], ayahku berkata; dan dibacakan kepada [Sufyan]; aku mendengar [Ibnu Abu Husain] dari [Syahr bin Hausyab] dari [Asma' binti Yazid]. Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Husain] dari [Syahr bin Hausyab] dari [Asma'], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu menggabungkan rasa lapar dan kedustaan.\""},"4267":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي حُسَيْنٍ سَمِعَ شَهْرًا يَقُولُ سَمِعْتُ أَسْمَاءَ بِنْتَ يَزِيدَ إِحْدَى نِسَاءِ بَنِي عَبْدِ الْأَشْهَلِ تَقُولُمَرَّ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي نِسْوَةٍ فَسَلَّمَ عَلَيْنَا وَقَالَ إِيَّاكُنَّ وَكُفْرَ الْمُنَعَّمِينَ فَقُلْنَا يَا رَسُولَ اللَّهِ وَمَا كُفْرُ الْمُنَعَّمِينَ قَالَ لَعَلَّ إِحْدَاكُنَّ أَنْ تَطُولَ أَيْمَتُهَا بَيْنَ أَبَوَيْهَا وَتَعْنُسَ فَيَرْزُقَهَا اللَّهُ عَزَّ وَجَلَّ زَوْجًا وَيَرْزُقَهَا مِنْهُ مَالًا وَوَلَدًا فَتَغْضَبَ الْغَضْبَةَ فَرَاحَتْ تَقُولُ مَا رَأَيْتُ مِنْهُ يَوْمًا خَيْرًا قَطُّ وَقَالَ مَرَّةً خَيْرًا قَطُّ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Husain] dia mendengar [Syahr] berkata, aku mendengar dari [Asma' binti Yazid] salah seorang isteri bani Abdul Asyhal, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati kami yang sedang berkumpul bersama para wanita, kemudian beliau memberikan salam kepada kami seraya bersabda: \"Jauhilah oleh kalian kufrul Muna'amin, \" Maka kami bertanya, \"Wahai Rasulullah, apa itu kufrul Muna'amin?\" beliau menjawab: \"Mungkin salah seorang di antara kalian mengundur-undur masa perawannya di antara kedua orang tuanya, kemudian Allah memberinya seorang suami dan Allah beri rizki berupa harta dan anak. Kemudian ia marah dan pergi sambil berkata, 'Sungguh, sehari punaku tidak pernah melihatnya berbuat baik sama sekali.\" Dan sekali waktu ia menyebutkan, \"Kebaikan sama sekali.\""},"4268":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ عَنْ مُحَمَّدِ بْنِ مُهَاجِرٍ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقْتُلُوا أَوْلَادَكُمْ سِرًّا فَإِنَّ قَتْلَ الْغَيْلِ يُدْرِكُ الْفَارِسَ فَيُدَعْثِرُهُ عَنْ ظَهْرِ فَرَسِهِ","id":"Telah menceritakan kepada kami [Al Fadll bin Dukain] telah menceritakan kepada kami [Ibnu Abu Ghanayah] dari [Muhammad bin Muhajir] dari [ayahnya] dari [Asma' binti Yazid] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membunuh anak-anak kalian dengan sembunyi-sembunyi, sesungguhnya ghilah dapat menjadikan seorang penunggang kuda menjadi lemah dan jatuh dari atas kuda.\" "},"4269":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا دَاوُدُ يَعْنِى ابْنَ يَزِيدَ الْأَوْدِيَّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَصْلُحُ مِنْ الذَّهَبِ شَيْءٌ وَلَا بَصِيصُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] telah menceritakan kepada kami [Daud] -yakni Ibnu Yazid Al Audi- dari [Syahr bin Hausyab] dari [Asma' binti Yazid] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada kebaikan sesuatupun dari emas dan tidak pula kilauannya.\""},"4270":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْحَمِيدِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ قَالَتْتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِرْعُهُ مَرْهُونَةٌحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَهْرَامَ الْفَزَارِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Hamid] dari [Syahr bin Hausyab] dari [Asma'] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam wafat, baju besi beliau masih tergadaikan.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Bakkar] telah menceritakan kepada kami [Abdul Hamid bin Bahram Al Fazari] dari [Syahr Bin Hausyab] dari [Asma' binti Yazid] dengan hadits yang semisalnya.\""},"4271":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ فَقَالَ إِذَا كَانَ قَبْلَ خُرُوجِ الدَّجَّالِ بِثَلَاثِ سِنِينَ حَبَسَتْ السَّمَاءُ ثُلُثَ قَطْرِهَا وَحَبَسَتْ الْأَرْضُ ثُلُثَ نَبَاتِهَا فَإِذَا كَانَتْ السَّنَةُ الثَّانِيَةُ حَبَسَتْ السَّمَاءُ ثُلُثَيْ قَطْرِهَا وَحَبَسَتْ الْأَرْضُ ثُلُثَيْ نَبَاتِهَا فَإِذَا كَانَتْ السَّنَةُ الثَّالِثَةُ حَبَسَتْ السَّمَاءُ قَطْرَهَا كُلَّهُ وَحَبَسَتْ الْ��َرْضُ نَبَاتَهَا كُلَّهُ فَلَا يَبْقَى ذُو خُفٍّ وَلَا ظِلْفٍ إِلَّا هَلَكَ فَيَقُولُ الدَّجَّالُ لِلرَّجُلِ مِنْ أَهْلِ الْبَادِيَةِ أَرَأَيْتَ إِنْ بَعَثْتُ إِبِلَكَ ضِخَامًا ضُرُوعُهَا عِظَامًا أَسْنِمَتُهَا أَتَعْلَمُ أَنِّي رَبُّكَ فَيَقُولُ نَعَمْ فَتَمَثَّلُ لَهُ الشَّيَاطِينُ عَلَى صُورَةِ إِبِلِهِ فَيَتَّبِعُهُ وَيَقُولُ لِلرَّجُلِ أَرَأَيْتَ إِنْ بَعَثْتُ أَبَاكَ وَابْنَكَ وَمَنْ تَعْرِفُ مِنْ أَهْلِكَ أَتَعْلَمُ أَنِّي رَبُّكَ فَيَقُولُ نَعَمْ فَيُمَثِّلُ لَهُ الشَّيَاطِينَ عَلَى صُوَرِهِمْ فَيَتَّبِعُهُ ثُمَّ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَكَى أَهْلُ الْبَيْتِ ثُمَّ رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَبْكِي فَقَالَ مَا يُبْكِيكُمْ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا ذَكَرْتَ مِنْ الدَّجَّالِ فَوَاللَّهِ إِنَّ أَمَةَ أَهْلِي لَتَعْجِنُ عَجِينَهَا فَمَا تَبْلُغُ حَتَّى تَكَادَ تَفَتَّتُ مِنْ الْجُوعِ فَكَيْفَ نَصْنَعُ يَوْمَئِذٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْفِي الْمُؤْمِنِينَ عَنْ الطَّعَامِ وَالشَّرَابِ يَوْمَئِذٍ التَّكْبِيرُ وَالتَّسْبِيحُ وَالتَّحْمِيدُ ثُمَّ قَالَ لَا تَبْكُوا فَإِنْ يَخْرُجْ الدَّجَّالُ وَأَنَا فِيكُمْ فَأَنَا حَجِيجُهُ وَإِنْ يَخْرُجْ بَعْدِي فَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Jarir bin Hazim] dari [Qatadah] dari [Syahr bin Hausyab] dari [Asma' binti Yazid] dia berkata, \"Kami bersama Nabi shallallahu 'alaihi wasallam di rumahnya, kemudian beliau bersabda: \"Tiga tahun sebelum keluarnya Dajjal, langit akan menahan sepertiga dari air hujannya, dan bumi menahan sepertiga dari tumbuh-tumbuhannya. Pada tahun yang kedua, langit akan menahan dua pertiga dari air hujannya dan bumi akan menahan dua pertiga dari tumbuh-tumbuhannya. Pada tahun yang ketiga langit akan menahan air hujan semuanya dan bumi juga akan menahan tumbuh-tumbuhan semuanya, maka tidaklah yang memiliki sepatu atau tapak kaki (pada hewan) kecuali akan binasa. Kemudian Dajjal berkata kepada seorang lelaki dari penduduk kampung, 'Bagaimana pendapatmu jika aku bangkitkan untamu dengan susu yang besar dan punuknya besar, apakah kamu tahu bahwa aku adalah Rabbmu? Lelaki itu menjawab, 'Ya.' Lalu setan berubah bentuk seperti untanya dan mengikutinya. Kemudian Dajjal berkata kepada orang tadi, 'Bagaimana pendapatmu jika aku bangkitkan bapak dan anakmu dan siapa yang kamu ketahui dari keluargamu, apakah kamu tahu bahwa aku adalah Rabbmu? ' maka lelaki itu menjawab, 'Ya'. Maka setan berubah bentuk seperti keluarganya dan mengikutinya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam keluar sedangkan anggota keluarga sama menangis, lalu Rasulullah shallallahu 'alaihi wasallam kembali sedangkan kami sedang menangis, beliau bertanya: \"Apa yang menyebabkan kalian menangis?\" Aku menjawab, \"Wahai Rasulullah, karena sesuatu yang tuan sebutkan tentang Dajjal. Demi Allah, sungguh, budak keluargaku membuat adonan tepung namun tidak jadi hingga aku hampir mati karena lapar. Maka apa yang harus kami lakukan pada hari itu? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Cukup makanan dan minuman bagi orang-orang beriman pada hari itu dengan Takbir (bacaan Allahu Akbar), tasbih (bacaan subhaanallah) dan tahmid (bacaan Al Hamdulillah).\" Kemudian beliau bersabda: \"Janganlah kalian menangis, jika Dajjal keluar dan aku bersama kalian maka aku yang akan melawannya, namun jika dia keluar setelah aku meninggal, maka Allah adalah pelindungku bagi setiap kaum muslimin.\""},"4272":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ{ إِنَّهُ عَمِلَ غَيْرَ صَالِحٍ }وَسَمِعْتُهُ يَقْرَأُ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ إِنَّ اللَّهَ يَغْفِرُ الذُّنُوبَ جَمِيعًا }وَلَا يُبَالِي{ إِنَّهُ هُوَ الْغَفُورُ الرَّحِيمُ }","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Syahr bin Hausyab] dari [Asma' binti Yazid] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca ayat: INNAHU 'AMILA GHAIRU SHAALIH (Sesungguhnya (perbuatan) nya perbuatan yang tidak baik) ' (Qs. Huud: 46), dan aku mendengarnya membaca: YA 'IBAADIYAL LADZIINA ASRAFUU 'ALAA ANFUSIHIM LAA TAQNATHUU MIN RAHMATILLAAH INNALLAAHA YAGHFIRUDZ DZUNUUBA JAMII'A (Hai hamba-hamba-Ku yang malampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah. Sesungguhnya Allah mengampuni dosa-dosa semuanya) ' (Qs. Az Zummar: 53), dan tidak memperdulikan; INNAHU HUWAL GHAFUURUR RAHIM (Sesungguhnya Dia-lah yang Maha Pengampun lagi Maha Penyayang) ' (Qs. Az Zummar: 53)."},"4273":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ عَنِ ابْنِ خُثَيْمٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَقُولُ أَيُّهَا النَّاسُ مَا يَحْمِلُكُمْ عَلَى أَنْ تَتَابَعُوا فِي الْكَذِبِ كَمَا يَتَتَابَعُ الْفَرَاشُ فِي النَّارِ كُلُّ الْكَذِبِ يُكْتَبُ عَلَى ابْنِ آدَمَ إِلَّا ثَلَاثَ خِصَالٍ رَجُلٌ كَذَبَ عَلَى امْرَأَتِهِ لِيُرْضِيَهَا أَوْ رَجُلٌ كَذَبَ فِي خَدِيعَةِ حَرْبٍ أَوْ رَجُلٌ كَذَبَ بَيْنَ امْرَأَيْنِ مُسْلِمَيْنِ لِيُصْلِحَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdii] telah menceritakan kepada kami [Daud bin Abdurrahman] dari [Ibnu Hutsaim] dari [Syahr bin Hausyab] dari [Asma' binti Yazid] bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah, kemudian beliau bersabda: \"Wahai sekalian manusia, apa yang mendorong kalian ikut-ikutan berdusta sebagaimana anai-anai berebut ke api, setiap perbuatan dusta akan dicatat atas anak adam kecuali tiga hal; seorang suami yang berbohong kepada isterinya supaya isterinya ridla, atau seseorang yang berdusta dalam rangka strategi perang dan seseorang yang berbohong di antara kedua belah pihak dari kaum muslimin untuk mendamaikan keduanya.\""},"4274":{"ar":"حَدَّثَنَا هَاشِمٌ هُوَ ابْنُ الْقَاسِمِ حَدَّثَنَا عَبْدُ الْحَمِيدِ قَالَ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ قَالَ حَدَّثَتْنِي أَسْمَاءُ بِنْتُ يَزِيدَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ نِسَاءَ الْمُسْلِمِينَ لِلْبَيْعَةِ فَقَالَتْ لَهُ أَسْمَاءُ أَلَا تَحْسُرُ لَنَا عَنْ يَدِكَ يَا رَسُولَ اللَّهِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَسْتُ أُصَافِحُ النِّسَاءَ وَلَكِنْ آخُذُ عَلَيْهِنَّ وَفِي النِّسَاءِ خَالَةٌ لَهَا عَلَيْهَا قُلْبَانِ مِنْ ذَهَبٍ وَخَوَاتِيمُ مِنْ ذَهَبٍ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا هَذِهِ هَلْ يَسُرُّكِ أَنْ يُحَلِّيَكِ اللَّهُ يَوْمَ الْقِيَامَةِ مِنْ جَمْرِ جَهَنَّمَ سِوَارَيْنِ وَخَوَاتِيمَ فَقَالَتْ أَعُوذُ بِاللَّهِ يَا نَبِيَّ اللَّهِ قَالَتْ قُلْتُ يَا خَالَتِي اطْرَحِي مَا عَلَيْكِ فَطَرَحَتْهُ فَحَدَّثَتْنِي أَسْمَاءُ وَاللَّهِ يَا بُنَيَّ لَقَدْ طَرَحَتْهُ فَمَا أَدْرِي مَنْ لَقَطَهُ مِنْ مَكَانِهِ وَلَا الْتَفَتَ مِنَّا أَحَدٌ إِلَيْهِ قَالَتْ أَسْمَاءُ فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنَّ إِحْدَاهُنَّ تَصْلَفُ عِنْدَ زَوْجِهَا إِذَا لَمْ تُمَلَّحْ لَهُ أَوْ تَحَلَّى لَهُ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَلَى إِحْدَاكُنَّ أَنْ تَتَّخِذَ قُرْطَيْنِ مِنْ فِضَّةٍ وَتَتَّخِذَ لَهَا جُمَانَتَيْنِ مِنْ فِضَّةٍ فَتُدْرِجَهُ بَيْنَ أَنَامِلِهَا بِشَيْءٍ مِنْ زَعْفَرَانٍ فَإِذَا هُوَ كَالذَّهَبِ يَبْرُقُ","id":"Telah menceritakan kepada kami [Hasyim] -yaitu Ibnu Qasim- telah menceritakan kepada kami [Abdul Hamid] berkata, telah menceritakan kepada kami [Syahr bin Hausyab] berkata, telah menceritakan kepadaku [Asma' binti Yazid] bahwa Rasulullah shallallahu 'alaihi wasallam mengumpulkan para wanita kaum Muslimin untuk berbaiat, maka Asma' berkata kepada beliau, \"Tidakkah tuan mengulurkan tanganmu wahai Rasulullah?\" Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sesungguhnya aku tidak berjabat tangan dengan wanita, akan tetapi aku hanya sekedar mengambil sumpah dari mereka.\" Dan di antara para wanita itu ada bibinya, ia mengenakan gelang dan cincin dari emas, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah kamu suka jika Allah mengenakanmu gelang dan cincin dari api neraka pada hari Kiamat kelak?\" maka dia berkata, \"Aku berlindung diri kepada Allah wahai Nabi Allah.\" Asma' berkata, \"Lantas aku berkata kepada bibiku, \"Buanglah sesuatu yang ada padamu, \" lalu dia membuangnya.\" Asma mendengar kepadaku, \"Demi Allah, wahai anakku, sungguh dia telah membuangnya, dan aku tidak tahu siapa yang mengambil dari tempatnya, dan tidak ada satupun dari kami yang hendak mengambilnya.\" Asma' berkata, \"Maka aku berkata, \"Wahai Nabi Allah, sesungguhnya salah satu dari kami merasa tidak enak bersama suaminya jika tidak mengenakannya atau berhias dengannya?\" Nabi shallallahu 'alaihi wasallam pun bersabda: \"Kenapa salah seorang dari kalian tidak membuat anting dari perak, atau membuat kedua cincinya dari perak lalu memasukkannya di antara jari-jarinya dan dicampur dengan Za'faran, sehingga ia seperti emas yang mengkilap.\""},"4275":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ ابْنُ جُرَيْجٍإِنَّ مَعْمَرًا شَرِبَ مِنْ الْعِلْمِ بِأَنْفَعَقَالَ أَبِي وَمَاتَ مَعْمَرٌ وَلَهُ ثَمَانٍ وَخَمْسُونَ سَنَةً","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, [Ibnu Juraij] telah berkata, \"Sungguh Ma'mar telah menyerap ilmu yang sangat bermanfaat.\" Abdullah berkata, \"Ma'mar meninggal dalam usia lima puluh delapan tahun.\""},"4276":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ أُمِّهِ سَلْمَى قَالَتْاشْتَكَتْ فَاطِمَةُ شَكْوَاهَا الَّتِي قُبِضَتْ فِيهِ فَكُنْتُ أُمَرِّضُهَا فَأَصْبَحَتْ يَوْمًا كَأَمْثَلِ مَا رَأَيْتُهَا فِي شَكْوَاهَا تِلْكَ قَالَتْ وَخَرَجَ عَلِيٌّ لِبَعْضِ حَاجَتِهِ فَقَالَتْ يَا أُمَّهْ اسْكُبِي لِي غُسْلًا فَسَكَبْتُ لَهَا غُسْلًا فَاغْتَسَلَتْ كَأَحْسَنِ مَا رَأَيْتُهَا تَغْتَسِلُ ثُمَّ قَالَتْ يَا أُمَّهْ أَعْطِينِي ثِيَابِيَ الْجُدُدَ فَأَعْطَيْتُهَا فَلَبِسَتْهَا ثُمَّ قَالَتْ يَا أُمَّهْ قَدِّمِي لِي فِرَاشِي وَسَطَ الْبَيْتِ فَفَعَلْتُ وَاضْطَجَعَتْ وَاسْتَقْبَلَتْ الْقِبْلَةَ وَجَعَلَتْ يَدَهَا تَحْتَ خَدِّهَا ثُمَّ قَالَتْ يَا أُمَّهْ إِنِّي مَقْبُوضَةٌ الْآنَ إِنِّي مَقْبُوضَةٌ الْآنَ وَقَدْ تَطَهَّرْتُ فَلَا يَكْشِفُنِي أَحَدٌ فَقُبِضَتْ مَكَانَهَا قَالَتْ فَجَاءَ عَلِيٌّ فَأَخْبَرْتُهُقَالَ عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ فَذَكَرَ نَحْوَهُ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu An Nadlr] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Muhammad bin Ishaq] dari [Ubaidullah bin Abu Rafi'] dari [Ayahnya] dari ibunya [Salma] dia berkata, \"Fatimah mengalami sakit yang membawanya kepada kematian, dan akulah yang merawatnya. Suatu hari aku lihat ia merasakan rasa sakit itu kembali, sebagaimana yang biasa aku lihat.\" Salma berkata, \"Ali kemudian keluar untuk suatu keperluan, kemudian Fatimah berkata, \"Wahai ibu, tuangkanlah air untuk mandiku.\" Kemudian aku tuangkan air untuknya, lalu dia pun mandi dengan sebaik-baiknya sebagaimana yang aku lihat. Kemudian dia berkata, \"Wahai ibu, berikan kepadaku bajuku yang baru.\" Lalu aku memberikannya dan dia pun memakainya. Setelah itu ia berkata lagi, \"Wahai ibu, letakkan tempat tidurku ke tengah-tengah rumah.\" Maka aku pun melakukannya, lalu dia berbaring dan menghadap ke kiblat sambil meletakkan tangannya di bawah pipinya, kemudian ia berkata, \"Wahai ibu, sungguh sekarang tiba waktunya. Sungguh, sekarang tiba waktunya. Dan aku telah bersuci maka jangan ada seorangpun yang menyingkapku.\" Kemudian dia wafat di tempat tidurnya.\" Salma berkata, \"Kemudian Ali datang lalu aku kabarkan hal itu kepadanya.\" Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Ja'far Al Warakani] dia berkata, telah bercerita kepada kami [Ibrahim bin Sa'ad] dari [Muhammad bin Ishaq] kemudian dia menyebutkan hadits seperti itu.\""},"4277":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ أَبِي الْمَوَالِي عَنْ أَيُّوبَ بْنِ حَسَنِ بْنِ عَلِيِّ بْنِ أَبِي رَافِعٍ عَنْ جَدَّتِهِ سَلْمَى خَادِمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَا سَمِعْتُ أَحَدًا قَطُّ يَشْكُو إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعًا فِي رَأْسِهِ إِلَّا قَالَ احْتَجِمْ وَلَا وَجَعًا فِي رِجْلَيْهِ إِلَّا قَالَ اخْضِبْهُمَا بِالْحِنَّاءِ","id":"Telah menceritakan kepada kami [Abu Amir] telah menceritakan kepada kami [Abdurrahman] -yakni Ibnu Abu Al Mawali- dari [Ayyub bin Hasan bin Ali bin Abu Rafi'] dari neneknya [Salma] pelayan Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Aku tidak pernah mendengar seseorang mengadu tentang sakit yang ada di kepalanya kepada Rasulullah shallallahu 'alaihi wasallam, kecuali beliau mengatakan kepadanya agar berbekam, dan tidaklah sakit di kedua kaki kecuali beliau mengatakan agar mengecat keduanya dengan daun pacar.\""},"4278":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي حَدَّثَنَا فَائِدٌ مَوْلَى بَنِي رَافِعٍ عَنْ عَلِيِّ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَمَّتِهِ سَلْمَى قَالَتْمَا اشْتَكَى أَحَدٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعًا فِي رَأْسِهِ إِلَّا قَالَ احْتَجِمْ وَلَا اشْتَكَى إِلَيْهِ أَحَدٌ وَجَعًا فِي رِجْلَيْهِ إِلَّا قَالَ اخْضِبْ رِجْلَيْكَ","id":"Telah menceritakan kepada kami [Abu Sa'id] bekas budak bani Hasyim, telah menceritakan kepada kami [Abdurrahman bin Abu Al Mawali] telah menceritakan kepada kami [Faid] bekas budak bani Rafi', dari [Ali bin Ubaidullah bin Abu Rafi'] dari bibinya [Salma] dia berkata, \"Tidak ada seorang pun yang mengadu sakit kepala kepada Rasulullah shallallahu 'alaihi wasallam, kecuali beliau mengatakan kepadanya agar berbekam, dan tidaklah sakit di kedua kaki kecuali beliau mengatakan agar mengecat keduanya dengan daun pacar.\""},"4279":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ شَرِيكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا بِقَتْلِ الْأَوْزَاغِ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Hamid bin Jubair bin Syaibah] dari [Sa'id bin Al Musayyab] dari [Ummu Syarik] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau memerintahkan untuk membunuh cicak.\""},"4280":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَتْنِي أُمُّ شَرِيكٍ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَفِرَّنَّ النَّاسُ مِنْ الدَّجَّالِ فِي الْجِبَالِ قَالَتْ أُمُّ شَرِيكٍ يَا رَسُولَ اللَّهِ فَأَيْنَ الْعَرَبُ يَوْمَئِذٍ قَالَ كُلُّهُمْ قَلِيلٌ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] dia berkata, telah menceritakan kepadaku [Abu Zubair] bahwa dia telah mendengar [Jabir bin Abdullah] berkata, telah menceritakan kepadaku [Ummu Syarik], bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah manusia berlari dari Dajjal menuju gunung-gunung.\" Ummu Syarik bertanya, \"Wahai Rasulullah, di manakah orang-orang Arab pada hari itu?\" Beliau menjawab: \"Jumlah mereka sangat sedikit.\""},"4281":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ أُمِّ شَرِيكٍ أَنَّهَاكَانَتْ مِمَّنْ وَهَبَتْ نَفْسَهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin Urwah] dari [Urwah] dari [Ummu Syarik], bahwa dia termasuk orang yang menawarkan dirinya kepada Nabi shallallahu 'alaihi wasallam.\""},"4282":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَخْبَرَهُ أَبُوهُ قَالَنَزَلْتُ عَلَى أُمِّ أَيُّوبَ الَّذِينَ نَزَلَ عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلْتُ عَلَيْهَا فَحَدَّثَتْنِي بِهَذَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ تَكَلَّفُوا طَعَامًا فِيهِ بَعْضُ هَذِهِ الْبُقُولِ فَقَرَّبُوهُ فَكَرِهَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لِأَصْحَابِهِ كُلُوا إِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ إِنِّي أَخَافُ أَنْ أُوذِيَ صَاحِبِي يَعْنِي الْمَلَكَ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] telah menceritakan kepada kami [Ubaidullah bin Abu Yazid] dari [Bapaknya] berkata; \"Aku singgah ke tempat [Ummu Ayyub], yaitu orang yang Rasulullah shallallahu 'alaihi wasallam pernah singgah kepada mereka. Ketika aku singgah, ia menceritakan kepadaku seperti ini dari Rasulullah shallallahu 'alaihi wasallam, bahwa para sahabat pernah membawa makanan yang di dalamnya banyak sayurannya, kemudian mereka mendekatkan kepada beliau, akan tetapi Rasulullah shallallahu 'alaihi wasallam tidak suka seraya bersabda kepada para sahabatnya: \"Makanlah, sesungguhnya aku tidak seperti salah seorang di antara kalian, aku khawatir jika aku menyakiti sahabatku ini, yakni malaikat.\""},"4283":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ يَعْنِى ابْنَ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ أُمِّ أَيُّوبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَزَلَ الْقُرْآنُ عَلَى سَبْعَةِ أَحْرُفٍ أَيَّهَا قَرَأْتَ أَجْزَأَكَ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah] -yakni Ibnu Abu Yazid- dari [Ayahnya] dari [Ummu Ayyub] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Qur'an turun dengan tujuh huruf, mana saja yang kamu baca, niscaya kamu aka mendapat pahala.\""},"4284":{"ar":"حَدَّثَنَا حُسَيْنٌ وَأَبُو نُعَيْمٍ قَالَا ثَنَا إِسْرَائِيلُ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ أَبِي يَزِيدَ الضَّنِّيِّ عَنْ مَيْمُونَةَ بِنْتِ سَعْدٍ مَوْلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ وَلَدِ الزِّنَا قَالَ لَا خَيْرَ فِيهِ نَعْلَانِ أُجَاهِدُ بِهِمَا فِي سَبِيلِ اللَّهِ أَحَبُّ إِلَيَّ مِنْ أَنْ أُعْتِقَ وَلَدَ زِنًا","id":"Telah menceritakan kepada kami [Husain] dan [Abu Nu'aim] keduanya berkata, telah menceritakan kepada kami [Israil] dari [Zaid bin Jubair] dari [Abu Yazid Adl Dlanni] dari [Maimunah] bekas budak Nabi shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang anak hasil zina, maka beliau menjawab: \"Tidak ada kebaikan padanya, dua sandal yang aku pergunakan berjihad di jalan Allah lebih aku sukai dari pada aku memerdekakan anak hasil zina.\""},"4285":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ أَبِي يَزِيدَ الضَّنِّيِّ عَنْ مَيْمُونَةَ مَوْلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ قَبَّلَ امْرَأَتَهُ وَهُوَ صَائِمٌ قَالَ قَدْ أَفْطَرَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra'il] dari [Zaid bin Jubair] dari [Abu Yazid Adl Dlanni] dari [Maimunah] bekas budak Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya tentang seorang suami yang mencium isterinya, padahal dia sedang berpuasa. Maka beliau menjawab: \"Dia telah berbuka.\""},"4286":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ ثَنَا عِيسَى قَالَ ثَنَا ثَوْرٌ عَنْ زِيَادِ بْنِ أَبِي سَوْدَةَ عَنْ أَخِيهِ أَنَّ مَيْمُونَةَ مَوْلَاةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْيَا نَبِيَّ اللَّهِ أَفْتِنَا فِي بَيْتِ الْمَقْدِسِ فَقَالَ أَرْضُ الْمَنْشَرِ وَالْمَحْشَرِ ائْتُوهُ فَصَلُّوا فِيهِ فَإِنَّ صَلَاةً فِيهِ كَأَلْفِ صَلَاةٍ فِيمَا سِوَاهُ قَالَتْ أَرَأَيْتَ مَنْ لَمْ يُطِقْ أَنْ يَتَحَمَّلَ إِلَيْهِ أَوْ يَأْتِيَهُ قَالَ فَلْيُهْدِ إِلَيْهِ زَيْتًا يُسْرَجُ فِيهِ فَإِنَّ مَنْ أَهْدَى لَهُ كَانَ كَمَنْ صَلَّى فِيهِحَدَّثَنَا أَبُو مُوسَى الْهَرَوِيُّ قَالَ ثَنَا عِيسَى بْنُ يُونُسَ بِإِسْنَادِهِ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ali bin Bahr] berkata, telah menceritakan kepada kami [Isa] berkata, telah menceritakan kepada kami [Tsaur] dari [Ziyad bin Abu Saudah] dari [saudara laki-lakinya] bahwa [Maimunah] bekas budak Nabi shallallahu 'alaihi wasallam, berkata, \"Wahai Nabi Allah, berilah kami fatwa tentang Baitul Maqdis.\" Beliau menjawab: \"Itu adalah bumi yang terbentang dan mahsyar (perkumpulan), datanglah ke sana dan laksanakan shalat di sana, karena shalat di sana sama dengan melaksanakan seribu shalat di tempat lainnya.\" Beliau bertanya, \"Bagaimana pendapat tuan jika seseorang tidak mampu untuk datang ke sana?\" Nabi menjawab: \"Hendaklah dia menginfakkan minyak untuk penerangan di sana karena barangsiapa yang memberikan minyak untuk penerangan di dalamnya, maka ia seperti orang yang melaksanakan shalat di dalamnya.\" Telah menceritakan kepada kami [Abu Musa Al Harawi] dia berkata, telah menceritakan kepada kami [Isa bin Yunus] dengan sanadnya, kemudian dia menyebutkan hadits seperti itu.\""},"4287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ ثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ مَعْنٍ عَنِ ابْنَةِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا حَفِظْتُ ق إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ يَوْمَ الْجُمُعَةِ قَالَتْ وَكَانَ تَنُّورُنَا وَتَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Hubaib bin Abdurrahman] dari [Abdullah bin Muhammad bin Ma'n] dari [Anak perempuan Haritsah bin Nu'an] dia berkata, \"Aku hafal surat Qaaf langsung dari Rasulullah shallallahu 'alaihi wasallam sewaktu beliau khutbah Jum'at, dia berkata, \"Karena kompor kami dan kompor Rasulullah shallallahu 'alaihi wasallam itu satu.\""},"4288":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ الْحَكَمِ قَالَ ثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ قَالَ ذَكَرَهُ يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا مِنْ وَرَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِهَا فِي الصُّبْحِ","id":"Telah menceritakan kepada kami [Hakam bin Musa] -Abdullah berkata; dan aku telah mendengarnya- dari [Hakam] berkata, telah menceritakan kepada kami [Abdurrahman bin Abu Ar Rijal] berkata, [Yahya bin Sa'id] telah menyebutkan kepadanya dari [Amrah] dari [Ummu Hisyam binti Haritsah bin Nu'man] dia berkata, \"Aku tidak mengambil QAAF WAL QUR'ANIL MAJIID (surat Qaaf) kecuali di belakang Nabi shallallahu 'alaihi wasallam, sewaktu beliau membacanya pada saat shalat subuh.\""},"4289":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ ثَنَا لَيْثٌ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنِ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ حَدَّثَتْهُأَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَى قُرْؤُكِ فَلَا تُصَلِّي فَإِذَا مَرَّ الْقُرْءُ فَتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقُرْءِ إِلَى الْقُرْءِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Laits] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah] dari [Al Mundzir bin Al Mughirah] dari [Urwah bin Zubair] bahwa [Fatimah binti Abu Qubais] telah menceriatakan kepadanya, bahwa dirinya menemui Rasulullah shallallahu 'alaihi wasallam dan mengadukan kepada beliau mengenai darah (kebiasaan wanita), maka beliau bersabda: \"Hanyasannya ia adalah darah kotor, maka lihatlah jika telah datang masa quru`mu (haid), janganlah kamu mengerjakan shalat, dan jika telah berlalu masa quru'mu (haid), maka bersucilah kemudian tunaikan shalat antara haid pertama dengan masa haid kedua.\""},"4290":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ ثَنَا إِسْرَائِيلُ عَنْ عُثْمَانَ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَتْنِي خَالَتِي فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ قَالَتْأَتَيْتُ عَائِشَةَ فَقُلْتُ لَهَا يَا أُمَّ الْمُؤْمِنِينَ قَدْ خَشِيتُ أَنْ لَا يَكُونَ لِي حَظٌّ فِي الْإِسْلَامِ وَأَنْ أَكُونَ مِنْ أَهْلِ النَّارِ أَمْكُثُ مَا شَاءَ اللَّهُ مِنْ يَوْمِ أُسْتَحَاضُ فَلَا أُصَلِّي لِلَّهِ عَزَّ وَجَلَّ صَلَاةً قَالَتْ اجْلِسِي حَتَّى يَجِيءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ يَا رَسُولَ اللَّهِ هَذِهِ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ تَخْشَى أَنْ لَا يَكُونَ لَهَا حَظٌّ فِي الْإِسْلَامِ وَأَنْ تَكُونَ مِنْ أَهْلِ النَّارِ تَمْكُثُ مَا شَاءَ اللَّهُ مِنْ يَوْمِ تُسْتَحَاضُ فَلَا تُصَلِّي لِلَّهِ عَزَّ وَجَلَّ صَلَاةً فَقَالَ مُرِي فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ فَلْتُمْسِكْ كُلَّ شَهْرٍ عَدَدَ أَيَّامِ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ وَتَحْتَشِي وَتَسْتَثْفِرُ وَتَنَظَّفُ ثُمَّ تَطَهَّرُ عِنْدَ كُلِّ صَلَاةٍ وَتُصَلِّي فَإِنَّمَا ذَلِكَ رَكْضَةٌ مِنْ الشَّيْطَانِ أَوْ عِرْقٌ انْقَطَعَ أَوْ دَاءٌ عَرَضَ لَهَا","id":"Telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Israil] dari [Utsman bin Sa'd] dari [Abdullah bin Abu Mulaikah] berkata, telah menceritakan kepadaku bibiku [Fatimah binti Abu Hubaisy] dia berkata, \"Aku datang kepada 'Aisyah, maka aku berkata kepadanya, \"Wahai Ummul Mukminin, aku khawatir jika aku mempunyai lagi bagian dari Islam sehingga aku termasuk dari penghuni neraka, aku berdiam diri sesuai dengan kehendak Allah (lamanya), semenjak aku mengeluarkan darah istihadlah aku tidak pernah melaksanakan shalat sama sekali.\" Aisyah lalu berkata, \"Duduklah kamu sampai Nabi shallallahu 'alaihi wasallam datang.\" Maka tatkala Nabi shallallahu 'alaihi wasallam datang, Aisyah berkata, \"Wahai Rasulullah, ini adalah Fatimah binti Abu Hubais, dia khawatir jika dirinya tidak lagi memiliki bagian dari Islam dan termasuk dari penghuni neraka. Dia berdiam diri sesuai dengan kehendak Allah (lamanya), semenjak dia mengeluarkan darah istihadlah dia tidak pernah melaksanakan shalat sama sekali.\" Maka beliau bersabda: \"Suruhlah Fatimah binti Abu Hubais untuk menghitung setiap bulannya berapa hari dia biasa menjalani masa haidnya, kemudian suruhlah dia mandi.\""},"4291":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ ثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أُمِّ كُرْزٍ الْخُزَاعِيَّةِ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُلَامٍ فَبَالَ عَلَيْهِ فَأَمَرَ بِهِ فَنُضِحَ وَأُتِيَ بِجَارِيَةٍ فَبَالَتْ عَلَيْهِ فَأَمَرَ بِهِ فَغُسِلَ","id":"Telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari [Amru bin Syu'aib] dari [Ummu Kurz Al Khuza'iyyah] dia berkata, \"Dihadapkan kepada Nabi shallallahu 'alaihi wasallam seorang bayi laki-laki, yang kemudian mengencinginya. Beliau lalu memerintahkan untuk memercikinya. Dan dihadapkan pula seorang bayi perempuan, ketika bayi itu kencing maka beliau memerintahkan untuk mencuci (bekas kencingnya).\""},"4292":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ أَبِي الشَّعْثَاءِ قَالَخَرَجْتُ حَاجًّا فَجِئْتُ حَتَّى دَخَلْتُ الْبَيْتَ فَلَمَّا كُنْتُ بَيْنَ السَّارِيَتَيْنِ مَضَيْتُ حَتَّى لَزِقْتُ بِالْحَائِطِ فَجَاءَ ابْنُ عُمَرَ فَصَلَّى إِلَى جَنْبِي فَصَلَّى أَرْبَعًا فَلَمَّا صَلَّى قُلْتُ أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْبَيْتِ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّهُ صَلَّى هَاهُنَا فَقُلْتُ كَمْ صَلَّى قَالَ عَلَى هَذَا أَجِدُنِي أَلُومُ نَفْسِي إِنِّي مَكَثْتُ مَعَهُ عُمُرًا لَمْ أَسْأَلْهُ كَمْ صَلَّىثُمَّ حَجَجْتُ مِنْ الْعَامِ الْمُقْبِلِ فَجِئْتُ فَقُمْتُ فِي مَقَامِهِ فَجَاءَ ابْنُ الزُّبَيْرِ فَصَلَّى فِيهِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Umarah] dari [Abu Sya'tsa`] dia berkata, \"Aku keluar melaksanakan haji, lalu aku datang hingga masuk ke dalam Ka'bah, ketika aku berada di antara dua tiang aku berlalu hingga menyentuh dinding. Kemudian [Ibnu Umar] datang dan melaksanakan shalat empat rakaat di sampingku, selesai shalat aku bertanya kepadanya, 'Di bagian manakah Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat di dalam Ka'bah? ' dia menjawab, ['Usamah Bin Zaid] telah bercerita kepada kami bahwa beliau melaksanakan shalat di sini.\" Kemudian aku bertanya, \"Berapa rakaat beliau shalat?\" dia menjawab, \"Karena inilah aku marah dengan diriku sendiri, sekian lama aku hidup bersama beliau namun aku tidak pernah menanyakannya.\" Kemudian aku melaksanakan haji pada tahun berikutnya, lalu aku datang dan shalat di tempat yang Ibnu Abbas gunakan untuk shalat, lalu Ibnu Zubair datang dan melaksanakan shalat empat rakaat di tempat tersebut.\""},"4293":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَزَوَّجَنِي أَبِي فِي إِمَارَةِ عُثْمَانَ فَدَعَا نَفَرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ صَفْوَانُ بْنُ أُمَيَّةَ وَهُوَ شَيْخٌ كَبِيرٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْهَسُوا اللَّحْمَ نَهْسًا فَإِنَّهُ أَهْنَأُ وَأَمْرَأُ أَوْ أَشْهَى وَأَمْرَأُقَالَ سُفْيَانُ الشَّكُّ مِنِّي أَوْ مِنْهُ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Karim] dari [Abdullah bin Al Harits] dia berkata, \"Ayahku telah menikahkan aku pada masa kepemimpinannya Utsman, maka dia mengundang beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam. Lalu datanglah [Shafwan bin Umayyah], sedangkan dia telah lanjut usia, kemudian dia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gigitlah (makanlah) oleh kalian daging, karena sesungguhnya ia lebih enak dan lezat, atau lebih membangkitkan selera dan lebih lezat.\" Perawi berkata, [Sufyan] ragu 'dariku' ataukah 'darinya'."},"4294":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ ثَنَا التَّيْمِيُّ يَعْنِي سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ يَعْنِي النَّهْدِيَّ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَالطَّاعُونُ وَالْبَطْنُ وَالْغَرَقُ وَالنُّفَسَاءُ شَهَادَةٌقَالَ حَدَّثَنَا بِهِ أَبُو عُثْمَانَ مِرَارًا وَقَدْ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [At Taimi] -yakni Sulaiman- dari [Abu Utsman] -yakni An Nahdi- dari [Amir bin Malik] dari [Shafwan bin Umayyah] berkata, \"(Meninggal) karena penyakit tha'un, sakit perut, tenggelam dan habis melahirkan adalah mati syahid.\" Telah menceritakan kepada kami tentangnya [Abu Utsman] secara terus menerus, dan sekali waktu ia memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam sekali.\""},"4295":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شَرِيكٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَارَ مِنْهُ يَوْمَ حُنَيْنٍ أَدْرَاعًا فَقَالَ أَغَصْبًا يَا مُحَمَّدُ قَالَ بَلْ عَارِيَةٌ مَضْمُونَةٌ قَالَ فَضَاعَ بَعْضُهَا فَعَرَضَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُضَمِّنَهَا لَهُ قَالَ أَنَا الْيَوْمَ يَا رَسُولَ اللَّهِ فِي الْإِسْلَامِ أَرْغَبُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Syarik] dari [Abdul Aziz bin Rufai'] dari [Umayyah bin Shafwan bin Umayyah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam meminjam baju besi darinya pada waktu perang Hunain, maka dia berkata, \"Apakah kamu telah mengambilnya wahai Muhammad?\" Beliau bersabda: \"Bahkan aku meminjamnya dengan jaminan.\" Dia berkata, \"Lalu sebagian (baju besinya) ada yang hilang, sehingga Rasulullah shallallahu 'alaihi wasallam menerangkan kepadanya dan membayar uang jaminan, maka Umayyah pun berkata, \"Wahai Rasulullah, pada hari ini aku lebih mencintai Islam.\""},"4296":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ ثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ قَالَ ثَنَا الزُّهْرِيُّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِأَنَّ صَفْوَانَ بْنَ أُمَيَّةَ بْنِ خَلَفٍ قِيلَ لَهُ هَلَكَ مَنْ لَمْ يُهَاجِرْ قَالَ فَقُلْتُ لَا أَصِلُ إِلَى أَهْلِي حَتَّى آتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكِبْتُ رَاحِلَتِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ زَعَمُوا أَنَّهُ هَلَكَ مَنْ لَمْ يُهَاجِرْ قَالَ كَلَّا أَبَا وَهْبٍ فَارْجِعْ إِلَى أَبَاطِحِ مَكَّةَ قَالَ فَبَيْنَا أَنَا رَاقِدٌ جَاءَ السَّارِقُ فَأَخَذَ ثَوْبِي مِنْ تَحْتِ رَأْسِي فَأَدْرَكْتُهُ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ هَذَا سَرَقَ ثَوْبِي فَأَمَرَ بِهِ أَنْ يُقْطَعَ فَقُلْتُ يَا رَسُولَ اللَّهِ لَيْسَ هَذَا أَرَدْتُ هُوَ عَلَيْهِ صَدَقَةٌ قَالَ هَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Muhammad bin Abu Hafshah] berkata, telah menceritakan kepada kami [Az Zuhry] dari [Shafwan bin Abdullah] bahwa Shafwan bin Umayah bin Khalaf pernah dikatakan kepadanya, \"Binasalah orang-orang yang belum berhijrah.\" Shafwan berkata, \"Maka aku berkata, \"Aku tidak akan menemui keluargaku sampai aku mendatangi Rasulullah shallallahu 'alaihi wasallam.\" Kemudian aku menaiki hewan tungganganku dan pergi menemui Rasulullah shallallahu 'alaihi wasallam, kukatakan kepada beliau, \"Wahai Rasulullah, orang-orang menganggap bahwa binasalah bagi orang-orang yang belum berhijrah?\" Beliau bersabda: \"Sekali-kali tidak wahai Abu Wahb, kembalilah kamu ke lembah di Makkah.\" Shafwan berkata, \"Maka tatkala aku tiduran, seorang pencuri datang dan mencuri kain yang aku taruh di bawah kepalaku, lantas aku menangkapnya dan membawanya ke hadapan Nabi shallallahu 'alaihi wasallam. Aku katakan, \"Laki-laki ini telah mencuri pakaianku!\" Beliau lantas memerintahkan untuk memotong tangannya, maka aku pun berkata, \"Wahai Rasulullah, bukan ini yang aku maksudkan, biarlah ini sedekah buat dia.\" Beliau bersabda: \"Kenapa tidak kamu katakan itu sebelum kamu bawa dia kemari.\""},"4297":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ قَالَ أَخْبَرَنَا ابْنُ مُبَارَكٍ عَنْ يُونُسَ عَنِ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَإِنَّهُ لَأَبْغَضُ النَّاسِ إِلَيَّ فَمَا زَالَ يُعْطِينِي حَتَّى صَارَ وَإِنَّهُ لَأَحَبُّ النَّاسِ إِلَيَّ","id":"Telah menceritakan kepada kami [Zakaria bin Adi] berkata, telah mengabarkan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Shafwan bin Umayyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberiku sesuatu pada waktu perang Hunain, padahal dia adalah orang yang paling aku benci. Dan beliau terus saja memberiku sesuatu sehingga dia menjadi sosok manusia yang paling aku cintai.\""},"4298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ ثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ طَارِقِ بْنِ مُرَقَّعٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّ رَجُلًا سَرَقَ بُرْدَهُ فَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ تَجَاوَزْتُ عَنْهُ قَالَ فَلَوْلَا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنِي بِهِ يَا أَبَا وَهْبٍ فَقَطَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Sa'id] -yakni Ibnu Abu Arubah- dari [Qatadah] dari [Atha'] dari [Thariq bin Muraqqa'] dari [Shafwan bin Umayyah], bahwa seorang laki-laki telah mencuri kainnya, maka pencuri itu pun dibawa ke hadapan Nabi shallallahu 'alaihi wasallam. Beliau kemudian menyuruh untuk memotong tangannya, maka Shafwan pun berkata, \"Wahai Rasulullah, aku telah berlebihan terhadapnya.\" Beliau bersabda: \"Wahai Abu Wahb, sekiranya hal ini terjadi sebelum kamu membawanya kehadapanku.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap memotong tangannya.\""},"4299":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ ثَنَا وُهَيْبٌ قَالَ ثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّهُ قِيلَ لَهُ إِنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مَنْ هَاجَرَ قَالَ فَقُلْتُ لَا أَدْخُلُ مَنْزِلِي حَتَّى آتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ هَذَا سَرَقَ خَمِيصَةً لِي لِرَجُلٍ مَعَهُ فَأَمَرَ بِقَطْعِهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَهَبْتُهَا لَهُ قَالَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُمْ يَقُولُونَ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مَنْ هَاجَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا هِجْرَةَ بَعْدَ فَتْحِ مَكَّةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Shafwan bin Umayyah] bahwa dikatakan kepadanya, \"Tidak akan masuk surga kecuali orang yang telah berhijrah.\" Shafwan lalu berkata, \"Maka aku pun berkata, \"Aku tidak akan masuk ke rumah sebelum aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menanyakan kepada beliau.\" Lalu aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, sesungguhnya laki-laki ini telah mencuri selembar kainku.\" Maka beliau memerintahkan untuk memotong tangan orang yang telah mencurinya, tetapi Shafwan justru berkata, \"Wahai Rasulullah, sesungguhnya aku telah memberikan untuknya.\" Beliau bersabda: \"Kenapa itu tidak kamu lakukan sebelum kamu bawa dia kemari!\" Shufwan berkata, \"Lalu aku berkata, \"Wahai Rasulullah, orang-orang berkata, 'Tidak akan masuk surga kecuali orang-orang yang telah berhijrah'? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hijrah setelah penaklukan Makkah, yang ada adalah Jihad dan niat, akan tetapi jika kalian diseru untuk berperang maka berangkatlah.\""},"4300":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ يَعْنِي النَّهْدِيَّ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطَّاعُونُ شَهَادَةٌ وَالْغَرَقُ شَهَادَةٌ وَالْبَطْنُ شَهَادَةٌ وَالنُّفَسَاءُ شَهَادَةٌ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Sulaiman At Taimi] dari [Abu Utsman] -yakni An Nahdi- dari [Amir bin Malik] dari [Shafwan bin Umayyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"(Orang yang meninggal karena) penyakit Tha'un adalah syahid, mati tenggelam adalah syahid, mati sakit perut adalah syahid dan mati karena melahirkan adalah syahid.\""},"4301":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ ثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ أَبِى سُلَيْمَانَ قَالَ قَالَ صَفْوَانُ بْنُ أُمَيَّةَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آخُذُ اللَّحْمَ عَنْ الْعَظْمِ بِيَدِي فَقَالَ يَا صَفْوَانُ قُلْتُ لَبَّيْكَ قَالَ قَرِّبْ اللَّحْمَ مِنْ فِيكَ فَإِنَّهُ أَهْنَأُ وَأَمْرَأُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Abdurrahman bin Mu'awiyyah] dari [Utsman bin Abu Sulaiman] berkata, \" [Shafwan bin Umayyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melihatku saat aku sedang mengambil daging yang masih menempel pada tulangnya dengan tanganku, maka beliau bersabda: \"Wahai Shafwan.\" Aku menjawab, \"Aku penuhi panggilanmu.\" Beliau lalu bersabda: \"Dekatkanlah daging itu ke mulutmu, sesungguhnya itu lebih mudah dan lebih enak.\""},"4302":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ ثَنَا سُلَيْمَانُ يَعْنِى ابْنَ قَرْمٍ عَنْ سِمَاكٍ عَنْ حُمَيْدِ ابْنِ أُخْتِ صَفْوَانَ بْنِ أُمَيَّةَ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَكُنْتُ نَائِمًا فِي الْمَسْجِدِ عَلَى خَمِيصَةٍ لِي فَسُرِقَتْ فَأَخَذْنَا السَّارِقَ فَرَفَعْنَاهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَفِي خَمِيصَتِي ثَمَنُ ثَلَاثِينَ دِرْهَمًا أَنَا أَهَبُهَا لَهُ أَوَ أَبِيعُهَا لَهُ قَالَ فَهَلَّا كَانَ قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] berkata, telah menceritakan kepada kami [Sulaiman] -yakni Ibnu Qarm- dari [Simak] dari [Humaid bin Ukhti Shafwan bin Umayyah] dari [Shafwan bin Umayyah] dia berkata, \"Aku sedang tidur di dalam masjid dengan beralaskan kain milikku, tiba-tiba kain tersebut dicuri, maka aku menangkap pencuri tersebut dan membawanya ke hadapan Nabi shallallahu 'alaihi wasallam. Maka beliau pun memerintahkan untuk memotong tangannya, lantas aku berkata, \"Wahai Rasulullah, kainku hanya seharga tiga puluh delapan dirham, aku kasihkan untuknya atau aku jual kepadanya.\" Beliau bersabda: \"Kenapa itu tidak kamu lakukan sebelum kamu bawa dia kemari!\""},"4303":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو وَسُرَيْجٌ الْمَعْنَى قَالَا ثَنَا نَافِعُ بْنُ عُمَرَ يَعْنِي الْجُمَحِيَّ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ عَنْ أَبِي بَكْرِ بْنِ أَبِي زُهَيْرٍ قَالَ أَبِي كِلَاهُمَا قَالَ عَنْ أَبِي بَكْرِ بْنِ أَبِي زُهَيْرٍ الثَّقَفِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِالنَّبَاءَةِ أَوْ النَّبَاوَةِ شَكَّ نَافِعُ بْنُ عُمَرَ مِنْ الطَّائِفِ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تُوشِكُونَ أَنْ تَعْرِفُوا أَهْلَ الْجَنَّةِ مِنْ أَهْلِ النَّارِ أَوْ قَالَ خِيَارُكُمْ مِنْ شِرَارِكُمْ قَالَ فَقَالَ رَجُلٌ مِنْ النَّاسِ بِمَ يَا رَسُولَ اللَّهِ قَالَ بِالثَّنَاءِ السَّيِّئِ وَالثَّنَاءِ الْحَسَنِ وَأَنْتُمْ شُهَدَاءُ اللَّهِ بَعْضُكُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Abdul Malik bin Amru] dan [Suraij] secara makna, keduanya berkata, telah menceritakan kepada kami [Nafi' bin Amru] -yaitu Al Jumahi- dari [Umaiyah bin Shafwan] dari [Abu Bakar bin Abu Zuhair] -Abdullah berkata; ayahku berkata; keduanya berkata dari Abu Bakar bin Abu Zuhair Ats Tsaqafi- dari [Bapaknya] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di Naba`ah atau Nabawah -Nafi' bin Umar masih ragu-, beliau bersabda: \"Wahai manusia, sesungguhnya kalian hampir saja mengetahui penghuni Surga dari penduduk neraka, \" atau dalam riwayat lain beliau bersabda: \"Orang yang paling baik di antara kalian dari yang peling jahat di antara kalian.\" Abu Zuhair berkata, \"Lalu seorang laki-laki dari mereka berkata, \"Wahai Rasulullah, bagaimana kami mengetahuinya?\" Beliau menjawab: \"Dengan pujian yang buruk dan dengan pujian yang baik, dan kalian adalah saksi-saksi Allah antara sebagian kalian dengan sebagian yang lain.\""},"4304":{"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ قَالَ أَخْبَرَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ قَالَ سَمِعْتُ يَحْيَى بْنَ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي بَعْجَةُ بْنُ عَبْدِ اللَّهِ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمْ يَوْمًا هَذَا يَوْمُ عَاشُورَاءَ فَصُومُوا فَقَالَ رَجُلٌ مِنْ بَنِى عَمْرِو بْنِ عَوْفٍ يَا رَسُولَ اللَّهِ إِنِّي تَرَكْتُ قَوْمِي مِنْهُمْ صَائِمٌ وَمِنْهُمْ مُفْطِرٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ إِلَيْهِمْ فَمَنْ كَانَ مِنْهُمْ مُفْطِرًا فَلْيُتِمَّ صَوْمَهُ","id":"Telah menceritakan kepada kami [Hisyam Bin Sa'id] berkata, telah mengabarkan kepada kami [Mu'awiyah bin Sallam] dia berkata, aku mendengar [Yahya bin Abu Katsir] berkata, telah mengabarkan kepadaku [Ba'jah bin Abdullah] bahwa [bapaknya] telah mengabarkan kepadanya, bahwa pada suatu hari Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka: \"Ini adalah hari Asyura, maka berpuasalah kalian.\" Lalu berkatalah salah seorang lelaki dari bani Amru Bin Auf, \"Wahai Rasulullah, aku tinggalkan kaumku, sedangkan di antara mereka ada yang berpuasa dan ada yang berbuka?\" maka Nabi shallallahu 'alaihi wasallam pun menjawab: \"Pergilah kepada mereka, barangsiapa di antara mereka ada yang berbuka maka suruhklah untuk menyempurnakan puasanya.\""},"4305":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ ثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أَبِيهِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِحْدَى صَلَاتَيْ الْعَشِيِّ الظُّهْرِ أَوْ الْعَصْرِ وَهُوَ حَامِلُ حَسَنٍ أَوْ حُسَيْنٍ فَتَقَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَهُ ثُمَّ كَبَّرَ لِلصَّلَاةِ فَصَلَّى فَسَجَدَ بَيْنَ ظَهْرَيْ صَلَاتِهِ سَجْدَةً أَطَالَهَا قَالَ إِنِّي رَفَعْتُ رَأْسِي فَإِذَا الصَّبِيُّ عَلَى ظَهَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ سَاجِدٌ فَرَجَعْتُ فِي سُجُودِي فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ النَّاسُ يَا رَسُولَ اللَّهِ إِنَّكَ سَجَدْتَ بَيْنَ ظَهْرَيْ الصَّلَاةِ سَجْدَةً أَطَلْتَهَا حَتَّى ظَنَنَّا أَنَّهُ قَدْ حَدَثَ أَمْرٌ أَوْ أَنَّهُ يُوحَى إِلَيْكَ قَالَ كُلُّ ذَلِكَ لَمْ يَكُنْ وَلَكِنَّ ابْنِي ارْتَحَلَنِي فَكَرِهْتُ أَنْ أُعَجِّلَهُ حَتَّى يَقْضِيَ حَاجَتَهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Jarir bin Hazim] berkata, telah menceritakan kepada kami [Muhammad bin Abu Ya'qub] dari [Abdullah bin Syaddad] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar bersama kami pada salah satu dari dua shalat siang; zhuhur atau ashar, dan saat itu beliau membawa Hasan atau Husain. Nabi shallallahu 'alaihi wasallam lalu maju ke depan dan meletakkannya, kemudian bertakbir untuk shalat, beliau lalu shalat. Kemudian beliau sujud di antara (rakaat) shalatnya dengan sujud yang sangat lama.\" Syaddad berkata, \"Sungguh aku mengangkat kepalaku dan ternyata seorang anak kecil naik di atas punggung Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang sujud, kemudian aku kembali sujud, maka setelah Rasulullah shallallahu 'alaihi wasallam selesai shalat, orang-orang berkata kepada beliau, \"Wahai Rasulullah, sesungguhnya tuan malakukan sujud sangat panjang sekali di tengah-tengah shalat, hingga kami mengira telah terjadi sesuatu atau turun wahyu kepada tuan?\" Kemudian beliau menjawab: \"Semua itu tidak terjadi melainkan anakku menaiki punggungku, dan aku tidak suka untuk mempercepat sampai dia selesai dari keinginannya.\""}};
